import { GoogleGenAI, Type } from "@google/genai";
import { TripRecommendation } from "../types";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const getTripRecommendation = async (destination: string, currentLocation?: string): Promise<TripRecommendation> => {
  const prompt = `Plan a short trip to ${destination} ${currentLocation ? `starting from ${currentLocation}` : ''}. 
    Provide a travel itinerary with estimated time and distance. 
    Focus on popular spots in India.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          duration: { type: Type.STRING },
          distance: { type: Type.STRING },
          highlights: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["title", "description", "duration", "distance", "highlights"]
      }
    }
  });

  return JSON.parse(response.text) as TripRecommendation;
};

