}

export const LayerPanel: React.FC<LayerPanelProps> = ({ isOpen, onClose, activeLayers, onToggleLayer }) => {
  const layers = [
    { id: MapLayerType.STREET, label: 'Street', icon: '🏙️' },
    { id: MapLayerType.SATELLITE, label: 'Satellite', icon: '🛰️' },
    { id: MapLayerType.TRAFFIC, label: 'Live Traffic', icon: '🚦' },
    { id: MapLayerType.TRANSIT, label: 'Transit', icon: '🚌' },
    { id: MapLayerType.BUILDINGS, label: '3D Buildings', icon: '🏢' },
  ];

  return (
    <div className={`fixed top-24 right-6 w-72 glass rounded-3xl p-6 shadow-2xl z-[999] transition-all duration-500 transform ${isOpen ? 'translate-x-0 opacity-100' : 'translate-x-[120%] opacity-0'}`}>
