import React, { useEffect, useRef, useState, useCallback } from 'react';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import OSM from 'ol/source/OSM';
import VectorSource from 'ol/source/Vector';
import { fromLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import { Header } from './components/Header';
import { LayerPanel } from './components/LayerPanel';
import { BottomPanel } from './components/BottomPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapLayerType, UserLocation, TripRecommendation } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, TRAFFIC_COLORS } from './constants';
import { getTripRecommendation } from './services/geminiService';

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const trafficSource = useRef<VectorSource>(new VectorSource());

  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET, MapLayerType.TRAFFIC]);
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [isBottomPanelExpanded, setIsBottomPanelExpanded] = useState(false);
  const [userLocation, setUserLocation] = useState<UserLocation | null>(null);
  const [aiRecommendation, setAiRecommendation] = useState<TripRecommendation | null>(null);
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  // Initialize Map
  useEffect(() => {
    if (!mapRef.current) return;

    const baseLayer = new TileLayer({
      source: new OSM({
        url: MAP_SOURCES.STREET
      }),
      visible: true
    });

    const satelliteLayer = new TileLayer({
      source: new OSM({
        url: MAP_SOURCES.SATELLITE
      }),
      visible: false
    });

    const trafficLayer = new VectorLayer({
      source: trafficSource.current,
      style: (feature) => {
        const speed = feature.get('speed') || 0;
        const color = speed > 60 ? TRAFFIC_COLORS.FAST : speed > 30 ? TRAFFIC_COLORS.MEDIUM : TRAFFIC_COLORS.SLOW;
        return new Style({
          image: new Circle({
            radius: 5,
            fill: new Fill({ color }),
            stroke: new Stroke({ color: 'white', width: 1.5 })
          })
        });
      }
    });

    const map = new Map({
      target: mapRef.current,
      layers: [baseLayer, satelliteLayer, trafficLayer],
      view: new View({
        center: fromLonLat(DEFAULT_CENTER),
        zoom: DEFAULT_ZOOM,
        smoothExtentConstraint: true,
        smoothResolutionConstraint: true,
      }),
      controls: []
    });

    mapInstance.current = map;

    // Traffic Simulation
    const interval = setInterval(() => {
      trafficSource.current.clear();
      const center = map.getView().getCenter();
      if (!center) return;

      for (let i = 0; i < 50; i++) {
        const offsetLng = (Math.random() - 0.5) * 0.05;
        const offsetLat = (Math.random() - 0.5) * 0.05;
        const speed = Math.random() * 80;

        const feature = new Feature({
          geometry: new Point([center[0] + offsetLng * 100000, center[1] + offsetLat * 100000]),
          speed
        });
        trafficSource.current.addFeature(feature);
      }
    }, 2000);

    return () => {
      clearInterval(interval);
      map.setTarget(undefined);
    };
  }, []);

  // Sync Layers
  useEffect(() => {
    if (!mapInstance.current) return;
    const layers = mapInstance.current.getLayers().getArray();
    const streetLayer = layers[0] as TileLayer<OSM>;
    const satelliteLayer = layers[1] as TileLayer<OSM>;
    const trafficLayer = layers[2] as VectorLayer<VectorSource>;

    streetLayer.setVisible(activeLayers.includes(MapLayerType.STREET));
    satelliteLayer.setVisible(activeLayers.includes(MapLayerType.SATELLITE));
    trafficLayer.setVisible(activeLayers.includes(MapLayerType.TRAFFIC));
  }, [activeLayers]);

  const handleSearch = async (query: string) => {
    if (!query) return;
    setIsLoadingAi(true);
    setIsBottomPanelExpanded(true);
    try {
      const rec = await getTripRecommendation(query, userLocation ? `${userLocation.lat},${userLocation.lng}` : undefined);
      setAiRecommendation(rec);
    } catch (err) {
      console.error("AI Planning Error:", err);
    } finally {
      setIsLoadingAi(false);
    }
  };

  const handleLocate = useCallback(() => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition((pos) => {
      const loc = { lat: pos.coords.latitude, lng: pos.coords.longitude };
      setUserLocation(loc);
      if (mapInstance.current) {
        mapInstance.current.getView().animate({
          center: fromLonLat([loc.lng, loc.lat]),
          zoom: 15,
          duration: 1000
        });
      }
    });
  }, []);

  const handleVoice = () => {
    const msg = new SpeechSynthesisUtterance("Starting navigation. Head north on your current street.");
    window.speechSynthesis.speak(msg);
  };

  const handleAR = () => {
    alert("AR Feature Simulation: Align your device with the horizon to overlay directions on live camera feed.");
  };

  return (
    <div className="relative w-full h-screen overflow-hidden bg-slate-900">
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        onSearch={handleSearch}
        onLocate={handleLocate}
        onToggleLayers={() => setIsLayerPanelOpen(p => !p)}
        onToggleDirections={() => setIsBottomPanelExpanded(p => !p)}
        isLayersOpen={isLayerPanelOpen}
      />

      <LayerPanel 
        isOpen={isLayerPanelOpen}
        onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers}
        onToggleLayer={(l) => {
          setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l]);
        }}
      />

      <FloatingControls 
        onRecenter={handleLocate}
        onVoice={handleVoice}
        onAR={handleAR}
      />

      <BottomPanel 
        isExpanded={isBottomPanelExpanded}
        onToggle={() => setIsBottomPanelExpanded(p => !p)}
        aiRecommendation={aiRecommendation}
        isLoadingAi={isLoadingAi}
      />

      {/* Map Overlay Blur (Bottom only) */}
      <div className="absolute bottom-0 left-0 right-0 h-32 bg-gradient-to-t from-slate-900/60 to-transparent pointer-events-none" />
    </div>
  );
};

export default App;

