import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { Style, Circle, Fill, Stroke } from 'ol/style';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { MapTheme, MapLayerType, Destination } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, TRAFFIC_COLORS } from './constants';

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const trafficSource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [weather, setWeather] = useState({ temp: 24, condition: 'Clear' });

  // Update clock
  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  // Initialize Map with smooth settings
  useEffect(() => {
    if (!mapRef.current) return;

    const baseLayer = new TileLayer({
      source: new OSM({ url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT }),
      zIndex: 0
    });

    const trafficLayer = new VectorLayer({
      source: trafficSource.current,
      zIndex: 10,
      updateWhileAnimating: true,
      updateWhileInteracting: true,
      style: (feature) => {
        const speed = feature.get('speed') || 0;
        const color = speed > 60 ? TRAFFIC_COLORS.FAST : speed > 30 ? TRAFFIC_COLORS.MEDIUM : TRAFFIC_COLORS.SLOW;
        return new Style({
          image: new Circle({
            radius: 4,
            fill: new Fill({ color: color + 'CC' }),
            stroke: new Stroke({ color: 'white', width: 1 })
          })
        });
      }
    });

    const map = new Map({
      target: mapRef.current,
      layers: [baseLayer, trafficLayer],
      view: new View({
        center: fromLonLat(DEFAULT_CENTER),
        zoom: DEFAULT_ZOOM,
        smoothExtentConstraint: true,
        smoothResolutionConstraint: true,
        multiWorld: true,
        constrainResolution: true,
      }),
      controls: []
    });

    mapInstance.current = map;

    // Listen for map movements to update simulated local weather
    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const coords = toLonLat(center);
        // Simulate local variation
        const pseudoTemp = 20 + Math.abs(coords[0] % 10);
        setWeather({ 
          temp: Math.round(pseudoTemp), 
          condition: pseudoTemp > 26 ? 'Sunny' : 'Partly Cloudy' 
        });
      }
    });

    // Hyper-Smooth Traffic Particles
    const simulateTraffic = () => {
      trafficSource.current.clear();
      const center = map.getView().getCenter();
      if (!center) return;

      const features = [];
      const view = map.getView();
      const extent = view.calculateExtent(map.getSize());
      const width = extent[2] - extent[0];
      const height = extent[3] - extent[1];

      for (let i = 0; i < 40; i++) {
        const x = extent[0] + Math.random() * width;
        const y = extent[1] + Math.random() * height;
        const speed = Math.random() * 100;
        features.push(new Feature({
          geometry: new Point([x, y]),
          speed
        }));
      }
      trafficSource.current.addFeatures(features);
    };

    const interval = setInterval(simulateTraffic, 4000);
    simulateTraffic();

    return () => {
      clearInterval(interval);
      map.setTarget(undefined);
    };
  }, []);

  // Sync Theme
  useEffect(() => {
    if (!mapInstance.current) return;
    const layers = mapInstance.current.getLayers().getArray();
    const base = layers[0] as TileLayer<OSM>;
    base.setSource(new OSM({ url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT }));
  }, [theme]);

  const handleDestinationSelect = (dest: Destination) => {
    if (!mapInstance.current) return;
    mapInstance.current.getView().animate({
      center: fromLonLat(dest.coords),
      zoom: 16,
      duration: 2000,
      easing: (t) => t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t // Custom EaseInOut
    });
  };

  const handleLocate = () => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition((pos) => {
      if (mapInstance.current) {
        mapInstance.current.getView().animate({
          center: fromLonLat([pos.coords.longitude, pos.coords.latitude]),
          zoom: 17,
          duration: 1200
        });
      }
    }, (err) => {
      console.warn("Location error:", err.message);
    }, { enableHighAccuracy: true });
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-1000 ${theme === MapTheme.DARK ? 'bg-slate-950' : 'bg-slate-50'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme}
        onThemeToggle={() => setTheme(t => t === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onSearch={() => {}}
        onLocate={handleLocate}
        onOpenLayers={() => {}}
      />

      {/* Re-engineered Status Widget with Weather */}
      <motion.div 
        initial={{ x: -150, opacity: 0 }}
        animate={{ x: 0, opacity: 1 }}
        transition={{ type: 'spring', damping: 20, stiffness: 100 }}
        className={`fixed top-24 left-6 z-[999] p-5 rounded-[28px] shadow-2xl flex flex-col gap-3 min-w-[180px] ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}
      >
        <div className="flex justify-between items-start">
          <div className="flex flex-col">
            <div className="flex items-center gap-2 mb-1">
              <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
              <span className={`text-[10px] font-bold uppercase tracking-widest ${theme === MapTheme.DARK ? 'text-white/40' : 'text-slate-900/40'}`}>Live</span>
            </div>
            <div className={`text-2xl font-bold tracking-tight ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
              {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
            </div>
          </div>
          <div className="text-2xl">{weather.condition === 'Sunny' ? '☀️' : '⛅'}</div>
        </div>

        <div className={`h-px w-full ${theme === MapTheme.DARK ? 'bg-white/10' : 'bg-black/5'}`} />

        <div className="flex justify-between items-center">
          <div>
            <div className={`text-[10px] font-bold uppercase tracking-tighter ${theme === MapTheme.DARK ? 'text-white/30' : 'text-slate-400'}`}>Local Temp</div>
            <div className={`text-xl font-bold ${theme === MapTheme.DARK ? 'text-blue-400' : 'text-blue-600'}`}>{weather.temp}°C</div>
          </div>
          <div className="text-right">
            <div className={`text-[10px] font-bold uppercase tracking-tighter ${theme === MapTheme.DARK ? 'text-white/30' : 'text-slate-400'}`}>AQI</div>
            <div className="text-xl font-bold text-emerald-500">42</div>
          </div>
        </div>
      </motion.div>

      <BottomPanel 
        theme={theme}
        onDestinationSelect={handleDestinationSelect}
      />

      {/* High-Performance Controls */}
      <div className="fixed bottom-24 right-6 flex flex-col gap-3 z-[1001]">
         <motion.button 
          whileHover={{ scale: 1.1, rotate: 5 }}
          whileTap={{ scale: 0.9 }}
          onClick={handleLocate}
          className="w-16 h-16 rounded-[24px] bg-blue-600 text-white flex items-center justify-center text-2xl shadow-[0_15px_30px_rgba(37,99,235,0.4)]"
