  onSearch: (q: string) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
}

export const Header: React.FC<HeaderProps> = ({ 
  theme, 
  onThemeToggle, 
  onLocate, 
  onOpenLayers,
  onSuggestionSelect 
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<Destination[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!query.trim()) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(() => {
      const q = query.toLowerCase();
      const filtered = POPULAR_DESTINATIONS.filter(dest => 
        dest.name.toLowerCase().includes(q) ||
        dest.category.toLowerCase().includes(q)
      ).slice(0, 5);
      setSuggestions(filtered);
    }, 200);

    return () => clearTimeout(timer);
  }, [query]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsFocused(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSelect = (dest: Destination) => {
    setQuery(dest.name);
    setSuggestions([]);
    setIsFocused(false);
    onSuggestionSelect(dest);
  };

  return (
    <motion.header 
      initial={{ y: -100, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[1000] p-4 flex justify-center pointer-events-none"
    >
      <div className="max-w-6xl w-full flex items-start gap-3 pointer-events-auto">
        <motion.div 
          layout
          className={`flex items-center gap-3 px-5 py-3 rounded-2xl shadow-2xl transition-colors duration-500 h-[52px] ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900'}`}
        >
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold shadow-lg">D</div>
          <span className="font-bold text-lg hidden md:block">Disha Pro</span>
        </motion.div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-4 py-3 rounded-2xl shadow-2xl transition-all duration-500 group h-[52px] ${
            theme === MapTheme.DARK 
              ? `glass ${isFocused ? 'bg-slate-800/90 ring-2 ring-blue-500/50' : 'hover:bg-slate-800/40'}` 
              : `glass-light ${isFocused ? 'bg-white ring-2 ring-blue-400/30' : 'hover:bg-white/80'}`
          }`}>
            <span className={`mr-3 transition-colors ${isFocused ? 'text-blue-500' : 'text-slate-400'}`}>🔍</span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Search places, categories..." 
              className="bg-transparent border-none outline-none w-full text-base font-semibold placeholder:text-slate-500 transition-colors"
              style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
            />
            {query && (
              <button 
                onClick={() => { setQuery(''); setSuggestions([]); }}
                className="ml-2 w-6 h-6 flex items-center justify-center rounded-full hover:bg-slate-500/20 text-slate-400 hover:text-slate-200 transition-colors"
              >
                ✕
              </button>
            )}
          </div>

          <AnimatePresence>
            {isFocused && (
              <motion.div
                initial={{ opacity: 0, y: 10, scale: 0.98 }}
                animate={{ opacity: 1, y: 5, scale: 1 }}
                exit={{ opacity: 0, y: 10, scale: 0.98 }}
                className={`absolute top-full left-0 right-0 mt-2 rounded-2xl shadow-2xl overflow-hidden border transition-colors duration-500 ${
                  theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'
                }`}
              >
                <div className="max-h-80 overflow-y-auto py-2">
                  {suggestions.length > 0 ? (
                    suggestions.map((dest) => (
                      <div
                        key={dest.id}
                        onClick={() => handleSelect(dest)}
                        className={`px-4 py-3 flex items-center gap-4 cursor-pointer transition-colors ${
                          theme === MapTheme.DARK ? 'hover:bg-white/10' : 'hover:bg-blue-50'
                        }`}
                      >
                        <div className="text-2xl w-10 h-10 flex items-center justify-center rounded-xl bg-slate-500/10 shrink-0">
                          {dest.image}
                        </div>
                        <div className="flex-1 overflow-hidden">
                          <div className={`font-bold text-sm truncate ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
                            {dest.name}
                          </div>
                          <div className={`text-xs opacity-60 font-medium truncate ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-500'}`}>
                            {dest.category} • {dest.description}
                          </div>
                        </div>
                      </div>
                    ))
                  ) : query.length > 0 ? (
                    <div className="px-6 py-8 text-center opacity-40">No results found</div>
                  ) : (
                    <div className="px-4 py-2">
                      <div className="text-[10px] font-bold uppercase tracking-widest text-blue-500 mb-2 px-2">Popular Nearby</div>
                      {POPULAR_DESTINATIONS.slice(0, 3).map(dest => (
                        <div key={dest.id} onClick={() => handleSelect(dest)} className={`px-2 py-2 rounded-xl flex items-center gap-3 cursor-pointer transition-colors ${theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-black/5'}`}>
                          <span className="text-lg opacity-80">{dest.image}</span>
                          <span className="text-sm font-medium">{dest.name}</span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex gap-2">
          <button 
            onClick={onThemeToggle}
            className={`w-[52px] h-[52px] rounded-xl flex items-center justify-center shadow-2xl transition-all hover:scale-105 active:scale-95 ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600'}`}
          >
            {theme === MapTheme.DARK ? '☀️' : '🌙'}
          </button>
          <button 
            onClick={onLocate}
            className={`w-[52px] h-[52px] rounded-xl flex items-center justify-center shadow-2xl transition-all hover:scale-105 active:scale-95 ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}
          >
            🎯
          </button>
          <button 
            onClick={onOpenLayers}
            className={`w-[52px] h-[52px] rounded-xl flex items-center justify-center shadow-2xl transition-all hover:scale-105 active:scale-95 ${theme === MapTheme.DARK ? 'glass text-emerald-400' : 'glass-light text-emerald-600'}`}
          >
            🗺️
          </button>
        </div>
      </div>
    </motion.header>
  );
};

export enum MapLayerType {
  STREET = 'street',
  SATELLITE = 'satellite',
  TRAFFIC = 'traffic',
  TRANSIT = 'transit',
  BUILDINGS = 'buildings',
  ROUTE = 'route'
}

export enum MapTheme {
  DARK = 'dark',
  LIGHT = 'light'
}

export interface UserLocation {
  lat: number;
  lng: number;
}

export interface Destination {
  id: string;
  name: string;
  category: string;
  coords: [number, number];
  description: string;
  image: string;
}

export interface RouteInfo {
  distance: string;
  duration: string;
  trafficDelay: string;
  congestionLevel: 'low' | 'moderate' | 'heavy';
}

export interface TrafficStatus {
  activeVehicles: number;
  incidents: number;
  stability: string;
}

import React, { useEffect, useRef, useState } from 'react';
import { motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import OSM from 'ol/source/OSM';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { MapTheme, MapLayerType, Destination, RouteInfo } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, TRAFFIC_COLORS, POPULAR_DESTINATIONS } from './constants';

interface Vehicle {
  feature: Feature<Point>;
  speed: number;
  heading: number;
  coords: [number, number];
}

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const trafficSource = useRef<VectorSource>(new VectorSource());
  const routeSource = useRef<VectorSource>(new VectorSource());
  const vehiclesRef = useRef<Vehicle[]>([]);
  const animationFrameId = useRef<number>(0);

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET, MapLayerType.TRAFFIC, MapLayerType.ROUTE]);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [weather, setWeather] = useState({ temp: 24, condition: 'Clear' });

  // Routing State
  const [startPoint, setStartPoint] = useState<Destination | null>(null);
  const [endPoint, setEndPoint] = useState<Destination | null>(null);
  const [routeInfo, setRouteInfo] = useState<RouteInfo | null>(null);

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  // Initialize Map
  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const baseLayer = new TileLayer({
      source: new OSM({ 
        url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT,
        crossOrigin: 'anonymous'
      }),
      zIndex: 0,
      properties: { id: 'base' }
    });

    const satelliteLayer = new TileLayer({
      source: new OSM({ url: MAP_SOURCES.SATELLITE, crossOrigin: 'anonymous' }),
      zIndex: 1,
      visible: activeLayers.includes(MapLayerType.SATELLITE),
      properties: { id: 'satellite' }
    });

    const trafficLayer = new VectorLayer({
      source: trafficSource.current,
      zIndex: 10,
      updateWhileAnimating: true,
      style: (feature) => {
        const speed = feature.get('speed') || 0;
        const color = speed > 60 ? TRAFFIC_COLORS.FAST : speed > 30 ? TRAFFIC_COLORS.MEDIUM : TRAFFIC_COLORS.SLOW;
        return new Style({
          image: new Circle({
            radius: 3,
            fill: new Fill({ color: color + 'EE' }),
            stroke: new Stroke({ color: theme === MapTheme.DARK ? 'rgba(255,255,255,0.8)' : 'rgba(0,0,0,0.4)', width: 1 })
          })
        });
      },
      properties: { id: 'traffic' }
    });

    const routeLayer = new VectorLayer({
      source: routeSource.current,
      zIndex: 5,
      style: new Style({
        stroke: new Stroke({
          color: '#3b82f6',
          width: 6,
          lineCap: 'round',
          lineJoin: 'round'
        })
      }),
      properties: { id: 'route' }
    });

    const map = new Map({
      target: mapRef.current,
      layers: [baseLayer, satelliteLayer, routeLayer, trafficLayer],
      view: new View({
        center: fromLonLat(DEFAULT_CENTER),
        zoom: DEFAULT_ZOOM,
        smoothExtentConstraint: true,
        smoothResolutionConstraint: true,
        multiWorld: false,
        constrainResolution: true,
        maxZoom: 19,
        minZoom: 2
      }),
      controls: []
    });

    mapInstance.current = map;

    // Enhanced Traffic Simulation
    const initTraffic = () => {
      const center = fromLonLat(DEFAULT_CENTER);
      const count = 80;
      const vehicles: Vehicle[] = [];
      for (let i = 0; i < count; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = Math.random() * 8000;
        const coords: [number, number] = [
          center[0] + Math.cos(angle) * radius,
          center[1] + Math.sin(angle) * radius
        ];
        const feature = new Feature(new Point(coords));
        const speed = 20 + Math.random() * 80;
        feature.set('speed', speed);
        vehicles.push({ feature, speed: speed / 15, heading: Math.random() * Math.PI * 2, coords });
      }
      vehiclesRef.current = vehicles;
      trafficSource.current.addFeatures(vehicles.map(v => v.feature));
    };

    const animateTraffic = () => {
      vehiclesRef.current.forEach(v => {
        v.coords[0] += Math.cos(v.heading) * v.speed;
        v.coords[1] += Math.sin(v.heading) * v.speed;
        if (Math.random() > 0.98) v.heading += (Math.random() - 0.5) * 0.4;
        v.feature.getGeometry()?.setCoordinates(v.coords);
      });
      animationFrameId.current = requestAnimationFrame(animateTraffic);
    };

    initTraffic();
    animateTraffic();

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const coords = toLonLat(center);
        const pseudoTemp = 22 + Math.abs((coords[0] * coords[1]) % 8);
        setWeather({ temp: Math.round(pseudoTemp), condition: theme === MapTheme.DARK ? 'Clear' : 'Sunny' });
      }
    });

    return () => {
      cancelAnimationFrame(animationFrameId.current);
      if (mapInstance.current) {
        mapInstance.current.setTarget(undefined);
        mapInstance.current = null;
      }
    };
  }, []);

  // Sync Theme & Layers
  useEffect(() => {
    if (!mapInstance.current) return;
    const layers = mapInstance.current.getLayers().getArray();
    layers.forEach(layer => {
      const id = layer.get('id');
      if (id === 'base') {
        (layer as TileLayer<OSM>).setSource(new OSM({ 
          url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT,
          crossOrigin: 'anonymous'
        }));
        layer.setVisible(!activeLayers.includes(MapLayerType.SATELLITE));
      }
      if (id === 'satellite') layer.setVisible(activeLayers.includes(MapLayerType.SATELLITE));
      if (id === 'traffic') layer.setVisible(activeLayers.includes(MapLayerType.TRAFFIC));
      if (id === 'route') layer.setVisible(activeLayers.includes(MapLayerType.ROUTE));
    });
  }, [theme, activeLayers]);

  // Route Planning Logic
  const calculateRoute = (start: Destination, end: Destination) => {
    if (!mapInstance.current) return;
    routeSource.current.clear();

    const startCoords = fromLonLat(start.coords);
    const endCoords = fromLonLat(end.coords);

    // Accurate simulated road path generation
    // We create a few intermediate "waypoints" to simulate following street grids
    const mid1: [number, number] = [startCoords[0], endCoords[1]];
    const mid2: [number, number] = [endCoords[0], startCoords[1]];

    // Choose the mid point based on a pseudo-random "best path" factor
    const mid = Math.random() > 0.5 ? mid1 : mid2;
    const path = [startCoords, mid, endCoords];

    const lineFeature = new Feature(new LineString(path));
    routeSource.current.addFeature(lineFeature);

    // Calculate metrics
    const dx = end.coords[0] - start.coords[0];
    const dy = end.coords[1] - start.coords[1];
    const distKm = (Math.sqrt(dx * dx + dy * dy) * 111).toFixed(1);
    const baseTime = parseFloat(distKm) * 2.5; // 2.5 mins per km avg
    const trafficFactor = 1 + (Math.random() * 0.4);
    const totalTime = (baseTime * trafficFactor).toFixed(0);

    setRouteInfo({
      distance: `${distKm} km`,
      duration: `${totalTime} min`,
      trafficDelay: `${(parseFloat(totalTime) - baseTime).toFixed(0)} min delay`,
      congestionLevel: trafficFactor > 1.3 ? 'heavy' : trafficFactor > 1.15 ? 'moderate' : 'low'
    });

    // Zoom to fit route
    const extent = lineFeature.getGeometry()?.getExtent();
    if (extent) {
      mapInstance.current.getView().fit(extent, {
        padding: [100, 100, 100, 100],
        duration: 1500,
        easing: (t) => t * (2 - t)
      });
    }
  };

  const handleDestinationSelect = (dest: Destination) => {
    if (startPoint && !endPoint && startPoint.id !== dest.id) {
      setEndPoint(dest);
      calculateRoute(startPoint, dest);
    } else {
      setStartPoint(dest);
      setEndPoint(null);
      setRouteInfo(null);
      routeSource.current.clear();

      if (mapInstance.current) {
        mapInstance.current.getView().animate({
          center: fromLonLat(dest.coords),
          zoom: 17,
          duration: 1800,
          easing: (t) => t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t
        });
      }
    }
  };

  const handleLocate = () => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition((pos) => {
      const myLocation: Destination = {
        id: 'me',
        name: 'My Location',
        category: 'Personal',
        coords: [pos.coords.longitude, pos.coords.latitude],
        description: 'Your current position',
        image: '📍'
      };
      setStartPoint(myLocation);
      if (mapInstance.current) {
        mapInstance.current.getView().animate({
          center: fromLonLat(myLocation.coords),
          zoom: 17,
          duration: 1200
        });
      }
    }, (err) => console.warn(err.message), { enableHighAccuracy: true });
  };

  const toggleLayer = (layer: MapLayerType) => {
    setActiveLayers(prev => prev.includes(layer) ? prev.filter(l => l !== layer) : [...prev, layer]);
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-1000 ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-blue-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme}
        onThemeToggle={() => setTheme(t => t === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onSearch={() => {}}
        onLocate={handleLocate}
        onOpenLayers={() => setIsLayerPanelOpen(!isLayerPanelOpen)}
        onSuggestionSelect={handleDestinationSelect}
      />

      <LayerPanel 
        isOpen={isLayerPanelOpen}
        onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers}
        onToggleLayer={toggleLayer}
        theme={theme}
      />

      {/* Dynamic Status Widget */}
      <motion.div 
        layout
        initial={{ x: -150, opacity: 0 }}
        animate={{ x: 0, opacity: 1 }}
        transition={{ type: 'spring', damping: 22, stiffness: 120 }}
        className={`fixed top-24 left-6 z-[999] p-5 rounded-[28px] shadow-2xl flex flex-col gap-3 min-w-[200px] transition-all duration-700 ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}
      >
        <div className="flex justify-between items-start">
          <div className="flex flex-col">
            <div className="flex items-center gap-2 mb-1">
              <div className={`w-2 h-2 rounded-full animate-pulse ${theme === MapTheme.DARK ? 'bg-indigo-400' : 'bg-amber-400'} shadow-[0_0_10px_currentColor]`} />
              <span className={`text-[10px] font-bold uppercase tracking-widest opacity-60`}>
                {theme === MapTheme.DARK ? 'Night Mode' : 'Day Mode'}
              </span>
            </div>
            <div className="text-3xl font-extrabold tracking-tighter">
              {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
            </div>
          </div>
          <motion.div key={theme} initial={{ scale: 0.5, rotate: -45 }} animate={{ scale: 1, rotate: 0 }} className="text-3xl">
            {theme === MapTheme.DARK ? '🌙' : '☀️'}
          </motion.div>
        </div>
        <div className={`h-px w-full ${theme === MapTheme.DARK ? 'bg-white/10' : 'bg-black/5'}`} />
        <div className="flex justify-between items-center px-1">
          <div>
            <div className="text-[10px] font-bold uppercase tracking-tighter opacity-40">Temp</div>
            <div className={`text-xl font-black ${theme === MapTheme.DARK ? 'text-blue-400' : 'text-blue-600'}`}>{weather.temp}°C</div>
          </div>
          <div className="text-right">
            <div className="text-[10px] font-bold uppercase tracking-tighter opacity-40">Weather</div>
            <div className="text-sm font-bold opacity-80">{weather.condition}</div>
          </div>
        </div>
      </motion.div>

      <BottomPanel 
        theme={theme} 
        onDestinationSelect={handleDestinationSelect}
        startPoint={startPoint}
        endPoint={endPoint}
        routeInfo={routeInfo}
        onClearRoute={() => {
          setStartPoint(null);
          setEndPoint(null);
          setRouteInfo(null);
          routeSource.current.clear();
        }}
      />

      <div className="fixed bottom-24 right-6 flex flex-col gap-3 z-[1001]">
         <motion.button 
          whileHover={{ scale: 1.1, y: -2 }}
          whileTap={{ scale: 0.95 }}
          onClick={handleLocate}
          className="w-16 h-16 rounded-[24px] bg-blue-600 text-white flex items-center justify-center text-2xl shadow-[0_15px_30px_rgba(37,99,235,0.4)] transition-transform"
        >
          🎯
        </motion.button>
      </div>

      <motion.div 
        animate={{ opacity: theme === MapTheme.DARK ? 0.6 : 0.1 }}
        className="absolute inset-0 pointer-events-none transition-opacity duration-1000 z-[1]" 
        style={{ 
          background: theme === MapTheme.DARK 
            ? 'radial-gradient(circle at center, transparent 20%, #000 160%)'
            : 'radial-gradient(circle at center, transparent 40%, #2563eb 200%)'
        }} 
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Destination, MapTheme, RouteInfo } from '../types';
import { POPULAR_DESTINATIONS } from '../constants';

interface BottomPanelProps {
  theme: MapTheme;
  onDestinationSelect: (d: Destination) => void;
  startPoint: Destination | null;
  endPoint: Destination | null;
  routeInfo: RouteInfo | null;
  onClearRoute: () => void;
}

export const BottomPanel: React.FC<BottomPanelProps> = ({ 
  theme, 
  onDestinationSelect,
  startPoint,
  endPoint,
  routeInfo,
  onClearRoute
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [activeTab, setActiveTab] = useState<'explore' | 'route' | 'traffic'>('explore');

  // Automatically switch to route tab if points are selected
  useEffect(() => {
    if (startPoint || endPoint) {
      setActiveTab('route');
      setIsExpanded(true);
    }
  }, [startPoint, endPoint]);

  return (
    <motion.div 
      initial={false}
      animate={{ height: isExpanded ? 460 : 70 }}
      className={`fixed bottom-0 left-0 right-0 z-[998] rounded-t-[40px] shadow-[0_-10px_40px_rgba(0,0,0,0.3)] transition-colors duration-500 ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}
    >
      <div 
        className="h-16 flex flex-col items-center justify-center cursor-pointer group"
        onClick={() => setIsExpanded(!isExpanded)}
      >
        <div className={`w-12 h-1.5 rounded-full mb-1 transition-colors ${theme === MapTheme.DARK ? 'bg-white/20 group-hover:bg-white/40' : 'bg-black/10 group-hover:bg-black/20'}`} />
        <span className={`text-xs font-bold uppercase tracking-widest ${theme === MapTheme.DARK ? 'text-white/40' : 'text-slate-900/40'}`}>
          {isExpanded ? 'Minimize' : (startPoint && endPoint ? 'Route Details' : 'Explore Nearby')}
        </span>
      </div>

      <AnimatePresence>
        {isExpanded && (
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 20 }}
            className="px-8 pb-8 overflow-hidden"
          >
            <div className="flex gap-4 mb-6 border-b border-white/5 pb-2">
              {[
                { id: 'explore', label: 'EXPLORE' },
                { id: 'route', label: 'DIRECTIONS' },
                { id: 'traffic', label: 'TRAFFIC' }
              ].map(tab => (
                <button 
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as any)}
