                          <div>
                            <div className="text-[10px] font-bold uppercase opacity-60">Distance</div>
                            <div className="text-2xl font-black">{routeInfo.distance}</div>
                          </div>
                          <div>
                            <div className="text-[10px] font-bold uppercase opacity-60">Congestion</div>
                            <div className={`text-2xl font-black capitalize ${
                              routeInfo.congestionLevel === 'heavy' ? 'text-red-500' : 
                              routeInfo.congestionLevel === 'moderate' ? 'text-amber-500' : 'text-emerald-500'
                            }`}>
                              {routeInfo.congestionLevel}
