                    </div>
                  )}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center h-full space-y-4">
                  <div className="w-20 h-20 rounded-full bg-emerald-500/20 flex items-center justify-center text-emerald-500 text-4xl">⚡</div>
