import React, { useEffect, useRef, useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import OSM from 'ol/source/OSM';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, TRAFFIC_COLORS, TRANSLATIONS } from './constants';

interface Vehicle {
  feature: Feature<Point>;
  speed: number;
  heading: number;
  coords: [number, number];
}

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const trafficSource = useRef<VectorSource>(new VectorSource());
  const routeSource = useRef<VectorSource>(new VectorSource());
  const vehiclesRef = useRef<Vehicle[]>([]);
  const animationFrameId = useRef<number>(0);

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET, MapLayerType.TRAFFIC, MapLayerType.ROUTE]);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [weather, setWeather] = useState({ temp: 24, condition: 'Clear' });
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const [startPoint, setStartPoint] = useState<Destination | null>(null);
  const [endPoint, setEndPoint] = useState<Destination | null>(null);
  const [routeInfo, setRouteInfo] = useState<RouteInfo | null>(null);

  const t = TRANSLATIONS[language];

  // Sync Online Status
  useEffect(() => {
    const handleStatus = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatus);
    window.addEventListener('offline', handleStatus);
    return () => {
      window.removeEventListener('online', handleStatus);
      window.removeEventListener('offline', handleStatus);
    };
  }, []);

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  // Persistent Cache Logic (localStorage for routes and view)
  const saveState = useCallback(() => {
    if (!mapInstance.current) return;
    const view = mapInstance.current.getView();
    const state = {
      center: toLonLat(view.getCenter() as [number, number]),
      zoom: view.getZoom(),
      theme,
      language,
      startPoint,
      endPoint,
      routeInfo
    };
    localStorage.setItem('disha_map_state', JSON.stringify(state));
  }, [theme, language, startPoint, endPoint, routeInfo]);

  useEffect(() => {
    const timer = setInterval(saveState, 5000);
    return () => clearInterval(timer);
  }, [saveState]);

  // Enhanced Pathfinding Algorithm (Heuristic Grid-based simulation)
  const calculateRoute = (start: Destination, end: Destination) => {
    if (!mapInstance.current) return;
    routeSource.current.clear();

    const startCoords = fromLonLat(start.coords) as [number, number];
    const endCoords = fromLonLat(end.coords) as [number, number];

    // Generate complex path with mid-point waypoints and jitter for "street-following" look
    const path: [number, number][] = [startCoords];
    const segments = 12; // High resolution for smooth curves/turns

    for (let i = 1; i < segments; i++) {
      const p = i / segments;
      const noise = (Math.random() - 0.5) * 500; // Random offset for "roads"

      // Interpolate with grid-bias
      let nextX, nextY;
      if (i % 2 === 0) {
        nextX = startCoords[0] + (endCoords[0] - startCoords[0]) * p + noise;
        nextY = startCoords[1] + (endCoords[1] - startCoords[1]) * p;
      } else {
        nextX = startCoords[0] + (endCoords[0] - startCoords[0]) * p;
        nextY = startCoords[1] + (endCoords[1] - startCoords[1]) * p + noise;
      }
      path.push([nextX, nextY]);
    }

    path.push(endCoords);
    const lineFeature = new Feature(new LineString(path));
    routeSource.current.addFeature(lineFeature);

    // Advanced Metrics
    const rawDist = Math.sqrt(Math.pow(end.coords[0] - start.coords[0], 2) + Math.pow(end.coords[1] - start.coords[1], 2)) * 111.3;
    const actualDist = rawDist * 1.42; // Real-world curvature coefficient
    const distText = actualDist.toFixed(1);

    const trafficSeed = Math.random();
    const delay = trafficSeed > 0.7 ? 15 : trafficSeed > 0.3 ? 5 : 2;
    const baseTime = parseFloat(distText) * 2.1;
    const finalTime = (baseTime + delay).toFixed(0);

    setRouteInfo({
      distance: `${distText} km`,
      duration: `${finalTime} min`,
      trafficDelay: `${delay} min delay`,
      congestionLevel: delay > 10 ? 'heavy' : delay > 4 ? 'moderate' : 'low'
    });

    mapInstance.current.getView().fit(lineFeature.getGeometry()?.getExtent()!, { 
      padding: [160, 80, 160, 80], 
      duration: 2500,
      easing: (t) => t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2
    });
  };

  // Map Initialization
  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const saved = JSON.parse(localStorage.getItem('disha_map_state') || '{}');

    const map = new Map({
      target: mapRef.current,
      layers: [
        new TileLayer({
          source: new OSM({ 
            url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT,
            crossOrigin: 'anonymous'
          }),
          zIndex: 0,
          properties: { id: 'base' }
        }),
        new TileLayer({
          source: new OSM({ url: MAP_SOURCES.SATELLITE, crossOrigin: 'anonymous' }),
          zIndex: 1,
          visible: false,
          properties: { id: 'satellite' }
        }),
        new VectorLayer({
          source: routeSource.current,
          zIndex: 5,
          style: new Style({
            stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round', lineJoin: 'round' })
          }),
          properties: { id: 'route' }
        }),
        new VectorLayer({
          source: trafficSource.current,
          zIndex: 10,
          style: (feature) => {
            const speed = feature.get('speed') || 0;
            const color = speed > 60 ? TRAFFIC_COLORS.FAST : speed > 30 ? TRAFFIC_COLORS.MEDIUM : TRAFFIC_COLORS.SLOW;
            return new Style({
              image: new Circle({
                radius: 2.5,
                fill: new Fill({ color: color + 'BB' }),
                stroke: new Stroke({ color: theme === MapTheme.DARK ? 'rgba(255,255,255,0.2)' : 'rgba(0,0,0,0.1)', width: 1 })
              })
            });
          },
          properties: { id: 'traffic' }
        })
      ],
      view: new View({
        center: fromLonLat(saved.center || DEFAULT_CENTER),
        zoom: saved.zoom || DEFAULT_ZOOM,
        smoothExtentConstraint: true,
        smoothResolutionConstraint: true,
        multiWorld: false,
        constrainResolution: true,
        maxZoom: 19,
        minZoom: 2
      }),
      controls: []
    });

    mapInstance.current = map;

    // Traffic Simulation
    const initTraffic = () => {
      const center = fromLonLat(DEFAULT_CENTER) as [number, number];
      const count = isOnline ? 110 : 40; // Fewer vehicles in offline mock
      for (let i = 0; i < count; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = Math.random() * 18000;
        const coords: [number, number] = [center[0] + Math.cos(angle) * radius, center[1] + Math.sin(angle) * radius];
        const feature = new Feature(new Point(coords));
        const speed = 10 + Math.random() * 80;
        feature.set('speed', speed);
        vehiclesRef.current.push({ feature, speed: speed / 22, heading: Math.random() * Math.PI * 2, coords });
      }
      trafficSource.current.addFeatures(vehiclesRef.current.map(v => v.feature));
    };

    const animate = () => {
      vehiclesRef.current.forEach(v => {
        v.coords[0] += Math.cos(v.heading) * v.speed;
        v.coords[1] += Math.sin(v.heading) * v.speed;
        if (Math.random() > 0.98) v.heading += (Math.random() - 0.5) * 0.4;
        v.feature.getGeometry()?.setCoordinates(v.coords);
      });
      animationFrameId.current = requestAnimationFrame(animate);
    };

    initTraffic();
    animate();

    return () => {
      cancelAnimationFrame(animationFrameId.current);
      map.setTarget(undefined);
      mapInstance.current = null;
    };
  }, []);

  // Sync state changes
  useEffect(() => {
    if (!mapInstance.current) return;
    const layers = mapInstance.current.getLayers().getArray();
    layers.forEach(l => {
      const id = l.get('id');
      if (id === 'base') {
        (l as TileLayer<OSM>).setSource(new OSM({ url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT, crossOrigin: 'anonymous' }));
        l.setVisible(!activeLayers.includes(MapLayerType.SATELLITE));
      }
      if (id === 'satellite') l.setVisible(activeLayers.includes(MapLayerType.SATELLITE));
      if (id === 'traffic') l.setVisible(activeLayers.includes(MapLayerType.TRAFFIC));
      if (id === 'route') l.setVisible(activeLayers.includes(MapLayerType.ROUTE));
    });
  }, [theme, activeLayers]);

  const handleDestinationSelect = (dest: Destination) => {
    if (startPoint && !endPoint && startPoint.id !== dest.id) {
      setEndPoint(dest);
      calculateRoute(startPoint, dest);
    } else {
      setStartPoint(dest);
      setEndPoint(null);
      setRouteInfo(null);
      routeSource.current.clear();
      mapInstance.current?.getView().animate({ center: fromLonLat(dest.coords), zoom: 16, duration: 2000 });
    }
  };

  const handleLocate = () => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition((pos) => {
      const myLocation: Destination = {
        id: 'me',
        name: { en: 'My Location', hi: 'मेरा स्थान', kn: 'ನನ್ನ ಸ್ಥಳ', es: 'Mi ubicación' },
        category: { en: 'Personal', hi: 'व्यक्तिगत', kn: 'ವೈಯಕ್ತಿಕ', es: 'Personal' },
        coords: [pos.coords.longitude, pos.coords.latitude],
        description: { en: 'Highly accurate position', hi: 'सटीक स्थिति', kn: 'ನಿಖರವಾದ ಸ್ಥಾನ', es: 'Posición exacta' },
        image: '📍'
      };
      handleDestinationSelect(myLocation);
    }, null, { enableHighAccuracy: true });
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-1000 ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme}
        language={language}
        onLanguageChange={setLanguage}
        onThemeToggle={() => setTheme(t => t === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLocate={handleLocate}
        onOpenLayers={() => setIsLayerPanelOpen(!isLayerPanelOpen)}
        onSuggestionSelect={handleDestinationSelect}
      />

      {/* Online/Offline Status Indicator */}
      <motion.div 
        animate={{ opacity: isOnline ? 0 : 1 }}
        className="fixed top-20 left-1/2 -translate-x-1/2 z-[1001] px-4 py-1.5 rounded-full bg-amber-500 text-black text-[10px] font-black uppercase tracking-widest shadow-xl pointer-events-none"
      >
        Offline Mode - Limited Data
      </motion.div>

      <LayerPanel 
        isOpen={isLayerPanelOpen}
        onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
        theme={theme}
      />

      {/* Atmospheric Widget - Fixed positioning to eliminate Header overlap */}
      <AnimatePresence>
        <motion.div 
          layout
          initial={{ x: -100, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          className={`fixed top-[100px] left-4 lg:left-8 z-[900] p-5 rounded-[32px] shadow-2xl flex flex-col gap-4 min-w-[180px] lg:min-w-[220px] transition-all duration-700 ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}
        >
          <div className="flex justify-between items-start gap-6">
            <div className="flex flex-col">
              <div className="flex items-center gap-2 mb-1">
                <div className={`w-1.5 h-1.5 rounded-full animate-pulse ${theme === MapTheme.DARK ? 'bg-indigo-400' : 'bg-amber-500'}`} />
                <span className={`text-[10px] font-black uppercase tracking-widest opacity-60`}>
                  {theme === MapTheme.DARK ? t.nightMode : t.dayMode}
                </span>
              </div>
              <div className="text-3xl font-black tracking-tighter leading-none">
                {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
            <div className="text-3xl leading-none">
              {theme === MapTheme.DARK ? '🌙' : '☀️'}
            </div>
          </div>
          <div className={`h-px w-full ${theme === MapTheme.DARK ? 'bg-white/10' : 'bg-black/5'}`} />
          <div className="flex justify-between items-center px-1">
            <div>
              <div className="text-[9px] font-black uppercase tracking-widest opacity-40">{t.temp}</div>
              <div className={`text-2xl font-black ${theme === MapTheme.DARK ? 'text-blue-400' : 'text-blue-600'}`}>{weather.temp}°C</div>
            </div>
            <div className="text-right">
              <div className="text-[9px] font-black uppercase tracking-widest opacity-40">{t.weather}</div>
              <div className="text-sm font-extrabold opacity-80">{weather.condition}</div>
            </div>
          </div>
        </motion.div>
      </AnimatePresence>

      <BottomPanel 
        theme={theme} 
        language={language}
        onDestinationSelect={handleDestinationSelect}
        startPoint={startPoint}
        endPoint={endPoint}
        routeInfo={routeInfo}
        onClearRoute={() => { setStartPoint(null); setEndPoint(null); setRouteInfo(null); routeSource.current.clear(); }}
      />

      <div className="fixed bottom-24 right-4 lg:right-8 flex flex-col gap-4 z-[1001]">
         <motion.button 
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.9 }}
          onClick={handleLocate}
          className="w-14 h-14 lg:w-16 lg:h-16 rounded-[24px] bg-blue-600 text-white flex items-center justify-center text-3xl shadow-[0_20px_40px_rgba(37,99,235,0.4)] transition-transform"
        >
          🎯
        </motion.button>
      </div>

      <motion.div 
        animate={{ opacity: theme === MapTheme.DARK ? 0.5 : 0.05 }}
        className="absolute inset-0 pointer-events-none transition-opacity duration-1000 z-[1]" 
        style={{ 
          background: theme === MapTheme.DARK 
            ? 'radial-gradient(circle at center, transparent 30%, #000 180%)'
            : 'radial-gradient(circle at center, transparent 50%, #2563eb 250%)'
        }} 
      />
    </div>
  );
};

export default App;

