                          <div>
                            <div className="text-[10px] font-black uppercase tracking-widest opacity-50 mb-2">{t.distance}</div>
                            <div className="text-3xl lg:text-4xl font-black">{routeInfo.distance}</div>
                          </div>
                          <div>
                            <div className="text-[10px] font-black uppercase tracking-widest opacity-50 mb-2">{t.congestion}</div>
                            <div className={`text-3xl lg:text-4xl font-black capitalize ${
                              routeInfo.congestionLevel === 'heavy' ? 'text-red-500' : 
                              routeInfo.congestionLevel === 'moderate' ? 'text-amber-500' : 'text-emerald-500'
