                          <button className="flex-[2] lg:flex-none px-12 py-4.5 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-[0_15px_30px_rgba(37,99,235,0.4)] transition-all active:scale-95">
                            {t.startNav}
                          </button>
