                    </motion.div>
                  )}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center h-full space-y-8 py-10 lg:py-16">
                  <div className="w-24 h-24 lg:w-32 lg:h-32 rounded-full bg-blue-500/10 flex items-center justify-center text-blue-500 text-5xl lg:text-6xl animate-pulse">🛰️</div>
                  <div className="text-center max-w-xl px-6">
                    <h4 className={`font-black text-3xl lg:text-4xl mb-4 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Real-Time Analysis</h4>
                    <p className="text-base lg:text-lg text-slate-500 font-bold leading-relaxed opacity-80 italic">"Global positioning system is synced. Map tiles are currently being cached locally for high-performance offline access. Seamless navigation is guaranteed."</p>
                  </div>
                </div>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
