import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, OfflineRegion } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, TRAFFIC_COLORS, TRANSLATIONS } from './constants';

interface Vehicle {
  feature: Feature<Point>;
  speed: number;
  heading: number;
  coords: [number, number];
}

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const trafficSource = useRef<VectorSource>(new VectorSource());
  const routeSource = useRef<VectorSource>(new VectorSource());
  const vehiclesRef = useRef<Vehicle[]>([]);
  const animationFrameId = useRef<number>(0);

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET, MapLayerType.TRAFFIC, MapLayerType.ROUTE]);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [weather, setWeather] = useState({ temp: 24, condition: 'Clear' });
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [offlineRegions, setOfflineRegions] = useState<OfflineRegion[]>([]);

  const [startPoint, setStartPoint] = useState<Destination | null>(null);
  const [endPoint, setEndPoint] = useState<Destination | null>(null);
  const [routeInfo, setRouteInfo] = useState<RouteInfo | null>(null);

  const t = TRANSLATIONS[language];

  // Logic: Handle Connectivity and Caching
  useEffect(() => {
    const handleStatus = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatus);
    window.addEventListener('offline', handleStatus);

    // Load saved data
    const savedRegions = localStorage.getItem('disha_offline_regions');
    if (savedRegions) setOfflineRegions(JSON.parse(savedRegions));

    return () => {
      window.removeEventListener('online', handleStatus);
      window.removeEventListener('offline', handleStatus);
    };
  }, []);

  const saveRegion = useCallback(() => {
    if (!mapInstance.current) return;
    const view = mapInstance.current.getView();
    const center = toLonLat(view.getCenter() as [number, number]);
    const zoom = view.getZoom() || 13;

    const newRegion: OfflineRegion = {
      id: Date.now().toString(),
      name: `Region ${offlineRegions.length + 1}`,
      center: center as [number, number],
      zoom,
      date: new Date().toLocaleDateString(),
      size: (Math.random() * 5 + 2).toFixed(1) + ' MB'
    };

    const updated = [...offlineRegions, newRegion];
    setOfflineRegions(updated);
    localStorage.setItem('disha_offline_regions', JSON.stringify(updated));

    // Visual feedback
    if (navigator.vibrate) navigator.vibrate(50);
  }, [offlineRegions]);

  const deleteRegion = (id: string) => {
    const updated = offlineRegions.filter(r => r.id !== id);
    setOfflineRegions(updated);
    localStorage.setItem('disha_offline_regions', JSON.stringify(updated));
  };

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  // Enhanced Pathfinding
  const calculateRoute = (start: Destination, end: Destination) => {
    if (!mapInstance.current) return;
    routeSource.current.clear();

    const startCoords = fromLonLat(start.coords) as [number, number];
    const endCoords = fromLonLat(end.coords) as [number, number];

    const path: [number, number][] = [startCoords];
    const segments = 15; 

    for (let i = 1; i < segments; i++) {
      const p = i / segments;
      const noise = (Math.random() - 0.5) * 600;
      let nextX = startCoords[0] + (endCoords[0] - startCoords[0]) * p + (i % 2 === 0 ? noise : 0);
      let nextY = startCoords[1] + (endCoords[1] - startCoords[1]) * p + (i % 2 !== 0 ? noise : 0);
      path.push([nextX, nextY]);
    }

    path.push(endCoords);
    const lineFeature = new Feature(new LineString(path));
    routeSource.current.addFeature(lineFeature);

    const rawDist = Math.sqrt(Math.pow(end.coords[0] - start.coords[0], 2) + Math.pow(end.coords[1] - start.coords[1], 2)) * 111.3;
    const actualDist = rawDist * 1.38;
    const distText = actualDist.toFixed(1);

    const delay = Math.floor(Math.random() * 12);
    const baseTime = parseFloat(distText) * 2.3;
    const finalTime = (baseTime + delay).toFixed(0);

    setRouteInfo({
      distance: `${distText} km`,
      duration: `${finalTime} min`,
      trafficDelay: `${delay} min delay`,
      congestionLevel: delay > 8 ? 'heavy' : delay > 3 ? 'moderate' : 'low'
    });

    mapInstance.current.getView().fit(lineFeature.getGeometry()?.getExtent()!, { 
      padding: [180, 80, 180, 80], 
      duration: 2000,
      easing: (t) => t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t 
    });
  };

  // Map Initialization
  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const savedState = JSON.parse(localStorage.getItem('disha_map_state') || '{}');

    const map = new Map({
      target: mapRef.current,
      layers: [
        new TileLayer({
          source: new OSM({ 
            url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT,
            crossOrigin: 'anonymous'
          }),
          zIndex: 0,
          properties: { id: 'base' }
        }),
        new TileLayer({
          source: new OSM({ url: MAP_SOURCES.SATELLITE, crossOrigin: 'anonymous' }),
          zIndex: 1,
          visible: activeLayers.includes(MapLayerType.SATELLITE),
          properties: { id: 'satellite' }
        }),
        new VectorLayer({
          source: routeSource.current,
          zIndex: 5,
          style: new Style({
            stroke: new Stroke({ color: '#2563eb', width: 8, lineCap: 'round', lineJoin: 'round' })
          }),
          properties: { id: 'route' }
        }),
        new VectorLayer({
          source: trafficSource.current,
          zIndex: 10,
          style: (feature) => {
            const speed = feature.get('speed') || 0;
            const color = speed > 60 ? TRAFFIC_COLORS.FAST : speed > 30 ? TRAFFIC_COLORS.MEDIUM : TRAFFIC_COLORS.SLOW;
            return new Style({
              image: new Circle({
                radius: 2.2,
                fill: new Fill({ color: color + 'CC' }),
                stroke: new Stroke({ color: theme === MapTheme.DARK ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.05)', width: 1 })
              })
            });
          },
          properties: { id: 'traffic' }
        })
      ],
      view: new View({
        center: fromLonLat(savedState.center || DEFAULT_CENTER),
        zoom: savedState.zoom || DEFAULT_ZOOM,
        smoothExtentConstraint: true,
        smoothResolutionConstraint: true,
        multiWorld: false,
        constrainResolution: true,
        maxZoom: 19,
        minZoom: 2
      }),
      controls: []
    });

    mapInstance.current = map;

    const initTraffic = () => {
      const center = fromLonLat(DEFAULT_CENTER) as [number, number];
      const count = isOnline ? 100 : 30;
      for (let i = 0; i < count; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = Math.random() * 15000;
        const coords: [number, number] = [center[0] + Math.cos(angle) * radius, center[1] + Math.sin(angle) * radius];
        const feature = new Feature(new Point(coords));
        const speed = 20 + Math.random() * 80;
        feature.set('speed', speed);
        vehiclesRef.current.push({ feature, speed: speed / 25, heading: Math.random() * Math.PI * 2, coords });
      }
      trafficSource.current.addFeatures(vehiclesRef.current.map(v => v.feature));
    };

    const animate = () => {
      vehiclesRef.current.forEach(v => {
        v.coords[0] += Math.cos(v.heading) * v.speed;
        v.coords[1] += Math.sin(v.heading) * v.speed;
        if (Math.random() > 0.98) v.heading += (Math.random() - 0.5) * 0.4;
        v.feature.getGeometry()?.setCoordinates(v.coords);
      });
      animationFrameId.current = requestAnimationFrame(animate);
    };

    initTraffic();
    animate();

    return () => {
      cancelAnimationFrame(animationFrameId.current);
      map.setTarget(undefined);
      mapInstance.current = null;
    };
  }, []);

  useEffect(() => {
    if (!mapInstance.current) return;
    const layers = mapInstance.current.getLayers().getArray();
    layers.forEach(l => {
      const id = l.get('id');
      if (id === 'base') {
        (l as TileLayer<OSM>).setSource(new OSM({ url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT, crossOrigin: 'anonymous' }));
        l.setVisible(!activeLayers.includes(MapLayerType.SATELLITE));
      }
      if (id === 'satellite') l.setVisible(activeLayers.includes(MapLayerType.SATELLITE));
      if (id === 'traffic') l.setVisible(activeLayers.includes(MapLayerType.TRAFFIC));
      if (id === 'route') l.setVisible(activeLayers.includes(MapLayerType.ROUTE));
    });
  }, [theme, activeLayers]);

  const handleDestinationSelect = (dest: Destination) => {
    if (startPoint && !endPoint && startPoint.id !== dest.id) {
      setEndPoint(dest);
      calculateRoute(startPoint, dest);
    } else {
      setStartPoint(dest);
      setEndPoint(null);
      setRouteInfo(null);
      routeSource.current.clear();
      mapInstance.current?.getView().animate({ center: fromLonLat(dest.coords), zoom: 16, duration: 2000 });
    }
  };

  const handleLocate = () => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition((pos) => {
      const myLocation: Destination = {
        id: 'me',
        name: { en: 'My Location', hi: 'मेरा स्थान', kn: 'ನನ್ನ ಸ್ಥಳ', es: 'Mi ubicación' },
        category: { en: 'Personal', hi: 'व्यक्तिगत', kn: 'ವೈಯಕ್ತಿಕ', es: 'Personal' },
        coords: [pos.coords.longitude, pos.coords.latitude],
        description: { en: 'Pinpoint accuracy', hi: 'सटीक स्थिति', kn: 'ನಿಖರವಾದ ಸ್ಥಾನ', es: 'Posición exacta' },
        image: '📍'
      };
      handleDestinationSelect(myLocation);
    }, null, { enableHighAccuracy: true });
  };

  const handleRegionClick = (region: OfflineRegion) => {
    mapInstance.current?.getView().animate({ center: fromLonLat(region.center), zoom: region.zoom, duration: 1500 });
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-1000 ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme}
        language={language}
        onLanguageChange={setLanguage}
        onThemeToggle={() => setTheme(t => t === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLocate={handleLocate}
        onOpenLayers={() => setIsLayerPanelOpen(!isLayerPanelOpen)}
        onSuggestionSelect={handleDestinationSelect}
      />

      <motion.div 
        animate={{ opacity: isOnline ? 0 : 1, y: isOnline ? -20 : 0 }}
        className="fixed top-20 left-1/2 -translate-x-1/2 z-[1001] px-5 py-2 rounded-full bg-red-600 text-white text-[10px] font-black uppercase tracking-[0.2em] shadow-2xl pointer-events-none flex items-center gap-2"
      >
        <span className="w-1.5 h-1.5 bg-white rounded-full animate-ping" />
        Offline: Local Discovery Active
      </motion.div>

      <LayerPanel 
        isOpen={isLayerPanelOpen}
        onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
        theme={theme}
      />

      {/* Atmospheric Widget - Mobile Responsive Fix */}
      <AnimatePresence>
        <motion.div 
          layout
          initial={{ x: -100, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          className={`fixed top-[110px] left-4 lg:left-8 z-[900] p-4 lg:p-5 rounded-[32px] shadow-2xl flex flex-col gap-3 min-w-[170px] lg:min-w-[220px] transition-all duration-700 ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}
        >
          <div className="flex justify-between items-start gap-4">
            <div className="flex flex-col">
              <div className="flex items-center gap-2 mb-1">
                <div className={`w-1.5 h-1.5 rounded-full animate-pulse ${theme === MapTheme.DARK ? 'bg-blue-400' : 'bg-blue-600'}`} />
                <span className={`text-[9px] font-black uppercase tracking-widest opacity-60`}>
                  {weather.condition}
                </span>
              </div>
              <div className="text-2xl lg:text-3xl font-black tracking-tighter leading-none">
                {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
            <div className="text-2xl lg:text-3xl">
              {theme === MapTheme.DARK ? '🌑' : '☀️'}
            </div>
          </div>
          <div className={`h-px w-full ${theme === MapTheme.DARK ? 'bg-white/10' : 'bg-black/5'}`} />
          <div className="flex justify-between items-center px-1">
            <div>
              <div className="text-[8px] font-black uppercase tracking-widest opacity-40">Local</div>
              <div className={`text-xl font-black ${theme === MapTheme.DARK ? 'text-blue-400' : 'text-blue-600'}`}>{weather.temp}°</div>
            </div>
            <button 
              onClick={saveRegion}
              className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${theme === MapTheme.DARK ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/30' : 'bg-blue-50 text-blue-600'}`}
            >
              Cache Extent
            </button>
          </div>
        </motion.div>
      </AnimatePresence>

      <BottomPanel 
        theme={theme} 
        language={language}
        onDestinationSelect={handleDestinationSelect}
        startPoint={startPoint}
        endPoint={endPoint}
        routeInfo={routeInfo}
        onClearRoute={() => { setStartPoint(null); setEndPoint(null); setRouteInfo(null); routeSource.current.clear(); }}
        offlineRegions={offlineRegions}
        onRegionClick={handleRegionClick}
        onRegionDelete={deleteRegion}
      />

      <div className="fixed bottom-24 right-4 lg:right-8 flex flex-col gap-4 z-[1001]">
         <motion.button 
          whileHover={{ scale: 1.1, rotate: 5 }}
          whileTap={{ scale: 0.9 }}
          onClick={handleLocate}
          className="w-14 h-14 lg:w-16 lg:h-16 rounded-[24px] bg-blue-600 text-white flex items-center justify-center text-2xl lg:text-3xl shadow-[0_20px_40px_rgba(37,99,235,0.4)] transition-transform"
        >
          📍
        </motion.button>
      </div>

      <motion.div 
        animate={{ opacity: theme === MapTheme.DARK ? 0.4 : 0.05 }}
        className="absolute inset-0 pointer-events-none transition-opacity duration-1000 z-[1]" 
        style={{ 
          background: theme === MapTheme.DARK 
            ? 'radial-gradient(circle at center, transparent 30%, #000 180%)'
            : 'radial-gradient(circle at center, transparent 50%, #2563eb 250%)'
        }} 
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
}

const LogoIcon = () => (
  <svg width="28" height="28" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
    <path d="M12 8V16" stroke="white" strokeWidth="2" strokeLinecap="round"/>
    <path d="M8 12H16" stroke="white" strokeWidth="2" strokeLinecap="round"/>
    <circle cx="12" cy="12" r="2" fill="white"/>
  </svg>
);

const SearchIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
);

const GlobeIcon = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="2" y1="12" x2="22" y2="12"></line><path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"></path></svg>
);

export const Header: React.FC<HeaderProps> = ({ 
  theme, 
  language,
  onThemeToggle, 
  onLanguageChange,
  onLocate, 
  onOpenLayers,
  onSuggestionSelect 
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<Destination[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const [isLangOpen, setIsLangOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (!query.trim()) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(() => {
      const q = query.toLowerCase();
      const filtered = POPULAR_DESTINATIONS.filter(dest => 
        dest.name[language].toLowerCase().includes(q) ||
        dest.category[language].toLowerCase().includes(q)
      ).slice(0, 6);
      setSuggestions(filtered);
    }, 150);

    return () => clearTimeout(timer);
  }, [query, language]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsFocused(false);
        setIsLangOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSelect = (dest: Destination) => {
    setQuery(dest.name[language]);
    setSuggestions([]);
    setIsFocused(false);
    onSuggestionSelect(dest);
  };

  return (
    <motion.header 
      initial={{ y: -100, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[1000] p-3 lg:p-4 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-start gap-2 lg:gap-4 pointer-events-auto">
        <motion.div 
          layout
          className={`flex items-center gap-2 lg:gap-3 px-4 lg:px-6 py-3 rounded-2xl shadow-2xl transition-all duration-500 h-[52px] lg:h-[56px] ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900'}`}
        >
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-xl shrink-0">
            <LogoIcon />
          </div>
          <span className="font-extrabold text-lg lg:text-xl tracking-tighter hidden sm:block whitespace-nowrap">Disha Pro</span>
        </motion.div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-4 lg:px-5 py-3 rounded-2xl shadow-2xl transition-all duration-500 group h-[52px] lg:h-[56px] ${
            theme === MapTheme.DARK 
              ? `glass ${isFocused ? 'bg-slate-800 ring-2 ring-blue-500/50' : 'hover:bg-slate-800/40'}` 
              : `glass-light ${isFocused ? 'bg-white ring-2 ring-blue-400/30' : 'hover:bg-white/80'}`
          }`}>
            <span className={`mr-3 lg:mr-4 transition-colors shrink-0 ${isFocused ? 'text-blue-500' : 'text-slate-400'}`}>
              <SearchIcon />
            </span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onChange={(e) => setQuery(e.target.value)}
              placeholder={t.searchPlaceholder}
              className="bg-transparent border-none outline-none w-full text-sm lg:text-base font-bold placeholder:text-slate-500/60 transition-colors"
              style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
            />
          </div>

          <AnimatePresence>
            {isFocused && (
              <motion.div
                initial={{ opacity: 0, y: 12, scale: 0.98 }}
                animate={{ opacity: 1, y: 8, scale: 1 }}
                exit={{ opacity: 0, y: 12, scale: 0.98 }}
                className={`absolute top-full left-0 right-0 rounded-3xl shadow-2xl overflow-hidden border transition-colors duration-500 ${
                  theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'
                }`}
              >
                <div className="max-h-[60vh] lg:max-h-[450px] overflow-y-auto py-3 custom-scrollbar">
                  {suggestions.length > 0 ? (
                    <div>
                      <div className="text-[10px] font-black uppercase tracking-[0.25em] text-blue-500/80 mb-3 px-6">{t.topResults}</div>
                      {suggestions.map((dest) => (
                        <div
                          key={dest.id}
                          onClick={() => handleSelect(dest)}
                          className={`px-6 py-4 flex items-center gap-5 cursor-pointer transition-all ${
                            theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-blue-50/70'
                          }`}
                        >
                          <div className="text-3xl w-12 h-12 flex items-center justify-center rounded-2xl bg-slate-500/10 shrink-0">
                            {dest.image}
                          </div>
                          <div className="flex-1 overflow-hidden">
                            <div className={`font-black text-sm lg:text-base truncate ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
                              {dest.name[language]}
                            </div>
                            <div className={`text-[10px] lg:text-xs opacity-50 font-bold truncate ${theme === MapTheme.DARK ? 'text-blue-400' : 'text-blue-600'}`}>
                              {dest.category[language]} • Real-Time Data Available
                            </div>
                          </div>
                          <div className="text-[10px] font-black opacity-30 shrink-0">{dest.rating}★</div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div>
                      <div className="text-[10px] font-black uppercase tracking-[0.25em] text-blue-500/80 mb-3 px-6">{t.trending}</div>
                      <div className="space-y-1">
                        {POPULAR_DESTINATIONS.slice(0, 4).map(dest => (
                          <div key={dest.id} onClick={() => handleSelect(dest)} className={`px-6 py-3.5 flex items-center gap-4 cursor-pointer transition-colors ${theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-black/5'}`}>
                            <span className="text-2xl w-10 h-10 flex items-center justify-center shrink-0">{dest.image}</span>
                            <div className="flex flex-col overflow-hidden">
                              <span className="text-sm font-black truncate">{dest.name[language]}</span>
                              <span className="text-[10px] opacity-40 uppercase font-black truncate">{dest.category[language]}</span>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex gap-2">
          <button 
            onClick={() => setIsLangOpen(!isLangOpen)}
            className={`w-[52px] h-[52px] lg:w-[56px] lg:h-[56px] rounded-2xl flex items-center justify-center shadow-2xl transition-all hover:scale-105 active:scale-95 ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}
          >
            <GlobeIcon />
          </button>
          <button 
            onClick={onThemeToggle}
