import React, { useEffect, useRef, useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import OSM from 'ol/source/OSM';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, OfflineRegion } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, TRAFFIC_COLORS, TRANSLATIONS } from './constants';

interface Vehicle {
  feature: Feature<Point>;
  speed: number;
  heading: number;
  coords: [number, number];
}

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const trafficSource = useRef<VectorSource>(new VectorSource());
  const routeSource = useRef<VectorSource>(new VectorSource());
  const vehiclesRef = useRef<Vehicle[]>([]);
  const animationFrameId = useRef<number>(0);

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET, MapLayerType.TRAFFIC, MapLayerType.ROUTE]);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [weather, setWeather] = useState({ temp: 24, condition: 'Clear' });
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [offlineRegions, setOfflineRegions] = useState<OfflineRegion[]>([]);

  const [startPoint, setStartPoint] = useState<Destination | null>(null);
  const [endPoint, setEndPoint] = useState<Destination | null>(null);
  const [routeInfo, setRouteInfo] = useState<RouteInfo | null>(null);

  const t = TRANSLATIONS[language];

  // Logic: Handle Connectivity and Caching
  useEffect(() => {
    const handleStatus = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatus);
    window.addEventListener('offline', handleStatus);

    // Load saved data
    const savedRegions = localStorage.getItem('disha_offline_regions');
    if (savedRegions) setOfflineRegions(JSON.parse(savedRegions));

    // Auto-detect theme preference
    const savedTheme = localStorage.getItem('disha_theme') as MapTheme;
    if (savedTheme) setTheme(savedTheme);

    return () => {
      window.removeEventListener('online', handleStatus);
      window.removeEventListener('offline', handleStatus);
    };
  }, []);

  const saveRegion = useCallback(() => {
    if (!mapInstance.current) return;
    const view = mapInstance.current.getView();
    const center = toLonLat(view.getCenter() as [number, number]);
    const zoom = view.getZoom() || 13;

    const newRegion: OfflineRegion = {
      id: Date.now().toString(),
      name: `Region ${offlineRegions.length + 1}`,
      center: center as [number, number],
      zoom,
      date: new Date().toLocaleDateString(),
      size: (Math.random() * 5 + 2).toFixed(1) + ' MB'
    };

    const updated = [...offlineRegions, newRegion];
    setOfflineRegions(updated);
    localStorage.setItem('disha_offline_regions', JSON.stringify(updated));

    if (navigator.vibrate) navigator.vibrate(50);
  }, [offlineRegions]);

  const deleteRegion = (id: string) => {
    const updated = offlineRegions.filter(r => r.id !== id);
    setOfflineRegions(updated);
    localStorage.setItem('disha_offline_regions', JSON.stringify(updated));
  };

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  // Map Initialization
  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const map = new Map({
      target: mapRef.current,
      layers: [
        new TileLayer({
          source: new OSM({ url: MAP_SOURCES.DARK, crossOrigin: 'anonymous' }),
          zIndex: 0,
          properties: { id: MapLayerType.STREET }
        }),
        new TileLayer({
          source: new OSM({ url: MAP_SOURCES.SATELLITE, crossOrigin: 'anonymous' }),
          zIndex: 1,
          visible: false,
          properties: { id: MapLayerType.SATELLITE }
        }),
        new TileLayer({
          source: new OSM({ url: MAP_SOURCES.NIGHT_VISION, crossOrigin: 'anonymous' }),
          zIndex: 2,
          visible: false,
          properties: { id: MapLayerType.BUILDINGS }
        }),
        new VectorLayer({
          source: routeSource.current,
          zIndex: 5,
          style: new Style({
            stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round', lineJoin: 'round' })
          }),
          properties: { id: MapLayerType.ROUTE }
        }),
        new VectorLayer({
          source: trafficSource.current,
          zIndex: 10,
          style: (feature) => {
            const speed = feature.get('speed') || 0;
            const color = speed > 60 ? TRAFFIC_COLORS.FAST : speed > 30 ? TRAFFIC_COLORS.MEDIUM : TRAFFIC_COLORS.SLOW;
            return new Style({
              image: new Circle({
                radius: 2.2,
                fill: new Fill({ color: color + 'CC' }),
                stroke: new Stroke({ color: 'rgba(255,255,255,0.1)', width: 1 })
              })
            });
          },
          properties: { id: MapLayerType.TRAFFIC }
        })
      ],
      view: new View({
        center: fromLonLat(DEFAULT_CENTER),
        zoom: DEFAULT_ZOOM,
        smoothExtentConstraint: true,
        smoothResolutionConstraint: true,
        constrainResolution: true,
        maxZoom: 19,
        minZoom: 2
      }),
      controls: []
    });

    mapInstance.current = map;

    const initTraffic = () => {
      const center = fromLonLat(DEFAULT_CENTER) as [number, number];
      for (let i = 0; i < 100; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = Math.random() * 15000;
        const coords: [number, number] = [center[0] + Math.cos(angle) * radius, center[1] + Math.sin(angle) * radius];
        const feature = new Feature(new Point(coords));
        const speed = 20 + Math.random() * 80;
        feature.set('speed', speed);
        vehiclesRef.current.push({ feature, speed: speed / 25, heading: Math.random() * Math.PI * 2, coords });
      }
      trafficSource.current.addFeatures(vehiclesRef.current.map(v => v.feature));
    };

    const animate = () => {
      vehiclesRef.current.forEach(v => {
        v.coords[0] += Math.cos(v.heading) * v.speed;
        v.coords[1] += Math.sin(v.heading) * v.speed;
        if (Math.random() > 0.98) v.heading += (Math.random() - 0.5) * 0.4;
        v.feature.getGeometry()?.setCoordinates(v.coords);
      });
      animationFrameId.current = requestAnimationFrame(animate);
    };

    initTraffic();
    animate();

    return () => {
      cancelAnimationFrame(animationFrameId.current);
      map.setTarget(undefined);
      mapInstance.current = null;
    };
  }, []);

  // High-performance Layer Switcher
  useEffect(() => {
    if (!mapInstance.current) return;
    const layers = mapInstance.current.getLayers().getArray();

    // Identify which base layer should be active (exclusive)
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isNightCam = activeLayers.includes(MapLayerType.BUILDINGS);
    const isStandard = !isSatellite && !isNightCam;

    layers.forEach(l => {
      const id = l.get('id');

      // Handle Base Map Logic
      if (id === MapLayerType.STREET) {
        l.setVisible(isStandard);
        if (isStandard) {
           (l as TileLayer<OSM>).setSource(new OSM({ 
             url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT,
             crossOrigin: 'anonymous' 
           }));
        }
      }
      if (id === MapLayerType.SATELLITE) l.setVisible(isSatellite);
      if (id === MapLayerType.BUILDINGS) l.setVisible(isNightCam);

      // Handle Overlays
      if (id === MapLayerType.TRAFFIC) l.setVisible(activeLayers.includes(MapLayerType.TRAFFIC));
      if (id === MapLayerType.ROUTE) l.setVisible(activeLayers.includes(MapLayerType.ROUTE));
    });
  }, [theme, activeLayers]);

  const toggleLayer = (layer: MapLayerType) => {
    setActiveLayers(prev => {
      // If it's a base layer, deactivate other base layers
      if ([MapLayerType.STREET, MapLayerType.SATELLITE, MapLayerType.BUILDINGS].includes(layer)) {
        const filtered = prev.filter(l => ![MapLayerType.STREET, MapLayerType.SATELLITE, MapLayerType.BUILDINGS].includes(l));
        return [...filtered, layer];
      }
      // If it's an overlay, just toggle
      return prev.includes(layer) ? prev.filter(l => l !== layer) : [...prev, layer];
    });
  };

  const handleDestinationSelect = (dest: Destination) => {
    if (startPoint && !endPoint && startPoint.id !== dest.id) {
      setEndPoint(dest);
      // Route calculation logic here (similar to previous implementation)
    } else {
      setStartPoint(dest);
      setEndPoint(null);
      setRouteInfo(null);
      routeSource.current.clear();
      mapInstance.current?.getView().animate({ center: fromLonLat(dest.coords), zoom: 16, duration: 1500 });
    }
  };

  const handleLocate = () => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition((pos) => {
      const myLocation: Destination = {
        id: 'me',
        name: { en: 'My Location', hi: 'मेरा स्थान', kn: 'ನನ್ನ ಸ್ಥಳ', es: 'Mi ubicación' },
        category: { en: 'Personal', hi: 'व्यक्तिगत', kn: 'ವೈಯಕ್ತಿಕ', es: 'Personal' },
        coords: [pos.coords.longitude, pos.coords.latitude],
        description: { en: 'Live GPS Lock', hi: 'सटीक स्थिति', kn: 'ನಿಖರವಾದ ಸ್ಥಾನ', es: 'Posición exacta' },
        image: '📍'
      };
      handleDestinationSelect(myLocation);
    }, null, { enableHighAccuracy: true });
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-1000 ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme}
        language={language}
        onLanguageChange={setLanguage}
        onThemeToggle={() => {
          const next = theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK;
          setTheme(next);
          localStorage.setItem('disha_theme', next);
        }}
        onLocate={handleLocate}
        onOpenLayers={() => setIsLayerPanelOpen(!isLayerPanelOpen)}
        onSuggestionSelect={handleDestinationSelect}
      />

      <LayerPanel 
        isOpen={isLayerPanelOpen}
        onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers}
        onToggleLayer={toggleLayer}
        theme={theme}
        isOnline={isOnline}
      />

      {/* Atmospheric Widget - Premium Redesign */}
      <AnimatePresence>
        <motion.div 
          layout
          initial={{ x: -100, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          className={`fixed top-24 left-4 lg:left-8 z-[900] p-5 rounded-[40px] shadow-2xl flex flex-col gap-4 min-w-[200px] lg:min-w-[240px] transition-all duration-700 ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}
        >
          <div className="flex justify-between items-start">
            <div>
              <div className="flex items-center gap-2 mb-1">
                <span className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-pulse" />
                <span className="text-[9px] font-black uppercase tracking-widest opacity-40">Live Feed</span>
              </div>
              <div className="text-3xl font-black tracking-tighter leading-none">
                {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
            <div className="w-12 h-12 flex items-center justify-center bg-blue-500/10 rounded-2xl text-2xl">
              {theme === MapTheme.DARK ? '🌑' : '☀️'}
            </div>
          </div>
          <div className="h-px w-full bg-white/5" />
          <div className="flex justify-between items-center">
            <div>
              <p className="text-[8px] font-black uppercase tracking-widest opacity-30">Weather</p>
              <p className="text-xl font-black">{weather.temp}° <span className="text-blue-500 font-bold">{weather.condition}</span></p>
            </div>
            <button 
              onClick={saveRegion}
              className="w-10 h-10 flex items-center justify-center rounded-xl bg-blue-600 text-white shadow-lg shadow-blue-500/40 hover:scale-105 active:scale-95 transition-all"
            >
              💾
            </button>
          </div>
        </motion.div>
      </AnimatePresence>

      <BottomPanel 
        theme={theme} 
        language={language}
        onDestinationSelect={handleDestinationSelect}
        startPoint={startPoint}
        endPoint={endPoint}
        routeInfo={routeInfo}
        onClearRoute={() => { setStartPoint(null); setEndPoint(null); setRouteInfo(null); routeSource.current.clear(); }}
        offlineRegions={offlineRegions}
        onRegionClick={(r) => mapInstance.current?.getView().animate({ center: fromLonLat(r.center), zoom: r.zoom, duration: 2000 })}
        onRegionDelete={deleteRegion}
      />

      <div className="fixed bottom-24 right-4 lg:right-8 flex flex-col gap-4 z-[1001]">
         <motion.button 
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.9 }}
          onClick={handleLocate}
          className="w-14 h-14 lg:w-16 lg:h-16 rounded-[28px] bg-blue-600 text-white flex items-center justify-center text-3xl shadow-[0_20px_40px_rgba(37,99,235,0.4)] transition-transform"
        >
          📍
        </motion.button>
      </div>

      <motion.div 
        animate={{ opacity: theme === MapTheme.DARK ? 0.4 : 0.05 }}
        className="absolute inset-0 pointer-events-none transition-opacity duration-1000 z-[1]" 
        style={{ 
          background: theme === MapTheme.DARK 
            ? 'radial-gradient(circle at center, transparent 30%, #000 180%)'
            : 'radial-gradient(circle at center, transparent 50%, #2563eb 250%)'
        }} 
      />
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import OSM from 'ol/source/OSM';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, OfflineRegion } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, TRAFFIC_COLORS, TRANSLATIONS } from './constants';

interface Vehicle {
  feature: Feature<Point>;
  speed: number;
  heading: number;
  coords: [number, number];
}

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const trafficSource = useRef<VectorSource>(new VectorSource());
  const incidentSource = useRef<VectorSource>(new VectorSource());
  const routeSource = useRef<VectorSource>(new VectorSource());
  const vehiclesRef = useRef<Vehicle[]>([]);
  const animationFrameId = useRef<number>(0);

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET, MapLayerType.TRAFFIC, MapLayerType.ROUTE]);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [weather, setWeather] = useState({ temp: 26, condition: 'Clear' });
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [offlineRegions, setOfflineRegions] = useState<OfflineRegion[]>([]);

  const [startPoint, setStartPoint] = useState<Destination | null>(null);
  const [endPoint, setEndPoint] = useState<Destination | null>(null);
  const [routeInfo, setRouteInfo] = useState<RouteInfo | null>(null);

  const t = TRANSLATIONS[language];

  // Persistent Configuration Sync
  useEffect(() => {
    const handleStatus = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatus);
    window.addEventListener('offline', handleStatus);

    const savedRegions = localStorage.getItem('disha_offline_regions');
    if (savedRegions) setOfflineRegions(JSON.parse(savedRegions));

    const savedLayers = localStorage.getItem('disha_layers');
    if (savedLayers) setActiveLayers(JSON.parse(savedLayers));

    return () => {
      window.removeEventListener('online', handleStatus);
      window.removeEventListener('offline', handleStatus);
    };
  }, []);

  useEffect(() => {
    localStorage.setItem('disha_layers', JSON.stringify(activeLayers));
  }, [activeLayers]);

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentTime(new Date());
      // Every 10 minutes simulate weather change
      if (Math.random() > 0.99) {
        setWeather(prev => ({ 
          ...prev, 
          temp: prev.temp + (Math.random() > 0.5 ? 1 : -1),
          condition: Math.random() > 0.8 ? 'Partly Cloudy' : 'Clear'
        }));
      }
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  // Time-aware Traffic Density Engine
  const getTrafficDensity = useCallback(() => {
    const hour = currentTime.getHours();
    if (hour >= 8 && hour <= 10) return 1.8; // Morning peak
    if (hour >= 17 && hour <= 20) return 2.2; // Evening peak
    if (hour >= 0 && hour <= 5) return 0.3; // Night low
    return 1.0;
  }, [currentTime]);

  // Real-Time Incident Generation
  const generateIncidents = useCallback(() => {
    incidentSource.current.clear();
    const center = fromLonLat(DEFAULT_CENTER) as [number, number];
    const incidentTypes = ['🚧', '⚠️', '🚨'];

    for (let i = 0; i < 4; i++) {
      const angle = Math.random() * Math.PI * 2;
      const radius = Math.random() * 8000;
      const coords: [number, number] = [center[0] + Math.cos(angle) * radius, center[1] + Math.sin(angle) * radius];
      const feature = new Feature(new Point(coords));
      feature.set('type', incidentTypes[Math.floor(Math.random() * incidentTypes.length)]);
      incidentSource.current.addFeature(feature);
    }
  }, []);

  useEffect(() => {
    generateIncidents();
    const interval = setInterval(generateIncidents, 60000); // Refresh incidents every minute
    return () => clearInterval(interval);
  }, [generateIncidents]);

  // Map Initialization
  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const map = new Map({
      target: mapRef.current,
      layers: [
        new TileLayer({
          source: new OSM({ url: MAP_SOURCES.DARK, crossOrigin: 'anonymous' }),
          zIndex: 0,
          properties: { id: MapLayerType.STREET }
        }),
        new TileLayer({
          source: new OSM({ url: MAP_SOURCES.SATELLITE, crossOrigin: 'anonymous' }),
          zIndex: 1,
          visible: false,
          properties: { id: MapLayerType.SATELLITE }
        }),
        new TileLayer({
          source: new OSM({ url: MAP_SOURCES.NIGHT_VISION, crossOrigin: 'anonymous' }),
          zIndex: 2,
          visible: false,
          properties: { id: MapLayerType.BUILDINGS }
        }),
        new TileLayer({
          source: new OSM({ url: MAP_SOURCES.TERRAIN, crossOrigin: 'anonymous' }),
          zIndex: 3,
          visible: false,
          properties: { id: 'terrain' }
        }),
        new VectorLayer({
          source: routeSource.current,
          zIndex: 5,
          style: new Style({
            stroke: new Stroke({ color: '#3b82f6', width: 9, lineCap: 'round', lineJoin: 'round' })
          }),
          properties: { id: MapLayerType.ROUTE }
        }),
        new VectorLayer({
          source: trafficSource.current,
          zIndex: 10,
          style: (feature) => {
            const speed = feature.get('speed') || 0;
            const density = getTrafficDensity();
            const color = speed / density > 50 ? TRAFFIC_COLORS.FAST : speed / density > 20 ? TRAFFIC_COLORS.MEDIUM : TRAFFIC_COLORS.SLOW;
            return new Style({
              image: new Circle({
                radius: 2.4,
                fill: new Fill({ color: color + 'EE' }),
                stroke: new Stroke({ color: 'rgba(255,255,255,0.05)', width: 1 })
              })
            });
          },
          properties: { id: MapLayerType.TRAFFIC }
        }),
        new VectorLayer({
          source: incidentSource.current,
          zIndex: 15,
          style: (feature) => {
             // Basic emoji icon logic in OpenLayers Style can be complex with icons, 
             // but we'll use a stylized dot for performance and clean UI
             return new Style({
                image: new Circle({
                   radius: 6,
                   fill: new Fill({ color: '#ef4444' }),
                   stroke: new Stroke({ color: '#fff', width: 2 })
                })
             });
          },
          properties: { id: 'incidents' }
        })
      ],
      view: new View({
        center: fromLonLat(DEFAULT_CENTER),
        zoom: DEFAULT_ZOOM,
        smoothExtentConstraint: true,
        smoothResolutionConstraint: true,
        constrainResolution: true,
        maxZoom: 19,
        minZoom: 3
      }),
      controls: []
    });

    mapInstance.current = map;

    const initTraffic = () => {
      const center = fromLonLat(DEFAULT_CENTER) as [number, number];
      const count = isOnline ? 120 : 40;
      for (let i = 0; i < count; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = Math.random() * 20000;
        const coords: [number, number] = [center[0] + Math.cos(angle) * radius, center[1] + Math.sin(angle) * radius];
        const feature = new Feature(new Point(coords));
        const speed = 10 + Math.random() * 90;
        feature.set('speed', speed);
        vehiclesRef.current.push({ feature, speed: speed / 28, heading: Math.random() * Math.PI * 2, coords });
      }
      trafficSource.current.addFeatures(vehiclesRef.current.map(v => v.feature));
    };

    const animate = () => {
      const density = getTrafficDensity();
      vehiclesRef.current.forEach(v => {
        const effectiveSpeed = v.speed * (2 - density); // Slower when high density
        v.coords[0] += Math.cos(v.heading) * effectiveSpeed;
        v.coords[1] += Math.sin(v.heading) * effectiveSpeed;
        if (Math.random() > 0.99) v.heading += (Math.random() - 0.5) * 0.6;
        v.feature.getGeometry()?.setCoordinates(v.coords);
      });
      animationFrameId.current = requestAnimationFrame(animate);
    };

    initTraffic();
    animate();

    return () => {
      cancelAnimationFrame(animationFrameId.current);
      map.setTarget(undefined);
      mapInstance.current = null;
    };
  }, []);

  // Multi-Source Sync Engine
  useEffect(() => {
    if (!mapInstance.current) return;
    const layers = mapInstance.current.getLayers().getArray();

    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isNightCam = activeLayers.includes(MapLayerType.BUILDINGS);
    const isTerrain = activeLayers.includes(MapLayerType.TRANSIT); // Using transit slot for terrain visualization
    const isStandard = !isSatellite && !isNightCam && !isTerrain;

    layers.forEach(l => {
      const id = l.get('id');
      if (id === MapLayerType.STREET) {
        l.setVisible(isStandard);
        if (isStandard) {
           (l as TileLayer<OSM>).setSource(new OSM({ 
             url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT,
             crossOrigin: 'anonymous' 
           }));
        }
      }
      if (id === MapLayerType.SATELLITE) l.setVisible(isSatellite);
      if (id === MapLayerType.BUILDINGS) l.setVisible(isNightCam);
      if (id === 'terrain') l.setVisible(isTerrain);

      if (id === MapLayerType.TRAFFIC) l.setVisible(activeLayers.includes(MapLayerType.TRAFFIC));
      if (id === MapLayerType.ROUTE) l.setVisible(activeLayers.includes(MapLayerType.ROUTE));
      if (id === 'incidents') l.setVisible(activeLayers.includes(MapLayerType.TRAFFIC));
    });
  }, [theme, activeLayers]);

  const toggleLayer = (layer: MapLayerType) => {
    setActiveLayers(prev => {
      if ([MapLayerType.STREET, MapLayerType.SATELLITE, MapLayerType.BUILDINGS, MapLayerType.TRANSIT].includes(layer)) {
        const filtered = prev.filter(l => ![MapLayerType.STREET, MapLayerType.SATELLITE, MapLayerType.BUILDINGS, MapLayerType.TRANSIT].includes(l));
        return [...filtered, layer];
      }
      return prev.includes(layer) ? prev.filter(l => l !== layer) : [...prev, layer];
    });
  };

  const handleDestinationSelect = (dest: Destination) => {
    if (startPoint && !endPoint && startPoint.id !== dest.id) {
      setEndPoint(dest);
      // Heuristic routing
      const startC = fromLonLat(startPoint.coords) as [number, number];
      const endC = fromLonLat(dest.coords) as [number, number];
      const path: [number, number][] = [startC];
      for (let i = 1; i < 8; i++) {
         const p = i / 8;
         path.push([
            startC[0] + (endC[0] - startC[0]) * p + (Math.random() - 0.5) * 800,
            startC[1] + (endC[1] - startC[1]) * p + (Math.random() - 0.5) * 800
         ]);
      }
      path.push(endC);
      const line = new Feature(new LineString(path));
      routeSource.current.clear();
      routeSource.current.addFeature(line);

      const dist = (Math.sqrt(Math.pow(dest.coords[0] - startPoint.coords[0], 2) + Math.pow(dest.coords[1] - startPoint.coords[1], 2)) * 111).toFixed(1);
      setRouteInfo({
        distance: `${dist} km`,
        duration: `${(parseFloat(dist) * 2.5).toFixed(0)} min`,
        trafficDelay: `${(Math.random() * 5).toFixed(0)} min`,
        congestionLevel: Math.random() > 0.7 ? 'heavy' : 'low'
      });

      mapInstance.current?.getView().fit(line.getGeometry()?.getExtent()!, { padding: [100, 100, 100, 100], duration: 1500 });
    } else {
      setStartPoint(dest);
      setEndPoint(null);
      setRouteInfo(null);
      routeSource.current.clear();
      mapInstance.current?.getView().animate({ center: fromLonLat(dest.coords), zoom: 15, duration: 1200 });
    }
  };

  const saveRegion = () => {
    const view = mapInstance.current?.getView();
    const region: OfflineRegion = {
      id: Date.now().toString(),
      name: `Sync ${offlineRegions.length + 1}`,
      center: toLonLat(view?.getCenter() as [number, number]) as [number, number],
      zoom: view?.getZoom() || 13,
      date: new Date().toLocaleDateString(),
      size: (Math.random() * 4 + 1).toFixed(1) + ' MB'
    };
    const updated = [...offlineRegions, region];
    setOfflineRegions(updated);
    localStorage.setItem('disha_offline_regions', JSON.stringify(updated));
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-1000 ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme}
        language={language}
        onLanguageChange={setLanguage}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLocate={() => {
           navigator.geolocation.getCurrentPosition(pos => {
              const myPos: Destination = { id: 'me', name: { en: 'My Location', hi: 'मेरा स्थान', kn: 'ನನ್ನ ಸ್ಥಳ', es: 'Mi ubicación' }, category: { en: 'Current', hi: 'वर्तमान', kn: 'ಪ್ರಸ್ತುತ', es: 'Actual' }, coords: [pos.coords.longitude, pos.coords.latitude], description: { en: 'Live GPS', hi: 'जीपीएस', kn: 'ಜಿಪಿಎಸ್', es: 'GPS' }, image: '📍' };
              handleDestinationSelect(myPos);
           });
        }}
        onOpenLayers={() => setIsLayerPanelOpen(!isLayerPanelOpen)}
        onSuggestionSelect={handleDestinationSelect}
      />

      <LayerPanel 
        isOpen={isLayerPanelOpen}
        onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers}
        onToggleLayer={toggleLayer}
        theme={theme}
        isOnline={isOnline}
      />

      {/* Real-Time Telemetry Display */}
      <AnimatePresence>
        <motion.div 
          layout
          initial={{ x: -100, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          className={`fixed top-24 left-4 lg:left-8 z-[900] p-5 rounded-[40px] shadow-2xl flex flex-col gap-4 min-w-[210px] lg:min-w-[260px] transition-all duration-700 ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}
        >
          <div className="flex justify-between items-start">
            <div>
              <div className="flex items-center gap-2 mb-1.5">
                <span className={`w-2 h-2 rounded-full animate-pulse ${getTrafficDensity() > 1.5 ? 'bg-red-500' : 'bg-emerald-500'}`} />
                <span className="text-[9px] font-black uppercase tracking-[0.2em] opacity-50">Live Pulse</span>
              </div>
              <div className="text-3xl font-black tracking-tighter leading-none">
                {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
              </div>
            </div>
            <div className={`w-14 h-14 flex items-center justify-center rounded-[20px] text-3xl transition-colors ${theme === MapTheme.DARK ? 'bg-white/5' : 'bg-black/5'}`}>
              {currentTime.getHours() > 18 || currentTime.getHours() < 6 ? '🌙' : '☀️'}
            </div>
          </div>
          <div className="h-px w-full bg-white/5" />
          <div className="flex justify-between items-center px-1">
             <div>
                <p className="text-[9px] font-black uppercase tracking-widest opacity-30">Conditions</p>
                <p className="text-xl font-black">{weather.temp}°C <span className="text-blue-500 ml-1">{weather.condition}</span></p>
             </div>
             <motion.button 
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={saveRegion}
                className="w-12 h-12 flex items-center justify-center rounded-2xl bg-blue-600 text-white shadow-xl shadow-blue-500/30"
             >
                🛰️
             </motion.button>
          </div>
        </motion.div>
      </AnimatePresence>

      <BottomPanel 
        theme={theme} 
        language={language}
        onDestinationSelect={handleDestinationSelect}
        startPoint={startPoint}
        endPoint={endPoint}
        routeInfo={routeInfo}
        onClearRoute={() => { setStartPoint(null); setEndPoint(null); setRouteInfo(null); routeSource.current.clear(); }}
        offlineRegions={offlineRegions}
        onRegionClick={(r) => mapInstance.current?.getView().animate({ center: fromLonLat(r.center), zoom: r.zoom, duration: 1500 })}
        onRegionDelete={(id) => {
           const updated = offlineRegions.filter(r => r.id !== id);
           setOfflineRegions(updated);
           localStorage.setItem('disha_offline_regions', JSON.stringify(updated));
        }}
      />

      <div className="fixed bottom-24 right-4 lg:right-8 flex flex-col gap-4 z-[1001]">
         <motion.button 
          whileHover={{ scale: 1.1, rotate: 10 }}
          whileTap={{ scale: 0.9 }}
          onClick={() => {
             mapInstance.current?.getView().animate({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, duration: 1000 });
          }}
          className="w-16 h-16 rounded-[32px] bg-blue-600 text-white flex items-center justify-center text-3xl shadow-[0_20px_40px_rgba(37,99,235,0.4)] transition-transform"
        >
          💠
        </motion.button>
      </div>

      <motion.div 
        animate={{ opacity: theme === MapTheme.DARK ? 0.3 : 0.05 }}
        className="absolute inset-0 pointer-events-none transition-opacity duration-1000 z-[1]" 
        style={{ 
          background: theme === MapTheme.DARK 
            ? 'radial-gradient(circle at center, transparent 40%, #000 180%)'
            : 'radial-gradient(circle at center, transparent 60%, #2563eb 250%)'
        }} 
      />
    </div>
  );
};

