             <p className="text-[10px] font-black uppercase tracking-widest text-blue-500 mb-2">Cloud-Synced Data</p>
             <p className={`text-[9px] font-bold opacity-30 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Visualization parameters are processed locally for peak efficiency. Your selection is automatically persisted.</p>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

