            setActiveLayers(prev => [...prev.filter(x => ![MapLayerType.STREET, MapLayerType.SATELLITE, MapLayerType.BUILDINGS].includes(x)), l]);
          } else {
            setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l]);
          }
        }}
        theme={theme}
        isOnline={isOnline}
      />

