        theme={theme} 
        language={language}
        onDestinationSelect={handleDestinationSelect}
        startPoint={startPoint}
        endPoint={endPoint}
        routeInfo={routeInfo}
        onClearRoute={() => { setStartPoint(null); setEndPoint(null); setRouteInfo(null); routeSource.current.clear(); }}
        offlineRegions={offlineRegions}
        onRegionClick={(r) => mapInstance.current?.getView().animate({ center: fromLonLat(r.center), zoom: r.zoom, duration: 1500 })}
        onRegionDelete={(id) => {
          const next = offlineRegions.filter(x => x.id !== id);
          setOfflineRegions(next);
          localStorage.setItem('disha_offline_regions', JSON.stringify(next));
        }}
        onTravelModeChange={(mode) => {
          setTravelMode(mode);
          if (startPoint && endPoint) calculateRoute(startPoint, endPoint, mode);
        }}
        selectedPlace={selectedPlace}
        onClosePlace={() => setSelectedPlace(null)}
      />

      {/* Mode Status Widget */}
      <motion.div 
        layout
        className={`fixed top-24 left-6 z-[900] p-4 rounded-[32px] ${theme === MapTheme.DARK ? 'glass' : 'glass-light'} shadow-2xl min-w-[180px]`}
      >
        <div className="flex items-center gap-2 mb-2">
          <span className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-pulse" />
          <span className="text-[9px] font-black uppercase tracking-widest opacity-40">Urban Network</span>
        </div>
        <p className="text-3xl font-black tracking-tighter mb-1">
          {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </p>
        <div className="h-px bg-white/5 my-3" />
        <div className="flex justify-between items-center">
          <span className="text-xl font-bold">{weather.temp}°C</span>
          <span className="text-[10px] font-black text-blue-500 uppercase">{weather.condition}</span>
        </div>
      </motion.div>

      <motion.div 
        animate={{ opacity: theme === MapTheme.DARK ? 0.35 : 0.05 }}
        className="absolute inset-0 pointer-events-none transition-opacity duration-1000 z-[1]" 
        style={{ 
          background: theme === MapTheme.DARK 
            ? 'radial-gradient(circle at center, transparent 40%, #000 180%)'
            : 'radial-gradient(circle at center, transparent 60%, #2563eb 250%)'
        }} 
      />
    </div>
  );
};

export default App;

