    animate();

    return () => cancelAnimationFrame(animationFrameId.current);
  }, [getTrafficDensity]);

  // Sync Layers & Theme
  useEffect(() => {
    if (!mapInstance.current) return;
    const layers = mapInstance.current.getLayers().getArray();
    const isSat = activeLayers.includes(MapLayerType.SATELLITE);

    layers.forEach(l => {
      const id = l.get('id');
      if (id === MapLayerType.STREET) {
        l.setVisible(!isSat);
        if (!isSat) (l as TileLayer<OSM>).setSource(new OSM({ url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT, crossOrigin: 'anonymous' }));
      }
      if (id === MapLayerType.SATELLITE) l.setVisible(isSat);
      if (id === MapLayerType.TRAFFIC) l.setVisible(activeLayers.includes(MapLayerType.TRAFFIC));
      if (id === MapLayerType.ROUTE) l.setVisible(activeLayers.includes(MapLayerType.ROUTE));
    });
  }, [theme, activeLayers]);

  // Toggle 3D Mode Simulation (Rotation + Zoom)
  useEffect(() => {
    if (!mapInstance.current) return;
    const view = mapInstance.current.getView();
    view.animate({
      rotation: is3D ? Math.PI / 4 : 0,
      zoom: is3D ? view.getZoom()! + 1 : view.getZoom()! - 1,
      duration: 1000
    });
  }, [is3D]);

  const toggleNavigation = () => {
    if (navState.isActive) {
      setNavState(prev => ({ ...prev, isActive: false }));
    } else if (startPoint && endPoint) {
      setNavState(prev => ({ ...prev, isActive: true, progress: 0 }));
      // Zoom into start point
      mapInstance.current?.getView().animate({ center: fromLonLat(startPoint.coords), zoom: 18, duration: 1500 });

      // Simulate progress
      const interval = setInterval(() => {
        setNavState(prev => {
          if (prev.progress >= 100 || !prev.isActive) {
            clearInterval(interval);
            return { ...prev, isActive: false };
          }
          return { ...prev, progress: prev.progress + 0.5, distanceToTurn: `${Math.max(0, 450 - prev.progress * 4).toFixed(0)}m` };
        });
      }, 500);
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme}
        language={language}
        onLanguageChange={setLanguage}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLocate={() => {
          navigator.geolocation.getCurrentPosition(pos => {
            const me: Destination = { id: 'me', name: { en: 'My Location', hi: 'मेरा स्थान', kn: 'ನನ್ನ ಸ್ಥಳ', es: 'Mi ubicación' }, category: { en: 'Current', hi: 'वर्तमान', kn: 'ಪ್ರಸ್ತುತ', es: 'Actual' }, coords: [pos.coords.longitude, pos.coords.latitude], description: { en: 'GPS Locked', hi: 'जीपीएस', kn: 'ಜಿಪಿಎಸ್', es: 'GPS' }, image: '📍' };
            setStartPoint(me);
            mapInstance.current?.getView().animate({ center: fromLonLat(me.coords), zoom: 17, duration: 1200 });
          });
        }}
        onOpenLayers={() => setIsLayerPanelOpen(!isLayerPanelOpen)}
        onSuggestionSelect={(dest) => {
          setSelectedPlace(dest);
          if (startPoint && !endPoint) {
            setEndPoint(dest);
            calculateRoute(startPoint, dest, travelMode);
          } else {
            setStartPoint(dest);
            setEndPoint(null);
            setRouteInfo(null);
            routeSource.current.clear();
            mapInstance.current?.getView().animate({ center: fromLonLat(dest.coords), zoom: 16, duration: 1200 });
          }
        }}
      />

      {/* Navigation HUD Overlay */}
      <AnimatePresence>
        {navState.isActive && (
          <motion.div 
            initial={{ y: -150, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: -150, opacity: 0 }}
            className="fixed top-24 left-1/2 -translate-x-1/2 z-[1100] w-[90%] max-w-lg"
          >
            <div className={`p-6 rounded-[32px] shadow-2xl flex items-center gap-6 border-2 border-blue-500/30 ${theme === MapTheme.DARK ? 'glass bg-slate-900/90' : 'glass-light bg-white/90'}`}>
              <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-3xl text-white shadow-xl">
                ⬆️
              </div>
              <div className="flex-1">
                <p className="text-3xl font-black tracking-tight leading-none mb-1">{navState.distanceToTurn}</p>
                <p className="text-sm font-bold opacity-60 uppercase tracking-widest">{navState.currentStep}</p>
              </div>
              <button onClick={() => setNavState(prev => ({ ...prev, isActive: false }))} className="text-xs font-black uppercase tracking-widest text-red-500 py-2 px-4 rounded-xl bg-red-500/10">Exit</button>
            </div>
            <div className="w-full h-1.5 bg-white/10 mt-2 rounded-full overflow-hidden">
               <motion.div className="h-full bg-blue-500" initial={{ width: 0 }} animate={{ width: `${navState.progress}%` }} />
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <LayerPanel 
        isOpen={isLayerPanelOpen}
        onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers}
        onToggleLayer={(l) => {
          if ([MapLayerType.STREET, MapLayerType.SATELLITE].includes(l)) {
            setActiveLayers(prev => [...prev.filter(x => x !== MapLayerType.STREET && x !== MapLayerType.SATELLITE), l]);
          } else {
            setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l]);
          }
        }}
        theme={theme}
        isOnline={isOnline}
      />

      <BottomPanel 
        theme={theme} 
        language={language}
        onDestinationSelect={(dest) => {
          setSelectedPlace(dest);
          if (startPoint && !endPoint && startPoint.id !== dest.id) {
            setEndPoint(dest);
            calculateRoute(startPoint, dest, travelMode);
          } else {
            setStartPoint(dest);
            setEndPoint(null);
            setRouteInfo(null);
            routeSource.current.clear();
            mapInstance.current?.getView().animate({ center: fromLonLat(dest.coords), zoom: 16, duration: 1200 });
          }
        }}
        startPoint={startPoint}
        endPoint={endPoint}
        routeInfo={routeInfo}
        onClearRoute={() => { setStartPoint(null); setEndPoint(null); setRouteInfo(null); routeSource.current.clear(); }}
        offlineRegions={offlineRegions}
        onRegionClick={(r) => mapInstance.current?.getView().animate({ center: fromLonLat(r.center), zoom: r.zoom, duration: 1500 })}
        onRegionDelete={(id) => {
           const next = offlineRegions.filter(x => x.id !== id);
           setOfflineRegions(next);
           localStorage.setItem('disha_offline_regions', JSON.stringify(next));
        }}
        onTravelModeChange={(m) => {
          setTravelMode(m);
          if (startPoint && endPoint) calculateRoute(startPoint, endPoint, m);
        }}
        selectedPlace={selectedPlace}
        onClosePlace={() => setSelectedPlace(null)}
        onStartNavigation={toggleNavigation}
      />

      {/* Floating Action Buttons */}
      <div className="fixed bottom-24 right-6 flex flex-col gap-4 z-[1001]">
        <motion.button 
          whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }}
          onClick={() => setIs3D(!is3D)}
          className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-2xl transition-all ${is3D ? 'bg-blue-600 text-white' : (theme === MapTheme.DARK ? 'glass text-gray-400' : 'glass-light text-slate-500')}`}
          title="Toggle 3D"
        >
          🏙️
        </motion.button>
        <motion.button 
          whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.9 }}
          onClick={() => mapInstance.current?.getView().animate({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, rotation: 0, duration: 1000 })}
          className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-2xl transition-all ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}
          title="Recenter"
        >
          🎯
        </motion.button>
      </div>

      {/* Dynamic Status Display */}
      <motion.div layout className={`fixed top-24 right-6 z-[900] p-4 rounded-[28px] hidden lg:block ${theme === MapTheme.DARK ? 'glass' : 'glass-light'} shadow-2xl min-w-[200px]`}>
        <div className="flex items-center gap-3 mb-2">
          <span className={`w-2 h-2 rounded-full animate-pulse ${getTrafficDensity() > 1.5 ? 'bg-orange-500' : 'bg-emerald-500'}`} />
          <span className="text-[10px] font-black uppercase tracking-widest opacity-40">Urban Pulse</span>
        </div>
        <div className="text-2xl font-black tracking-tight">{weather.temp}°C {weather.condition}</div>
        <div className="text-[10px] opacity-30 mt-1 font-bold">Updated {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
      </motion.div>

      <motion.div 
        animate={{ opacity: theme === MapTheme.DARK ? 0.35 : 0.05 }}
        className="absolute inset-0 pointer-events-none transition-opacity duration-1000 z-[1]" 
        style={{ 
          background: theme === MapTheme.DARK 
            ? 'radial-gradient(circle at center, transparent 40%, #000 180%)'
            : 'radial-gradient(circle at center, transparent 60%, #2563eb 250%)'
        }} 
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Destination, MapTheme, RouteInfo, Language, OfflineRegion, TravelMode } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';

interface BottomPanelProps {
  theme: MapTheme;
  language: Language;
  onDestinationSelect: (d: Destination) => void;
  startPoint: Destination | null;
  endPoint: Destination | null;
  routeInfo: RouteInfo | null;
  onClearRoute: () => void;
  offlineRegions: OfflineRegion[];
  onRegionClick: (r: OfflineRegion) => void;
  onRegionDelete: (id: string) => void;
  onTravelModeChange: (mode: TravelMode) => void;
  selectedPlace: Destination | null;
  onClosePlace: () => void;
  onStartNavigation?: () => void;
}

export const BottomPanel: React.FC<BottomPanelProps> = ({ 
  theme, 
  language,
  onDestinationSelect,
  startPoint,
  endPoint,
  routeInfo,
  onClearRoute,
  offlineRegions,
  onRegionClick,
  onRegionDelete,
  onTravelModeChange,
  selectedPlace,
  onClosePlace,
  onStartNavigation
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [activeTab, setActiveTab] = useState<'explore' | 'route' | 'offline' | 'saved'>('explore');
  const [favorites, setFavorites] = useState<string[]>([]);
  const t = TRANSLATIONS[language] || TRANSLATIONS['en'];

  useEffect(() => {
    if (startPoint || endPoint) {
      setActiveTab('route');
      setIsExpanded(true);
    }
  }, [startPoint, endPoint]);

  useEffect(() => {
    if (selectedPlace) setIsExpanded(true);
  }, [selectedPlace]);

  useEffect(() => {
    const saved = localStorage.getItem('disha_favorites');
    if (saved) setFavorites(JSON.parse(saved));
  }, []);

  const toggleFavorite = (id: string) => {
    const next = favorites.includes(id) ? favorites.filter(f => f !== id) : [...favorites, id];
    setFavorites(next);
    localStorage.setItem('disha_favorites', JSON.stringify(next));
  };

  return (
    <motion.div 
      initial={false}
      animate={{ height: isExpanded ? 640 : 80 }}
      className={`fixed bottom-0 left-0 right-0 z-[998] rounded-t-[48px] shadow-[0_-20px_60px_rgba(0,0,0,0.4)] transition-colors duration-500 ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}
    >
      <div 
        className="h-16 flex flex-col items-center justify-center cursor-pointer group"
        onClick={() => setIsExpanded(!isExpanded)}
      >
        <div className={`w-12 h-1.5 rounded-full mb-1 transition-colors ${theme === MapTheme.DARK ? 'bg-white/10 group-hover:bg-white/30' : 'bg-black/5 group-hover:bg-black/20'}`} />
        <span className={`text-[9px] font-black uppercase tracking-[0.4em] opacity-40 group-hover:opacity-80`}>
          {isExpanded ? 'Slide Down' : 'Menu'}
        </span>
      </div>

      <AnimatePresence>
        {isExpanded && (
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 20 }}
            className="px-6 lg:px-12 pb-8 overflow-hidden h-[calc(100%-64px)] flex flex-col"
          >
            {selectedPlace ? (
              <div className="flex-1 overflow-y-auto custom-scrollbar">
                <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-6">
                    <span className="text-6xl">{selectedPlace.image}</span>
                    <div>
                      <h2 className={`text-3xl font-black ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{selectedPlace.name[language] || selectedPlace.name['en']}</h2>
                      <p className="text-blue-500 font-bold uppercase tracking-widest text-xs">{selectedPlace.category[language] || selectedPlace.category['en']}</p>
                    </div>
                  </div>
                  <button onClick={onClosePlace} className={`w-12 h-12 rounded-full flex items-center justify-center text-xl ${theme === MapTheme.DARK ? 'bg-white/5' : 'bg-black/5'}`}>✕</button>
                </div>

                <div className="flex gap-4 mb-8">
                  <button 
                    onClick={() => toggleFavorite(selectedPlace.id)}
                    className={`flex-1 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${favorites.includes(selectedPlace.id) ? 'bg-red-500 text-white' : 'bg-white/5 hover:bg-white/10'}`}
                  >
                    {favorites.includes(selectedPlace.id) ? '❤️ Saved' : '🤍 Save'}
                  </button>
                  <button 
                    onClick={() => onDestinationSelect(selectedPlace)}
                    className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest"
                  >
                    Directions
                  </button>
                  <button className={`w-16 h-14 rounded-2xl flex items-center justify-center text-xl ${theme === MapTheme.DARK ? 'bg-white/5' : 'bg-black/5'}`}>🔗</button>
                </div>

                <div className="space-y-8">
                  <section>
                    <h3 className="text-[10px] font-black uppercase tracking-[0.2em] opacity-30 mb-3">About</h3>
                    <p className={`text-lg leading-relaxed ${theme === MapTheme.DARK ? 'text-white/70' : 'text-slate-600'}`}>
                      {selectedPlace.description[language] || selectedPlace.description['en']}
                    </p>
                  </section>

                  {selectedPlace.reviews && (
                    <section>
                      <h3 className="text-[10px] font-black uppercase tracking-[0.2em] opacity-30 mb-4">Top Reviews</h3>
                      <div className="space-y-4">
                        {selectedPlace.reviews.map((r, i) => (
                          <div key={i} className={`p-5 rounded-3xl ${theme === MapTheme.DARK ? 'bg-white/5' : 'bg-black/5'}`}>
                            <div className="flex justify-between mb-2">
                              <span className="font-black text-sm">{r.author}</span>
                              <span className="text-yellow-500 font-black">{'★'.repeat(r.rating)}</span>
                            </div>
                            <p className="text-sm opacity-60 italic">"{r.text[language] || r.text['en']}"</p>
                          </div>
                        ))}
                      </div>
                    </section>
                  )}
                </div>
              </div>
            ) : (
              <>
                <div className="flex gap-8 mb-6 border-b border-white/5 pb-2 shrink-0 overflow-x-auto no-scrollbar">
                  {[
                    { id: 'explore', label: t.explore || 'Explore' },
                    { id: 'route', label: t.directions || 'Go' },
                    { id: 'saved', label: 'Saved' },
                    { id: 'offline', label: 'Offline' }
                  ].map(tab => (
                    <button 
                      key={tab.id}
                      onClick={() => setActiveTab(tab.id as any)}
                      className={`pb-4 px-1 font-black text-[11px] tracking-widest transition-all relative whitespace-nowrap ${activeTab === tab.id ? 'text-blue-500' : 'text-slate-500'}`}
                    >
                      {tab.label.toUpperCase()}
                      {activeTab === tab.id && <motion.div layoutId="tab-active" className="absolute bottom-0 left-0 right-0 h-1 bg-blue-500 rounded-full" />}
                    </button>
                  ))}
                </div>

                <div className="flex-1 overflow-y-auto pr-1 custom-scrollbar pb-16">
                  {activeTab === 'explore' ? (
                    <div className="space-y-8">
                      <div className="flex gap-3 overflow-x-auto no-scrollbar pb-2">
                        {['Restaurants', 'Gas', 'Coffee', 'Parks', 'Groceries'].map(cat => (
                          <button key={cat} className={`px-5 py-2.5 rounded-full whitespace-nowrap text-[10px] font-black uppercase tracking-widest border ${theme === MapTheme.DARK ? 'bg-white/5 border-white/10 text-white/50 hover:text-white' : 'bg-white border-black/5 text-slate-500 hover:text-slate-900'}`}>
                            {cat}
                          </button>
                        ))}
                      </div>
                      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                        {POPULAR_DESTINATIONS.map(dest => (
                          <div 
                            key={dest.id} 
                            onClick={() => onDestinationSelect(dest)}
                            className={`p-6 rounded-[36px] cursor-pointer transition-all border border-transparent hover:border-blue-500/30 ${theme === MapTheme.DARK ? 'bg-white/5 hover:bg-white/10' : 'bg-white hover:bg-blue-50 shadow-lg shadow-blue-500/5'}`}
                          >
                            <div className="text-5xl mb-4">{dest.image}</div>
                            <h4 className="font-black text-xl mb-1">{dest.name[language] || dest.name['en']}</h4>
                            <p className="text-[10px] font-black uppercase tracking-widest opacity-40">{dest.category[language] || dest.category['en']}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  ) : activeTab === 'route' ? (
                    <div className="space-y-8">
                      <div className={`flex gap-4 p-2 rounded-3xl ${theme === MapTheme.DARK ? 'bg-white/5' : 'bg-black/5'}`}>
                        {[
                          { id: 'driving', icon: '🚗' },
                          { id: 'walking', icon: '🚶' },
                          { id: 'cycling', icon: '🚲' },
                          { id: 'transit', icon: '🚌' }
                        ].map(m => (
                          <button 
                            key={m.id}
                            onClick={() => onTravelModeChange(m.id as TravelMode)}
                            className={`flex-1 py-3 rounded-2xl text-2xl transition-all ${routeInfo?.mode === m.id ? 'bg-blue-600 shadow-lg shadow-blue-500/30' : 'hover:bg-black/5'}`}
                          >
                            {m.icon}
                          </button>
                        ))}
                      </div>

                      {routeInfo ? (
                        <div className={`p-8 rounded-[40px] border-2 border-blue-500/40 ${theme === MapTheme.DARK ? 'bg-blue-500/5' : 'bg-blue-50'}`}>
                          <div className="grid grid-cols-3 gap-8">
                            <div>
                              <p className="text-[9px] font-black opacity-40 uppercase mb-1">Time</p>
                              <p className={`text-4xl font-black ${routeInfo.congestionLevel === 'heavy' ? 'text-red-500' : 'text-blue-500'}`}>{routeInfo.duration}</p>
                            </div>
                            <div>
                              <p className="text-[9px] font-black opacity-40 uppercase mb-1">Dist</p>
                              <p className="text-3xl font-black">{routeInfo.distance}</p>
                            </div>
                            <div>
                              <p className="text-[9px] font-black opacity-40 uppercase mb-1">Delay</p>
                              <p className={`text-3xl font-black ${routeInfo.trafficDelay === 'None' ? 'text-emerald-500' : 'text-red-500'}`}>{routeInfo.trafficDelay}</p>
                            </div>
                          </div>
                          <div className="flex gap-4 mt-8">
                             <button onClick={onClearRoute} className="flex-1 py-5 bg-red-500/10 text-red-500 rounded-3xl font-black text-xs uppercase tracking-[0.2em]">Cancel</button>
                             <button onClick={onStartNavigation} className="flex-[2] py-5 bg-blue-600 text-white rounded-3xl font-black text-xs uppercase tracking-[0.2em] shadow-2xl shadow-blue-500/40">Start Now</button>
                          </div>
                        </div>
                      ) : (
                        <div className="flex flex-col items-center justify-center py-20 opacity-20 text-center">
                          <span className="text-7xl mb-6">🛰️</span>
                          <p className="font-black uppercase tracking-widest max-w-[200px]">Select a place to see the traffic-optimized route</p>
                        </div>
                      )}
                    </div>
                  ) : activeTab === 'saved' ? (
                    <div className="grid grid-cols-1 gap-4">
                      {POPULAR_DESTINATIONS.filter(d => favorites.includes(d.id)).length > 0 ? (
                        POPULAR_DESTINATIONS.filter(d => favorites.includes(d.id)).map(dest => (
                          <div 
                            key={dest.id} 
                            onClick={() => onDestinationSelect(dest)}
                            className={`p-5 rounded-3xl flex items-center gap-6 cursor-pointer ${theme === MapTheme.DARK ? 'bg-white/5' : 'bg-white shadow-md'}`}
                          >
                            <span className="text-4xl">{dest.image}</span>
                            <div className="flex-1">
                              <p className="font-black text-lg">{dest.name[language] || dest.name['en']}</p>
                              <p className="text-[9px] font-bold opacity-40 uppercase">{dest.category['en']}</p>
                            </div>
                            <span className="text-red-500 text-xl">❤️</span>
                          </div>
                        ))
                      ) : (
                        <div className="text-center py-20 opacity-20 font-black uppercase tracking-widest">No saved places yet</div>
                      )}
                    </div>
                  ) : (
                    <div className="space-y-6">
                      {offlineRegions.map(r => (
                        <div key={r.id} className={`p-6 rounded-3xl flex justify-between items-center ${theme === MapTheme.DARK ? 'bg-white/5' : 'bg-white shadow-md'}`}>
                          <div>
                            <p className="font-black text-lg">{r.name}</p>
                            <p className="text-[10px] font-bold opacity-30">{r.date} • {r.size}</p>
                          </div>
                          <div className="flex gap-2">
                             <button onClick={() => onRegionDelete(r.id)} className="w-10 h-10 rounded-xl bg-red-500/10 text-red-500">🗑️</button>
                             <button onClick={() => onRegionClick(r)} className="px-4 py-2 bg-blue-600 text-white rounded-xl text-[10px] font-black">SYNC</button>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

