import React, { useEffect, useRef, useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import OSM from 'ol/source/OSM';
import VectorLayer from 'ol/layer/Vector';
import VectorSource from 'ol/source/Vector';
import { LineString, Point } from 'ol/geom';
import { Feature } from 'ol';
import { Style, Stroke, Icon } from 'ol/style';
import { fromLonLat, toLonLat } from 'ol/proj';
import { get as getProjection } from 'ol/proj';
import { transform } from 'ol/proj';
import { defaults as defaultControls } from 'ol/control';
import { FullScreen } from 'ol/control';

import './App.css';

// Type definitions
interface RouteInfo {
  route: number[][];
  totalDistance: number;
  totalTime: number;
  congestion: string;
}

const App: React.FC = () => {
  const [map, setMap] = useState<Map | null>(null);
  const [routeInfo, setRouteInfo] = useState<RouteInfo | null>(null);
  const [startPoint, setStartPoint] = useState<number[] | null>(null);
  const [endPoint, setEndPoint] = useState<number[] | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const mapRef = useRef<HTMLDivElement>(null);
  const routeSource = useRef<VectorSource | null>(null);
  const markerSource = useRef<VectorSource | null>(null);

  // Default values
  const defaultZoom = 15;
  const defaultCenter = [8.54019, 47.3769]; // Zurich, Switzerland
  const projection = getProjection('EPSG:3857');

