                  activeLayers.includes(MapLayerType.TRAFFIC) 
                    ? 'border-emerald-500 bg-emerald-500/10' 
                    : `border-transparent ${theme === MapTheme.DARK ? 'bg-white/5 hover:bg-white/10' : 'bg-black/5 hover:bg-black/10'}`
                }`}
              >
                <div className="text-4xl w-16 h-16 flex items-center justify-center rounded-2xl bg-white/5 shrink-0">🚦</div>
                <div className="flex-1">
                  <div className={`font-black text-lg ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Real-Time Traffic</div>
                  <div className="text-[10px] font-bold opacity-40 uppercase tracking-widest">Live Flow Data</div>
                </div>
                <div className={`w-14 h-7 rounded-full relative transition-colors ${activeLayers.includes(MapLayerType.TRAFFIC) ? 'bg-emerald-500' : 'bg-slate-600'}`}>
                   <motion.div animate={{ x: activeLayers.includes(MapLayerType.TRAFFIC) ? 28 : 0 }} className="absolute top-1 left-1 w-5 h-5 bg-white rounded-full shadow" />
                </div>
              </div>
            </section>
          </div>

          <div className="mt-12 p-8 rounded-[40px] bg-blue-600/5 border border-blue-500/10 text-center">
             <p className="text-[10px] font-black uppercase tracking-widest text-blue-500 mb-2">Adaptive Rendering</p>
             <p className={`text-[9px] font-bold opacity-30 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>The map engine automatically optimizes tile loading based on your current network speed and zoom level.</p>
