  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
);

const LayersIcon = () => (
  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <polygon points="12 2 2 7 12 12 22 7 12 2"></polygon>
    <polyline points="2 17 12 22 22 17"></polyline>
    <polyline points="2 12 12 17 22 12"></polyline>
  </svg>
);

export const Header: React.FC<HeaderProps> = ({ 
  theme, 
  language,
  onThemeToggle, 
  onLanguageChange,
  onLocate, 
  onOpenLayers,
  onSuggestionSelect 
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<Destination[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (!query.trim()) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(() => {
      const q = query.toLowerCase();
      const filtered = POPULAR_DESTINATIONS.filter(dest => 
        dest.name[language].toLowerCase().includes(q) ||
        dest.category[language].toLowerCase().includes(q)
      ).slice(0, 8);
      setSuggestions(filtered);
    }, 100);

    return () => clearTimeout(timer);
  }, [query, language]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsFocused(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSelect = (dest: Destination) => {
    setQuery(dest.name[language]);
    setSuggestions([]);
    setIsFocused(false);
    onSuggestionSelect(dest);
  };

  return (
    <motion.header 
      initial={{ y: -100, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[1800] p-4 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-start gap-4 pointer-events-auto">
        <div className={`flex items-center gap-3 px-6 py-3 rounded-2xl shadow-2xl transition-all h-[56px] ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900'}`}>
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-xl shrink-0">
            <LogoIcon />
          </div>
          <span className="font-extrabold text-xl tracking-tighter hidden sm:block">Disha Maps</span>
        </div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-6 py-3 rounded-[24px] shadow-2xl transition-all group h-[56px] ${
            theme === MapTheme.DARK 
              ? `glass ${isFocused ? 'ring-2 ring-blue-500/50 bg-slate-800' : 'hover:bg-slate-800/40'}` 
              : `glass-light ${isFocused ? 'ring-2 ring-blue-400/30 bg-white' : 'hover:bg-white/80'}`
          }`}>
            <span className={`mr-4 transition-colors shrink-0 ${isFocused ? 'text-blue-500' : 'text-slate-400'}`}>
              <SearchIcon />
            </span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onChange={(e) => setQuery(e.target.value)}
              placeholder={t.searchPlaceholder}
              className="bg-transparent border-none outline-none w-full text-base font-bold placeholder:text-slate-500/60"
              style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
            />
          </div>

          <AnimatePresence>
            {isFocused && (
              <motion.div
                initial={{ opacity: 0, y: 12, scale: 0.98 }}
                animate={{ opacity: 1, y: 8, scale: 1 }}
                exit={{ opacity: 0, y: 12, scale: 0.98 }}
                className={`absolute top-full left-0 right-0 rounded-[36px] shadow-2xl overflow-hidden border ${
                  theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'
                }`}
              >
                <div className="max-h-[70vh] overflow-y-auto py-4 custom-scrollbar">
                  {suggestions.length > 0 ? (
                    <div>
                      <div className="text-[11px] font-black uppercase tracking-[0.2em] text-blue-500/80 mb-4 px-8">Quick Results</div>
                      {suggestions.map((dest) => (
                        <div
                          key={dest.id}
                          onClick={() => handleSelect(dest)}
                          className={`px-8 py-4 flex items-center gap-6 cursor-pointer transition-all ${
                            theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-blue-50/70'
                          }`}
                        >
                          <div className="text-4xl w-14 h-14 flex items-center justify-center rounded-3xl bg-slate-500/10 shrink-0">
                            {dest.image}
                          </div>
                          <div className="flex-1 overflow-hidden">
                            <div className={`font-black text-lg truncate ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
                              {dest.name[language]}
                            </div>
                            <div className={`text-xs opacity-50 font-bold truncate ${theme === MapTheme.DARK ? 'text-blue-400' : 'text-blue-600'}`}>
                              {dest.category[language]} • Available Now
                            </div>
                          </div>
                          <div className="text-xs font-black opacity-30 shrink-0">{dest.rating}★</div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div>
                      <div className="text-[11px] font-black uppercase tracking-[0.2em] text-blue-500/80 mb-4 px-8">Popular Destinations</div>
                      <div className="grid grid-cols-1 gap-1">
                        {POPULAR_DESTINATIONS.slice(0, 5).map(dest => (
                          <div key={dest.id} onClick={() => handleSelect(dest)} className={`px-8 py-4 flex items-center gap-5 cursor-pointer transition-colors ${theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-black/5'}`}>
                            <span className="text-3xl shrink-0">{dest.image}</span>
                            <div className="flex flex-col">
                              <span className="text-base font-black">{dest.name[language]}</span>
                              <span className="text-[10px] opacity-40 uppercase font-black">{dest.category[language]}</span>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex gap-2 shrink-0">
          <button 
            onClick={onOpenLayers}
            className={`w-[56px] h-[56px] rounded-2xl flex items-center justify-center shadow-2xl transition-all hover:scale-110 active:scale-90 ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}
          >
            <LayersIcon />
          </button>
          <button 
            onClick={onThemeToggle}
            className={`w-[56px] h-[56px] rounded-2xl flex items-center justify-center shadow-2xl transition-all hover:scale-110 active:scale-90 ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600'}`}
          >
            {theme === MapTheme.DARK ? '☀️' : '🌙'}
