  );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Destination, MapTheme, RouteInfo, Language, OfflineRegion, TravelMode } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';

interface BottomPanelProps {
  theme: MapTheme;
  language: Language;
  onDestinationSelect: (d: Destination) => void;
  startPoint: Destination | null;
  endPoint: Destination | null;
  routeInfo: RouteInfo | null;
  onClearRoute: () => void;
  offlineRegions: OfflineRegion[];
  onRegionClick: (r: OfflineRegion) => void;
  onRegionDelete: (id: string) => void;
  onTravelModeChange: (mode: TravelMode) => void;
  selectedPlace: Destination | null;
  onClosePlace: () => void;
  onStartNavigation?: () => void;
}

export const BottomPanel: React.FC<BottomPanelProps> = ({ 
  theme, 
  language,
  onDestinationSelect,
  startPoint,
  endPoint,
  routeInfo,
  onClearRoute,
  offlineRegions,
  onRegionClick,
  onRegionDelete,
  onTravelModeChange,
  selectedPlace,
  onClosePlace,
  onStartNavigation
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [activeTab, setActiveTab] = useState<'explore' | 'route' | 'offline' | 'saved'>('explore');
  const [favorites, setFavorites] = useState<string[]>([]);
  const t = TRANSLATIONS[language] || TRANSLATIONS['en'];

  useEffect(() => {
    if (startPoint || endPoint) {
      setActiveTab('route');
      setIsExpanded(true);
    }
  }, [startPoint, endPoint]);

  useEffect(() => {
    if (selectedPlace) setIsExpanded(true);
  }, [selectedPlace]);

  useEffect(() => {
    const saved = localStorage.getItem('disha_favorites');
    if (saved) setFavorites(JSON.parse(saved));
  }, []);

  const toggleFavorite = (id: string) => {
    const next = favorites.includes(id) ? favorites.filter(f => f !== id) : [...favorites, id];
    setFavorites(next);
    localStorage.setItem('disha_favorites', JSON.stringify(next));
  };

  return (
    <motion.div 
      initial={false}
      animate={{ height: isExpanded ? 640 : 80 }}
      className={`fixed bottom-0 left-0 right-0 z-[1200] rounded-t-[48px] shadow-[0_-20px_60px_rgba(0,0,0,0.4)] transition-colors duration-500 overflow-hidden ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}
    >
      <div 
        className="h-16 flex flex-col items-center justify-center cursor-pointer group shrink-0"
        onClick={() => setIsExpanded(!isExpanded)}
      >
        <div className={`w-12 h-1.5 rounded-full mb-1 transition-colors ${theme === MapTheme.DARK ? 'bg-white/10 group-hover:bg-white/30' : 'bg-black/5 group-hover:bg-black/20'}`} />
        <span className={`text-[9px] font-black uppercase tracking-[0.4em] opacity-40 group-hover:opacity-80 transition-opacity`}>
          {isExpanded ? 'Collapse' : 'Slide Up'}
        </span>
      </div>

      <AnimatePresence mode="wait">
        {isExpanded && (
          <motion.div 
            key="content"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="px-6 lg:px-12 pb-8 overflow-hidden h-[calc(100%-64px)] flex flex-col"
          >
            {selectedPlace ? (
              <div className="flex-1 overflow-y-auto custom-scrollbar pr-2">
                <div className="flex justify-between items-start mb-8">
                  <div className="flex items-center gap-8">
                    <span className="text-7xl group-hover:scale-110 transition-transform">{selectedPlace.image}</span>
                    <div>
                      <h2 className={`text-4xl font-black ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{selectedPlace.name[language] || selectedPlace.name['en']}</h2>
                      <p className="text-blue-500 font-bold uppercase tracking-widest text-xs mt-1">{selectedPlace.category[language] || selectedPlace.category['en']}</p>
                    </div>
                  </div>
                  <button onClick={onClosePlace} className={`w-14 h-14 rounded-[20px] flex items-center justify-center text-xl transition-all ${theme === MapTheme.DARK ? 'bg-white/5 hover:bg-white/10 text-white' : 'bg-black/5 hover:bg-black/10 text-slate-900'}`}>✕</button>
                </div>

                <div className="flex gap-4 mb-10">
                  <button 
                    onClick={() => toggleFavorite(selectedPlace.id)}
                    className={`flex-1 py-5 rounded-[24px] font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-3 transition-all ${favorites.includes(selectedPlace.id) ? 'bg-red-500 text-white shadow-lg shadow-red-500/30' : 'bg-white/5 hover:bg-white/10 border border-white/10'}`}
                  >
                    {favorites.includes(selectedPlace.id) ? '❤️ Saved' : '🤍 Save'}
                  </button>
                  <button 
                    onClick={() => onDestinationSelect(selectedPlace)}
                    className="flex-[2] py-5 bg-blue-600 text-white rounded-[24px] font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-blue-500/40 hover:bg-blue-500 transition-all"
                  >
                    Get Directions
                  </button>
                </div>

                <div className="space-y-10">
                  <section>
                    <h3 className="text-[10px] font-black uppercase tracking-[0.25em] opacity-30 mb-4 text-blue-500">Overview</h3>
                    <p className={`text-xl leading-relaxed font-medium ${theme === MapTheme.DARK ? 'text-white/80' : 'text-slate-700'}`}>
                      {selectedPlace.description[language] || selectedPlace.description['en']}
                    </p>
                  </section>

                  {selectedPlace.reviews && (
                    <section>
                      <h3 className="text-[10px] font-black uppercase tracking-[0.25em] opacity-30 mb-6 text-blue-500">Visitor Feedback</h3>
                      <div className="space-y-6">
                        {selectedPlace.reviews.map((r, i) => (
                          <div key={i} className={`p-6 rounded-[32px] ${theme === MapTheme.DARK ? 'bg-white/5 border border-white/5' : 'bg-black/5 border border-black/5'}`}>
                            <div className="flex justify-between items-center mb-3">
                              <span className="font-black text-sm">{r.author}</span>
                              <div className="flex text-yellow-500 gap-0.5">
                                {'★'.repeat(r.rating)}
                              </div>
                            </div>
                            <p className="text-base opacity-60 font-medium italic leading-snug">"{r.text[language] || r.text['en']}"</p>
                          </div>
                        ))}
                      </div>
                    </section>
                  )}
                </div>
              </div>
            ) : (
              <>
                <div className="flex gap-8 mb-8 border-b border-white/5 pb-2 shrink-0 overflow-x-auto no-scrollbar">
                  {[
                    { id: 'explore', label: t.explore || 'Explore' },
                    { id: 'route', label: t.directions || 'Go' },
                    { id: 'saved', label: 'Saved' },
                    { id: 'offline', label: 'Offline' }
                  ].map(tab => (
                    <button 
                      key={tab.id}
                      onClick={() => setActiveTab(tab.id as any)}
                      className={`pb-4 px-2 font-black text-[12px] tracking-widest transition-all relative whitespace-nowrap ${activeTab === tab.id ? 'text-blue-500' : 'text-slate-500 opacity-60 hover:opacity-100'}`}
                    >
                      {tab.label.toUpperCase()}
                      {activeTab === tab.id && <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-1 bg-blue-500 rounded-full" />}
                    </button>
