                <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar pb-10">
                  {activeTab === 'explore' ? (
                    <div className="space-y-10">
                      <div className="flex gap-4 overflow-x-auto no-scrollbar pb-4">
                        {['Restaurants', 'Fuel', 'Cafe', 'Museums', 'Parks'].map(cat => (
                          <button key={cat} className={`px-6 py-3 rounded-full whitespace-nowrap text-[10px] font-black uppercase tracking-[0.2em] border transition-all ${theme === MapTheme.DARK ? 'bg-white/5 border-white/10 text-white/50 hover:bg-white/10 hover:text-white' : 'bg-white border-black/5 text-slate-500 hover:text-slate-900 shadow-sm'}`}>
                            {cat}
                          </button>
                        ))}
                      </div>
                      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
                        {POPULAR_DESTINATIONS.map(dest => (
                          <div 
                            key={dest.id} 
                            onClick={() => onDestinationSelect(dest)}
                            className={`group p-8 rounded-[40px] cursor-pointer transition-all border border-transparent hover:border-blue-500/30 ${theme === MapTheme.DARK ? 'bg-white/5 hover:bg-white/10' : 'bg-white hover:bg-blue-50 shadow-xl shadow-blue-500/5'}`}
                          >
                            <div className="text-6xl mb-6 group-hover:scale-110 transition-transform origin-left">{dest.image}</div>
                            <h4 className="font-black text-2xl mb-2">{dest.name[language] || dest.name['en']}</h4>
                            <p className="text-[11px] font-black uppercase tracking-[0.2em] opacity-40 text-blue-500">{dest.category[language] || dest.category['en']}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  ) : activeTab === 'route' ? (
                    <div className="space-y-8">
                      <div className={`flex gap-4 p-2.5 rounded-[32px] ${theme === MapTheme.DARK ? 'bg-white/5' : 'bg-black/5'}`}>
                        {[
                          { id: 'driving', icon: '🚗' },
                          { id: 'walking', icon: '🚶' },
                          { id: 'cycling', icon: '🚲' },
                          { id: 'transit', icon: '🚌' }
                        ].map(m => (
                          <button 
                            key={m.id}
                            onClick={() => onTravelModeChange(m.id as TravelMode)}
                            className={`flex-1 py-4 rounded-[24px] text-3xl transition-all ${routeInfo?.mode === m.id ? 'bg-blue-600 shadow-xl shadow-blue-500/40 text-white' : 'hover:bg-white/10 grayscale opacity-40 hover:grayscale-0 hover:opacity-100'}`}
                          >
                            {m.icon}
                          </button>
                        ))}
                      </div>

                      {routeInfo ? (
                        <div className={`p-10 rounded-[48px] border-2 border-blue-500/30 shadow-2xl ${theme === MapTheme.DARK ? 'bg-blue-500/10' : 'bg-blue-50'}`}>
                          <div className="grid grid-cols-3 gap-10">
                            <div>
                              <p className="text-[10px] font-black opacity-40 uppercase mb-2 tracking-widest">Est. Time</p>
                              <p className={`text-5xl font-black ${routeInfo.congestionLevel === 'heavy' ? 'text-red-500' : 'text-blue-500'}`}>{routeInfo.duration}</p>
                            </div>
                            <div>
                              <p className="text-[10px] font-black opacity-40 uppercase mb-2 tracking-widest">Total Dist</p>
                              <p className="text-4xl font-black">{routeInfo.distance}</p>
                            </div>
                            <div>
                              <p className="text-[10px] font-black opacity-40 uppercase mb-2 tracking-widest">Traffic</p>
                              <p className={`text-4xl font-black ${routeInfo.trafficDelay === 'None' ? 'text-emerald-500' : 'text-red-500'}`}>{routeInfo.trafficDelay}</p>
                            </div>
                          </div>
                          <div className="flex gap-6 mt-12">
                             <button onClick={onClearRoute} className={`flex-1 py-5 rounded-[28px] font-black text-xs uppercase tracking-[0.2em] transition-all ${theme === MapTheme.DARK ? 'bg-white/5 text-white hover:bg-white/10' : 'bg-white text-slate-900 border border-slate-200'}`}>Clear</button>
                             <button onClick={onStartNavigation} className="flex-[2] py-5 bg-blue-600 text-white rounded-[28px] font-black text-xs uppercase tracking-[0.2em] shadow-2xl shadow-blue-500/40 hover:bg-blue-500 transition-all">Start Nav</button>
                          </div>
                        </div>
                      ) : (
                        <div className="flex flex-col items-center justify-center py-24 opacity-20 text-center">
                          <span className="text-8xl mb-8">🧭</span>
                          <p className="font-black uppercase tracking-[0.3em] max-w-[240px] leading-loose">Choose destination to analyze route dynamics</p>
                        </div>
                      )}
                    </div>
                  ) : activeTab === 'saved' ? (
                    <div className="grid grid-cols-1 gap-6">
                      {POPULAR_DESTINATIONS.filter(d => favorites.includes(d.id)).length > 0 ? (
                        POPULAR_DESTINATIONS.filter(d => favorites.includes(d.id)).map(dest => (
                          <div 
                            key={dest.id} 
                            onClick={() => onDestinationSelect(dest)}
                            className={`p-6 rounded-[32px] flex items-center gap-8 cursor-pointer border transition-all ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5 hover:bg-white/10' : 'bg-white shadow-lg border-slate-100 hover:shadow-xl'}`}
                          >
                            <span className="text-5xl">{dest.image}</span>
                            <div className="flex-1">
                              <p className="font-black text-xl">{dest.name[language] || dest.name['en']}</p>
                              <p className="text-[10px] font-bold opacity-40 uppercase tracking-widest mt-1 text-blue-500">{dest.category['en']}</p>
                            </div>
                            <span className="text-red-500 text-2xl drop-shadow-sm">❤️</span>
                          </div>
                        ))
                      ) : (
                        <div className="text-center py-24 opacity-20 font-black uppercase tracking-[0.3em]">Your library is empty</div>
                      )}
                    </div>
                  ) : (
                    <div className="space-y-6">
                      {offlineRegions.length > 0 ? offlineRegions.map(r => (
