                          <div>
                            <p className="font-black text-xl">{r.name}</p>
                            <p className="text-[11px] font-bold opacity-30 mt-1 uppercase tracking-widest">{r.date} • {r.size}</p>
                          </div>
                          <div className="flex gap-4">
                             <button onClick={() => onRegionDelete(r.id)} className="w-12 h-12 rounded-2xl bg-red-500/10 text-red-500 hover:bg-red-500 transition-colors">🗑️</button>
                             <button onClick={() => onRegionClick(r)} className="px-6 py-3 bg-blue-600 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest shadow-lg shadow-blue-500/20">Sync</button>
                          </div>
                        </div>
                      )) : (
                        <div className="text-center py-24 opacity-20 font-black uppercase tracking-[0.3em]">No cached regions found</div>
                      )}
                    </div>
                  )}
                </div>
              </>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
