import React, { useEffect, useRef, useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import OSM from 'ol/source/OSM';
import VectorSource from 'ol/source/Vector';
import { fromLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, OfflineRegion, TravelMode, NavigationState } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, TRAFFIC_COLORS, TRANSLATIONS, POPULAR_DESTINATIONS, ROUTE_FACTORS } from './constants';

interface Vehicle {
  feature: Feature<Point>;
  speed: number;
  heading: number;
  coords: [number, number];
}

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const trafficSource = useRef<VectorSource>(new VectorSource());
  const routeSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const navMarkerSource = useRef<VectorSource>(new VectorSource());
  const vehiclesRef = useRef<Vehicle[]>([]);
  const animationFrameId = useRef<number>(0);

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  // Traffic is removed from initial activeLayers to satisfy "disabled at start" request
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET, MapLayerType.ROUTE]);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [weather, setWeather] = useState({ temp: 24, condition: 'Partial Clouds' });
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [offlineRegions, setOfflineRegions] = useState<OfflineRegion[]>([]);
  const [travelMode, setTravelMode] = useState<TravelMode>('driving');
  const [is3D, setIs3D] = useState(false);
  const [mapRotation, setMapRotation] = useState(0);

  const [startPoint, setStartPoint] = useState<Destination | null>(null);
  const [endPoint, setEndPoint] = useState<Destination | null>(null);
  const [routeInfo, setRouteInfo] = useState<RouteInfo | null>(null);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [navState, setNavState] = useState<NavigationState>({
    isActive: false,
    currentStep: "Proceed to highlighted route",
    distanceToTurn: "0m",
    progress: 0
  });

  useEffect(() => {
    const handleStatus = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatus);
    window.addEventListener('offline', handleStatus);
    return () => {
      window.removeEventListener('online', handleStatus);
      window.removeEventListener('offline', handleStatus);
    };
  }, []);

  const getTrafficDensity = useCallback(() => {
    const hour = currentTime.getHours() + currentTime.getMinutes() / 60;
    // Mathematical Sine-Wave for traffic peak simulation (8-10am and 5-7pm)
    const morningPeak = Math.exp(-Math.pow(hour - 9, 2) / 1.5);
    const eveningPeak = Math.exp(-Math.pow(hour - 18, 2) / 1.5);
    return 1.0 + (morningPeak + eveningPeak) * 2.5;
  }, [currentTime]);

  const calculateRoute = useCallback((start: Destination, end: Destination, mode: TravelMode) => {
    if (!mapInstance.current) return;
    const startC = fromLonLat(start.coords) as [number, number];
    const endC = fromLonLat(end.coords) as [number, number];

    const steps = 25;
    const allCoords: [number, number][] = [startC];

    for (let i = 1; i < steps; i++) {
       const p = i / steps;
       const noise = (Math.random() - 0.5) * 400;
       allCoords.push([
          startC[0] + (endC[0] - startC[0]) * p + (i % 2 === 0 ? noise : -noise),
          startC[1] + (endC[1] - startC[1]) * p + (i % 3 === 0 ? -noise : noise)
       ]);
    }
    allCoords.push(endC);

    routeSource.current.clear();
    let maxDelay = 0;

    for (let i = 0; i < allCoords.length - 1; i++) {
      const segmentCoords = [allCoords[i], allCoords[i+1]];
      const congestionFactor = Math.random();
      if (congestionFactor > maxDelay) maxDelay = congestionFactor;

      const status: 'fast' | 'medium' | 'slow' = congestionFactor > 0.85 ? 'slow' : congestionFactor > 0.6 ? 'medium' : 'fast';
      const feature = new Feature(new LineString(segmentCoords));
      const color = status === 'slow' ? TRAFFIC_COLORS.SLOW : status === 'medium' ? TRAFFIC_COLORS.MEDIUM : '#3b82f6';

      feature.setStyle(new Style({
        stroke: new Stroke({ color, width: 12, lineCap: 'round', lineJoin: 'round' })
      }));
      routeSource.current.addFeature(feature);
    }

    const distRaw = Math.sqrt(Math.pow(end.coords[0] - start.coords[0], 2) + Math.pow(end.coords[1] - start.coords[1], 2)) * 111.32;
    const time = Math.round(distRaw * (ROUTE_FACTORS[mode] || 2.2));

    setRouteInfo({
      distance: `${distRaw.toFixed(1)} km`,
      duration: `${time} min`,
      trafficDelay: maxDelay > 0.7 ? `${Math.floor(Math.random() * 10 + 2)} min` : 'None',
      congestionLevel: time > 30 ? 'moderate' : 'low',
      mode
    });

    mapInstance.current.getView().fit(routeSource.current.getExtent(), { padding: [140, 80, 140, 80], duration: 1000 });
  }, []);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const map = new Map({
      target: mapRef.current,
      layers: [
        new TileLayer({
          source: new OSM({ url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT, crossOrigin: 'anonymous' }),
          zIndex: 0, properties: { id: 'base-layer' }
        }),
        new VectorLayer({ source: trafficSource.current, zIndex: 5, properties: { id: MapLayerType.TRAFFIC } }),
        new VectorLayer({ source: routeSource.current, zIndex: 10, properties: { id: MapLayerType.ROUTE } }),
        new VectorLayer({ 
          source: navMarkerSource.current, 
          zIndex: 100,
          style: new Style({
            image: new Circle({ radius: 13, fill: new Fill({ color: '#fff' }), stroke: new Stroke({ color: '#2563eb', width: 6 }) })
          })
        }),
        new VectorLayer({
          source: poiSource.current, zIndex: 30,
          style: () => new Style({
            image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) })
          }),
          properties: { id: 'pois' }
        })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true }),
      controls: []
    });

    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
    });

    map.on('postrender', () => {
      setMapRotation(map.getView().getRotation());
    });

    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      poiSource.current.addFeature(f);
    });

    const initTraffic = () => {
      const center = fromLonLat(DEFAULT_CENTER) as [number, number];
      for (let i = 0; i < 250; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = Math.random() * 20000;
        const coords: [number, number] = [center[0] + Math.cos(angle) * radius, center[1] + Math.sin(angle) * radius];
        const feature = new Feature(new Point(coords));
        const speed = 20 + Math.random() * 60;
        feature.set('speed', speed);
        vehiclesRef.current.push({ feature, speed: speed / 30, heading: Math.random() * Math.PI * 2, coords });
      }
      trafficSource.current.addFeatures(vehiclesRef.current.map(v => v.feature));
    };

    const animateTraffic = () => {
      const density = getTrafficDensity();
      vehiclesRef.current.forEach(v => {
        const s = v.speed * (1.8 / density);
        v.coords[0] += Math.cos(v.heading) * s;
        v.coords[1] += Math.sin(v.heading) * s;
        if (Math.random() > 0.99) v.heading += (Math.random() - 0.5) * 0.5;
        v.feature.getGeometry()?.setCoordinates(v.coords);
      });
      animationFrameId.current = requestAnimationFrame(animateTraffic);
    };

    initTraffic();
    animateTraffic();

    return () => cancelAnimationFrame(animationFrameId.current);
  }, []);

  useEffect(() => {
    if (!mapInstance.current) return;
    const layers = mapInstance.current.getLayers().getArray();
    const baseLayer = layers.find(l => l.get('id') === 'base-layer') as TileLayer<OSM>;
    if (!baseLayer) return;

    let sourceUrl = theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT;
    const customTypes = [MapLayerType.SATELLITE, MapLayerType.MINIMALIST, MapLayerType.RETRO, MapLayerType.INDUSTRIAL];
    for (const type of customTypes) {
      if (activeLayers.includes(type)) {
        sourceUrl = (MAP_SOURCES as any)[type.toUpperCase()];
        break;
      }
    }

    baseLayer.setSource(new OSM({ url: sourceUrl, crossOrigin: 'anonymous' }));
    layers.forEach(l => {
      const id = l.get('id');
      if (id === MapLayerType.TRAFFIC) l.setVisible(activeLayers.includes(MapLayerType.TRAFFIC));
      if (id === MapLayerType.ROUTE) l.setVisible(activeLayers.includes(MapLayerType.ROUTE));
    });
  }, [theme, activeLayers]);

  useEffect(() => {
    if (!mapInstance.current) return;
    mapInstance.current.getView().animate({
      rotation: is3D ? Math.PI / 4 : 0,
      zoom: is3D ? 17.5 : mapInstance.current.getView().getZoom(),
      duration: 1000
    });
  }, [is3D]);

  const toggleNavigation = () => {
    if (navState.isActive) {
      setNavState(prev => ({ ...prev, isActive: false }));
      navMarkerSource.current.clear();
      setIs3D(false);
    } else if (startPoint && endPoint) {
      setNavState(prev => ({ ...prev, isActive: true, progress: 0 }));
      setIs3D(true);
      const startC = fromLonLat(startPoint.coords);
      const endC = fromLonLat(endPoint.coords);
      const navMarker = new Feature(new Point(startC));
      navMarkerSource.current.clear();
      navMarkerSource.current.addFeature(navMarker);

      mapInstance.current?.getView().animate({ center: startC, zoom: 19.5, duration: 800 });

      let currentProgress = 0;
      const interval = setInterval(() => {
        currentProgress += 0.25;
        if (currentProgress >= 100) {
          clearInterval(interval);
          setNavState(prev => ({ ...prev, isActive: false }));
          navMarkerSource.current.clear();
          setIs3D(false);
          return;
        }

        const currentPos: [number, number] = [
          startC[0] + (endC[0] - startC[0]) * (currentProgress / 100),
          startC[1] + (endC[1] - startC[1]) * (currentProgress / 100)
        ];
        navMarker.getGeometry()?.setCoordinates(currentPos);
        mapInstance.current?.getView().setCenter(currentPos);

        setNavState(prev => ({ 
          ...prev, 
          progress: currentProgress, 
          distanceToTurn: `${Math.max(0, 800 - Math.floor(currentProgress * 8))}m`,
          currentStep: currentProgress > 70 ? "Arriving at Target" : "Guided route active"
        }));
      }, 100);
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme} language={language}
        onLanguageChange={setLanguage}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLocate={() => {
          navigator.geolocation.getCurrentPosition(pos => {
            const me: Destination = { id: 'me', name: { en: 'My Location', hi: 'मेरा स्थान', kn: 'ನನ್ನ ಸ್ಥಳ', es: 'Mi ubicación' }, category: { en: 'GPS', hi: 'जीपीएस', kn: 'ಜಿಪಿಎಸ್', es: 'GPS' }, coords: [pos.coords.longitude, pos.coords.latitude], description: { en: 'Live GPS coordinate', hi: 'जीपीएस', kn: 'ಜಿಪಿಎಸ್', es: 'GPS' }, image: '📍' };
            setStartPoint(me);
            mapInstance.current?.getView().animate({ center: fromLonLat(me.coords), zoom: 18, duration: 1000 });
          }, (err) => alert("Please enable location services"));
        }}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => {
          setSelectedPlace(dest);
          if (startPoint && !endPoint && startPoint.id !== dest.id) {
            setEndPoint(dest);
            calculateRoute(startPoint, dest, travelMode);
          } else {
            setStartPoint(dest);
            setEndPoint(null);
            setRouteInfo(null);
            routeSource.current.clear();
            mapInstance.current?.getView().animate({ center: fromLonLat(dest.coords), zoom: 17, duration: 900 });
          }
        }}
      />

      <AnimatePresence>
        {navState.isActive && (
          <motion.div initial={{ y: -160, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: -160, opacity: 0 }} className="fixed top-24 left-1/2 -translate-x-1/2 z-[2000] w-[94%] max-w-lg">
            <div className={`p-6 rounded-[36px] shadow-2xl flex items-center gap-6 border-2 border-blue-500/40 ${theme === MapTheme.DARK ? 'glass bg-slate-900/95' : 'glass-light bg-white/95'}`}>
              <div className="w-16 h-16 bg-blue-600 rounded-[22px] flex items-center justify-center text-3xl text-white shadow-xl">
                {navState.progress > 90 ? '📍' : '🚙'}
              </div>
              <div className="flex-1">
                <p className="text-3xl font-black tracking-tight leading-none mb-1 text-blue-500">{navState.distanceToTurn}</p>
                <p className="text-sm font-bold opacity-70 uppercase tracking-widest">{navState.currentStep}</p>
              </div>
              <button onClick={() => setNavState(prev => ({ ...prev, isActive: false }))} className="text-xs font-black uppercase tracking-widest text-red-500 py-3.5 px-6 rounded-2xl bg-red-500/10 hover:bg-red-500/20 transition-all border border-red-500/20">End</button>
            </div>
            <div className="w-full h-1.5 bg-white/10 mt-3 rounded-full overflow-hidden shadow-inner">
               <motion.div className="h-full bg-blue-500" initial={{ width: 0 }} animate={{ width: `${navState.progress}%` }} />
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={isOnline}
        onToggleLayer={(l) => {
          const baseStyles = [MapLayerType.STREET, MapLayerType.SATELLITE, MapLayerType.MINIMALIST, MapLayerType.RETRO, MapLayerType.INDUSTRIAL];
          if (baseStyles.includes(l)) {
            setActiveLayers(prev => [...prev.filter(x => !baseStyles.includes(x)), l]);
          } else {
            setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l]);
          }
        }}
      />

      <BottomPanel 
        theme={theme} language={language}
        startPoint={startPoint} endPoint={endPoint} routeInfo={routeInfo}
        selectedPlace={selectedPlace} onClosePlace={() => setSelectedPlace(null)}
        onStartNavigation={toggleNavigation}
        onDestinationSelect={(dest) => {
          setSelectedPlace(dest);
          if (startPoint && !endPoint && startPoint.id !== dest.id) {
            setEndPoint(dest);
            calculateRoute(startPoint, dest, travelMode);
          } else {
            setStartPoint(dest);
            setEndPoint(null);
            setRouteInfo(null);
            routeSource.current.clear();
            mapInstance.current?.getView().animate({ center: fromLonLat(dest.coords), zoom: 16.5, duration: 1000 });
          }
        }}
        onClearRoute={() => { setStartPoint(null); setEndPoint(null); setRouteInfo(null); routeSource.current.clear(); navMarkerSource.current.clear(); }}
        offlineRegions={offlineRegions}
        onRegionClick={(r) => mapInstance.current?.getView().animate({ center: fromLonLat(r.center), zoom: r.zoom, duration: 1400 })}
        onRegionDelete={(id) => setOfflineRegions(prev => prev.filter(x => x.id !== id))}
        onTravelModeChange={(m) => {
          setTravelMode(m);
          if (startPoint && endPoint) calculateRoute(startPoint, endPoint, m);
        }}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, rotation: 0, duration: 1000 })}
        onVoice={() => {}}
        on3D={() => setIs3D(!is3D)}
        is3D={is3D}
        rotation={mapRotation}
      />

      <motion.div layout className={`fixed top-24 left-6 z-[900] p-5 rounded-[36px] hidden lg:block ${theme === MapTheme.DARK ? 'glass' : 'glass-light'} shadow-2xl min-w-[260px]`}>
        <div className="flex items-center gap-3 mb-3">
          <span className={`w-3 h-3 rounded-full animate-pulse ${getTrafficDensity() > 2.0 ? 'bg-orange-500' : 'bg-emerald-500'}`} />
          <span className="text-[10px] font-black uppercase tracking-widest opacity-50">System Telemetry</span>
        </div>
        <div className="text-3xl font-black tracking-tight">{weather.temp}°C {weather.condition}</div>
        <div className="text-[10px] opacity-40 mt-3 font-bold flex items-center gap-2">
           Network Load: {(getTrafficDensity() * 12).toFixed(1)}% Active
        </div>
      </motion.div>

      <motion.div 
        animate={{ opacity: theme === MapTheme.DARK ? 0.3 : 0.05 }}
        className="absolute inset-0 pointer-events-none transition-opacity duration-1000 z-[1]" 
        style={{ background: theme === MapTheme.DARK ? 'radial-gradient(circle at center, transparent 40%, #000 150%)' : 'radial-gradient(circle at center, transparent 60%, #3b82f6 240%)' }} 
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Destination, MapTheme, RouteInfo, Language, OfflineRegion, TravelMode } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';

interface BottomPanelProps {
  theme: MapTheme;
  language: Language;
  onDestinationSelect: (d: Destination) => void;
  startPoint: Destination | null;
  endPoint: Destination | null;
  routeInfo: RouteInfo | null;
  onClearRoute: () => void;
  offlineRegions: OfflineRegion[];
  onRegionClick: (r: OfflineRegion) => void;
  onRegionDelete: (id: string) => void;
  onTravelModeChange: (mode: TravelMode) => void;
  selectedPlace: Destination | null;
  onClosePlace: () => void;
  onStartNavigation?: () => void;
}

export const BottomPanel: React.FC<BottomPanelProps> = ({ 
  theme, 
  language,
  onDestinationSelect,
  startPoint,
  endPoint,
  routeInfo,
  onClearRoute,
  offlineRegions,
  onRegionClick,
  onRegionDelete,
  onTravelModeChange,
  selectedPlace,
  onClosePlace,
  onStartNavigation
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [activeTab, setActiveTab] = useState<'explore' | 'route' | 'offline' | 'saved'>('explore');
  const [favorites, setFavorites] = useState<string[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language] || TRANSLATIONS['en'];

  useEffect(() => {
    if (startPoint || endPoint) {
      setActiveTab('route');
      setIsExpanded(true);
    }
  }, [startPoint, endPoint]);

  useEffect(() => {
    if (selectedPlace) {
      setIsExpanded(true);
      scrollRef.current?.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedPlace]);

  useEffect(() => {
    const saved = localStorage.getItem('disha_favorites');
    if (saved) setFavorites(JSON.parse(saved));
  }, []);

  const toggleFavorite = (id: string) => {
    const next = favorites.includes(id) ? favorites.filter(f => f !== id) : [...favorites, id];
    setFavorites(next);
    localStorage.setItem('disha_favorites', JSON.stringify(next));
  };

  return (
    <motion.div 
      initial={false}
      animate={{ height: isExpanded ? 'calc(80vh)' : '80px' }}
      transition={{ type: 'spring', damping: 28, stiffness: 220 }}
      className={`fixed bottom-0 left-0 right-0 z-[1300] rounded-t-[48px] shadow-[0_-20px_60px_rgba(0,0,0,0.4)] overflow-hidden flex flex-col ${theme === MapTheme.DARK ? 'glass bg-slate-950/90' : 'glass-light bg-white/95'}`}
    >
      {/* Handle & Pull Header */}
      <div 
        className="h-16 flex items-center justify-between px-10 shrink-0 cursor-pointer active:scale-95 transition-transform"
        onClick={() => setIsExpanded(!isExpanded)}
      >
        <div className="flex-1 flex justify-center translate-x-4">
          <div className={`w-16 h-2 rounded-full transition-colors ${theme === MapTheme.DARK ? 'bg-white/10 group-hover:bg-white/30' : 'bg-black/10 group-hover:bg-black/20'}`} />
        </div>

        {isExpanded && (
          <button 
            onClick={(e) => { e.stopPropagation(); setIsExpanded(false); }}
            className={`w-10 h-10 rounded-full flex items-center justify-center transition-all shadow-sm ${theme === MapTheme.DARK ? 'bg-white/5 hover:bg-white/10 text-white' : 'bg-black/5 hover:bg-black/10 text-slate-900'}`}
          >
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m6 9 6 6 6-6"/></svg>
          </button>
        )}
      </div>

      <AnimatePresence mode="wait">
        {isExpanded && (
          <motion.div 
            key="content"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="flex-1 overflow-hidden flex flex-col relative"
          >
            <div ref={scrollRef} className="flex-1 overflow-y-auto custom-scrollbar px-6 lg:px-12 pb-[120px]">
              {selectedPlace ? (
                <div className="space-y-10 pt-4">
                  <div className="flex justify-between items-start">
                    <div className="flex items-center gap-8">
                      <span className="text-8xl hover:scale-110 transition-transform">{selectedPlace.image}</span>
                      <div>
                        <h2 className={`text-4xl font-black leading-tight ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{selectedPlace.name[language] || selectedPlace.name['en']}</h2>
                        <p className="text-blue-600 font-black uppercase tracking-widest text-[12px] mt-1">{selectedPlace.category[language] || selectedPlace.category['en']}</p>
                      </div>
                    </div>
                    <button onClick={onClosePlace} className={`w-14 h-14 rounded-[22px] flex items-center justify-center text-xl transition-all ${theme === MapTheme.DARK ? 'bg-white/5 hover:bg-white/10 text-white' : 'bg-black/5 hover:bg-black/10 text-slate-900'}`}>✕</button>
                  </div>

                  <div className="space-y-12">
                    <section>
                      <h3 className="text-[11px] font-black uppercase tracking-[0.3em] opacity-40 mb-4 text-blue-500">Summary</h3>
                      <p className={`text-xl leading-relaxed font-semibold ${theme === MapTheme.DARK ? 'text-white/80' : 'text-slate-700'}`}>
                        {selectedPlace.description[language] || selectedPlace.description['en']}
                      </p>
                    </section>

                    {selectedPlace.reviews && (
                      <section>
                        <h3 className="text-[11px] font-black uppercase tracking-[0.3em] opacity-40 mb-6 text-blue-500">Visitor Intel</h3>
                        <div className="space-y-6">
                          {selectedPlace.reviews.map((r, i) => (
                            <div key={i} className={`p-8 rounded-[40px] border ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5' : 'bg-black/5 border-black/5'}`}>
                              <div className="flex justify-between items-center mb-3">
                                <span className="font-black text-base">{r.author}</span>
                                <div className="flex text-yellow-500 gap-1">{'★'.repeat(r.rating)}</div>
                              </div>
                              <p className="text-base opacity-70 font-medium italic leading-relaxed">"{r.text[language] || r.text['en']}"</p>
                            </div>
                          ))}
                        </div>
                      </section>
                    )}
                  </div>
                </div>
              ) : (
                <>
                  <div className="flex gap-8 mb-8 border-b border-white/5 pb-2 shrink-0 overflow-x-auto no-scrollbar">
                    {[
                      { id: 'explore', label: t.explore },
                      { id: 'route', label: t.directions },
                      { id: 'saved', label: 'Library' },
                      { id: 'offline', label: 'Cached' }
                    ].map(tab => (
                      <button 
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id as any)}
                        className={`pb-4 px-2 font-black text-[13px] tracking-[0.2em] transition-all relative whitespace-nowrap ${activeTab === tab.id ? 'text-blue-500' : 'text-slate-500 opacity-60 hover:opacity-100'}`}
                      >
                        {tab.label.toUpperCase()}
                        {activeTab === tab.id && <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-1.5 bg-blue-500 rounded-full" />}
                      </button>
                    ))}
                  </div>

                  <div className="space-y-8">
                    {activeTab === 'explore' ? (
                      <div className="space-y-10">
                        <div className="flex gap-4 overflow-x-auto no-scrollbar py-2">
                          {['Dining', 'Fuel', 'Parks', 'History', 'Groceries'].map(cat => (
                            <button key={cat} className={`px-8 py-3.5 rounded-full whitespace-nowrap text-[11px] font-black uppercase tracking-widest border transition-all ${theme === MapTheme.DARK ? 'bg-white/5 border-white/10 text-white/50 hover:bg-white/10 hover:text-white' : 'bg-white border-black/5 text-slate-500 shadow-sm'}`}>
                              {cat}
                            </button>
                          ))}
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
                          {POPULAR_DESTINATIONS.map(dest => (
                            <div 
                              key={dest.id} 
                              onClick={() => onDestinationSelect(dest)}
                              className={`group p-10 rounded-[48px] cursor-pointer transition-all border border-transparent hover:border-blue-500/30 ${theme === MapTheme.DARK ? 'bg-white/5 hover:bg-white/10' : 'bg-white hover:bg-blue-50 shadow-lg'}`}
                            >
                              <div className="text-7xl mb-6 group-hover:scale-110 transition-transform origin-left">{dest.image}</div>
                              <h4 className="font-black text-2xl mb-2">{dest.name[language] || dest.name['en']}</h4>
                              <p className="text-[11px] font-black uppercase tracking-[0.3em] opacity-40 text-blue-600">{dest.category[language] || dest.category['en']}</p>
                            </div>
                          ))}
                        </div>
                      </div>
                    ) : activeTab === 'route' ? (
                      <div className="space-y-8">
                        <div className={`flex gap-4 p-3 rounded-[32px] ${theme === MapTheme.DARK ? 'bg-white/5' : 'bg-black/5'}`}>
                          {[
                            { id: 'driving', icon: '🚗' },
                            { id: 'walking', icon: '🚶' },
                            { id: 'cycling', icon: '🚲' },
                            { id: 'transit', icon: '🚌' }
                          ].map(m => (
                            <button 
                              key={m.id}
                              onClick={() => onTravelModeChange(m.id as TravelMode)}
                              className={`flex-1 py-5 rounded-[24px] text-4xl transition-all ${routeInfo?.mode === m.id ? 'bg-blue-600 shadow-2xl text-white' : 'opacity-40 hover:opacity-100 hover:bg-white/5'}`}
                            >
                              {m.icon}
                            </button>
                          ))}
                        </div>

                        {routeInfo ? (
                          <div className={`p-10 rounded-[56px] border-2 border-blue-600/30 shadow-[0_25px_60px_rgba(37,99,235,0.15)] relative overflow-hidden ${theme === MapTheme.DARK ? 'bg-blue-600/5' : 'bg-blue-50/70'}`}>
                            <div className="grid grid-cols-3 gap-8 text-center">
                              <div>
                                <p className="text-[11px] font-black opacity-40 uppercase mb-2 tracking-[0.2em]">ETA</p>
                                <p className={`text-5xl font-black ${routeInfo.congestionLevel === 'heavy' ? 'text-red-500' : 'text-blue-600'}`}>{routeInfo.duration}</p>
                              </div>
                              <div>
                                <p className="text-[11px] font-black opacity-40 uppercase mb-2 tracking-[0.2em]">Distance</p>
                                <p className="text-4xl font-black">{routeInfo.distance}</p>
                              </div>
                              <div>
                                <p className="text-[11px] font-black opacity-40 uppercase mb-2 tracking-[0.2em]">Load</p>
                                <p className={`text-4xl font-black ${routeInfo.trafficDelay === 'None' ? 'text-emerald-500' : 'text-red-500'}`}>{routeInfo.trafficDelay}</p>
                              </div>
                            </div>
                          </div>
                        ) : (
                          <div className="flex flex-col items-center justify-center py-24 opacity-20 text-center space-y-8">
                            <span className="text-9xl">🧭</span>
                            <p className="font-black uppercase tracking-[0.4em] max-w-[280px] leading-loose">Select a point to initialize drive-path analysis</p>
                          </div>
                        )}
                      </div>
                    ) : activeTab === 'saved' ? (
                      <div className="grid grid-cols-1 gap-6">
                        {POPULAR_DESTINATIONS.filter(d => favorites.includes(d.id)).length > 0 ? (
                          POPULAR_DESTINATIONS.filter(d => favorites.includes(d.id)).map(dest => (
                            <div 
                              key={dest.id} 
                              onClick={() => onDestinationSelect(dest)}
