                              </div>
                              <span className="text-red-500 text-3xl">❤️</span>
                            </div>
                          ))
                        ) : (
                          <div className="text-center py-24 opacity-20 font-black uppercase tracking-[0.3em]">No saved assets</div>
                        )}
                      </div>
                    ) : (
                      <div className="space-y-6">
                        {offlineRegions.length > 0 ? offlineRegions.map(r => (
                          <div key={r.id} className={`p-8 rounded-[42px] flex justify-between items-center border transition-all ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5' : 'bg-white shadow-xl border-slate-100'}`}>
                            <div>
                              <p className="font-black text-2xl">{r.name}</p>
                              <p className="text-[12px] font-bold opacity-40 mt-1 uppercase tracking-[0.15em]">{r.date} • {r.size}</p>
                            </div>
                            <div className="flex gap-4">
                               <button onClick={() => onRegionDelete(r.id)} className="w-14 h-14 rounded-[18px] bg-red-500/10 text-red-500 hover:bg-red-500 hover:text-white transition-all flex items-center justify-center">🗑️</button>
                               <button onClick={() => onRegionClick(r)} className="px-8 py-3 bg-blue-600 text-white rounded-[18px] text-[12px] font-black uppercase tracking-[0.2em] shadow-lg shadow-blue-600/30">Sync</button>
                            </div>
                          </div>
                        )) : (
                          <div className="text-center py-24 opacity-20 font-black uppercase tracking-[0.3em]">Global cache clear</div>
                        )}
                      </div>
