            {/* FIXED ACTION FOOTER - Anchor buttons so they don't glitch away */}
            <AnimatePresence>
              {(selectedPlace || routeInfo) && (
                <motion.div 
                  initial={{ y: 100 }}
                  animate={{ y: 0 }}
                  exit={{ y: 100 }}
                  className={`absolute bottom-0 left-0 right-0 p-8 pt-4 pb-12 z-[10] border-t ${theme === MapTheme.DARK ? 'glass border-white/5' : 'glass-light border-black/5'}`}
                >
                  <div className="flex gap-4">
                    {selectedPlace && !routeInfo && (
                      <>
                        <button 
                          onClick={() => toggleFavorite(selectedPlace.id)}
                          className={`flex-1 py-5 rounded-[26px] font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-3 transition-all ${favorites.includes(selectedPlace.id) ? 'bg-red-500 text-white' : 'bg-white/5 hover:bg-white/10 border border-white/10'}`}
                        >
                          {favorites.includes(selectedPlace.id) ? 'Saved' : 'Save'}
                        </button>
                        <button 
                          onClick={() => onDestinationSelect(selectedPlace)}
                          className="flex-[2] py-5 bg-blue-600 text-white rounded-[26px] font-black text-xs uppercase tracking-[0.2em] shadow-2xl"
                        >
                          Get Route
                        </button>
                      </>
                    )}
                    {routeInfo && (
                      <>
                        <button onClick={onClearRoute} className={`flex-1 py-5 rounded-[26px] font-black text-xs uppercase tracking-[0.2em] transition-all ${theme === MapTheme.DARK ? 'bg-white/5 text-white hover:bg-white/10' : 'bg-white text-slate-900 border border-slate-200 shadow-sm'}`}>Cancel</button>
                        <button onClick={onStartNavigation} className="flex-[2] py-5 bg-blue-600 text-white rounded-[26px] font-black text-xs uppercase tracking-[0.2em] shadow-2xl shadow-blue-600/40 hover:bg-blue-500 transition-all">Start Guidance</button>
                      </>
                    )}
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
