interface HeaderProps {
  theme: MapTheme;
  language: Language;
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
}

const LogoIcon = () => (
  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="3.5" fill="currentColor"/>
  </svg>
);

export const Header: React.FC<HeaderProps> = ({ 
  theme, 
  language,
  onThemeToggle, 
  onLocate, 
  onOpenLayers,
  onSuggestionSelect 
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<Destination[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (!query.trim()) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(() => {
      const q = query.toLowerCase();
      // Weighted Fuzzy Matching Logic
      const ranked = POPULAR_DESTINATIONS.map(dest => {
        let score = 0;
        if (dest.name[language].toLowerCase().startsWith(q)) score += 10;
        else if (dest.name[language].toLowerCase().includes(q)) score += 5;

        if (dest.category[language].toLowerCase().includes(q)) score += 3;
        if (dest.description[language].toLowerCase().includes(q)) score += 1;

        return { dest, score };
      })
      .filter(item => item.score > 0)
      .sort((a, b) => b.score - a.score)
      .map(item => item.dest)
      .slice(0, 10);

      setSuggestions(ranked);
    }, 100);

    return () => clearTimeout(timer);
  }, [query, language]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsFocused(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSelect = (dest: Destination) => {
    setQuery(dest.name[language]);
    setSuggestions([]);
    setIsFocused(false);
    onSuggestionSelect(dest);
  };

  return (
    <motion.header 
      initial={{ y: -100, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[1900] p-5 flex justify-center pointer-events-none"
