          <div className="w-12 h-12 bg-blue-600 rounded-[18px] flex items-center justify-center text-white shadow-xl shrink-0">
            <LogoIcon />
          </div>
          <span className="font-black text-2xl tracking-tighter hidden sm:block">Disha</span>
        </div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-8 py-3 rounded-[30px] shadow-2xl transition-all group h-[64px] ${
            theme === MapTheme.DARK 
              ? `glass ${isFocused ? 'ring-2 ring-blue-500 bg-slate-900' : 'hover:bg-slate-900/60'}` 
              : `glass-light ${isFocused ? 'ring-2 ring-blue-500 bg-white' : 'hover:bg-white/95'}`
          }`}>
            <span className={`mr-4 transition-colors shrink-0 ${isFocused ? 'text-blue-500 scale-110' : 'text-slate-400 opacity-60'}`}>
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
            </span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onChange={(e) => setQuery(e.target.value)}
              placeholder={t.searchPlaceholder}
              className="bg-transparent border-none outline-none w-full text-lg font-black tracking-tight placeholder:text-slate-500/40"
              style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
            />
          </div>

          <AnimatePresence>
            {isFocused && (
              <motion.div
                initial={{ opacity: 0, y: 15, scale: 0.98 }}
                animate={{ opacity: 1, y: 12, scale: 1 }}
                exit={{ opacity: 0, y: 15, scale: 0.98 }}
                className={`absolute top-full left-0 right-0 rounded-[40px] shadow-[0_30px_90px_rgba(0,0,0,0.5)] overflow-hidden border ${
                  theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'
                }`}
              >
                <div className="max-h-[65vh] overflow-y-auto py-6 custom-scrollbar">
                  {suggestions.length > 0 ? (
                    <div>
                      <div className="text-[11px] font-black uppercase tracking-[0.3em] text-blue-500 mb-4 px-10">Optimized Results</div>
                      {suggestions.map((dest) => (
