                            <span className="text-4xl shrink-0 grayscale opacity-40">{dest.image}</span>
                            <div className="flex flex-col">
                              <span className="text-lg font-black opacity-80">{dest.name[language]}</span>
                              <span className="text-[10px] opacity-30 uppercase font-black tracking-widest">{dest.category[language]}</span>
