          </AnimatePresence>
        </div>

        <div className="flex gap-3 shrink-0">
          <button 
            onClick={onOpenLayers}
            className={`w-[64px] h-[64px] rounded-[24px] flex items-center justify-center shadow-2xl transition-all hover:scale-110 active:scale-90 ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}
          >
            <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline><polyline points="2 12 12 17 22 12"></polyline></svg>
          </button>
          <button 
            onClick={onThemeToggle}
            className={`w-[64px] h-[64px] rounded-[24px] flex items-center justify-center shadow-2xl transition-all hover:scale-110 active:scale-90 ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600'}`}
          >
