import React, { useEffect, useRef, useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import OSM from 'ol/source/OSM';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import { getDistance } from 'ol/sphere';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, OfflineRegion, TravelMode, NavigationState } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, TRAFFIC_COLORS, TRANSLATIONS, POPULAR_DESTINATIONS, ROUTE_FACTORS } from './constants';

interface Vehicle {
  feature: Feature<Point>;
  speed: number;
  heading: number;
  coords: [number, number];
}

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const trafficSource = useRef<VectorSource>(new VectorSource());
  const routeSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const navMarkerSource = useRef<VectorSource>(new VectorSource());
  const vehiclesRef = useRef<Vehicle[]>([]);
  const animationFrameId = useRef<number>(0);

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  // Traffic strictly disabled at start
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET, MapLayerType.ROUTE]);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [weather, setWeather] = useState({ temp: 24, condition: 'Clear Sky' });
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [offlineRegions, setOfflineRegions] = useState<OfflineRegion[]>([]);
  const [travelMode, setTravelMode] = useState<TravelMode>('driving');
  const [is3D, setIs3D] = useState(false);
  const [mapRotation, setMapRotation] = useState(0);

  const [startPoint, setStartPoint] = useState<Destination | null>(null);
  const [endPoint, setEndPoint] = useState<Destination | null>(null);
  const [routeInfo, setRouteInfo] = useState<RouteInfo | null>(null);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [navState, setNavState] = useState<NavigationState>({
    isActive: false,
    currentStep: "Proceed to the highlighted route",
    distanceToTurn: "0m",
    progress: 0
  });

  useEffect(() => {
    const handleStatus = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatus);
    window.addEventListener('offline', handleStatus);
    return () => {
      window.removeEventListener('online', handleStatus);
      window.removeEventListener('offline', handleStatus);
    };
  }, []);

  const getTrafficDensity = useCallback(() => {
    const hour = currentTime.getHours() + currentTime.getMinutes() / 60;
    const peak1 = 9; // Morning Rush
    const peak2 = 18; // Evening Rush
    const density = 1.0 + (Math.exp(-Math.pow(hour - peak1, 2) / 2) + Math.exp(-Math.pow(hour - peak2, 2) / 2)) * 2.2;
    return density;
  }, [currentTime]);

  const calculateRoute = useCallback((start: Destination, end: Destination, mode: TravelMode) => {
    if (!mapInstance.current) return;

    // Accurate Geodesic Distance Calculation
    const geodesicDist = getDistance(start.coords, end.coords) / 1000; // in km

    const startC = fromLonLat(start.coords) as [number, number];
    const endC = fromLonLat(end.coords) as [number, number];

    const steps = 30;
    const allCoords: [number, number][] = [startC];

    // Generate complex grid-following path
    for (let i = 1; i < steps; i++) {
       const p = i / steps;
       const noise = (Math.random() - 0.5) * 500;
       allCoords.push([
          startC[0] + (endC[0] - startC[0]) * p + (i % 2 === 0 ? noise : -noise),
          startC[1] + (endC[1] - startC[1]) * p + (i % 3 === 0 ? -noise : noise)
       ]);
    }
    allCoords.push(endC);

    routeSource.current.clear();
    let totalDelay = 0;
    let maxCongestion = 0;

    for (let i = 0; i < allCoords.length - 1; i++) {
      const segmentCoords = [allCoords[i], allCoords[i+1]];
      const roll = Math.random();
      if (roll > maxCongestion) maxCongestion = roll;

      const status: 'fast' | 'medium' | 'slow' = roll > 0.88 ? 'slow' : roll > 0.65 ? 'medium' : 'fast';
      const feature = new Feature(new LineString(segmentCoords));
      const color = status === 'slow' ? TRAFFIC_COLORS.SLOW : status === 'medium' ? TRAFFIC_COLORS.MEDIUM : '#3b82f6';

      if (status === 'slow') totalDelay += Math.random() * 5;

      feature.setStyle(new Style({
        stroke: new Stroke({ color, width: 14, lineCap: 'round', lineJoin: 'round' })
      }));
      routeSource.current.addFeature(feature);
    }

    const baseTime = geodesicDist * (ROUTE_FACTORS[mode] || 2.2);
    const timeWithTraffic = Math.round(baseTime + totalDelay);

    setRouteInfo({
      distance: `${geodesicDist.toFixed(2)} km`,
      duration: `${timeWithTraffic} min`,
      trafficDelay: totalDelay > 2 ? `${Math.floor(totalDelay)} min` : 'None',
      congestionLevel: maxCongestion > 0.85 ? 'heavy' : 'low',
      mode
    });

    mapInstance.current.getView().fit(routeSource.current.getExtent(), { 
      padding: [160, 100, 160, 100], 
      duration: 1200,
      easing: (t) => t * (2 - t)
    });
  }, []);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const map = new Map({
      target: mapRef.current,
      layers: [
        new TileLayer({
          source: new OSM({ url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT, crossOrigin: 'anonymous' }),
          zIndex: 0, properties: { id: 'base-layer' }
        }),
        new VectorLayer({ source: trafficSource.current, zIndex: 5, properties: { id: MapLayerType.TRAFFIC } }),
        new VectorLayer({ source: routeSource.current, zIndex: 10, properties: { id: MapLayerType.ROUTE } }),
        new VectorLayer({ 
          source: navMarkerSource.current, 
          zIndex: 150,
          style: new Style({
            image: new Circle({ 
              radius: 14, 
              fill: new Fill({ color: '#fff' }), 
              stroke: new Stroke({ color: '#2563eb', width: 6 }) 
            })
          })
        }),
        new VectorLayer({
          source: poiSource.current, zIndex: 40,
          style: () => new Style({
            image: new Circle({ radius: 10, fill: new Fill({ color: '#2563eb' }), stroke: new Stroke({ color: '#fff', width: 3 }) })
          }),
          properties: { id: 'pois' }
        })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true }),
      controls: []
    });

    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
    });

    map.on('postrender', () => {
      setMapRotation(map.getView().getRotation());
    });

    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      poiSource.current.addFeature(f);
    });

    const initTraffic = () => {
      const center = fromLonLat(DEFAULT_CENTER) as [number, number];
      for (let i = 0; i < 280; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = Math.random() * 25000;
        const coords: [number, number] = [center[0] + Math.cos(angle) * radius, center[1] + Math.sin(angle) * radius];
        const feature = new Feature(new Point(coords));
        const speed = 25 + Math.random() * 80;
        feature.set('speed', speed);
        vehiclesRef.current.push({ feature, speed: speed / 35, heading: Math.random() * Math.PI * 2, coords });
      }
      trafficSource.current.addFeatures(vehiclesRef.current.map(v => v.feature));
    };

    const animateTraffic = () => {
      const density = getTrafficDensity();
      vehiclesRef.current.forEach(v => {
        const s = v.speed * (2.0 / density);
        v.coords[0] += Math.cos(v.heading) * s;
        v.coords[1] += Math.sin(v.heading) * s;
        if (Math.random() > 0.992) v.heading += (Math.random() - 0.5) * 0.4;
        v.feature.getGeometry()?.setCoordinates(v.coords);
      });
      animationFrameId.current = requestAnimationFrame(animateTraffic);
    };

    initTraffic();
    animateTraffic();

    return () => cancelAnimationFrame(animationFrameId.current);
  }, []);

  useEffect(() => {
    if (!mapInstance.current) return;
    const layers = mapInstance.current.getLayers().getArray();
    const baseLayer = layers.find(l => l.get('id') === 'base-layer') as TileLayer<OSM>;
    if (!baseLayer) return;

    let sourceUrl = theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT;
    const styles = [MapLayerType.SATELLITE, MapLayerType.MINIMALIST, MapLayerType.RETRO, MapLayerType.INDUSTRIAL];
    for (const style of styles) {
      if (activeLayers.includes(style)) {
        sourceUrl = (MAP_SOURCES as any)[style.toUpperCase()];
        break;
      }
    }

    baseLayer.setSource(new OSM({ url: sourceUrl, crossOrigin: 'anonymous' }));
    layers.forEach(l => {
      const id = l.get('id');
      if (id === MapLayerType.TRAFFIC) l.setVisible(activeLayers.includes(MapLayerType.TRAFFIC));
      if (id === MapLayerType.ROUTE) l.setVisible(activeLayers.includes(MapLayerType.ROUTE));
    });
  }, [theme, activeLayers]);

  useEffect(() => {
    if (!mapInstance.current) return;
    mapInstance.current.getView().animate({
      rotation: is3D ? Math.PI / 4 : 0,
      zoom: is3D ? 17.8 : mapInstance.current.getView().getZoom(),
      duration: 1200
    });
  }, [is3D]);

  const toggleNavigation = () => {
    if (navState.isActive) {
      setNavState(prev => ({ ...prev, isActive: false }));
      navMarkerSource.current.clear();
      setIs3D(false);
    } else if (startPoint && endPoint) {
      setNavState(prev => ({ ...prev, isActive: true, progress: 0 }));
      setIs3D(true);
      const startC = fromLonLat(startPoint.coords);
      const endC = fromLonLat(endPoint.coords);
      const navMarker = new Feature(new Point(startC));
      navMarkerSource.current.clear();
      navMarkerSource.current.addFeature(navMarker);

      mapInstance.current?.getView().animate({ center: startC, zoom: 20, duration: 1000 });

      let currentProgress = 0;
      const interval = setInterval(() => {
        currentProgress += 0.3;
        if (currentProgress >= 100) {
          clearInterval(interval);
          setNavState(prev => ({ ...prev, isActive: false }));
          navMarkerSource.current.clear();
          setIs3D(false);
          return;
        }

        const currentPos: [number, number] = [
          startC[0] + (endC[0] - startC[0]) * (currentProgress / 100),
          startC[1] + (endC[1] - startC[1]) * (currentProgress / 100)
        ];
        navMarker.getGeometry()?.setCoordinates(currentPos);
        mapInstance.current?.getView().setCenter(currentPos);

        setNavState(prev => ({ 
          ...prev, 
          progress: currentProgress, 
          distanceToTurn: `${Math.max(0, 1000 - Math.floor(currentProgress * 10))}m`,
          currentStep: currentProgress > 80 ? "Arriving at Destination" : "Continue on planned path"
        }));
      }, 100);
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme} language={language}
        onLanguageChange={setLanguage}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLocate={() => {
          navigator.geolocation.getCurrentPosition(pos => {
            const me: Destination = { 
              id: 'me', 
              name: { en: 'Live Location', hi: 'मेरा स्थान', kn: 'ನನ್ನ ಸ್ಥಳ', es: 'Mi ubicación' }, 
              category: { en: 'GPS', hi: 'जीपीएस', kn: 'ಜಿಪಿಎಸ್', es: 'GPS' }, 
              coords: [pos.coords.longitude, pos.coords.latitude], 
              description: { en: 'Precision GPS Locked', hi: 'जीपीएस', kn: 'ಜಿಪಿಎಸ್', es: 'GPS' }, 
              image: '📍' 
            };
            setStartPoint(me);
            mapInstance.current?.getView().animate({ center: fromLonLat(me.coords), zoom: 18.5, duration: 1000 });
          }, () => alert("Location access denied. Please check browser permissions."));
        }}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => {
          setSelectedPlace(dest);
          if (startPoint && !endPoint && startPoint.id !== dest.id) {
            setEndPoint(dest);
            calculateRoute(startPoint, dest, travelMode);
          } else {
            setStartPoint(dest);
            setEndPoint(null);
            setRouteInfo(null);
            routeSource.current.clear();
            mapInstance.current?.getView().animate({ center: fromLonLat(dest.coords), zoom: 17, duration: 1100 });
          }
        }}
      />

      <AnimatePresence>
        {navState.isActive && (
          <motion.div initial={{ y: -180, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: -180, opacity: 0 }} className="fixed top-24 left-1/2 -translate-x-1/2 z-[2000] w-[95%] max-w-lg">
            <div className={`p-7 rounded-[40px] shadow-2xl flex items-center gap-7 border-2 border-blue-500/50 ${theme === MapTheme.DARK ? 'glass bg-slate-900/98' : 'glass-light bg-white/98'}`}>
              <div className="w-20 h-20 bg-blue-600 rounded-[28px] flex items-center justify-center text-4xl text-white shadow-xl">
                {navState.progress > 85 ? '🚩' : '🚘'}
              </div>
              <div className="flex-1">
                <p className="text-4xl font-black tracking-tighter leading-none mb-1 text-blue-500">{navState.distanceToTurn}</p>
                <p className="text-sm font-bold opacity-80 uppercase tracking-widest">{navState.currentStep}</p>
              </div>
              <button onClick={() => setNavState(prev => ({ ...prev, isActive: false }))} className="text-[10px] font-black uppercase tracking-widest text-red-500 py-4 px-7 rounded-2xl bg-red-500/10 hover:bg-red-500/20 transition-all border border-red-500/30">Stop</button>
            </div>
            <div className="w-full h-2 bg-white/10 mt-4 rounded-full overflow-hidden border border-white/5">
               <motion.div className="h-full bg-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.6)]" initial={{ width: 0 }} animate={{ width: `${navState.progress}%` }} />
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={isOnline}
        onToggleLayer={(l) => {
          const bases = [MapLayerType.STREET, MapLayerType.SATELLITE, MapLayerType.MINIMALIST, MapLayerType.RETRO, MapLayerType.INDUSTRIAL];
          if (bases.includes(l)) {
            setActiveLayers(prev => [...prev.filter(x => !bases.includes(x)), l]);
          } else {
            setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l]);
          }
        }}
      />

      <BottomPanel 
        theme={theme} language={language}
        startPoint={startPoint} endPoint={endPoint} routeInfo={routeInfo}
        selectedPlace={selectedPlace} onClosePlace={() => setSelectedPlace(null)}
        onStartNavigation={toggleNavigation}
        onDestinationSelect={(dest) => {
          setSelectedPlace(dest);
          if (startPoint && !endPoint && startPoint.id !== dest.id) {
            setEndPoint(dest);
            calculateRoute(startPoint, dest, travelMode);
          } else {
            setStartPoint(dest);
            setEndPoint(null);
            setRouteInfo(null);
            routeSource.current.clear();
            mapInstance.current?.getView().animate({ center: fromLonLat(dest.coords), zoom: 17, duration: 1100 });
          }
        }}
        onClearRoute={() => { setStartPoint(null); setEndPoint(null); setRouteInfo(null); routeSource.current.clear(); navMarkerSource.current.clear(); }}
        offlineRegions={offlineRegions}
        onRegionClick={(r) => mapInstance.current?.getView().animate({ center: fromLonLat(r.center), zoom: r.zoom, duration: 1500 })}
        onRegionDelete={(id) => setOfflineRegions(prev => prev.filter(x => x.id !== id))}
        onTravelModeChange={(m) => {
          setTravelMode(m);
          if (startPoint && endPoint) calculateRoute(startPoint, endPoint, m);
        }}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, rotation: 0, duration: 1000 })}
        onVoice={() => {}}
        on3D={() => setIs3D(!is3D)}
        is3D={is3D}
        rotation={mapRotation}
      />

      {/* Telemetry Display */}
      <motion.div layout className={`fixed top-24 left-7 z-[900] p-6 rounded-[42px] hidden lg:block ${theme === MapTheme.DARK ? 'glass' : 'glass-light'} shadow-2xl min-w-[280px]`}>
        <div className="flex items-center gap-3 mb-4">
          <span className={`w-3.5 h-3.5 rounded-full animate-pulse ${getTrafficDensity() > 2.0 ? 'bg-amber-500' : 'bg-emerald-500'}`} />
          <span className="text-[11px] font-black uppercase tracking-[0.3em] opacity-50">Global Telemetry</span>
        </div>
        <div className="text-4xl font-black tracking-tight mb-1">{weather.temp}°C</div>
        <div className="text-xs font-bold opacity-60 uppercase tracking-widest">{weather.condition}</div>
        <div className="text-[10px] opacity-40 mt-5 font-black border-t border-white/5 pt-4">
           ACTIVE NODES: {(getTrafficDensity() * 14).toFixed(0)} • BANDWIDTH: 98%
        </div>
      </motion.div>

      <motion.div 
        animate={{ opacity: theme === MapTheme.DARK ? 0.35 : 0.05 }}
        className="absolute inset-0 pointer-events-none transition-opacity duration-1000 z-[1]" 
        style={{ background: theme === MapTheme.DARK ? 'radial-gradient(circle at center, transparent 40%, #000 160%)' : 'radial-gradient(circle at center, transparent 60%, #3b82f6 240%)' }} 
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Destination, MapTheme, RouteInfo, Language, OfflineRegion, TravelMode } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';

interface BottomPanelProps {
  theme: MapTheme;
  language: Language;
  onDestinationSelect: (d: Destination) => void;
  startPoint: Destination | null;
  endPoint: Destination | null;
  routeInfo: RouteInfo | null;
  onClearRoute: () => void;
  offlineRegions: OfflineRegion[];
  onRegionClick: (r: OfflineRegion) => void;
  onRegionDelete: (id: string) => void;
  onTravelModeChange: (mode: TravelMode) => void;
  selectedPlace: Destination | null;
  onClosePlace: () => void;
  onStartNavigation?: () => void;
}

export const BottomPanel: React.FC<BottomPanelProps> = ({ 
  theme, 
  language,
  onDestinationSelect,
  startPoint,
  endPoint,
  routeInfo,
  onClearRoute,
  offlineRegions,
  onRegionClick,
  onRegionDelete,
  onTravelModeChange,
  selectedPlace,
  onClosePlace,
  onStartNavigation
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [activeTab, setActiveTab] = useState<'explore' | 'route' | 'offline' | 'saved'>('explore');
  const [favorites, setFavorites] = useState<string[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language] || TRANSLATIONS['en'];

  useEffect(() => {
    if (startPoint || endPoint) {
      setActiveTab('route');
      setIsExpanded(true);
    }
  }, [startPoint, endPoint]);

  useEffect(() => {
    if (selectedPlace) {
      setIsExpanded(true);
      scrollRef.current?.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedPlace]);

  useEffect(() => {
    const saved = localStorage.getItem('disha_favorites');
    if (saved) setFavorites(JSON.parse(saved));
  }, []);

  const toggleFavorite = (id: string) => {
    const next = favorites.includes(id) ? favorites.filter(f => f !== id) : [...favorites, id];
    setFavorites(next);
    localStorage.setItem('disha_favorites', JSON.stringify(next));
  };

  return (
    <motion.div 
      initial={false}
      animate={{ height: isExpanded ? 'calc(82vh)' : '84px' }}
      transition={{ type: 'spring', damping: 30, stiffness: 240 }}
      className={`fixed bottom-0 left-0 right-0 z-[1400] rounded-t-[56px] shadow-[0_-25px_80px_rgba(0,0,0,0.45)] overflow-hidden flex flex-col ${theme === MapTheme.DARK ? 'glass bg-slate-950/92' : 'glass-light bg-white/96'}`}
    >
      {/* Precision Handle & Header */}
      <div 
        className="h-20 flex items-center justify-between px-12 shrink-0 cursor-pointer active:scale-98 transition-transform"
        onClick={() => setIsExpanded(!isExpanded)}
      >
        <div className="flex-1 flex justify-center translate-x-4">
          <div className={`w-20 h-2.5 rounded-full transition-colors ${theme === MapTheme.DARK ? 'bg-white/10 group-hover:bg-white/30' : 'bg-black/10 group-hover:bg-black/20'}`} />
        </div>

        {isExpanded && (
          <button 
            onClick={(e) => { e.stopPropagation(); setIsExpanded(false); }}
            className={`w-12 h-12 rounded-[20px] flex items-center justify-center transition-all shadow-lg ${theme === MapTheme.DARK ? 'bg-white/5 hover:bg-white/10 text-white' : 'bg-black/5 hover:bg-black/10 text-slate-900'}`}
          >
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"><path d="m6 9 6 6 6-6"/></svg>
          </button>
        )}
      </div>

      <AnimatePresence mode="wait">
        {isExpanded && (
          <motion.div 
            key="content"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="flex-1 overflow-hidden flex flex-col relative"
          >
            {/* Main Content Area - Dynamic Scroll */}
            <div ref={scrollRef} className="flex-1 overflow-y-auto custom-scrollbar px-8 lg:px-14 pb-[150px]">
              {selectedPlace ? (
                <div className="space-y-12 pt-4">
                  <div className="flex justify-between items-start">
                    <div className="flex items-center gap-10">
                      <span className="text-9xl hover:scale-105 transition-transform duration-500 drop-shadow-xl">{selectedPlace.image}</span>
                      <div>
                        <h2 className={`text-5xl font-black leading-tight tracking-tighter ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{selectedPlace.name[language] || selectedPlace.name['en']}</h2>
                        <p className="text-blue-500 font-black uppercase tracking-[0.4em] text-[13px] mt-2">{selectedPlace.category[language] || selectedPlace.category['en']}</p>
                      </div>
                    </div>
                    <button onClick={onClosePlace} className={`w-16 h-16 rounded-[24px] flex items-center justify-center text-2xl transition-all ${theme === MapTheme.DARK ? 'bg-white/5 hover:bg-white/10 text-white' : 'bg-black/5 hover:bg-black/10 text-slate-900'}`}>✕</button>
                  </div>

                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
                    <section className="space-y-6">
                      <h3 className="text-[12px] font-black uppercase tracking-[0.4em] opacity-40 text-blue-500">Spatial Intelligence</h3>
                      <p className={`text-2xl leading-relaxed font-bold ${theme === MapTheme.DARK ? 'text-white/85' : 'text-slate-700'}`}>
                        {selectedPlace.description[language] || selectedPlace.description['en']}
                      </p>
                    </section>

                    {selectedPlace.reviews && (
                      <section className="space-y-8">
                        <h3 className="text-[12px] font-black uppercase tracking-[0.4em] opacity-40 text-blue-500">Real-Time Reviews</h3>
                        <div className="space-y-6">
                          {selectedPlace.reviews.map((r, i) => (
                            <div key={i} className={`p-10 rounded-[48px] border-2 ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5' : 'bg-black/5 border-black/5'}`}>
                              <div className="flex justify-between items-center mb-4">
                                <span className="font-black text-lg">{r.author}</span>
                                <div className="flex text-yellow-500 gap-1.5 text-sm">{'★'.repeat(r.rating)}</div>
                              </div>
                              <p className="text-lg opacity-80 font-semibold italic leading-relaxed">"{r.text[language] || r.text['en']}"</p>
                            </div>
                          ))}
                        </div>
                      </section>
                    )}
                  </div>
                </div>
              ) : (
                <>
                  {/* Persistent Tabs */}
                  <div className="flex gap-10 mb-10 border-b border-white/5 pb-3 shrink-0 overflow-x-auto no-scrollbar">
                    {[
                      { id: 'explore', label: t.explore },
                      { id: 'route', label: t.directions },
                      { id: 'saved', label: 'Library' },
                      { id: 'offline', label: 'Cloud' }
                    ].map(tab => (
                      <button 
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id as any)}
                        className={`pb-5 px-3 font-black text-[14px] tracking-[0.25em] transition-all relative whitespace-nowrap ${activeTab === tab.id ? 'text-blue-500' : 'text-slate-500 opacity-60 hover:opacity-100'}`}
                      >
                        {tab.label.toUpperCase()}
                        {activeTab === tab.id && <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-2 bg-blue-500 rounded-full" />}
                      </button>
                    ))}
                  </div>

                  <div className="space-y-10">
                    {activeTab === 'explore' ? (
                      <div className="space-y-12">
                        <div className="flex gap-5 overflow-x-auto no-scrollbar py-3">
                          {['Food', 'Gas', 'Nature', 'Art', 'Shopping'].map(cat => (
                            <button key={cat} className={`px-10 py-4 rounded-full whitespace-nowrap text-[12px] font-black uppercase tracking-[0.2em] border-2 transition-all ${theme === MapTheme.DARK ? 'bg-white/5 border-white/10 text-white/50 hover:bg-white/10 hover:text-white' : 'bg-white border-black/5 text-slate-500 shadow-md hover:text-slate-900'}`}>
                              {cat}
                            </button>
                          ))}
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-10">
                          {POPULAR_DESTINATIONS.map(dest => (
                            <div 
                              key={dest.id} 
                              onClick={() => onDestinationSelect(dest)}
                              className={`group p-10 rounded-[56px] cursor-pointer transition-all border-2 border-transparent hover:border-blue-500/40 ${theme === MapTheme.DARK ? 'bg-white/5 hover:bg-white/10 shadow-2xl' : 'bg-white hover:bg-blue-50 shadow-xl shadow-blue-500/5'}`}
                            >
                              <div className="text-8xl mb-8 group-hover:scale-110 transition-transform origin-left duration-500">{dest.image}</div>
                              <h4 className="font-black text-3xl mb-3 tracking-tighter">{dest.name[language] || dest.name['en']}</h4>
                              <p className="text-[12px] font-black uppercase tracking-[0.35em] opacity-40 text-blue-600">{dest.category[language] || dest.category['en']}</p>
                            </div>
                          ))}
                        </div>
                      </div>
                    ) : activeTab === 'route' ? (
                      <div className="space-y-10">
                        <div className={`flex gap-5 p-4 rounded-[40px] ${theme === MapTheme.DARK ? 'bg-white/5' : 'bg-black/5'}`}>
                          {[
                            { id: 'driving', icon: '🚗' },
                            { id: 'walking', icon: '🚶' },
                            { id: 'cycling', icon: '🚲' },
                            { id: 'transit', icon: '🚌' }
                          ].map(m => (
                            <button 
                              key={m.id}
                              onClick={() => onTravelModeChange(m.id as TravelMode)}
                              className={`flex-1 py-6 rounded-[28px] text-5xl transition-all ${routeInfo?.mode === m.id ? 'bg-blue-600 shadow-3xl text-white' : 'opacity-40 hover:opacity-100 hover:bg-white/5'}`}
                            >
                              {m.icon}
                            </button>
                          ))}
                        </div>

                        {routeInfo ? (
                          <div className={`p-12 rounded-[64px] border-4 border-blue-600/25 shadow-[0_30px_100px_rgba(37,99,235,0.2)] relative overflow-hidden ${theme === MapTheme.DARK ? 'bg-blue-600/5' : 'bg-blue-50/80'}`}>
                            <div className="grid grid-cols-3 gap-12 text-center">
                              <div>
                                <p className="text-[12px] font-black opacity-40 uppercase mb-3 tracking-[0.3em]">Accurate ETA</p>
                                <p className={`text-6xl font-black ${routeInfo.congestionLevel === 'heavy' ? 'text-red-500' : 'text-blue-600'}`}>{routeInfo.duration}</p>
                              </div>
                              <div>
                                <p className="text-[12px] font-black opacity-40 uppercase mb-3 tracking-[0.3em]">Geodesic Dist</p>
                                <p className="text-5xl font-black">{routeInfo.distance}</p>
                              </div>
                              <div>
                                <p className="text-[12px] font-black opacity-40 uppercase mb-3 tracking-[0.3em]">Load Index</p>
                                <p className={`text-5xl font-black ${routeInfo.trafficDelay === 'None' ? 'text-emerald-500' : 'text-red-500'}`}>{routeInfo.trafficDelay}</p>
                              </div>
                            </div>
                          </div>
                        ) : (
                          <div className="flex flex-col items-center justify-center py-28 opacity-25 text-center space-y-10">
                            <span className="text-[140px] animate-bounce-slow">🧭</span>
                            <p className="font-black uppercase tracking-[0.5em] max-w-[320px] leading-relaxed text-xl">Select endpoint to process navigation matrix</p>
                          </div>
                        )}
                      </div>
                    ) : activeTab === 'saved' ? (
                      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                        {POPULAR_DESTINATIONS.filter(d => favorites.includes(d.id)).length > 0 ? (
                          POPULAR_DESTINATIONS.filter(d => favorites.includes(d.id)).map(dest => (
                            <div 
                              key={dest.id} 
                              onClick={() => onDestinationSelect(dest)}
                              className={`p-10 rounded-[48px] flex items-center gap-12 cursor-pointer border-2 transition-all ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5 hover:bg-white/10' : 'bg-white shadow-xl border-slate-100'}`}
                            >
                              <span className="text-7xl drop-shadow-lg">{dest.image}</span>
                              <div className="flex-1">
                                <p className="font-black text-3xl tracking-tighter">{dest.name[language] || dest.name['en']}</p>
                                <p className="text-[12px] font-bold opacity-45 uppercase tracking-[0.3em] mt-2 text-blue-600">{dest.category['en']}</p>
                              </div>
                              <span className="text-red-500 text-5xl">♥</span>
                            </div>
                          ))
                        ) : (
                          <div className="col-span-full text-center py-32 opacity-25 font-black uppercase tracking-[0.4em] text-xl">Your data library is empty</div>
                        )}
                      </div>
                    ) : (
                      <div className="space-y-8">
                        {offlineRegions.length > 0 ? offlineRegions.map(r => (
                          <div key={r.id} className={`p-10 rounded-[48px] flex justify-between items-center border-2 transition-all ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5' : 'bg-white shadow-xl border-slate-100'}`}>
                            <div>
                              <p className="font-black text-3xl tracking-tighter">{r.name}</p>
                              <p className="text-[13px] font-bold opacity-45 mt-2 uppercase tracking-[0.2em]">{r.date} • {r.size}</p>
                            </div>
                            <div className="flex gap-5">
                               <button onClick={() => onRegionDelete(r.id)} className="w-16 h-16 rounded-[22px] bg-red-500/10 text-red-500 hover:bg-red-500 hover:text-white transition-all flex items-center justify-center text-xl shadow-md">🗑️</button>
                               <button onClick={() => onRegionClick(r)} className="px-10 py-4 bg-blue-600 text-white rounded-[22px] text-[13px] font-black uppercase tracking-[0.25em] shadow-2xl shadow-blue-600/40">Sync Data</button>
                            </div>
                          </div>
                        )) : (
                          <div className="text-center py-32 opacity-25 font-black uppercase tracking-[0.4em] text-xl">Global spatial cache clear</div>
                        )}
                      </div>
                    )}
                  </div>
                </>
              )}
            </div>

            {/* ANCHORED ACTION FOOTER - High Precision Interaction */}
            <AnimatePresence>
              {(selectedPlace || routeInfo) && (
                <motion.div 
                  initial={{ y: 120 }}
                  animate={{ y: 0 }}
                  exit={{ y: 120 }}
                  className={`absolute bottom-0 left-0 right-0 p-10 pt-6 pb-14 z-[20] border-t-2 ${theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'}`}
                >
                  <div className="flex gap-6 max-w-6xl mx-auto">
                    {selectedPlace && !routeInfo && (
                      <>
                        <button 
                          onClick={() => toggleFavorite(selectedPlace.id)}
                          className={`flex-1 py-6 rounded-[32px] font-black text-sm uppercase tracking-[0.3em] flex items-center justify-center gap-4 transition-all ${favorites.includes(selectedPlace.id) ? 'bg-red-500 text-white shadow-2xl' : 'bg-white/5 hover:bg-white/10 border-2 border-white/10 shadow-lg'}`}
                        >
                          {favorites.includes(selectedPlace.id) ? 'Library Locked' : 'Add to Library'}
                        </button>
                        <button 
                          onClick={() => onDestinationSelect(selectedPlace)}
                          className="flex-[2] py-6 bg-blue-600 text-white rounded-[32px] font-black text-sm uppercase tracking-[0.3em] shadow-[0_15px_45px_rgba(37,99,235,0.4)] hover:bg-blue-500 hover:scale-[1.02] transition-all"
                        >
                          Execute Path Analysis
                        </button>
                      </>
                    )}
                    {routeInfo && (
                      <>
                        <button onClick={onClearRoute} className={`flex-1 py-6 rounded-[32px] font-black text-sm uppercase tracking-[0.3em] transition-all ${theme === MapTheme.DARK ? 'bg-white/5 text-white hover:bg-white/10 shadow-lg border-2 border-white/5' : 'bg-white text-slate-900 border-2 border-slate-200 shadow-xl'}`}>Clear Path</button>
                        <button onClick={onStartNavigation} className="flex-[2] py-6 bg-blue-600 text-white rounded-[32px] font-black text-sm uppercase tracking-[0.3em] shadow-[0_20px_50px_rgba(37,99,235,0.45)] hover:bg-blue-500 hover:scale-[1.02] transition-all">Engage Real-Time Guidance</button>
                      </>
                    )}
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
}

const LogoIcon = () => (
  <svg width="36" height="36" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

export const Header: React.FC<HeaderProps> = ({ 
  theme, 
  language,
  onThemeToggle, 
  onLocate, 
  onOpenLayers,
  onSuggestionSelect 
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<Destination[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (!query.trim()) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(() => {
      const q = query.toLowerCase();
      // Complex Weighted Fuzzy Search
      const ranked = POPULAR_DESTINATIONS.map(dest => {
        let score = 0;
        const name = dest.name[language].toLowerCase();
        const cat = dest.category[language].toLowerCase();
        const desc = dest.description[language].toLowerCase();

        if (name.startsWith(q)) score += 12;
        else if (name.includes(q)) score += 6;

        if (cat.includes(q)) score += 8;
        if (desc.includes(q)) score += 2;

        // Category mapping (e.g., 'food' -> 'restaurants', 'park' -> 'nature')
        const synonyms: Record<string, string[]> = {
          food: ['dining', 'restaurants', 'cafe', 'groceries', 'shopping'],
          park: ['nature', 'botanical', 'wildlife', 'parks'],
          drive: ['fuel', 'transport', 'shopping']
        };

        Object.entries(synonyms).forEach(([key, values]) => {
          if (q.includes(key) && values.some(v => cat.includes(v))) score += 5;
        });

        return { dest, score };
      })
      .filter(item => item.score > 0)
      .sort((a, b) => b.score - a.score)
      .map(item => item.dest)
      .slice(0, 10);

      setSuggestions(ranked);
    }, 120);

    return () => clearTimeout(timer);
  }, [query, language]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsFocused(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSelect = (dest: Destination) => {
    setQuery(dest.name[language]);
    setSuggestions([]);
    setIsFocused(false);
    onSuggestionSelect(dest);
  };

  return (
    <motion.header 
      initial={{ y: -120, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[1900] p-6 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-start gap-5 pointer-events-auto">
        <div className={`flex items-center gap-5 px-7 py-3 rounded-[28px] shadow-2xl transition-all h-[68px] ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900'}`}>
          <div className="w-14 h-14 bg-blue-600 rounded-[20px] flex items-center justify-center text-white shadow-xl shrink-0">
            <LogoIcon />
          </div>
          <span className="font-black text-3xl tracking-tighter hidden sm:block">Disha</span>
        </div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-10 py-3 rounded-[34px] shadow-2xl transition-all group h-[68px] ${
            theme === MapTheme.DARK 
              ? `glass ${isFocused ? 'ring-2 ring-blue-500 bg-slate-900 shadow-[0_0_40px_rgba(59,130,246,0.25)]' : 'hover:bg-slate-900/70'}` 
              : `glass-light ${isFocused ? 'ring-2 ring-blue-500 bg-white' : 'hover:bg-white/98'}`
          }`}>
            <span className={`mr-5 transition-all shrink-0 ${isFocused ? 'text-blue-500 scale-125' : 'text-slate-400 opacity-50'}`}>
              <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
            </span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onChange={(e) => setQuery(e.target.value)}
              placeholder={t.searchPlaceholder}
              className="bg-transparent border-none outline-none w-full text-xl font-black tracking-tight placeholder:text-slate-500/35"
              style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
            />
          </div>

          <AnimatePresence>
            {isFocused && (
              <motion.div
                initial={{ opacity: 0, y: 20, scale: 0.97 }}
                animate={{ opacity: 1, y: 15, scale: 1 }}
                exit={{ opacity: 0, y: 20, scale: 0.97 }}
                className={`absolute top-full left-0 right-0 rounded-[48px] shadow-[0_40px_120px_rgba(0,0,0,0.55)] overflow-hidden border-2 ${
                  theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'
                }`}
              >
                <div className="max-h-[70vh] overflow-y-auto py-8 custom-scrollbar">
                  {suggestions.length > 0 ? (
                    <div>
                      <div className="text-[12px] font-black uppercase tracking-[0.4em] text-blue-500 mb-5 px-12">Search Matrix Results</div>
                      {suggestions.map((dest) => (
                        <div
                          key={dest.id}
                          onClick={() => handleSelect(dest)}
                          className={`px-12 py-6 flex items-center gap-10 cursor-pointer transition-all ${
                            theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-blue-50/60'
                          }`}
                        >
                          <div className="text-6xl w-20 h-20 flex items-center justify-center rounded-[32px] bg-slate-500/5 shrink-0 shadow-inner hover:scale-105 transition-transform duration-500">
                            {dest.image}
                          </div>
                          <div className="flex-1 overflow-hidden">
                            <div className={`font-black text-2xl truncate ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{dest.name[language]}</div>
                            <div className="text-[12px] font-black uppercase tracking-[0.3em] opacity-50 text-blue-600 mt-2">{dest.category[language]}</div>
                          </div>
                          <div className="text-base font-black opacity-30 shrink-0">{dest.rating}★</div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div>
                      <div className="text-[12px] font-black uppercase tracking-[0.4em] text-blue-500 mb-8 px-12">Universal Hub Quick Select</div>
                      <div className="grid grid-cols-1 gap-2">
                        {POPULAR_DESTINATIONS.slice(0, 6).map(dest => (
                          <div key={dest.id} onClick={() => handleSelect(dest)} className={`px-12 py-5 flex items-center gap-8 cursor-pointer transition-colors ${theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-black/5'}`}>
                            <span className="text-5xl shrink-0 grayscale opacity-45 hover:grayscale-0 hover:opacity-100 transition-all">{dest.image}</span>
                            <div className="flex flex-col">
                              <span className="text-xl font-black opacity-85 tracking-tighter">{dest.name[language]}</span>
                              <span className="text-[11px] opacity-35 uppercase font-black tracking-widest mt-1">{dest.category[language]}</span>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex gap-4 shrink-0">
          <button 
            onClick={onOpenLayers}
            className={`w-[68px] h-[68px] rounded-[28px] flex items-center justify-center shadow-2xl transition-all hover:scale-110 active:scale-95 ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}
          >
            <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5" strokeLinecap="round"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline><polyline points="2 12 12 17 22 12"></polyline></svg>
          </button>
          <button 
            onClick={onThemeToggle}
            className={`w-[68px] h-[68px] rounded-[28px] flex items-center justify-center shadow-2xl transition-all hover:scale-110 active:scale-95 ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600'}`}
          >
            {theme === MapTheme.DARK ? '☀️' : '🌙'}
          </button>
        </div>
      </div>
    </motion.header>
  );
};

