                  <div className="space-y-10">
                    {activeTab === 'explore' ? (
                      <div className="space-y-12">
                        <div className="flex justify-between items-center">
                           <h3 className="text-[13px] font-black uppercase tracking-[0.3em] opacity-50 text-blue-600">Proximity Sort Active</h3>
                           <span className="text-[11px] font-black bg-blue-500/10 text-blue-500 px-4 py-2 rounded-full uppercase tracking-widest">Live GPS Signal</span>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-10">
                          {nearbyDestinations.map(dest => (
                            <div 
                              key={dest.id} 
                              onClick={() => onDestinationSelect(dest)}
                              className={`group p-10 rounded-[56px] cursor-pointer transition-all border-2 border-transparent hover:border-blue-500/40 relative overflow-hidden ${theme === MapTheme.DARK ? 'bg-white/5 hover:bg-white/10 shadow-2xl' : 'bg-white hover:bg-blue-50 shadow-xl shadow-blue-500/5'}`}
                            >
                              <div className="text-8xl mb-8 group-hover:scale-110 transition-transform origin-left duration-500">{dest.image}</div>
                              <h4 className="font-black text-3xl mb-3 tracking-tighter truncate">{dest.name[language] || dest.name['en']}</h4>
                              <div className="flex justify-between items-center">
                                 <p className="text-[11px] font-black uppercase tracking-[0.3em] opacity-40 text-blue-600">{dest.category[language] || dest.category['en']}</p>
                                 {(dest as any).liveDistance && (
                                   <span className="text-[11px] font-black text-emerald-500">{formatDistance((dest as any).liveDistance)}</span>
                                 )}
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    ) : (
                      <div className="text-center py-32 opacity-25 font-black uppercase tracking-[0.4em] text-xl">Module content loading...</div>
                    )}
                  </div>
                </>
              )}
            </div>

            <AnimatePresence>
              {(selectedPlace || routeInfo) && (
                <motion.div 
                  initial={{ y: 120 }}
                  animate={{ y: 0 }}
                  exit={{ y: 120 }}
                  className={`absolute bottom-0 left-0 right-0 p-10 pt-6 pb-14 z-[20] border-t-2 ${theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'}`}
                >
                  <div className="flex gap-6 max-w-6xl mx-auto">
                    {selectedPlace && !routeInfo && (
                      <button 
                        onClick={() => onDestinationSelect(selectedPlace)}
                        className="flex-1 py-6 bg-blue-600 text-white rounded-[32px] font-black text-sm uppercase tracking-[0.3em] shadow-[0_15px_45px_rgba(37,99,235,0.4)] hover:bg-blue-500 hover:scale-[1.02] transition-all"
                      >
                        Initialize Route Matrix
                      </button>
                    )}
                    {routeInfo && (
                      <>
                        <button onClick={onClearRoute} className={`flex-1 py-6 rounded-[32px] font-black text-sm uppercase tracking-[0.3em] transition-all ${theme === MapTheme.DARK ? 'bg-white/5 text-white border-2 border-white/5' : 'bg-white text-slate-900 border-2 border-slate-200'}`}>Clear Path</button>
                        <button onClick={onStartNavigation} className="flex-[2] py-6 bg-blue-600 text-white rounded-[32px] font-black text-sm uppercase tracking-[0.3em] shadow-[0_20px_50px_rgba(37,99,235,0.45)] hover:bg-blue-500 hover:scale-[1.02] transition-all">Execute Guidance</button>
                      </>
                    )}
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export enum MapLayerType {
  STREET = 'street',
  SATELLITE = 'satellite',
  TRAFFIC = 'traffic',
  TRANSIT = 'transit',
  BUILDINGS = 'buildings',
  ROUTE = 'route',
  MINIMALIST = 'minimalist',
  RETRO = 'retro',
  INDUSTRIAL = 'industrial'
}

export enum MapTheme {
  DARK = 'dark',
  LIGHT = 'light'
}

export type Language = 'en' | 'hi' | 'kn' | 'es';

export type TravelMode = 'driving' | 'walking' | 'cycling' | 'transit';

export interface UserLocation {
  lat: number;
  lng: number;
}

export interface LocalizedString {
  en: string;
  hi: string;
  kn: string;
  es: string;
}

export interface PlaceReview {
  author: string;
  rating: number;
  text: LocalizedString;
  date: string;
}

export interface Destination {
  id: string;
  name: LocalizedString;
  category: LocalizedString;
  coords: [number, number];
  description: LocalizedString;
  image: string;
  rating?: number;
  reviews?: PlaceReview[];
  distance?: string;
  isFavorite?: boolean;
}

export interface OfflineRegion {
  id: string;
  name: string;
  center: [number, number];
  zoom: number;
  date: string;
  size: string;
}

export interface RouteSegment {
  coords: [number, number][];
  instruction: string;
  type: 'straight' | 'left' | 'right' | 'arrival';
  status: 'fast' | 'medium' | 'slow';
}

export interface RouteInfo {
  distance: string;
  duration: string;
  trafficDelay: string;
  congestionLevel: 'low' | 'moderate' | 'heavy';
  mode: TravelMode;
  segments: RouteSegment[];
}

export interface NavigationState {
  isActive: boolean;
  currentStep: string;
  distanceToTurn: string;
  progress: number;
  heading: number;
}

export interface MeasurementState {
  isActive: boolean;
  points: [number, number][];
  totalDistance: number;
}

export interface TrafficStatus {
  activeVehicles: number;
  incidents: number;
  stability: string;
}

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import OSM from 'ol/source/OSM';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import { getDistance } from 'ol/sphere';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke, Text } from 'ol/style';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, OfflineRegion, TravelMode, NavigationState, MeasurementState, RouteSegment } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, TRAFFIC_COLORS, POPULAR_DESTINATIONS, ROUTE_FACTORS } from './constants';

interface Vehicle {
  feature: Feature<Point>;
  speed: number;
  heading: number;
  coords: [number, number];
}

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const trafficSource = useRef<VectorSource>(new VectorSource());
  const routeSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const navMarkerSource = useRef<VectorSource>(new VectorSource());
  const measureSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const turnIndicatorSource = useRef<VectorSource>(new VectorSource());

  const vehiclesRef = useRef<Vehicle[]>([]);
  const animationFrameId = useRef<number>(0);

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET, MapLayerType.ROUTE]);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [offlineRegions, setOfflineRegions] = useState<OfflineRegion[]>([]);
  const [travelMode, setTravelMode] = useState<TravelMode>('driving');
  const [is3D, setIs3D] = useState(false);
  const [mapRotation, setMapRotation] = useState(0);
  const [mapCenterCoords, setMapCenterCoords] = useState<[number, number]>(DEFAULT_CENTER);

  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [startPoint, setStartPoint] = useState<Destination | null>(null);
  const [endPoint, setEndPoint] = useState<Destination | null>(null);
  const [routeInfo, setRouteInfo] = useState<RouteInfo | null>(null);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);

  const [measureState, setMeasureState] = useState<MeasurementState>({
    isActive: false,
    points: [],
    totalDistance: 0
  });

  const [navState, setNavState] = useState<NavigationState>({
    isActive: false,
    currentStep: "System Ready",
    distanceToTurn: "0m",
    progress: 0,
    heading: 0
  });

  useEffect(() => {
    if ("geolocation" in navigator) {
      const watchId = navigator.geolocation.watchPosition(
        (pos) => {
          const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
          setUserLiveCoords(coords);
          userLocSource.current.clear();
          const userFeature = new Feature(new Point(fromLonLat(coords)));
          userFeature.setStyle(new Style({
            image: new Circle({
              radius: 12,
              fill: new Fill({ color: '#3b82f6' }),
              stroke: new Stroke({ color: '#fff', width: 4 })
            })
          }));
          userLocSource.current.addFeature(userFeature);
        },
        null,
        { enableHighAccuracy: true }
      );
      return () => navigator.geolocation.clearWatch(watchId);
    }
  }, []);

  const calculateRoute = useCallback((start: Destination, end: Destination, mode: TravelMode) => {
    if (!mapInstance.current) return;
    const geodesicDist = getDistance(start.coords, end.coords) / 1000;
    const startC = fromLonLat(start.coords) as [number, number];
    const endC = fromLonLat(end.coords) as [number, number];

    const steps = 15;
    const segments: RouteSegment[] = [];
    const allPoints: [number, number][] = [startC];

    for (let i = 1; i <= steps; i++) {
       const p = i / steps;
       const noise = (Math.random() - 0.5) * 800;
       const point: [number, number] = [
          startC[0] + (endC[0] - startC[0]) * p + (i % 3 === 0 ? noise : 0),
          startC[1] + (endC[1] - startC[1]) * p + (i % 2 === 0 ? noise : 0)
       ];

       const prev = allPoints[allPoints.length - 1];
       const type = i === steps ? 'arrival' : Math.random() > 0.7 ? (Math.random() > 0.5 ? 'left' : 'right') : 'straight';
       const instruction = type === 'left' ? "Turn Left at Junction" : type === 'right' ? "Turn Right at Light" : "Continue Straight";

       segments.push({
         coords: [prev, point],
         type,
         instruction,
         status: Math.random() > 0.8 ? 'slow' : Math.random() > 0.6 ? 'medium' : 'fast'
       });

       allPoints.push(point);
    }

    routeSource.current.clear();
    turnIndicatorSource.current.clear();

    segments.forEach((seg, idx) => {
      const feature = new Feature(new LineString(seg.coords));
      const color = seg.status === 'slow' ? TRAFFIC_COLORS.SLOW : seg.status === 'medium' ? TRAFFIC_COLORS.MEDIUM : '#3b82f6';

      feature.setStyle(new Style({
        stroke: new Stroke({ color, width: 14, lineCap: 'round' })
      }));
      routeSource.current.addFeature(feature);

      if (seg.type !== 'straight') {
        const turnMarker = new Feature(new Point(seg.coords[1]));
        turnMarker.setStyle(new Style({
          text: new Text({
            text: seg.type === 'left' ? '⬅️' : seg.type === 'right' ? '➡️' : '📍',
            font: '24px Arial',
            offsetY: -20,
            fill: new Fill({ color: '#fff' })
          })
        }));
        turnIndicatorSource.current.addFeature(turnMarker);
      }
    });

    const baseTime = geodesicDist * (ROUTE_FACTORS[mode] || 2.2);
    setRouteInfo({
      distance: `${geodesicDist.toFixed(2)} km`,
      duration: `${Math.round(baseTime)} min`,
      trafficDelay: '2 min',
      congestionLevel: 'low',
      mode,
      segments
    });

    mapInstance.current.getView().fit(routeSource.current.getExtent(), { padding: [160, 100, 160, 100], duration: 1200 });
  }, []);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const map = new Map({
      target: mapRef.current,
      layers: [
        new TileLayer({
          source: new OSM({ url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT }),
          zIndex: 0, properties: { id: 'base-layer' }
        }),
        new VectorLayer({ source: trafficSource.current, zIndex: 5, properties: { id: MapLayerType.TRAFFIC } }),
        new VectorLayer({ source: routeSource.current, zIndex: 10, properties: { id: MapLayerType.ROUTE } }),
        new VectorLayer({ source: turnIndicatorSource.current, zIndex: 11, properties: { id: 'turns' } }),
        new VectorLayer({ source: measureSource.current, zIndex: 120, properties: { id: 'measure' } }),
        new VectorLayer({ source: userLocSource.current, zIndex: 150, properties: { id: 'user-loc' } }),
        new VectorLayer({ 
          source: navMarkerSource.current, 
          zIndex: 160,
          style: (feature) => new Style({
            image: new Circle({ 
              radius: 14, 
              fill: new Fill({ color: '#2563eb' }), 
              stroke: new Stroke({ color: '#fff', width: 4 }) 
            })
          })
        }),
        new VectorLayer({
          source: poiSource.current, zIndex: 40,
          style: () => new Style({
            image: new Circle({ radius: 10, fill: new Fill({ color: '#2563eb' }), stroke: new Stroke({ color: '#fff', width: 3 }) })
          }),
          properties: { id: 'pois' }
        })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true }),
      controls: []
    });

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) setMapCenterCoords(toLonLat(center) as [number, number]);
    });

    map.on('click', (evt) => {
      if (measureState.isActive) {
        const lonLat = toLonLat(evt.coordinate) as [number, number];
        setMeasureState(prev => {
          const newPoints = [...prev.points, lonLat];
          let totalDist = 0;
          for (let i = 0; i < newPoints.length - 1; i++) {
            totalDist += getDistance(newPoints[i], newPoints[i+1]);
          }
          measureSource.current.clear();
          newPoints.forEach(p => {
            const f = new Feature(new Point(fromLonLat(p)));
            f.setStyle(new Style({
              image: new Circle({ radius: 6, fill: new Fill({ color: '#10b981' }), stroke: new Stroke({ color: '#fff', width: 2 }) })
            }));
            measureSource.current.addFeature(f);
          });
          if (newPoints.length > 1) {
            const line = new Feature(new LineString(newPoints.map(p => fromLonLat(p))));
            line.setStyle(new Style({ stroke: new Stroke({ color: '#10b981', width: 4, lineDash: [8, 8] }) }));
            measureSource.current.addFeature(line);
          }
          return { ...prev, points: newPoints, totalDistance: totalDist / 1000 };
        });
        return;
      }
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
    });

    mapInstance.current = map;
    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      poiSource.current.addFeature(f);
    });

    const initTraffic = () => {
      const center = fromLonLat(DEFAULT_CENTER) as [number, number];
      for (let i = 0; i < 200; i++) {
        const angle = Math.random() * Math.PI * 2;
        const radius = Math.random() * 20000;
        const coords: [number, number] = [center[0] + Math.cos(angle) * radius, center[1] + Math.sin(angle) * radius];
        const feature = new Feature(new Point(coords));
        const speed = 25 + Math.random() * 60;
        feature.set('speed', speed);
        vehiclesRef.current.push({ feature, speed: speed / 40, heading: Math.random() * Math.PI * 2, coords });
      }
      trafficSource.current.addFeatures(vehiclesRef.current.map(v => v.feature));
    };

    const animateTraffic = () => {
      vehiclesRef.current.forEach(v => {
        v.coords[0] += Math.cos(v.heading) * v.speed;
        v.coords[1] += Math.sin(v.heading) * v.speed;
        if (Math.random() > 0.995) v.heading += (Math.random() - 0.5) * 1.5;
        v.feature.getGeometry()?.setCoordinates(v.coords);
      });
      animationFrameId.current = requestAnimationFrame(animateTraffic);
    };

    initTraffic();
    animateTraffic();
    return () => cancelAnimationFrame(animationFrameId.current);
  }, [measureState.isActive]);

  const toggleNavigation = () => {
    if (navState.isActive) {
      setNavState(prev => ({ ...prev, isActive: false }));
      navMarkerSource.current.clear();
      setIs3D(false);
      mapInstance.current?.getView().animate({ rotation: 0, duration: 1000 });
    } else if (routeInfo) {
      setNavState(prev => ({ ...prev, isActive: true, progress: 0 }));
      setIs3D(true);

      const allPoints = routeInfo.segments.flatMap(s => s.coords);
      const navMarker = new Feature(new Point(allPoints[0]));
      navMarkerSource.current.clear();
      navMarkerSource.current.addFeature(navMarker);

      let currentPointIdx = 0;
      const interval = setInterval(() => {
        if (currentPointIdx >= allPoints.length - 1) {
          clearInterval(interval);
          setNavState(prev => ({ ...prev, isActive: false }));
          return;
        }

        const current = allPoints[currentPointIdx];
        const next = allPoints[currentPointIdx + 1];

        // Calculate heading for auto-rotation
        const dx = next[0] - current[0];
        const dy = next[1] - current[1];
        const heading = -Math.atan2(dy, dx) + Math.PI / 2;

        navMarker.getGeometry()?.setCoordinates(next);
        mapInstance.current?.getView().animate({ 
          center: next, 
          rotation: heading,
          duration: 400 
        });

        const segIdx = Math.floor(currentPointIdx / 2);
        const segment = routeInfo.segments[segIdx] || routeInfo.segments[routeInfo.segments.length - 1];

        setNavState(prev => ({ 
          ...prev, 
          progress: (currentPointIdx / allPoints.length) * 100,
          currentStep: segment.instruction,
          distanceToTurn: `${Math.round(getDistance(toLonLat(current), toLonLat(next)))}m`
        }));

        currentPointIdx++;
      }, 500);
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme} language={language}
        mapCenter={userLiveCoords || mapCenterCoords}
        onLanguageChange={setLanguage}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLocate={() => {
          if (userLiveCoords) mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 18, duration: 1000 });
        }}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => {
          setSelectedPlace(dest);
          if (startPoint && !endPoint) {
            setEndPoint(dest);
            calculateRoute(startPoint, dest, travelMode);
          } else {
            setStartPoint(dest);
            setEndPoint(null);
            mapInstance.current?.getView().animate({ center: fromLonLat(dest.coords), zoom: 17, duration: 1000 });
          }
        }}
      />

      <AnimatePresence>
        {navState.isActive && (
          <motion.div initial={{ y: -150 }} animate={{ y: 0 }} exit={{ y: -150 }} className="fixed top-24 left-1/2 -translate-x-1/2 z-[2000] w-[90%] lg:w-[450px]">
            <div className={`p-8 rounded-[40px] shadow-2xl border-2 border-blue-500/50 ${theme === MapTheme.DARK ? 'glass bg-slate-900/98' : 'glass-light bg-white/98'}`}>
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 bg-blue-600 rounded-3xl flex items-center justify-center text-3xl shadow-lg">🧭</div>
                <div className="flex-1">
                  <p className="text-[10px] font-black uppercase tracking-[0.3em] text-blue-500 mb-1">Live Navigation</p>
                  <h3 className="text-2xl font-black leading-tight">{navState.currentStep}</h3>
                </div>
                <div className="text-right">
                  <p className="text-2xl font-black text-blue-500">{navState.distanceToTurn}</p>
                  <p className="text-[10px] font-bold opacity-40 uppercase tracking-widest">To Junction</p>
                </div>
              </div>
              <div className="mt-6 h-2 bg-white/5 rounded-full overflow-hidden">
                <motion.div className="h-full bg-blue-500" animate={{ width: `${navState.progress}%` }} />
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={isOnline}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language}
        userLocation={userLiveCoords}
        startPoint={startPoint} endPoint={endPoint} routeInfo={routeInfo}
        selectedPlace={selectedPlace} onClosePlace={() => setSelectedPlace(null)}
        onStartNavigation={toggleNavigation}
        onDestinationSelect={(dest) => {
          setSelectedPlace(dest);
          if (startPoint && !endPoint) {
            setEndPoint(dest);
            calculateRoute(startPoint, dest, travelMode);
          } else {
            setStartPoint(dest);
            setEndPoint(null);
          }
        }}
        onClearRoute={() => { setStartPoint(null); setEndPoint(null); setRouteInfo(null); routeSource.current.clear(); turnIndicatorSource.current.clear(); }}
        offlineRegions={offlineRegions}
        onRegionClick={(r) => mapInstance.current?.getView().animate({ center: fromLonLat(r.center), zoom: r.zoom, duration: 1000 })}
        onRegionDelete={(id) => setOfflineRegions(prev => prev.filter(x => x.id !== id))}
        onTravelModeChange={(m) => { setTravelMode(m); if (startPoint && endPoint) calculateRoute(startPoint, endPoint, m); }}
      />

      <FloatingControls 
        onRecenter={() => {
          const target = userLiveCoords ? fromLonLat(userLiveCoords) : fromLonLat(DEFAULT_CENTER);
          mapInstance.current?.getView().animate({ center: target, zoom: 18, rotation: 0, duration: 1000 });
        }}
        onVoice={() => {}}
        on3D={() => setIs3D(!is3D)}
        onMeasureToggle={() => setMeasureState(prev => ({ ...prev, isActive: !prev.isActive }))}
        is3D={is3D} isMeasuring={measureState.isActive} rotation={mapRotation}
      />

      <motion.div layout className={`fixed top-24 left-7 z-[900] p-6 rounded-[40px] hidden lg:block ${theme === MapTheme.DARK ? 'glass' : 'glass-light'} shadow-2xl min-w-[260px]`}>
        <div className="flex items-center gap-3 mb-4">
          <span className="w-3.5 h-3.5 rounded-full animate-pulse bg-emerald-500" />
          <span className="text-[11px] font-black uppercase tracking-[0.3em] opacity-50">Spatial Index</span>
        </div>
        <div className="space-y-1">
          <div className="text-4xl font-black tracking-tight mb-1">{(24.5).toFixed(1)}°C</div>
          <div className="text-xs font-bold opacity-60 uppercase tracking-widest">{userLiveCoords ? 'Global GPS Sync' : 'Static Mode'}</div>
        </div>
        <div className="text-[10px] opacity-40 mt-5 font-black border-t border-white/5 pt-4">
           NODES: 412 • FLOW: 98%
        </div>
      </motion.div>
    </div>
  );
};

