                      key={dest.id}
                      onClick={() => onDestinationSelect(dest)}
                      className={`p-8 rounded-[40px] border-2 border-transparent hover:border-blue-500 transition-all cursor-pointer ${theme === MapTheme.DARK ? 'bg-white/5' : 'bg-slate-50'}`}
                    >
                      <div className="text-7xl mb-6">{dest.image}</div>
                      <h3 className="text-2xl font-black tracking-tighter truncate">{dest.name[language] || dest.name['en']}</h3>
                      <div className="flex justify-between mt-2">
                        <span className="text-[10px] font-black uppercase tracking-widest text-blue-500">{dest.category[language]}</span>
                        {/* Fix: Safely access liveDistance property after adding it to Destination type */}
                        {dest.liveDistance !== undefined && <span className="text-[10px] font-bold text-emerald-500">{(dest.liveDistance / 1000).toFixed(1)} km</span>}
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="py-32 text-center opacity-20 font-black uppercase tracking-[0.5em]">Module Initializing</div>
              )}
            </div>

            {(selectedPlace || routeInfo) && (
              <div className="mt-8 flex gap-6">
                <button onClick={onClearRoute} className="flex-1 py-6 rounded-[28px] font-black text-xs uppercase tracking-widest bg-red-500/10 text-red-500">Reset</button>
                <button onClick={onStartNavigation} className="flex-[3] py-6 rounded-[28px] font-black text-xs uppercase tracking-widest bg-blue-600 text-white shadow-xl shadow-blue-600/30">Start Guided Drive</button>
              </div>
            )}
          </div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

