import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import OSM from 'ol/source/OSM';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import { getDistance } from 'ol/sphere';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke, Text, Icon } from 'ol/style';
import { GoogleGenAI } from "@google/genai";

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, TravelMode, NavigationState, MeasurementState, RouteSegment, MapIncident } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, TRAFFIC_COLORS, POPULAR_DESTINATIONS, ROUTE_FACTORS } from './constants';

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const trafficSource = useRef<VectorSource>(new VectorSource());
  const routeSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const navMarkerSource = useRef<VectorSource>(new VectorSource());
  const measureSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const incidentSource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET, MapLayerType.ROUTE, MapLayerType.INCIDENTS]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [routeInfo, setRouteInfo] = useState<RouteInfo | null>(null);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [incidents, setIncidents] = useState<MapIncident[]>([]);

  const [navState, setNavState] = useState<NavigationState>({
    isActive: false, currentStep: "Ready", distanceToTurn: "0m", progress: 0, heading: 0, speed: 0, altitude: 920
  });

  const [measureState, setMeasureState] = useState<MeasurementState>({ isActive: false, points: [], totalDistance: 0 });

  // Gemini AI Smart Search Implementation
  const handleAISearch = async (query: string) => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Given these locations: ${JSON.stringify(POPULAR_DESTINATIONS.map(d => ({id: d.id, name: d.name.en, cat: d.category.en, desc: d.description.en})))}, find the best match for the user query: "${query}". Return ONLY the JSON object of the matched location, or an empty object if no clear match.`,
        config: { responseMimeType: "application/json" }
      });

      const result = JSON.parse(response.text || '{}');
      if (result.id) {
        const dest = POPULAR_DESTINATIONS.find(d => d.id === result.id);
        if (dest) {
          setSelectedPlace(dest);
          mapInstance.current?.getView().animate({ center: fromLonLat(dest.coords), zoom: 17, duration: 1500 });
        }
      }
    } catch (err) {
      console.error("AI Search Error:", err);
    }
  };

  // Simulate Dynamic Incidents
  const spawnIncident = useCallback(() => {
    if (!mapInstance.current) return;
    const center = mapInstance.current.getView().getCenter();
    if (!center) return;

    const lonLat = toLonLat(center);
    const offset = (Math.random() - 0.5) * 0.04;
    const coords: [number, number] = [lonLat[0] + offset, lonLat[1] + offset];

    const types: ('accident' | 'construction' | 'police')[] = ['accident', 'construction', 'police'];
    const type = types[Math.floor(Math.random() * types.length)];
    const newIncident: MapIncident = {
      id: Math.random().toString(),
      type,
      coords,
      description: `${type.toUpperCase()} reported nearby. Use caution.`,
      severity: Math.random() > 0.5 ? 'high' : 'low',
      timestamp: Date.now()
    };

    setIncidents(prev => [...prev.slice(-4), newIncident]);

    const feature = new Feature(new Point(fromLonLat(coords)));
    feature.set('incidentData', newIncident);
    feature.setStyle(new Style({
      image: new Circle({
        radius: 15,
        fill: new Fill({ color: newIncident.severity === 'high' ? 'rgba(239, 68, 68, 0.4)' : 'rgba(245, 158, 11, 0.4)' }),
        stroke: new Stroke({ color: newIncident.severity === 'high' ? '#ef4444' : '#f59e0b', width: 3 })
      }),
      text: new Text({ text: type === 'accident' ? '💥' : type === 'police' ? '👮' : '🚧', font: '20px Arial', offsetY: -2 })
    }));
    incidentSource.current.addFeature(feature);

    setTimeout(() => {
      incidentSource.current.removeFeature(feature);
      setIncidents(prev => prev.filter(i => i.id !== newIncident.id));
    }, 45000);
  }, []);

  useEffect(() => {
    const timer = setInterval(spawnIncident, 30000);
    return () => clearInterval(timer);
  }, [spawnIncident]);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const map = new Map({
      target: mapRef.current,
      layers: [
        new TileLayer({
          source: new OSM({ url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT }),
          zIndex: 0, properties: { id: 'base-layer' }
        }),
        new VectorLayer({ source: trafficSource.current, zIndex: 5, properties: { id: MapLayerType.TRAFFIC } }),
        new VectorLayer({ source: routeSource.current, zIndex: 10, properties: { id: MapLayerType.ROUTE } }),
        new VectorLayer({ source: incidentSource.current, zIndex: 15, properties: { id: MapLayerType.INCIDENTS } }),
        new VectorLayer({ source: measureSource.current, zIndex: 120, properties: { id: 'measure' } }),
        new VectorLayer({ source: userLocSource.current, zIndex: 150, properties: { id: 'user-loc' } }),
        new VectorLayer({ source: navMarkerSource.current, zIndex: 160 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true }),
      controls: []
    });

    mapInstance.current = map;

    // Initial POIs
    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({
        image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) })
      }));
      poiSource.current.addFeature(f);
    });

    // Tracking
    if (navigator.geolocation) {
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 12, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      });
    }

    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
    });

    return () => map.setTarget(undefined);
  }, []);

  const calculateRoute = useCallback((end: Destination) => {
    if (!mapInstance.current || !userLiveCoords) return;
    const startC = fromLonLat(userLiveCoords) as [number, number];
    const endC = fromLonLat(end.coords) as [number, number];

    const steps = 10;
    const segments: RouteSegment[] = [];
    const allCoords: [number, number][] = [startC];

    for (let i = 1; i <= steps; i++) {
      const p = i / steps;
      const point: [number, number] = [
        startC[0] + (endC[0] - startC[0]) * p + (Math.random() - 0.5) * 400,
        startC[1] + (endC[1] - startC[1]) * p + (Math.random() - 0.5) * 400
      ];
      segments.push({
        coords: [allCoords[allCoords.length - 1], point],
        instruction: i === steps ? "Arrive at destination" : "Proceed straight",
        type: i === steps ? 'arrival' : 'straight',
        status: 'fast'
      });
      allCoords.push(point);
    }

    routeSource.current.clear();
    segments.forEach(seg => {
      const f = new Feature(new LineString(seg.coords));
      f.setStyle(new Style({ stroke: new Stroke({ color: '#3b82f6', width: 10, lineCap: 'round' }) }));
      routeSource.current.addFeature(f);
    });

    setRouteInfo({
      distance: `${(getDistance(userLiveCoords, end.coords)/1000).toFixed(1)} km`,
      duration: "14 min",
      trafficDelay: "0 min",
      congestionLevel: 'low',
      mode: 'driving',
      segments
    });

    mapInstance.current.getView().fit(routeSource.current.getExtent(), { padding: [150, 50, 150, 50], duration: 1000 });
  }, [userLiveCoords]);

  const runNavigation = () => {
    if (!routeInfo) return;
    setNavState(prev => ({ ...prev, isActive: true, progress: 0 }));
    setIs3D(true);

    let step = 0;
    const allPoints = routeInfo.segments.flatMap(s => s.coords);
    const marker = new Feature(new Point(allPoints[0]));
    navMarkerSource.current.clear();
    navMarkerSource.current.addFeature(marker);

    const interval = setInterval(() => {
      if (step >= allPoints.length - 1) {
        clearInterval(interval);
        setNavState(prev => ({ ...prev, isActive: false }));
        return;
      }
      const current = allPoints[step];
      const next = allPoints[step + 1];
      const heading = Math.atan2(next[0] - current[0], next[1] - current[1]);

      marker.getGeometry()?.setCoordinates(next);
      mapInstance.current?.getView().animate({ center: next, rotation: -heading, duration: 450 });

      setNavState(prev => ({ 
        ...prev, 
        progress: (step / allPoints.length) * 100,
        speed: 45 + Math.random() * 15,
        distanceToTurn: `${Math.round(getDistance(toLonLat(current), toLonLat(next)))}m`
      }));
      step++;
    }, 500);
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme} language={language}
        mapCenter={userLiveCoords || DEFAULT_CENTER}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 18, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onAISearch={handleAISearch}
      />

      <AnimatePresence>
        {navState.isActive && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[2500] pointer-events-none">
            {/* Navigation Cockpit HUD */}
            <div className="absolute top-32 left-1/2 -translate-x-1/2 w-[90%] lg:w-[500px] pointer-events-auto">
              <div className="glass p-8 rounded-[40px] border-2 border-blue-500/40 shadow-2xl">
                <div className="flex justify-between items-center mb-6">
                  <div className="flex items-center gap-6">
                    <div className="w-16 h-16 bg-blue-600 rounded-3xl flex items-center justify-center text-3xl">⬆️</div>
                    <div>
                      <h2 className="text-3xl font-black">{navState.distanceToTurn}</h2>
                      <p className="text-xs font-bold opacity-50 uppercase tracking-widest">Keep Straight</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-4xl font-black text-blue-500">{navState.speed.toFixed(0)}</p>
                    <p className="text-[10px] font-black opacity-40 uppercase tracking-widest">KM/H</p>
                  </div>
                </div>
                <div className="h-2 bg-white/5 rounded-full overflow-hidden">
                  <motion.div className="h-full bg-blue-500" animate={{ width: `${navState.progress}%` }} />
                </div>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language}
        userLocation={userLiveCoords}
        startPoint={null} endPoint={null} routeInfo={routeInfo}
        selectedPlace={selectedPlace} onClosePlace={() => setSelectedPlace(null)}
        onStartNavigation={runNavigation}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onClearRoute={() => { setRouteInfo(null); routeSource.current.clear(); }}
        offlineRegions={[]} onRegionClick={() => {}} onRegionDelete={() => {}}
        onTravelModeChange={() => {}}
      />

      <FloatingControls 
        onRecenter={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 18, rotation: 0, duration: 1000 })}
        onVoice={() => {}} on3D={() => setIs3D(!is3D)} onMeasureToggle={() => {}}
        is3D={is3D} isMeasuring={false} rotation={0}
      />

      {/* Incident Ticker */}
      <AnimatePresence>
        {incidents.length > 0 && !navState.isActive && (
          <motion.div initial={{ x: -100, opacity: 0 }} animate={{ x: 0, opacity: 1 }} exit={{ x: -100, opacity: 0 }} className="fixed top-24 right-6 z-[1800] space-y-3 pointer-events-none">
            {incidents.map(inc => (
              <div key={inc.id} className="glass p-4 rounded-3xl border-l-4 border-red-500 flex items-center gap-4 w-72">
                <span className="text-2xl">{inc.type === 'accident' ? '💥' : '👮'}</span>
                <div>
                  <p className="text-[10px] font-black uppercase text-red-500">{inc.type}</p>
                  <p className="text-xs font-bold leading-tight">{inc.description}</p>
                </div>
              </div>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { TRANSLATIONS } from '../constants';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onAISearch: (query: string) => Promise<void>;
}

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, onThemeToggle, onOpenLayers, onSuggestionSelect, onAISearch 
}) => {
  const [query, setQuery] = useState('');
  const [isFocused, setIsFocused] = useState(false);
  const [isAIActive, setIsAIActive] = useState(false);
  const [isSearching, setIsSearching] = useState(false);
  const t = TRANSLATIONS[language];

  const handleKeyDown = async (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && query.trim()) {
      setIsSearching(true);
      await onAISearch(query);
      setIsSearching(false);
      setIsFocused(false);
    }
  };

  return (
    <motion.header 
      initial={{ y: -100 }} animate={{ y: 0 }}
      className="fixed top-0 left-0 right-0 z-[1900] p-6 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-start gap-5 pointer-events-auto">
        <div className={`flex items-center gap-5 px-6 h-[68px] rounded-[28px] shadow-2xl ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}>
          <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white text-2xl">📍</div>
          <span className="font-black text-2xl tracking-tighter hidden sm:block">Disha</span>
        </div>

        <div className="flex-1 relative">
          <div className={`flex items-center px-8 h-[68px] rounded-[34px] shadow-2xl transition-all ${
            isFocused ? 'ring-2 ring-blue-500' : ''
          } ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}>
            <span className={`mr-4 text-2xl ${isAIActive ? 'text-purple-500 animate-pulse' : 'text-slate-400'}`}>
              {isAIActive ? '✨' : '🔍'}
            </span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onBlur={() => !query && setIsFocused(false)}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder={isAIActive ? "Ask AI about locations..." : t.searchPlaceholder}
              className="bg-transparent border-none outline-none w-full text-xl font-bold placeholder:text-slate-500/40"
            />
            <button 
              onClick={() => setIsAIActive(!isAIActive)}
              className={`ml-4 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${isAIActive ? 'bg-purple-600 text-white' : 'bg-white/5 opacity-50'}`}
            >
              AI Mode
            </button>
            {isSearching && <div className="ml-4 w-5 h-5 border-2 border-blue-500 border-t-transparent animate-spin rounded-full" />}
          </div>
        </div>

        <div className="flex gap-4">
          <button onClick={onOpenLayers} className={`w-[68px] h-[68px] rounded-[28px] flex items-center justify-center text-2xl ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}>🗺️</button>
          <button onClick={onThemeToggle} className={`w-[68px] h-[68px] rounded-[28px] flex items-center justify-center text-2xl ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}>{theme === MapTheme.DARK ? '☀️' : '🌙'}</button>
        </div>
      </div>
    </motion.header>
  );
};

