import VectorLayer from 'ol/layer/Vector';
import OSM from 'ol/source/OSM';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import { getDistance } from 'ol/sphere';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, TravelMode, NavigationState, RouteSegment } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const routeSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const navMarkerSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [activeRouteId, setActiveRouteId] = useState<string | null>(null);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [is3D, setIs3D] = useState(false);
  const [mapRotation, setMapRotation] = useState(0);

  const [navState, setNavState] = useState<NavigationState>({
    isActive: false, currentStep: "Ready", distanceToTurn: "0m", progress: 0, heading: 0, speed: 0
  });

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const map = new Map({
      target: mapRef.current,
      layers: [
        new TileLayer({
          source: new OSM({ url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT }),
          zIndex: 0, properties: { id: 'base-layer' }
        }),
        new VectorLayer({ source: routeSource.current, zIndex: 10, properties: { id: MapLayerType.ROUTE } }),
        new VectorLayer({ source: userLocSource.current, zIndex: 150, properties: { id: 'user-loc' } }),
        new VectorLayer({ source: navMarkerSource.current, zIndex: 160 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true }),
      controls: []
    });

    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({
        image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) })
      }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 12, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      });
    }

    map.on('moveend', () => setMapRotation(map.getView().getRotation()));
    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
    });

    return () => map.setTarget(undefined);
  }, []);

  const calculateMultiRoutes = useCallback((end: Destination) => {
    if (!mapInstance.current || !userLiveCoords) return;
    const startC = fromLonLat(userLiveCoords) as [number, number];
    const endC = fromLonLat(end.coords) as [number, number];

    // Generate 3 variations
    const routeVariations: RouteInfo[] = [
      { id: '1', distance: '5.2 km', duration: '14 min', label: 'Fastest', trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: [] },
      { id: '2', distance: '6.1 km', duration: '18 min', label: 'Eco', trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: [] },
      { id: '3', distance: '4.8 km', duration: '22 min', label: 'Avoiding Tolls', trafficDelay: '4m', congestionLevel: 'moderate', mode: 'driving', segments: [] }
    ];

    routeSource.current.clear();
    routeVariations.forEach((route, idx) => {
      const steps = 8;
      const coords: [number, number][] = [startC];
      for (let i = 1; i < steps; i++) {
        const p = i / steps;
        const jitter = (idx - 1) * 600; // Visual separation
        coords.push([
          startC[0] + (endC[0] - startC[0]) * p + (Math.random() - 0.5) * jitter,
          startC[1] + (endC[1] - startC[1]) * p + (Math.random() - 0.5) * jitter
        ]);
      }
      coords.push(endC);

      const line = new LineString(coords);
      const f = new Feature(line);
      f.setStyle(new Style({ 
        stroke: new Stroke({ 
          color: idx === 0 ? '#3b82f6' : 'rgba(100, 116, 139, 0.4)', 
          width: idx === 0 ? 10 : 8 
        }) 
      }));
      routeSource.current.addFeature(f);

      route.segments = [{ coords: [startC, endC], instruction: "Head East", type: 'straight', status: 'fast' }];
    });

    setRoutes(routeVariations);
    setActiveRouteId('1');
    mapInstance.current.getView().fit(routeSource.current.getExtent(), { padding: [150, 100, 150, 100], duration: 1000 });
  }, [userLiveCoords]);

  const runNavigation = () => {
    const activeRoute = routes.find(r => r.id === activeRouteId);
    if (!activeRoute) return;
    setNavState(prev => ({ ...prev, isActive: true, progress: 0 }));
    setIs3D(true);

    // Simplistic visual path simulation
    let progress = 0;
    const interval = setInterval(() => {
      progress += 2;
      if (progress >= 100) {
        clearInterval(interval);
        setNavState(prev => ({ ...prev, isActive: false }));
        setIs3D(false);
        return;
      }
      setNavState(prev => ({ ...prev, progress, speed: Math.floor(40 + Math.random() * 20), distanceToTurn: `${100 - progress}m` }));
    }, 500);
  };

  const handleVoiceSearch = () => {
    const SpeechRecognition = (window as any).webkitSpeechRecognition || (window as any).SpeechRecognition;
    if (SpeechRecognition) {
      const rec = new SpeechRecognition();
      rec.lang = language === 'hi' ? 'hi-IN' : 'en-US';
      rec.onresult = (e: any) => {
        const transcript = e.results[0][0].transcript;
        console.log("Voice Search:", transcript);
        // Fuzzy match logic would go here
      };
      rec.start();
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme} language={language}
        mapCenter={userLiveCoords || DEFAULT_CENTER}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 18, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { setSelectedPlace(dest); calculateMultiRoutes(dest); }}
        onVoiceSearch={handleVoiceSearch}
      />

      <AnimatePresence>
        {navState.isActive && (
          <motion.div initial={{ y: -150 }} animate={{ y: 0 }} exit={{ y: -150 }} className="fixed top-24 left-1/2 -translate-x-1/2 z-[2500] w-[90%] lg:w-[480px]">
            <div className="glass p-8 rounded-[40px] border-2 border-blue-500/40 shadow-2xl flex flex-col gap-6">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-6">
                  <div className="w-16 h-16 bg-blue-600 rounded-3xl flex items-center justify-center text-3xl">⬆️</div>
                  <div>
                    <h2 className="text-3xl font-black">{navState.distanceToTurn}</h2>
                    <p className="text-[10px] font-bold opacity-40 uppercase tracking-widest">Maintain current lane</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-4xl font-black text-blue-500 leading-none">{navState.speed}</p>
                  <p className="text-[10px] font-black opacity-40 uppercase tracking-widest mt-1">KM/H</p>
                </div>
              </div>
              <div className="h-2 bg-white/5 rounded-full overflow-hidden">
                <motion.div className="h-full bg-blue-500 shadow-[0_0_15px_#3b82f6]" animate={{ width: `${navState.progress}%` }} />
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language}
        userLocation={userLiveCoords}
        startPoint={null} endPoint={null} routeInfo={routes[0] || null}
        selectedPlace={selectedPlace} onClosePlace={() => setSelectedPlace(null)}
        onStartNavigation={runNavigation}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateMultiRoutes(dest); }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
        offlineRegions={[]} onRegionClick={() => {}} onRegionDelete={() => {}}
        onTravelModeChange={() => {}}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 18, duration: 1000 })}
        on3D={() => { setIs3D(!is3D); mapInstance.current?.getView().animate({ rotation: is3D ? 0 : Math.PI/4, duration: 1000 }); }}
        onMeasureToggle={() => {}}
        is3D={is3D} isMeasuring={false} rotation={mapRotation}
      />

      {/* Telemetry HUD */}
      <div className="fixed top-28 left-8 z-[800] space-y-4 pointer-events-none hidden lg:block">
        <div className="glass p-5 rounded-[30px] border-l-4 border-blue-500 w-48">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-widest">Altitude</p>
          <p className="text-2xl font-black">924 m</p>
        </div>
        <div className="glass p-5 rounded-[30px] border-l-4 border-emerald-500 w-48">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-widest">GPS Health</p>
          <p className="text-2xl font-black">Excellent</p>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onVoiceSearch: () => void;
}

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, onThemeToggle, onOpenLayers, onSuggestionSelect, onVoiceSearch 
}) => {
  const [query, setQuery] = useState('');
  const [isFocused, setIsFocused] = useState(false);
  const [suggestions, setSuggestions] = useState<Destination[]>([]);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (!query.trim()) {
      setSuggestions([]);
      return;
    }
    const q = query.toLowerCase();
    const filtered = POPULAR_DESTINATIONS.filter(d => 
      d.name[language].toLowerCase().includes(q) || 
      d.category[language].toLowerCase().includes(q)
    ).slice(0, 5);
    setSuggestions(filtered);
  }, [query, language]);

  return (
    <motion.header 
      initial={{ y: -100 }} animate={{ y: 0 }}
      className="fixed top-0 left-0 right-0 z-[1900] p-6 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-start gap-5 pointer-events-auto">
        <div className={`flex items-center gap-4 px-6 h-[68px] rounded-[28px] shadow-2xl ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}>
          <div className="w-11 h-11 bg-blue-600 rounded-2xl flex items-center justify-center text-white">
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path><circle cx="12" cy="10" r="3"></circle></svg>
          </div>
          <span className="font-black text-2xl tracking-tighter hidden md:block">Disha</span>
        </div>

        <div className="flex-1 relative">
          <div className={`flex items-center px-8 h-[68px] rounded-[34px] shadow-2xl transition-all ${
            isFocused ? 'ring-2 ring-blue-500' : ''
          } ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}>
            <span className="mr-4 text-slate-400">
              <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
            </span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onBlur={() => setTimeout(() => setIsFocused(false), 200)}
              onChange={(e) => setQuery(e.target.value)}
              placeholder={t.searchPlaceholder}
              className="bg-transparent border-none outline-none w-full text-xl font-bold placeholder:text-slate-500/40"
            />
            <button onClick={onVoiceSearch} className="ml-4 p-3 hover:bg-slate-500/10 rounded-full transition-colors">
              <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"></path><path d="M19 10v2a7 7 0 0 1-14 0v-2"></path><line x1="12" y1="19" x2="12" y2="23"></line><line x1="8" y1="23" x2="16" y2="23"></line></svg>
            </button>
          </div>

          <AnimatePresence>
            {isFocused && suggestions.length > 0 && (
              <motion.div 
                initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 15 }} exit={{ opacity: 0, y: 10 }}
                className={`absolute top-full left-0 right-0 rounded-[32px] overflow-hidden shadow-2xl ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}
              >
                {suggestions.map(dest => (
                  <div key={dest.id} onClick={() => onSuggestionSelect(dest)} className="px-8 py-5 flex items-center gap-5 cursor-pointer hover:bg-blue-600/10 transition-colors">
                    <span className="text-3xl">{dest.image}</span>
                    <div className="flex-1">
                      <div className="font-black text-lg">{dest.name[language]}</div>
                      <div className="text-[10px] font-bold opacity-40 uppercase tracking-widest text-blue-500">{dest.category[language]}</div>
                    </div>
                  </div>
                ))}
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex gap-4">
          <button onClick={onOpenLayers} className={`w-[68px] h-[68px] rounded-[28px] flex items-center justify-center text-blue-500 ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}>
             <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline></svg>
          </button>
          <button onClick={onThemeToggle} className={`w-[68px] h-[68px] rounded-[28px] flex items-center justify-center text-yellow-500 ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}>
            {theme === MapTheme.DARK ? '☀️' : '🌙'}
          </button>
        </div>
      </div>
    </motion.header>
  );
};

