      >
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M4 14l1-1 4 4 11-11"></path><path d="M20 20l-16-16"></path></svg>
      </motion.button>

      <motion.div 
        animate={{ rotate: -rotation * (180 / Math.PI) }} onClick={onRecenter}
        className="w-14 h-14 rounded-2xl glass flex items-center justify-center shadow-2xl cursor-pointer"
