};

import React, { useState, useEffect, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Destination, MapTheme, RouteInfo, Language, TravelMode } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface BottomPanelProps {
  theme: MapTheme;
  language: Language;
  onDestinationSelect: (d: Destination) => void;
  routeInfo: RouteInfo | null;
  userLocation: [number, number] | null;
  onClearRoute: () => void;
  onTravelModeChange: (mode: TravelMode) => void;
  selectedPlace: Destination | null;
  onClosePlace: () => void;
  onStartNavigation?: () => void;
  startPoint: any; // for compat
  endPoint: any; // for compat
  offlineRegions: any[]; // for compat
  onRegionClick: (r: any) => void;
  onRegionDelete: (id: string) => void;
}

export const BottomPanel: React.FC<BottomPanelProps> = ({ 
  theme, language, onDestinationSelect, routeInfo, userLocation, onClearRoute, onTravelModeChange, selectedPlace, onClosePlace, onStartNavigation
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (routeInfo || selectedPlace) setIsExpanded(true);
  }, [routeInfo, selectedPlace]);

  return (
    <motion.div 
      animate={{ height: isExpanded ? (selectedPlace ? '75vh' : '45vh') : '88px' }}
      className={`fixed bottom-0 left-0 right-0 z-[1400] rounded-t-[50px] shadow-2xl flex flex-col ${theme === MapTheme.DARK ? 'glass bg-slate-950/95' : 'glass-light bg-white/98'}`}
    >
      <div className="h-16 flex items-center justify-center cursor-pointer" onClick={() => setIsExpanded(!isExpanded)}>
        <div className="w-16 h-1.5 bg-slate-500/20 rounded-full" />
      </div>

      <AnimatePresence>
        {isExpanded && (
          <div className="flex-1 overflow-hidden flex flex-col px-8 lg:px-14 pb-12">
            {selectedPlace ? (
              <div className="overflow-y-auto no-scrollbar space-y-8">
                <div className="flex items-start justify-between">
                  <div>
                    <h2 className="text-4xl font-black tracking-tight">{selectedPlace.name[language]}</h2>
                    <div className="flex items-center gap-4 mt-2">
                      <span className="text-emerald-500 font-black text-xl">★ {selectedPlace.rating}</span>
                      <span className="text-xs font-bold opacity-30 uppercase tracking-widest">{selectedPlace.category[language]}</span>
                      <span className="text-xs font-black opacity-30">{''.padStart(selectedPlace.priceLevel || 0, '₹')}</span>
                    </div>
                  </div>
                  <button onClick={onClosePlace} className="w-12 h-12 rounded-full bg-slate-500/10 flex items-center justify-center text-xl">✕</button>
                </div>

                <div className="flex gap-4 overflow-x-auto no-scrollbar pb-2">
                  <button className="px-8 py-4 rounded-2xl bg-blue-600 text-white font-black text-xs uppercase tracking-widest flex items-center gap-2 shrink-0" onClick={() => onDestinationSelect(selectedPlace)}>
                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M3 11l19-9-9 19-2-8-8-2z"></path></svg>
                    {t.directions}
                  </button>
                  <button className="px-8 py-4 rounded-2xl bg-slate-500/10 font-black text-xs uppercase tracking-widest flex items-center gap-2 shrink-0">
                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.91-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"></path></svg>
                    {t.call}
                  </button>
                  <button className="px-8 py-4 rounded-2xl bg-slate-500/10 font-black text-xs uppercase tracking-widest flex items-center gap-2 shrink-0">
                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"></path></svg>
                    {t.save}
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 py-4 border-t border-slate-500/10">
                   <div className="space-y-4">
