              : `glass-light ${isFocused ? 'ring-2 ring-blue-500 bg-white' : 'hover:bg-white/98'}`
          }`}>
            <span className={`mr-5 transition-all shrink-0 ${isFocused ? 'text-blue-500 scale-125' : 'text-slate-400 opacity-50'}`}>
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
            </span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onChange={(e) => setQuery(e.target.value)}
              placeholder={t.searchPlaceholder}
              className="bg-transparent border-none outline-none w-full text-xl font-black tracking-tight placeholder:text-slate-500/35"
              style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
            />
          </div>

          <AnimatePresence mode="wait">
            {isFocused && (
              <motion.div
                initial={{ opacity: 0, y: 20, scale: 0.98 }}
                animate={{ opacity: 1, y: 15, scale: 1 }}
                exit={{ opacity: 0, y: 20, scale: 0.98 }}
                className={`absolute top-full left-0 right-0 rounded-[48px] shadow-[0_40px_120px_rgba(0,0,0,0.55)] overflow-hidden border-2 ${
                  theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'
                }`}
              >
                <div className="max-h-[75vh] overflow-y-auto py-8 custom-scrollbar">
                  {query.trim() ? (
                    <div>
                      <div className="flex items-center justify-between px-12 mb-6">
                        <div className="text-[11px] font-black uppercase tracking-[0.4em] text-blue-500">Live Discovery</div>
                        <div className="text-[10px] font-bold opacity-30 uppercase tracking-widest">Ranked by Proximity</div>
                      </div>

                      <div className="space-y-1">
                        {suggestions.length > 0 ? suggestions.map((dest) => (
                          <motion.div
                            layout
                            key={dest.id}
                            onClick={() => handleSelect(dest)}
                            className={`px-12 py-5 flex items-center gap-8 cursor-pointer transition-all relative group ${
                              theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-blue-50/60'
                            }`}
                          >
                            <div className="text-4xl w-16 h-16 flex items-center justify-center rounded-[24px] bg-slate-500/5 shrink-0 shadow-inner group-hover:scale-105 transition-transform">
                              {dest.image}
                            </div>
                            <div className="flex-1 min-w-0">
                              <div className="flex items-center gap-3">
                                <div className={`font-black text-xl truncate ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{dest.name[language]}</div>
                                <span className={`text-[10px] font-black px-2 py-0.5 rounded-full bg-slate-500/10 ${dest.live.color}`}>
                                  {dest.live.icon} {dest.live.label}
                                </span>
                              </div>
                              <div className="flex items-center gap-4 mt-1.5">
                                <div className="text-[10px] font-black uppercase tracking-[0.2em] opacity-40 text-blue-600">{dest.category[language]}</div>
                                <div className="w-1 h-1 rounded-full bg-slate-500/20" />
                                <div className="text-[10px] font-bold opacity-30">{dest.distance.toFixed(1)} km away</div>
                              </div>
                            </div>
                            <div className="opacity-0 group-hover:opacity-100 transition-opacity">
                               <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" className="text-blue-500"><path d="M5 12h14m-7-7l7 7-7 7"/></svg>
                            </div>
                          </motion.div>
                        )) : (
                          <div className="px-12 py-12 text-center">
                            <div className="text-4xl mb-4 opacity-20">🔍</div>
                            <div className="opacity-40 font-bold text-lg">No results found nearby</div>
                            <div className="text-xs opacity-30 mt-1">Try expanding your search or checking spelling</div>
                          </div>
                        )}
                      </div>
                    </div>
                  ) : (
                    <div className="space-y-12">
                      {recentSearches.length > 0 && (
                        <div>
                          <div className="text-[11px] font-black uppercase tracking-[0.4em] text-blue-500 mb-6 px-12">Recent Travels</div>
                          <div className="space-y-1">
                            {recentSearches.map(dest => (
                              <div key={`recent-${dest.id}`} onClick={() => handleSelect(dest)} className={`px-12 py-4 flex items-center gap-8 cursor-pointer transition-colors group ${theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-black/5'}`}>
