                              <div>
                                <span className="font-black text-xl block leading-none mb-1">{c.name}</span>
                                <span className="text-[10px] font-bold opacity-30 uppercase tracking-widest">Discover Nearby</span>
                              </div>
                            </button>
                          ))}
