  }, []);

  const updateRecentSearches = (dest: Destination) => {
    const updated = [dest, ...recentSearches.filter(r => r.id !== dest.id)].slice(0, 5);
    setRecentSearches(updated);
    localStorage.setItem('disha_recent_searches', JSON.stringify(updated));
  };

  useEffect(() => {
    if (!query.trim()) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(() => {
      const q = query.toLowerCase().trim();
      const ranked = POPULAR_DESTINATIONS.map(dest => {
        let score = 0;
        const name = dest.name[language].toLowerCase();
        const cat = dest.category[language].toLowerCase();

        if (name === q) score += 100;
        else if (name.startsWith(q)) score += 60;
        else if (name.includes(q)) score += 30;
        if (cat.includes(q)) score += 40;

        const similarity = stringSimilarity(name, q);
        if (similarity > 0.6) score += similarity * 40;

        const distance = getDistance(dest.coords, mapCenter);
        const proximityBonus = Math.max(0, 50 * Math.exp(-distance / 5000)); 
        score += proximityBonus;

        return { ...dest, score, distance: distance / 1000, live: getLiveStatus(dest.id) };
      })
      .filter(item => item.score > 15)
      .sort((a, b) => b.score - a.score)
      .slice(0, 6);

      setSuggestions(ranked as any);
    }, 150);

    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
