        <div className="flex gap-4 shrink-0">
          <button onClick={onOpenLayers} className={`w-[68px] h-[68px] rounded-[28px] flex items-center justify-center shadow-2xl transition-all hover:scale-105 active:scale-95 ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}>
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline></svg>
          </button>
          <button onClick={onThemeToggle} className={`w-[68px] h-[68px] rounded-[28px] flex items-center justify-center shadow-2xl transition-all hover:scale-105 active:scale-95 ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600'}`}>
