import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import { getDistance } from 'ol/sphere';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, TravelMode, NavigationState, MeasurementState } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const baseLayerRef = useRef<TileLayer<XYZ> | null>(null);
  const weatherLayerRef = useRef<TileLayer<XYZ> | null>(null);

  const routeSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const measureSource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [is3D, setIs3D] = useState(false);
  const [mapRotation, setMapRotation] = useState(0);

  const [navState, setNavState] = useState<NavigationState>({
    isActive: false, currentStep: "Ready", distanceToTurn: "0m", progress: 0, heading: 0, speed: 0
  });

  const [measureState, setMeasureState] = useState<MeasurementState>({ 
    isActive: false, points: [], totalDistance: 0 
  });

  // Layer Management
  useEffect(() => {
    if (!baseLayerRef.current || !weatherLayerRef.current) return;

    // Base Tile Switching
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    baseLayerRef.current.setSource(new XYZ({ 
      url: isSatellite ? MAP_SOURCES.SATELLITE : (theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT),
      crossOrigin: 'anonymous'
    }));

    // Weather Layer Visibility
    weatherLayerRef.current.setVisible(activeLayers.includes(MapLayerType.WEATHER));
  }, [activeLayers, theme]);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    // OpenWeatherMap or Mesonet Radar Tiles (Free/No Key for public nexrad)
    const weather = new TileLayer({
      source: new XYZ({
        url: 'https://mesonet.agron.iastate.edu/cache/tile.py/1.0.0/nexrad-n0q-900913/{z}/{x}/{y}.png',
      }),
      opacity: 0.6,
      visible: false,
      zIndex: 50
    });
    weatherLayerRef.current = weather;

    const base = new TileLayer({
      source: new XYZ({ url: theme === MapTheme.DARK ? MAP_SOURCES.DARK : MAP_SOURCES.LIGHT }),
      zIndex: 0
    });
    baseLayerRef.current = base;

    const map = new Map({
      target: mapRef.current,
      layers: [
        base,
        weather,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 150 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: measureSource.current, zIndex: 200 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true }),
      controls: []
    });

    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({
        image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) })
      }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      });
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) setMapViewCenter(toLonLat(center) as [number, number]);
      setMapRotation(map.getView().getRotation());
    });

    map.on('click', (evt) => {
      if (measureState.isActive) return; 
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
      else setSelectedPlace(null);
    });

    return () => map.setTarget(undefined);
  }, []);

  // REAL ROAD ROUTING (OSRM)
  const calculateRealRoute = async (end: Destination) => {
    if (!userLiveCoords) return;

    const start = userLiveCoords;
    const dest = end.coords;

    try {
      // Calling OSRM Public API
      const response = await fetch(
        `https://router.project-osrm.org/route/v1/driving/${start[0]},${start[1]};${dest[0]},${dest[1]}?overview=full&geometries=geojson`
      );
      const data = await response.json();

      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        const geojson = route.geometry;

        routeSource.current.clear();
        const format = new GeoJSON();
        // Fix: format.readFeature can return Feature<Geometry> | Feature<Geometry>[]
        const routeFeatureOrFeatures = format.readFeature(geojson, {
          dataProjection: 'EPSG:4326',
          featureProjection: 'EPSG:3857'
        });

        // Fix: handle potential array return to avoid type errors on setStyle and addFeature
        const features = Array.isArray(routeFeatureOrFeatures) 
          ? routeFeatureOrFeatures 
          : [routeFeatureOrFeatures];

        features.forEach((f: any) => {
          f.setStyle(new Style({
            stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round', lineJoin: 'round' })
          }));
        });

        routeSource.current.addFeatures(features as any);

        setRoutes([{
          id: '1',
          distance: `${(route.distance / 1000).toFixed(1)} km`,
          duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0',
          congestionLevel: 'low',
          mode: 'driving',
          segments: [],
          label: 'Optimal Path'
        }]);

        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { 
          padding: [200, 100, 200, 100], 
          duration: 1200 
        });
      }
    } catch (err) {
      console.error("Routing Error:", err);
      // Fallback to straight line if API fails
      const line = new Feature(new LineString([fromLonLat(start), fromLonLat(dest)]));
      line.setStyle(new Style({ stroke: new Stroke({ color: '#ef4444', width: 8 }) }));
      routeSource.current.clear();
      routeSource.current.addFeature(line);
    }
  };

  const toggleMeasure = () => {
    setMeasureState(prev => {
      if (prev.isActive) measureSource.current.clear();
      return { ...prev, isActive: !prev.isActive, points: [], totalDistance: 0 };
    });
  };

  const handleVoiceSearch = () => {
    const SpeechRecognition = (window as any).webkitSpeechRecognition || (window as any).SpeechRecognition;
    if (SpeechRecognition) {
      const rec = new SpeechRecognition();
      rec.onresult = (e: any) => {
        const transcript = e.results[0][0].transcript;
        console.log("Speech Input:", transcript);
        // Matching logic would trigger here
      };
      rec.start();
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 18, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { 
          setSelectedPlace(dest); 
          calculateRealRoute(dest); 
        }}
        onVoiceSearch={handleVoiceSearch}
      />

      <AnimatePresence>
        {activeLayers.includes(MapLayerType.WEATHER) && (
          <motion.div initial={{ x: -100, opacity: 0 }} animate={{ x: 0, opacity: 1 }} exit={{ x: -100, opacity: 0 }} className="fixed top-28 right-8 z-[800]">
            <div className="glass px-6 py-4 rounded-3xl border border-blue-500/30 flex items-center gap-4">
              <span className="text-3xl">⛈️</span>
              <div>
                <p className="text-[10px] font-black uppercase tracking-widest text-blue-500">Live Radar</p>
                <p className="font-bold">Localized Activity</p>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => {
          if (l === MapLayerType.SATELLITE || l === MapLayerType.STREET) {
             setActiveLayers(prev => prev.filter(x => x !== MapLayerType.SATELLITE && x !== MapLayerType.STREET).concat(l));
          } else {
             setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l]);
          }
        }}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace} onClosePlace={() => { setSelectedPlace(null); routeSource.current.clear(); }}
        onStartNavigation={() => setNavState(prev => ({ ...prev, isActive: true }))}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateRealRoute(dest); }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
        onTravelModeChange={() => {}} startPoint={null} endPoint={null} offlineRegions={[]} onRegionClick={() => {}} onRegionDelete={() => {}}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 18, duration: 1000 })}
        on3D={() => { setIs3D(!is3D); mapInstance.current?.getView().animate({ rotation: is3D ? 0 : Math.PI/4, duration: 1000 }); }}
        onMeasureToggle={toggleMeasure}
        is3D={is3D} isMeasuring={measureState.isActive} rotation={mapRotation}
      />

      {/* Telemetry HUD */}
      <div className="fixed top-28 left-8 z-[800] space-y-4 pointer-events-none hidden lg:block">
        <div className="glass p-5 rounded-[30px] border-l-4 border-blue-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-widest">Altitude</p>
          <p className="text-2xl font-black">924 m</p>
        </div>
        <div className="glass p-5 rounded-[30px] border-l-4 border-emerald-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-widest">Urban Flow</p>
          <p className="text-2xl font-black">Optimal</p>
        </div>
        <div className="glass p-5 rounded-[30px] border-l-4 border-amber-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-widest">Air Quality</p>
          <p className="text-2xl font-black text-amber-500">42 AQI</p>
        </div>
      </div>
    </div>
  );
};

export default App;

