        // Procedural Telemetry Update
        setTelemetry({
          altitude: Math.floor(800 + (Math.abs(lonLat[0]) % 1) * 500),
          flow: (lonLat[0] + lonLat[1]) % 2 > 1 ? 'Congested' : 'Optimal',
          aqi: Math.floor(30 + (Math.abs(lonLat[1]) % 1) * 80)
        });
      }
      setMapRotation(map.getView().getRotation());
    });

    map.on('click', (evt) => {
      if (measureState.isActive) return; 
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
      else setSelectedPlace(null);
    });

    return () => map.setTarget(undefined);
  }, []);

  // REAL ROAD ROUTING (OSRM)
  const calculateRealRoute = async (end: Destination) => {
    if (!userLiveCoords) return;

    try {
      const start = userLiveCoords;
      const dest = end.coords;

      const response = await fetch(
        `https://router.project-osrm.org/route/v1/driving/${start[0]},${start[1]};${dest[0]},${dest[1]}?overview=full&geometries=geojson`
      );
      const data = await response.json();

      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();

        const format = new GeoJSON();
        const features = format.readFeatures(route.geometry, {
          dataProjection: 'EPSG:4326',
          featureProjection: 'EPSG:3857'
        });

        features.forEach((f: any) => {
          f.setStyle(new Style({
            stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round', lineJoin: 'round' })
          }));
        });

        routeSource.current.addFeatures(features as any);

        setRoutes([{
          id: '1',
          distance: `${(route.distance / 1000).toFixed(1)} km`,
          duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0',
          congestionLevel: route.duration > route.distance / 10 ? 'moderate' : 'low',
          mode: 'driving',
          segments: [],
          label: 'Optimal Route'
        }]);

        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { 
          padding: [180, 100, 180, 100], 
          duration: 1000 
        });
      }
    } catch (err) {
      console.error("OSRM Route Error:", err);
      // Fallback
      const line = new Feature(new LineString([fromLonLat(userLiveCoords), fromLonLat(end.coords)]));
      line.setStyle(new Style({ stroke: new Stroke({ color: '#ef4444', width: 8 }) }));
      routeSource.current.clear();
      routeSource.current.addFeature(line);
    }
  };

  const toggleMeasure = () => {
    setMeasureState(prev => {
      if (prev.isActive) measureSource.current.clear();
      return { ...prev, isActive: !prev.isActive, points: [], totalDistance: 0 };
    });
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 18, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { 
          setSelectedPlace(dest); 
          calculateRealRoute(dest); 
        }}
        onVoiceSearch={() => {}}
      />

      <AnimatePresence>
        {activeLayers.includes(MapLayerType.WEATHER) && (
          <motion.div initial={{ x: -100, opacity: 0 }} animate={{ x: 0, opacity: 1 }} exit={{ x: -100, opacity: 0 }} className="fixed top-28 right-8 z-[800]">
            <div className="glass px-6 py-4 rounded-3xl border border-blue-500/30 flex items-center gap-4 shadow-2xl">
              <span className="text-3xl animate-pulse">⛈️</span>
              <div>
                <p className="text-[10px] font-black uppercase tracking-widest text-blue-500">Weather Radar</p>
                <p className="font-bold text-sm">NEXRAD Real-time</p>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => {
          if (l === MapLayerType.SATELLITE || l === MapLayerType.STREET) {
             setActiveLayers(prev => prev.filter(x => x !== MapLayerType.SATELLITE && x !== MapLayerType.STREET).concat(l));
          } else {
             setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l]);
          }
        }}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace} onClosePlace={() => { setSelectedPlace(null); routeSource.current.clear(); }}
        onStartNavigation={() => setNavState(prev => ({ ...prev, isActive: true }))}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateRealRoute(dest); }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
        onTravelModeChange={() => {}} startPoint={null} endPoint={null} offlineRegions={[]} onRegionClick={() => {}} onRegionDelete={() => {}}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 18, duration: 1000 })}
        on3D={() => { setIs3D(!is3D); mapInstance.current?.getView().animate({ rotation: is3D ? 0 : Math.PI/4, duration: 1000 }); }}
        onMeasureToggle={toggleMeasure}
        is3D={is3D} isMeasuring={measureState.isActive} rotation={mapRotation}
      />

      {/* Telemetry HUD */}
      <div className="fixed top-28 left-8 z-[800] space-y-4 pointer-events-none hidden lg:block">
        <div className="glass p-6 rounded-[34px] border-l-4 border-blue-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-widest">Elevation</p>
          <p className="text-2xl font-black">{telemetry.altitude} m</p>
        </div>
        <div className="glass p-6 rounded-[34px] border-l-4 border-emerald-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-widest">Urban Flow</p>
          <p className={`text-2xl font-black ${telemetry.flow === 'Congested' ? 'text-orange-500' : 'text-emerald-500'}`}>{telemetry.flow}</p>
        </div>
        <div className="glass p-6 rounded-[34px] border-l-4 border-amber-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-widest">Air Quality</p>
          <p className="text-2xl font-black">{telemetry.aqi} AQI</p>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onVoiceSearch: () => void;
}

const LogoIcon = () => (
  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

const getLiveStatus = (id: string) => {
  const statuses = [
    { label: 'Trending', icon: '🔥', color: 'text-orange-500' },
    { label: 'Quiet', icon: '🍃', color: 'text-emerald-500' },
    { label: 'Busy', icon: '👥', color: 'text-blue-500' },
    { label: 'Popular', icon: '⭐', color: 'text-amber-500' }
  ];
  const index = (parseInt(id) + new Date().getHours()) % statuses.length;
  return statuses[index];
};

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, mapCenter, onThemeToggle, onOpenLayers, onSuggestionSelect, onVoiceSearch 
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<(Destination & { distance: number, live: any })[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (!query.trim()) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(() => {
      const q = query.toLowerCase().trim();
      const results = POPULAR_DESTINATIONS.map(dest => {
        const name = dest.name[language].toLowerCase();
        const cat = dest.category[language].toLowerCase();
        const distance = getDistance(dest.coords, mapCenter) / 1000;

        // Scoring logic
        let score = 0;
        if (name.startsWith(q)) score += 100;
        else if (name.includes(q)) score += 50;
        if (cat.includes(q)) score += 30;

        // Proximity bias: Boost score for things within 10km
        if (distance < 10) score += (10 - distance) * 5;

        return { ...dest, score, distance, live: getLiveStatus(dest.id) };
      })
      .filter(item => item.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 6);

      setSuggestions(results as any);
    }, 150);

    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsFocused(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <motion.header 
      initial={{ y: -120, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[1900] p-6 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-start gap-5 pointer-events-auto">
        <div className={`flex items-center gap-5 px-7 py-3 rounded-[28px] shadow-2xl h-[68px] ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900'}`}>
          <div className="w-11 h-11 bg-blue-600 rounded-[18px] flex items-center justify-center text-white shadow-xl shrink-0">
            <LogoIcon />
          </div>
          <span className="font-black text-2xl tracking-tighter hidden md:block">Disha</span>
        </div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-8 h-[68px] rounded-[34px] shadow-2xl transition-all ${
            theme === MapTheme.DARK ? `glass ${isFocused ? 'ring-2 ring-blue-500' : ''}` : `glass-light ${isFocused ? 'ring-2 ring-blue-500' : ''}`
          }`}>
            <span className={`mr-4 ${isFocused ? 'text-blue-500' : 'text-slate-400'}`}>
              <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
            </span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onChange={(e) => setQuery(e.target.value)}
              placeholder={t.searchPlaceholder}
              className="bg-transparent border-none outline-none w-full text-xl font-black placeholder:text-slate-500/40"
              style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
            />
          </div>

          <AnimatePresence>
            {isFocused && (
              <motion.div
                initial={{ opacity: 0, y: 15 }}
                animate={{ opacity: 1, y: 12 }}
                exit={{ opacity: 0, y: 15 }}
                className={`absolute top-full left-0 right-0 rounded-[40px] shadow-[0_32px_96px_rgba(0,0,0,0.5)] overflow-hidden border ${
                  theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'
                }`}
              >
                <div className="max-h-[60vh] overflow-y-auto py-6 no-scrollbar">
                  {suggestions.length > 0 ? (
                    <div className="space-y-1">
                      {suggestions.map((dest) => (
                        <div 
                          key={dest.id} 
                          onClick={() => {
                            onSuggestionSelect(dest);
                            setIsFocused(false);
                            setQuery(dest.name[language]);
                          }} 
                          className="px-10 py-5 flex items-center gap-6 cursor-pointer hover:bg-blue-600/10 transition-colors group"
                        >
                          <div className="text-3xl w-14 h-14 flex items-center justify-center rounded-2xl bg-slate-500/5 group-hover:scale-110 transition-transform">
                            {dest.image}
                          </div>
                          <div className="flex-1">
                            <div className="font-black text-lg flex items-center gap-3">
                              {dest.name[language]}
                              <span className={`text-[9px] font-black uppercase ${dest.live.color}`}>{dest.live.icon} {dest.live.label}</span>
                            </div>
                            <div className="text-[10px] font-bold opacity-30 uppercase tracking-widest">{dest.category[language]} • {dest.distance.toFixed(1)} km away</div>
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="px-12 py-12 text-center">
                      <p className="font-bold opacity-40">Search nearby landmarks or categories...</p>
                    </div>
                  )}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex gap-4 shrink-0">
          <button onClick={onOpenLayers} className={`w-[68px] h-[68px] rounded-[28px] flex items-center justify-center shadow-2xl transition-all hover:scale-105 ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}>
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline></svg>
          </button>
          <button onClick={onThemeToggle} className={`w-[68px] h-[68px] rounded-[28px] flex items-center justify-center shadow-2xl transition-all hover:scale-105 ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600'}`}>
            {theme === MapTheme.DARK ? '☀️' : '🌙'}
          </button>
        </div>
      </div>
    </motion.header>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import { getDistance } from 'ol/sphere';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
import { GoogleGenAI } from '@google/genai';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, TravelMode, NavigationState, MeasurementState } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const baseLayerRef = useRef<TileLayer<XYZ> | null>(null);
  const weatherLayerRef = useRef<TileLayer<XYZ> | null>(null);

  const routeSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const measureSource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [is3D, setIs3D] = useState(false);
  const [mapRotation, setMapRotation] = useState(0);
  const [isSearching, setIsSearching] = useState(false);

  // Telemetry state
  const [telemetry, setTelemetry] = useState({
    altitude: 924,
    flow: 'Optimal',
    aqi: 42
  });

  const [navState, setNavState] = useState<NavigationState>({
    isActive: false, currentStep: "Ready", distanceToTurn: "0m", progress: 0, heading: 0, speed: 0
  });

  const [measureState, setMeasureState] = useState<MeasurementState>({ 
    isActive: false, points: [], totalDistance: 0 
  });

  // Manage layer updates
  useEffect(() => {
    if (!baseLayerRef.current || !weatherLayerRef.current) return;

    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    let url = isSatellite ? MAP_SOURCES.GOOGLE_SATELLITE : MAP_SOURCES.GOOGLE_STREET;

    // Allow users to fallback to dark mode for specific feel
    if (!isSatellite && theme === MapTheme.DARK && !activeLayers.includes(MapLayerType.STREET)) {
        url = MAP_SOURCES.DARK;
    }

    baseLayerRef.current.setSource(new XYZ({ 
      url: url,
      crossOrigin: 'anonymous'
    }));

    weatherLayerRef.current.setVisible(activeLayers.includes(MapLayerType.WEATHER));
  }, [activeLayers, theme]);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    // Real-time NEXRAD Radar Tiles
    const weather = new TileLayer({
      source: new XYZ({
        url: 'https://mesonet.agron.iastate.edu/cache/tile.py/1.0.0/nexrad-n0q-900913/{z}/{x}/{y}.png',
      }),
      opacity: 0.5,
      visible: false,
      zIndex: 50
    });
    weatherLayerRef.current = weather;

    const base = new TileLayer({
      source: new XYZ({ url: MAP_SOURCES.GOOGLE_STREET }),
      zIndex: 0
    });
    baseLayerRef.current = base;

    const map = new Map({
      target: mapRef.current,
      layers: [
        base,
        weather,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 150 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: measureSource.current, zIndex: 200 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true }),
      controls: []
    });

    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({
        image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) })
      }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      });
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);

        // Procedural Telemetry Update
        setTelemetry({
          altitude: Math.floor(800 + (Math.abs(lonLat[0]) % 1) * 500),
          flow: (lonLat[0] + lonLat[1]) % 2 > 1 ? 'Congested' : 'Optimal',
          aqi: Math.floor(30 + (Math.abs(lonLat[1]) % 1) * 80)
        });
      }
      setMapRotation(map.getView().getRotation());
    });

    map.on('click', (evt) => {
      if (measureState.isActive) return; 
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
      else setSelectedPlace(null);
    });

    return () => map.setTarget(undefined);
  }, []);

  // AI POWERED SEARCH WITH GOOGLE MAPS GROUNDING
  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: `Find real-time information and location for: ${query} in the current view. Return as specific location data.`,
        config: {
          tools: [{ googleMaps: {} }],
          toolConfig: {
            retrievalConfig: {
              latLng: {
                latitude: mapViewCenter[1],
                longitude: mapViewCenter[0]
              }
            }
          }
        },
      });

      const textOutput = response.text;
      const grounding = response.candidates?.[0]?.groundingMetadata;
      const chunks = grounding?.groundingChunks || [];

      // Extract place URI from grounding for compliance
      const mapLinks = chunks.filter(c => c.maps).map(c => ({
          uri: c.maps?.uri,
          title: c.maps?.title || query
      }));

      // In a real implementation we'd parse coordinates from the grounding or model text.
      // For this demo, we'll search the popular destinations or generate a local result.
      // Ideally, the model gives us lat/lng. Since we are using googleMaps tool, 
      // the grounding metadata usually helps identify the place.

      // Let's assume the first map link is our destination
      if (mapLinks.length > 0) {
          const mainPlace = mapLinks[0];
          // Create a dynamic destination object
          const dynamicDest: Destination = {
              id: 'ai-' + Date.now(),
              name: { en: mainPlace.title, hi: mainPlace.title, kn: mainPlace.title, es: mainPlace.title },
              category: { en: 'Discovery', hi: 'खोज', kn: 'ಶೋಧನೆ', es: 'Descubrimiento' },
              coords: mapViewCenter, // Fallback to current center if no coords in response
              description: { en: textOutput || 'Real-time search result', hi: textOutput, kn: textOutput, es: textOutput },
              image: '📍',
              rating: 4.5,
              website: mainPlace.uri,
              isOpen: true
          };

          setSelectedPlace(dynamicDest);

          // Boost: If the AI output mentions coordinates, we could parse them here.
          // For now, we rely on the grounding metadata.
      }
    } catch (err) {
      console.error("Gemini Maps Search Error:", err);
    } finally {
      setIsSearching(false);
    }
  };

  // REAL ROAD ROUTING (OSRM)
  const calculateRealRoute = async (end: Destination) => {
    if (!userLiveCoords) return;

    try {
      const start = userLiveCoords;
      const dest = end.coords;

      const response = await fetch(
        `https://router.project-osrm.org/route/v1/driving/${start[0]},${start[1]};${dest[0]},${dest[1]}?overview=full&geometries=geojson`
      );
      const data = await response.json();

      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();

        const format = new GeoJSON();
        const features = format.readFeatures(route.geometry, {
          dataProjection: 'EPSG:4326',
          featureProjection: 'EPSG:3857'
        });

        features.forEach((f: any) => {
          f.setStyle(new Style({
            stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round', lineJoin: 'round' })
          }));
        });

        routeSource.current.addFeatures(features as any);

        setRoutes([{
          id: '1',
          distance: `${(route.distance / 1000).toFixed(1)} km`,
          duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0',
          congestionLevel: route.duration > route.distance / 10 ? 'moderate' : 'low',
          mode: 'driving',
          segments: [],
          label: 'Optimal Route'
        }]);

        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { 
          padding: [180, 100, 180, 100], 
          duration: 1000 
        });
      }
    } catch (err) {
      console.error("OSRM Route Error:", err);
      // Fallback
      const line = new Feature(new LineString([fromLonLat(userLiveCoords), fromLonLat(end.coords)]));
      line.setStyle(new Style({ stroke: new Stroke({ color: '#ef4444', width: 8 }) }));
      routeSource.current.clear();
      routeSource.current.addFeature(line);
    }
  };

  const toggleMeasure = () => {
    setMeasureState(prev => {
      if (prev.isActive) measureSource.current.clear();
      return { ...prev, isActive: !prev.isActive, points: [], totalDistance: 0 };
    });
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 18, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { 
          setSelectedPlace(dest); 
          calculateRealRoute(dest); 
        }}
        onVoiceSearch={() => {}}
        onAISearch={handleAISearch}
      />

      {isSearching && (
          <div className="fixed inset-0 z-[3000] flex items-center justify-center bg-black/20 backdrop-blur-sm">
              <div className="glass p-8 rounded-[40px] flex flex-col items-center gap-6 animate-in fade-in zoom-in">
                  <div className="w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
                  <p className="font-black text-xl tracking-tight">AI Discovering Reality...</p>
              </div>
          </div>
      )}

      <AnimatePresence>
        {activeLayers.includes(MapLayerType.WEATHER) && (
          <motion.div initial={{ x: -100, opacity: 0 }} animate={{ x: 0, opacity: 1 }} exit={{ x: -100, opacity: 0 }} className="fixed top-28 right-8 z-[800]">
            <div className="glass px-6 py-4 rounded-3xl border border-blue-500/30 flex items-center gap-4 shadow-2xl">
              <span className="text-3xl animate-pulse">⛈️</span>
              <div>
                <p className="text-[10px] font-black uppercase tracking-widest text-blue-500">Weather Radar</p>
                <p className="font-bold text-sm">NEXRAD Real-time</p>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => {
          if (l === MapLayerType.SATELLITE || l === MapLayerType.STREET) {
             setActiveLayers(prev => prev.filter(x => x !== MapLayerType.SATELLITE && x !== MapLayerType.STREET).concat(l));
          } else {
             setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l]);
          }
        }}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace} onClosePlace={() => { setSelectedPlace(null); routeSource.current.clear(); }}
        onStartNavigation={() => setNavState(prev => ({ ...prev, isActive: true }))}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateRealRoute(dest); }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
        onTravelModeChange={() => {}} startPoint={null} endPoint={null} offlineRegions={[]} onRegionClick={() => {}} onRegionDelete={() => {}}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 18, duration: 1000 })}
        on3D={() => { setIs3D(!is3D); mapInstance.current?.getView().animate({ rotation: is3D ? 0 : Math.PI/4, duration: 1000 }); }}
        onMeasureToggle={toggleMeasure}
        is3D={is3D} isMeasuring={measureState.isActive} rotation={mapRotation}
      />

      {/* Telemetry HUD */}
      <div className="fixed top-28 left-8 z-[800] space-y-4 pointer-events-none hidden lg:block">
        <div className="glass p-6 rounded-[34px] border-l-4 border-blue-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-widest">Elevation</p>
          <p className="text-2xl font-black">{telemetry.altitude} m</p>
        </div>
        <div className="glass p-6 rounded-[34px] border-l-4 border-emerald-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-widest">Urban Flow</p>
          <p className={`text-2xl font-black ${telemetry.flow === 'Congested' ? 'text-orange-500' : 'text-emerald-500'}`}>{telemetry.flow}</p>
        </div>
        <div className="glass p-6 rounded-[34px] border-l-4 border-amber-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-widest">Air Quality</p>
          <p className="text-2xl font-black">{telemetry.aqi} AQI</p>
        </div>
      </div>
    </div>
  );
};

