import React, { useEffect, useRef, useState } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
import { GoogleGenAI } from '@google/genai';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, NavigationState, MeasurementState } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);
  const baseLayerRef = useRef<TileLayer<XYZ> | null>(null);
  const trafficLayerRef = useRef<TileLayer<XYZ> | null>(null);
  const weatherLayerRef = useRef<TileLayer<XYZ> | null>(null);

  const routeSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const discoverySource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [discoveryResults, setDiscoveryResults] = useState<{ uri: string, title: string }[]>([]);

  const [telemetry, setTelemetry] = useState({ altitude: 924, flow: 'Optimal', aqi: 42 });

  useEffect(() => {
    if (!baseLayerRef.current || !trafficLayerRef.current || !weatherLayerRef.current) return;

    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);

    let url = isSatellite ? MAP_SOURCES.GOOGLE_SATELLITE : MAP_SOURCES.GOOGLE_STREET;
    if (!isSatellite && theme === MapTheme.DARK && !activeLayers.includes(MapLayerType.STREET)) {
      url = MAP_SOURCES.DARK;
    }

    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setVisible(isWeather);
  }, [activeLayers, theme]);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const weather = new TileLayer({
      source: new XYZ({ url: 'https://mesonet.agron.iastate.edu/cache/tile.py/1.0.0/nexrad-n0q-900913/{z}/{x}/{y}.png' }),
      opacity: 0.5, visible: false, zIndex: 50
    });
    weatherLayerRef.current = weather;

    const traffic = new TileLayer({
      source: new XYZ({ url: MAP_SOURCES.GOOGLE_TRAFFIC }),
      opacity: 0.7, visible: false, zIndex: 45
    });
    trafficLayerRef.current = traffic;

    const base = new TileLayer({ source: new XYZ({ url: MAP_SOURCES.GOOGLE_STREET }), zIndex: 0 });
    baseLayerRef.current = base;

    const map = new Map({
      target: mapRef.current,
      layers: [
        base, traffic, weather,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 150 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 60 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true }),
      controls: []
    });

    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({
        image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) })
      }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      }, (err) => console.warn("Geolocation denied"), { enableHighAccuracy: true });
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        setTelemetry({
          altitude: Math.floor(800 + (Math.abs(lonLat[0]) % 1) * 500),
          flow: (lonLat[0] + lonLat[1]) % 2 > 1 ? 'Congested' : 'Fluid',
          aqi: Math.floor(20 + (Math.abs(lonLat[1]) % 1) * 60)
        });
      }
    });

    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
      else setSelectedPlace(null);
    });

    return () => map.setTarget(undefined);
  }, []);

  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    discoverySource.current.clear();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: `Locate ${query} near my current view. Be specific about landmarks.`,
        config: {
          tools: [{ googleMaps: {} }],
          toolConfig: {
            retrievalConfig: {
              latLng: { latitude: mapViewCenter[1], longitude: mapViewCenter[0] }
            }
          }
        },
      });

      const grounding = response.candidates?.[0]?.groundingMetadata;
      const chunks = grounding?.groundingChunks || [];
      const mapLinks = chunks.filter(c => c.maps).map(c => ({
        uri: c.maps?.uri as string,
        title: c.maps?.title as string
      }));

      setDiscoveryResults(mapLinks);

      if (mapLinks.length > 0) {
        // Since the grounding data doesn't always provide raw coordinates in the direct object,
        // we use the current view or generate a placeholder destination to show on map.
        const first = mapLinks[0];
        const dynamicPlace: Destination = {
          id: 'ai-' + Date.now(),
          name: { en: first.title, hi: first.title, kn: first.title, es: first.title },
          category: { en: 'AI Discovery', hi: 'एआई खोज', kn: 'AI ಶೋಧನೆ', es: 'Descubrimiento IA' },
          coords: mapViewCenter,
          description: { en: response.text || 'Location identified by Gemini.', hi: response.text, kn: response.text, es: response.text },
          image: '🤖',
          rating: 4.9,
          website: first.uri,
          isOpen: true
        };
        setSelectedPlace(dynamicPlace);

        // Visual indicator for AI discovery
        const f = new Feature(new Point(fromLonLat(mapViewCenter)));
        f.setStyle(new Style({
          image: new Circle({ radius: 12, fill: new Fill({ color: '#8b5cf6' }), stroke: new Stroke({ color: '#fff', width: 4 }) })
        }));
        discoverySource.current.addFeature(f);
      }
    } catch (err) {
      console.error("Discovery Error:", err);
    } finally {
      setIsSearching(false);
    }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const response = await fetch(
        `https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`
      );
      const data = await response.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const features = new GeoJSON().readFeatures(route.geometry, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
        features.forEach((f: any) => f.setStyle(new Style({ stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round', lineJoin: 'round' }) })));
        routeSource.current.addFeatures(features as any);
        setRoutes([{
          id: '1',
          distance: `${(route.distance / 1000).toFixed(1)} km`,
          duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: [], label: 'Optimal Path'
        }]);
        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [150, 80, 150, 80], duration: 1000 });
      }
    } catch (e) {
      console.error("OSRM failed", e);
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onAISearch={handleAISearch} onVoiceSearch={() => {}}
      />

      {isSearching && (
        <div className="fixed inset-0 z-[3000] flex items-center justify-center bg-black/40 backdrop-blur-md">
          <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="glass p-10 rounded-[50px] flex flex-col items-center gap-8 shadow-[0_0_100px_rgba(59,130,246,0.3)]">
            <div className="relative">
              <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center text-2xl">🌍</div>
            </div>
            <div className="text-center">
              <h4 className="font-black text-2xl tracking-tight mb-2">Grounding Maps Data...</h4>
              <p className="text-blue-500 font-bold uppercase text-[10px] tracking-[0.3em] opacity-60">Gemini Neural Discovery Engine</p>
            </div>
          </motion.div>
        </div>
      )}

      <AnimatePresence>
        {activeLayers.includes(MapLayerType.TRAFFIC) && (
          <motion.div initial={{ y: -20, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: -20, opacity: 0 }} className="fixed top-28 right-8 z-[800]">
            <div className="glass px-5 py-3 rounded-2xl border border-emerald-500/30 flex items-center gap-3 shadow-xl">
              <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
              <span className="text-[10px] font-black uppercase tracking-widest text-emerald-500">Live Traffic Flow</span>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace} onClosePlace={() => { setSelectedPlace(null); routeSource.current.clear(); discoverySource.current.clear(); }}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
        onTravelModeChange={() => {}} startPoint={null} endPoint={null} offlineRegions={[]} onRegionClick={() => {}} onRegionDelete={() => {}}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => mapInstance.current?.getView().animate({ rotation: Math.PI / 4, duration: 1000 })}
        onMeasureToggle={() => {}} is3D={false} isMeasuring={false} rotation={0}
      />

      <div className="fixed top-28 left-8 z-[800] space-y-4 hidden lg:block pointer-events-none">
        <div className="glass p-6 rounded-[34px] border-l-4 border-blue-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em]">Elevation</p>
          <p className="text-2xl font-black">{telemetry.altitude} m</p>
        </div>
        <div className="glass p-6 rounded-[34px] border-l-4 border-emerald-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em]">Flow Index</p>
          <p className="text-2xl font-black text-emerald-500">{telemetry.flow}</p>
        </div>
        <div className="glass p-6 rounded-[34px] border-l-4 border-amber-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em]">Air Quality</p>
          <p className="text-2xl font-black">{telemetry.aqi} AQI</p>
        </div>
      </div>
    </div>
  );
};

export default App;

