import React, { useEffect, useRef, useState } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
import { GoogleGenAI } from '@google/genai';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  // Layer References for dynamic switching
  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const infraLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false }));
  const nasaLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false, opacity: 0.6 }));

  const routeSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const discoverySource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [vitals, setVitals] = useState({ altitude: 0, density: 'Medium', speed: 0 });

  // Core Map Initialization
  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const map = new Map({
      target: mapRef.current,
      layers: [
        baseLayerRef.current,
        infraLayerRef.current,
        nasaLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 110 })
      ],
      view: new View({ 
        center: fromLonLat(DEFAULT_CENTER), 
        zoom: DEFAULT_ZOOM, 
        constrainResolution: true,
        smoothExtentConstraint: true 
      }),
      controls: []
    });

    mapInstance.current = map;

    // Load Initial Points
    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({
        image: new Circle({ 
          radius: 8, 
          fill: new Fill({ color: '#3b82f6' }), 
          stroke: new Stroke({ color: '#fff', width: 3 }) 
        })
      }));
      poiSource.current.addFeature(f);
    });

    // High Precision Geolocation
    if (navigator.geolocation) {
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ 
          image: new Circle({ 
            radius: 12, 
            fill: new Fill({ color: '#3b82f6' }), 
            stroke: new Stroke({ color: '#fff', width: 4 }) 
          }) 
        }));
        userLocSource.current.addFeature(f);
        setVitals(v => ({ ...v, speed: Math.floor(pos.coords.speed || 0) * 3.6 }));
      }, null, { enableHighAccuracy: true });
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        // Simulate elevation/density via coordinate math for HUD effect
        setVitals(v => ({
          ...v,
          altitude: Math.floor(400 + Math.abs(lonLat[0] % 1) * 1000),
          density: (lonLat[0] + lonLat[1]) % 2 > 1 ? 'High' : 'Urban'
        }));
      }
    });

    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
      else setSelectedPlace(null);
    });

    return () => map.setTarget(undefined);
  }, []);

  // Sync Layers with State
  useEffect(() => {
    if (!mapInstance.current) return;

    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isNASA = activeLayers.includes(MapLayerType.WEATHER);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isTerrain = activeLayers.includes(MapLayerType.INDUSTRIAL);

    // 1. Base Tile Logic
    let baseUrl = MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) baseUrl = MAP_SOURCES.GOOGLE_SATELLITE;
    else if (theme === MapTheme.DARK) baseUrl = MAP_SOURCES.DARK;

    baseLayerRef.current.setSource(new XYZ({ url: baseUrl, crossOrigin: 'anonymous' }));

    // 2. NASA MODIS Logic
    nasaLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NASA_GIBS_MODIS }));
    nasaLayerRef.current.setVisible(isNASA);

    // 3. Traffic Logic
    infraLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.GOOGLE_TRAFFIC }));
    infraLayerRef.current.setVisible(isTraffic);

  }, [activeLayers, theme]);

  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    discoverySource.current.clear();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: `Find real-time status and specific details for: ${query}. Focus on the area around ${mapViewCenter[0]}, ${mapViewCenter[1]}.`,
        config: {
          tools: [{ googleMaps: {} }],
          toolConfig: {
            retrievalConfig: {
              latLng: { latitude: mapViewCenter[1], longitude: mapViewCenter[0] }
            }
          }
        },
      });

      const grounding = response.candidates?.[0]?.groundingMetadata;
      const chunks = grounding?.groundingChunks || [];
      const mapLinks = chunks.filter(c => c.maps).map(c => ({
        uri: c.maps?.uri as string,
        title: c.maps?.title as string
      }));

      if (mapLinks.length > 0) {
        const first = mapLinks[0];
        const result: Destination = {
          id: `ai-${Date.now()}`,
          name: { en: first.title, hi: first.title, kn: first.title, es: first.title },
          category: { en: 'AI Intelligence', hi: 'एआई इंटेलिजेंस', kn: 'AI ಇಂಟೆಲಿಜೆನ್ಸ್', es: 'Inteligencia IA' },
          coords: mapViewCenter,
          description: { en: response.text || 'Detected via Maps Grounding.', hi: response.text, kn: response.text, es: response.text },
          image: '🛰️',
          rating: 4.8,
          website: first.uri,
          isOpen: true
        };
        setSelectedPlace(result);

        // Dynamic Marker
        const f = new Feature(new Point(fromLonLat(mapViewCenter)));
        f.setStyle(new Style({
          image: new Circle({ 
            radius: 14, 
            fill: new Fill({ color: '#8b5cf6' }), 
            stroke: new Stroke({ color: '#fff', width: 4 }) 
          })
        }));
        discoverySource.current.addFeature(f);
      }
    } catch (err) {
      console.error("Discovery Engine Error:", err);
    } finally {
      setIsSearching(false);
    }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const url = `https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`;
      const res = await fetch(url);
      const data = await res.json();

      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const features = new GeoJSON().readFeatures(route.geometry, { 
          dataProjection: 'EPSG:4326', 
          featureProjection: 'EPSG:3857' 
        });
        features.forEach((f: any) => f.setStyle(new Style({ 
          stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round' }) 
        })));
        routeSource.current.addFeatures(features as any);

        setRoutes([{
          id: 'rt1',
          distance: `${(route.distance / 1000).toFixed(1)} km`,
          duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0',
          congestionLevel: 'low',
          mode: 'driving',
          segments: []
        }]);

        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { 
          padding: [100, 100, 100, 100], 
          duration: 1200 
        });
      }
    } catch (e) {
      console.warn("Routing engine failed", e);
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-[#020617] text-white' : 'bg-white text-slate-900'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onAISearch={handleAISearch} onVoiceSearch={() => {}}
      />

      {isSearching && (
        <div className="fixed inset-0 z-[3000] flex items-center justify-center bg-black/40 backdrop-blur-xl">
          <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="glass p-12 rounded-[60px] flex flex-col items-center gap-6 text-center border-blue-500/20 shadow-[0_0_120px_rgba(59,130,246,0.4)]">
             <div className="relative">
                <div className="w-24 h-24 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center text-4xl">🛰️</div>
             </div>
             <div>
                <h4 className="font-black text-2xl tracking-tighter mb-1">Engaging Maps Grounding</h4>
                <p className="text-blue-400 font-black uppercase text-[10px] tracking-[0.4em]">Gemini 2.5 Multi-Spectral Analysis</p>
             </div>
          </motion.div>
        </div>
      )}

      {/* Urban Vitals HUD */}
      <div className="fixed top-28 left-8 z-[800] space-y-4 hidden lg:block pointer-events-none">
        <motion.div layout className="glass p-6 rounded-[34px] border-l-4 border-blue-600 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em]">Sea Level</p>
          <p className="text-3xl font-black">{vitals.altitude} m</p>
        </motion.div>
        <motion.div layout className="glass p-6 rounded-[34px] border-l-4 border-emerald-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em]">Urban Flux</p>
          <p className="text-3xl font-black text-emerald-500">{vitals.density}</p>
        </motion.div>
        <motion.div layout className="glass p-6 rounded-[34px] border-l-4 border-amber-500 w-48 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em]">Current Velocity</p>
          <p className="text-3xl font-black">{vitals.speed} <span className="text-sm opacity-50">km/h</span></p>
        </motion.div>
      </div>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      {/* Fix: Removed extra props (startPoint, endPoint, offlineRegions, etc.) that are not in BottomPanelProps interface */}
      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace} onClosePlace={() => { setSelectedPlace(null); routeSource.current.clear(); discoverySource.current.clear(); }}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
        onTravelModeChange={() => {}}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => mapInstance.current?.getView().animate({ rotation: Math.PI/4, duration: 1000 })}
        onMeasureToggle={() => {}} is3D={false} isMeasuring={false} rotation={0}
      />
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
import { GoogleGenAI } from '@google/genai';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

declare const puter: any;

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  // Layer References
  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const trafficLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false, opacity: 0.7 }));
  const weatherLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false }));
  const planetaryLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: -1, visible: false })); // Night / Satellite

  const routeSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const discoverySource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [isPuterReady, setIsPuterReady] = useState(false);

  const [telemetry, setTelemetry] = useState({
    altitude: 900,
    signal: 'Strong',
    urbanFlow: 'Fluid'
  });

  // Puter.js Integration: Load settings
  useEffect(() => {
    puter.ui.onReady(() => {
      setIsPuterReady(true);
      puter.kv.get('user_settings').then((data: string) => {
        if (data) {
          const settings = JSON.parse(data);
          if (settings.theme) setTheme(settings.theme);
          if (settings.lang) setLanguage(settings.lang);
        }
      }).catch(() => console.log("New Puter session started."));
    });
  }, []);

  // Persist settings via Puter
  const updateSettings = useCallback((updates: Partial<{theme: MapTheme, lang: Language}>) => {
    if (updates.theme) setTheme(updates.theme);
    if (updates.lang) setLanguage(updates.lang);

    if (isPuterReady) {
      puter.kv.set('user_settings', JSON.stringify({ 
        theme: updates.theme || theme, 
        lang: updates.lang || language 
      }));
    }
  }, [isPuterReady, theme, language]);

  // Core Map Initialization
  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current,
        baseLayerRef.current,
        trafficLayerRef.current,
        weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 110 })
      ],
      view: new View({ 
        center: fromLonLat(DEFAULT_CENTER), 
        zoom: DEFAULT_ZOOM, 
        constrainResolution: true,
        smoothExtentConstraint: true 
      }),
      controls: []
    });

    mapInstance.current = map;

    // Load Initial Intelligence Points
    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({
        image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) })
      }));
      poiSource.current.addFeature(f);
    });

    // Orbital Geolocation
    if (navigator.geolocation) {
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ 
          image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) 
        }));
        userLocSource.current.addFeature(f);
      }, null, { enableHighAccuracy: true });
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        // Telemetry calculation
        setTelemetry({
          altitude: Math.floor(800 + Math.abs(lonLat[0] % 1) * 1200),
          signal: (lonLat[0] + lonLat[1]) % 2 > 1 ? 'Stable' : 'Oscillating',
          urbanFlow: (lonLat[1] % 1) > 0.5 ? 'Heavy' : 'Fluid'
        });
      }
    });

    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
      else setSelectedPlace(null);
    });

    return () => map.setTarget(undefined);
  }, []);

  // Multi-Spectral Layer Controller
  useEffect(() => {
    if (!mapInstance.current) return;

    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);

    // 1. Base Layer
    let url = MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;
    else if (theme === MapTheme.DARK) url = MAP_SOURCES.DARK_CANVAS;

    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));

    // 2. Traffic Overlay
    trafficLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.GOOGLE_TRAFFIC }));
    trafficLayerRef.current.setVisible(isTraffic);

    // 3. NASA GIBS / Weather
    weatherLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NOAA_PRECIP }));
    weatherLayerRef.current.setVisible(isWeather);

    // 4. Night Marble / Sentinel
    planetaryLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NASA_GIBS_NIGHT }));
    planetaryLayerRef.current.setVisible(isNight);
    baseLayerRef.current.setOpacity(isNight ? 0.3 : 1.0);

  }, [activeLayers, theme]);

  // AI-Powered Spatial Grounding Discovery
  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    discoverySource.current.clear();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: `Locate ${query} near ${mapViewCenter[1]}, ${mapViewCenter[0]}. Provide real-time operational status.`,
        config: {
          tools: [{ googleMaps: {} }],
          toolConfig: {
            retrievalConfig: {
              latLng: { latitude: mapViewCenter[1], longitude: mapViewCenter[0] }
            }
          }
        },
      });

      const grounding = response.candidates?.[0]?.groundingMetadata;
      const chunks = grounding?.groundingChunks || [];
      const mapLinks = chunks.filter(c => c.maps).map(c => ({
        uri: c.maps?.uri as string,
        title: c.maps?.title as string
      }));

      if (mapLinks.length > 0) {
        const first = mapLinks[0];
        const discoveryDest: Destination = {
          id: `ai-${Date.now()}`,
          name: { en: first.title, hi: first.title, kn: first.title, es: first.title },
          category: { en: 'AI Discovery', hi: 'एआई खोज', kn: 'AI ಶೋಧನೆ', es: 'Hallazgo IA' },
          coords: mapViewCenter,
          description: { en: response.text || 'Intelligence retrieved from planetary index.', hi: response.text, kn: response.text, es: response.text },
          image: '🛰️',
          rating: 4.9,
          website: first.uri,
          isOpen: true
        };
        setSelectedPlace(discoveryDest);

        // Mark on map
        const f = new Feature(new Point(fromLonLat(mapViewCenter)));
        f.setStyle(new Style({
          image: new Circle({ 
            radius: 12, 
            fill: new Fill({ color: '#8b5cf6' }), 
            stroke: new Stroke({ color: '#fff', width: 4 }) 
          })
        }));
        discoverySource.current.addFeature(f);

        // Puter logic: save last discovery
        if (isPuterReady) {
          puter.kv.set('last_discovery', JSON.stringify(discoveryDest));
        }
      }
    } catch (err) {
      console.error("Spatial grounding failed:", err);
    } finally {
      setIsSearching(false);
    }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const features = new GeoJSON().readFeatures(route.geometry, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
        features.forEach((f: any) => f.setStyle(new Style({ stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round' }) })));
        routeSource.current.addFeatures(features as any);

        setRoutes([{
          id: 'rt1',
          distance: `${(route.distance / 1000).toFixed(1)} km`,
          duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);

        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [100, 100, 100, 100], duration: 1000 });
      }
    } catch (e) {
      console.error("OSRM failed:", e);
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-[#020617] text-[#e2e8f0]' : 'bg-[#f8fafc] text-[#0f172a]'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => updateSettings({ theme: theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK })}
        onLanguageChange={(l) => updateSettings({ lang: l })}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onAISearch={handleAISearch} onVoiceSearch={() => {}}
      />

      {isSearching && (
        <div className="fixed inset-0 z-[3000] flex items-center justify-center bg-black/60 backdrop-blur-md">
          <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="glass p-12 rounded-[50px] border border-blue-500/20 text-center flex flex-col items-center gap-6">
            <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
            <h4 className="font-black text-2xl tracking-tight">Syncing Planetary Index...</h4>
            <p className="text-blue-500 font-bold uppercase text-[10px] tracking-[0.4em] mono">Gemini 2.5 Multi-Spectral Grounding</p>
          </motion.div>
        </div>
      )}

      {/* Orbital Telemetry HUD */}
      <div className="fixed top-28 left-8 z-[800] space-y-4 pointer-events-none hidden lg:block">
        <div className="glass p-5 rounded-[28px] border-l-4 border-blue-600 w-52 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em] mono">Sea-Level Altitude</p>
          <p className="text-2xl font-black hud-text">{telemetry.altitude} m</p>
        </div>
        <div className="glass p-5 rounded-[28px] border-l-4 border-emerald-500 w-52 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em] mono">Orbital Link</p>
          <p className="text-2xl font-black text-emerald-500 hud-text">{telemetry.signal}</p>
        </div>
        <div className="glass p-5 rounded-[28px] border-l-4 border-amber-500 w-52 shadow-2xl">
          <p className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em] mono">Urban Density</p>
          <p className="text-2xl font-black hud-text">{telemetry.urbanFlow}</p>
        </div>
        {isPuterReady && (
          <div className="glass p-4 rounded-2xl flex items-center gap-3 w-52 border border-white/5">
            <div className="w-3 h-3 rounded-full bg-blue-500 animate-pulse"></div>
            <p className="text-[9px] font-black uppercase opacity-60 mono tracking-widest">Puter Cloud Connected</p>
          </div>
        )}
      </div>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace} onClosePlace={() => { setSelectedPlace(null); routeSource.current.clear(); discoverySource.current.clear(); }}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
        onTravelModeChange={() => {}}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => mapInstance.current?.getView().animate({ rotation: Math.PI / 4, duration: 1000 })}
        onMeasureToggle={() => {}} is3D={false} isMeasuring={false} rotation={0}
      />
    </div>
  );
};

export default App;

