    { id: MapLayerType.STREET, label: 'Roadmap Alpha', icon: '🏙️', desc: 'Google Optimized Vector' },
    { id: MapLayerType.SATELLITE, label: 'Orbital Recon', icon: '🛰️', desc: 'Hybrid Satellite Mosaic' },
