          className={`fixed top-0 right-0 bottom-0 w-full lg:w-[460px] p-10 lg:p-14 shadow-2xl z-[2000] border-l border-white/5 overflow-y-auto no-scrollbar transition-colors duration-500 ${theme === MapTheme.DARK ? 'glass' : 'glass-light'}`}
        >
          <div className="flex justify-between items-center mb-16">
            <div>
              <h3 className={`font-black text-4xl tracking-tighter ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Map Deck</h3>
              <p className="text-blue-500 font-black uppercase text-[10px] tracking-[0.4em] mono">Geospatial Intelligence Hub</p>
            </div>
            <button onClick={onClose} className="w-14 h-14 flex items-center justify-center rounded-3xl bg-white/5 text-gray-400 hover:text-white transition-colors">✕</button>
          </div>

          <div className="space-y-16">
            <section>
              <h4 className="text-[11px] font-black uppercase tracking-[0.3em] opacity-40 mb-8 mono">Cartographic Baselines</h4>
              <div className="grid grid-cols-1 gap-5">
                {baseLayers.map((layer) => {
                  const isActive = activeLayers.includes(layer.id);
