                    <motion.div 
                      key={layer.id}
                      whileHover={{ x: 8 }}
                      onClick={() => onToggleLayer(layer.id)}
                      className={`group p-6 rounded-[34px] cursor-pointer border-2 transition-all flex items-center gap-7 ${
                        isActive ? 'border-blue-600 bg-blue-600/10' : 'border-white/5 bg-white/5'
                      }`}
