                      <div className="text-4xl w-16 h-16 flex items-center justify-center rounded-2xl bg-white/5 shrink-0 transition-transform group-hover:scale-110">{layer.icon}</div>
                      <div className="flex-1">
                        <div className="font-black text-xl">{layer.label}</div>
                        <div className="text-[10px] font-bold opacity-40 uppercase tracking-widest">{layer.desc}</div>
                      </div>
                    </motion.div>
                  );
                })}
              </div>
            </section>

            <section>
              <h4 className="text-[11px] font-black uppercase tracking-[0.3em] opacity-40 mb-8 mono">Planetary Multi-Spectral</h4>
              <div className="space-y-5">
                {planetaryLayers.map((l) => {
                  const isActive = activeLayers.includes(l.id);
                  return (
                    <motion.div 
                      key={l.id}
                      whileHover={{ x: 8 }}
                      onClick={() => onToggleLayer(l.id)}
                      className={`p-6 rounded-[34px] cursor-pointer border-2 transition-all flex items-center gap-7 ${
                        isActive ? 'border-emerald-500 bg-emerald-500/10' : 'border-white/5 bg-white/5'
                      }`}
                    >
                      <div className="text-4xl w-16 h-16 flex items-center justify-center rounded-2xl bg-white/5 shrink-0">{l.icon}</div>
                      <div className="flex-1">
                        <div className="font-black text-xl">{l.label}</div>
                        <div className="text-[10px] font-bold opacity-40 uppercase tracking-widest">{l.desc}</div>
                      </div>
                      <div className={`w-14 h-7 rounded-full relative transition-colors ${isActive ? 'bg-emerald-500' : 'bg-slate-700'}`}>
                        <motion.div animate={{ x: isActive ? 28 : 0 }} className="absolute top-1 left-1 w-5 h-5 bg-white rounded-full shadow-lg" />
                      </div>
                    </motion.div>
                  );
                })}
              </div>
            </section>
          </div>
        </motion.div>
      )}
