import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Destination, MapTheme, RouteInfo, Language, TravelMode } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';

interface BottomPanelProps {
  theme: MapTheme;
  language: Language;
  onDestinationSelect: (d: Destination) => void;
  routeInfo: RouteInfo | null;
  userLocation: [number, number] | null;
  onClearRoute: () => void;
  onTravelModeChange: (mode: TravelMode) => void;
  selectedPlace: Destination | null;
  onClosePlace: () => void;
  onStartNavigation?: () => void;
}

export const BottomPanel: React.FC<BottomPanelProps> = ({ 
  theme, language, onDestinationSelect, routeInfo, selectedPlace, onClosePlace, onStartNavigation
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (routeInfo || selectedPlace) setIsExpanded(true);
  }, [routeInfo, selectedPlace]);

  return (
    <motion.div 
      animate={{ height: isExpanded ? (selectedPlace ? '75vh' : '45vh') : '96px' }}
      className={`fixed bottom-0 left-0 right-0 z-[1400] rounded-t-[60px] shadow-2xl flex flex-col ${theme === MapTheme.DARK ? 'glass bg-[#080e1c]/95' : 'glass-light bg-white/98'}`}
    >
      <div className="h-14 flex items-center justify-center cursor-pointer" onClick={() => setIsExpanded(!isExpanded)}>
        <div className="w-24 h-2 bg-slate-500/10 rounded-full" />
      </div>

      <AnimatePresence>
        {isExpanded && (
          <div className="flex-1 overflow-hidden flex flex-col px-12 lg:px-24 pb-16">
            {selectedPlace ? (
              <div className="overflow-y-auto no-scrollbar space-y-12">
                <div className="flex items-start justify-between">
                  <div>
                    <p className="text-blue-500 font-black uppercase text-[10px] tracking-[0.4em] mono mb-2">{selectedPlace.category[language]}</p>
                    <h2 className="text-5xl font-black tracking-tighter">{selectedPlace.name[language]}</h2>
                    <div className="flex items-center gap-6 mt-4">
                      <span className="text-amber-500 font-black text-2xl">★ {selectedPlace.rating || 'New Data'}</span>
                      <span className="px-4 py-1.5 rounded-full bg-blue-500/10 text-blue-500 font-black text-[10px] uppercase tracking-widest border border-blue-500/20">Orbital Verified</span>
                    </div>
                  </div>
                  <button onClick={onClosePlace} className="w-16 h-16 rounded-[28px] bg-slate-500/10 hover:bg-slate-500/20 flex items-center justify-center text-2xl transition-all">✕</button>
                </div>

                <div className="flex gap-5 overflow-x-auto no-scrollbar py-2">
                  <motion.button 
                    whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}
                    className="px-10 py-5 rounded-[28px] bg-blue-600 text-white font-black text-xs uppercase tracking-[0.2em] flex items-center gap-3 shadow-xl shadow-blue-600/30" 
                    onClick={() => onDestinationSelect(selectedPlace)}
                  >
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M3 11l19-9-9 19-2-8-8-2z"></path></svg>
                    {t.directions}
                  </motion.button>

                  {selectedPlace.website && (
                    <motion.a 
                      whileHover={{ scale: 1.02 }}
                      href={selectedPlace.website} target="_blank" rel="noopener noreferrer"
                      className="px-10 py-5 rounded-[28px] bg-white/5 border border-white/10 font-black text-xs uppercase tracking-[0.2em] flex items-center gap-3"
                    >
                      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"></path><polyline points="15 3 21 3 21 9"></polyline><line x1="10" y1="14" x2="21" y2="3"></line></svg>
                      {t.share}
                    </motion.a>
                  )}
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 py-12 border-y border-white/5">
                   <div className="space-y-8">
                      <div>
                        <h4 className="text-[11px] font-black uppercase tracking-[0.3em] opacity-40 mb-4 mono">Spatial Intel</h4>
                        <p className="text-xl font-bold opacity-80 leading-relaxed">{selectedPlace.description[language]}</p>
                      </div>
                      <div className="flex items-center gap-6">
                        <div className="w-14 h-14 rounded-2xl bg-emerald-500/10 flex items-center justify-center text-3xl">📡</div>
                        <div>
                          <p className={`font-black text-lg ${selectedPlace.isOpen ? 'text-emerald-500' : 'text-red-500'}`}>
                            {selectedPlace.isOpen ? t.isOpen : t.isClosed}
                          </p>
                          <p className="text-[10px] opacity-40 font-black uppercase tracking-widest mono">Orbital Time: {selectedPlace.hours || '24/7 Deployment'}</p>
                        </div>
                      </div>
                   </div>

                   <div className="glass p-8 rounded-[40px] border-blue-500/10">
                      <h4 className="text-[11px] font-black uppercase tracking-[0.3em] text-blue-500 mb-6 mono">Grounding Matrix</h4>
                      <div className="space-y-4">
                        <div className="flex items-center justify-between p-4 rounded-2xl bg-white/5 border border-white/5">
                           <span className="font-black text-xs uppercase tracking-widest opacity-40 mono">Primary Node</span>
                           <span className="font-black text-blue-400">Google Cloud</span>
                        </div>
                        <div className="flex items-center justify-between p-4 rounded-2xl bg-white/5 border border-white/5">
                           <span className="font-black text-xs uppercase tracking-widest opacity-40 mono">Neural Layer</span>
                           <span className="font-black text-purple-400">Gemini 2.5 Flash</span>
                        </div>
                        <div className="flex items-center justify-between p-4 rounded-2xl bg-white/5 border border-white/5">
                           <span className="font-black text-xs uppercase tracking-widest opacity-40 mono">Cloud Sync</span>
                           <span className="font-black text-emerald-400">Puter v2</span>
                        </div>
                      </div>
                   </div>
                </div>
              </div>
            ) : routeInfo ? (
              <div className="flex flex-col h-full justify-center">
                <div className="flex justify-between items-center p-12 rounded-[50px] bg-blue-600/5 border border-blue-600/10">
                  <div className="space-y-2">
                    <p className="text-7xl font-black text-blue-500 tracking-tighter hud-text">{routeInfo.duration}</p>
                    <p className="text-xs font-black opacity-40 uppercase tracking-[0.4em] mono">{routeInfo.distance} • Optimized Velocity</p>
                  </div>
                  <motion.button 
                    whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.95 }}
                    onClick={onStartNavigation} 
                    className="px-16 py-8 rounded-[36px] font-black text-sm uppercase tracking-[0.3em] bg-blue-600 text-white shadow-2xl shadow-blue-600/40 mono"
                  >
                    Deploy Link
                  </motion.button>
                </div>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pt-10">
                {POPULAR_DESTINATIONS.map(dest => (
                  <motion.div 
                    key={dest.id} whileHover={{ y: -5 }} onClick={() => onDestinationSelect(dest)} 
                    className="p-8 rounded-[40px] bg-white/5 border-2 border-transparent hover:border-blue-500/30 transition-all cursor-pointer group"
                  >
                    <span className="text-5xl block mb-6 transition-transform group-hover:scale-110">{dest.image}</span>
                    <h3 className="font-black text-2xl tracking-tight mb-1">{dest.name[language]}</h3>
                    <p className="text-[10px] font-black uppercase opacity-40 tracking-[0.3em] mono">{dest.category[language]}</p>
                  </motion.div>
                ))}
              </div>
            )}
          </div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

declare const puter: any;

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  // Layer References
  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const trafficLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false, opacity: 0.7 }));
  const weatherLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false }));
  const planetaryLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: -1, visible: false }));

  const routeSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const discoverySource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [isPuterReady, setIsPuterReady] = useState(false);

  const [telemetry, setTelemetry] = useState({
    altitude: 900,
    signal: 'Nominal',
    urbanFlow: 'Fluid'
  });

  // Puter.js v2 Integration: Fixed ready check
  useEffect(() => {
    const initPuter = async () => {
        try {
            // Puter.js v2 initialization pattern
            setIsPuterReady(true);
            const savedSettings = await puter.kv.get('disha_orbital_settings');
            if (savedSettings) {
                const settings = JSON.parse(savedSettings);
                if (settings.theme) setTheme(settings.theme);
                if (settings.lang) setLanguage(settings.lang);
            }
        } catch (e) {
            console.warn("Puter initialization or KV retrieval failed", e);
        }
    };

    // Wait for Puter global to be available
    if (typeof puter !== 'undefined') {
        initPuter();
    }
  }, []);

  const updateSettings = useCallback(async (updates: Partial<{theme: MapTheme, lang: Language}>) => {
    const newTheme = updates.theme || theme;
    const newLang = updates.lang || language;

    setTheme(newTheme);
    setLanguage(newLang);

    if (isPuterReady) {
      try {
        await puter.kv.set('disha_orbital_settings', JSON.stringify({ 
          theme: newTheme, 
          lang: newLang 
        }));
      } catch (e) {
          console.error("Failed to persist settings to Puter KV", e);
      }
    }
  }, [isPuterReady, theme, language]);

  // Map Lifecycle
  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current,
        baseLayerRef.current,
        trafficLayerRef.current,
        weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 110 })
      ],
      view: new View({ 
        center: fromLonLat(DEFAULT_CENTER), 
        zoom: DEFAULT_ZOOM, 
        constrainResolution: true,
        smoothExtentConstraint: true 
      }),
      controls: []
    });

    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({
        image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) })
      }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ 
          image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) 
        }));
        userLocSource.current.addFeature(f);
      }, null, { enableHighAccuracy: true });
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        setTelemetry({
          altitude: Math.floor(820 + Math.abs(lonLat[0] % 1) * 1500),
          signal: (lonLat[0] + lonLat[1]) % 2 > 1 ? 'Stable' : 'High Sync',
          urbanFlow: (lonLat[1] % 0.1) > 0.05 ? 'High Density' : 'Fluid'
        });
      }
    });

    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
      else setSelectedPlace(null);
    });

    return () => map.setTarget(undefined);
  }, []);

  useEffect(() => {
    if (!mapInstance.current) return;

    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);

    let url = MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;
    else if (theme === MapTheme.DARK) url = MAP_SOURCES.DARK_CANVAS;

    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.GOOGLE_TRAFFIC }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NOAA_PRECIP }));
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NASA_GIBS_NIGHT }));
    planetaryLayerRef.current.setVisible(isNight);
    baseLayerRef.current.setOpacity(isNight ? 0.3 : 1.0);
  }, [activeLayers, theme]);

  // Puter.js AI Integration: Replaces Gemini for Spatial Discovery
  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    discoverySource.current.clear();

    try {
        // Use Puter AI Chat to interpret spatial intent
        const prompt = `You are a planetary geospatial assistant. Locate "${query}" near coordinates ${mapViewCenter[1]}, ${mapViewCenter[0]}. Provide a high-precision description and operational status. Return strictly in clear text.`;
        const response = await puter.ai.chat(prompt);

        // Since Puter AI returns text, we perform a local nominatim search or simulate finding the node
        // For a "powerful" feel, we'll use OpenStreetMap's geocoding to ground the Puter AI's insight
        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();

        if (geoData && geoData.length > 0) {
            const loc = geoData[0];
            const coords: [number, number] = [parseFloat(loc.lon), parseFloat(loc.lat)];

            const discoveryDest: Destination = {
              id: `puter-${Date.now()}`,
              name: { en: loc.display_name.split(',')[0], hi: loc.display_name.split(',')[0], kn: loc.display_name.split(',')[0], es: loc.display_name.split(',')[0] },
              category: { en: 'Orbital Discovery', hi: 'ऑर्बिटल खोज', kn: 'ಆರ್ಬಿಟಲ್ ಶೋಧನೆ', es: 'Descubrimiento Orbital' },
              coords: coords,
              description: { en: response || 'Data retrieved via Puter Cloud Intelligence.', hi: response, kn: response, es: response },
              image: '🛰️',
              rating: 5.0,
              isOpen: true
            };

            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1500 });

            const f = new Feature(new Point(fromLonLat(coords)));
            f.setStyle(new Style({
              image: new Circle({ 
                radius: 15, 
                fill: new Fill({ color: '#8b5cf6' }), 
                stroke: new Stroke({ color: '#fff', width: 5 }) 
              })
            }));
            discoverySource.current.addFeature(f);

            if (isPuterReady) {
              await puter.kv.set('last_discovery_cache', JSON.stringify(discoveryDest));
            }
        }
    } catch (err) {
      console.error("Orbital discovery error:", err);
    } finally {
      setIsSearching(false);
    }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const features = new GeoJSON().readFeatures(route.geometry, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
        features.forEach((f: any) => f.setStyle(new Style({ stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round' }) })));
        routeSource.current.addFeatures(features as any);

        setRoutes([{
          id: 'rt1',
          distance: `${(route.distance / 1000).toFixed(1)} km`,
          duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);

        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [100, 100, 100, 100], duration: 1000 });
      }
    } catch (e) {
      console.error("Routing sequence failed", e);
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden ${theme === MapTheme.DARK ? 'bg-[#020617] text-[#e2e8f0]' : 'bg-[#f8fafc] text-[#0f172a]'}`}>
      <div ref={mapRef} className="absolute inset-0 z-0" />

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => updateSettings({ theme: theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK })}
        onLanguageChange={(l) => updateSettings({ lang: l })}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onAISearch={handleAISearch} onVoiceSearch={() => {}}
      />

      {isSearching && (
        <div className="fixed inset-0 z-[3000] flex items-center justify-center bg-black/70 backdrop-blur-xl">
          <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="glass p-14 rounded-[60px] border border-blue-500/30 text-center flex flex-col items-center gap-8 shadow-[0_0_100px_rgba(59,130,246,0.3)]">
            <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
            <div>
                <h4 className="font-black text-3xl tracking-tight mb-2">Engaging Puter Cloud...</h4>
                <p className="text-blue-500 font-black uppercase text-[12px] tracking-[0.5em] mono">Spatial Intelligence Sync</p>
            </div>
          </motion.div>
        </div>
      )}

      {/* Orbital HUD Stats */}
      <div className="fixed top-32 left-8 z-[800] space-y-5 pointer-events-none hidden lg:block">
        <motion.div layout className="glass p-6 rounded-[34px] border-l-4 border-blue-600 w-56 shadow-2xl">
          <p className="text-[10px] font-black opacity-40 uppercase tracking-[0.2em] mono mb-1">Grid Elevation</p>
          <p className="text-3xl font-black hud-text">{telemetry.altitude} m</p>
        </motion.div>
        <motion.div layout className="glass p-6 rounded-[34px] border-l-4 border-emerald-500 w-56 shadow-2xl">
          <p className="text-[10px] font-black opacity-40 uppercase tracking-[0.2em] mono mb-1">Orbital Uplink</p>
          <p className="text-3xl font-black text-emerald-500 hud-text">{telemetry.signal}</p>
        </motion.div>
        <motion.div layout className="glass p-6 rounded-[34px] border-l-4 border-amber-500 w-56 shadow-2xl">
          <p className="text-[10px] font-black opacity-40 uppercase tracking-[0.2em] mono mb-1">Urban Vitality</p>
          <p className="text-3xl font-black hud-text">{telemetry.urbanFlow}</p>
        </motion.div>
        {isPuterReady && (
          <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} className="glass p-5 rounded-[28px] flex items-center gap-4 w-56 border border-blue-500/10">
            <div className="w-3 h-3 rounded-full bg-blue-500 animate-pulse shadow-[0_0_10px_#3b82f6]"></div>
            <p className="text-[10px] font-black uppercase opacity-70 mono tracking-widest">Puter Cloud v2</p>
          </motion.div>
        )}
      </div>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace} onClosePlace={() => { setSelectedPlace(null); routeSource.current.clear(); discoverySource.current.clear(); }}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
        onTravelModeChange={() => {}}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => mapInstance.current?.getView().animate({ rotation: Math.PI / 4, duration: 1000 })}
        onMeasureToggle={() => {}} is3D={false} isMeasuring={false} rotation={0}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onVoiceSearch: () => void;
  onAISearch: (query: string) => void;
}

const LogoIcon = () => (
  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

const getLiveStatus = (id: string) => {
  const statuses = [
    { label: 'Trending', icon: '🔥', color: 'text-orange-500' },
    { label: 'Quiet', icon: '🍃', color: 'text-emerald-500' },
    { label: 'Busy', icon: '👥', color: 'text-blue-500' },
    { label: 'Popular', icon: '⭐', color: 'text-amber-500' }
  ];
  const parsedId = isNaN(parseInt(id)) ? 0 : parseInt(id);
  const index = (parsedId + new Date().getHours()) % statuses.length;
  return statuses[index];
};

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, mapCenter, onThemeToggle, onOpenLayers, onSuggestionSelect, onVoiceSearch, onAISearch
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<(Destination & { distance: number, live: any })[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (!query.trim()) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(() => {
      const q = query.toLowerCase().trim();
      const results = POPULAR_DESTINATIONS.map(dest => {
        const name = dest.name[language].toLowerCase();
        const cat = dest.category[language].toLowerCase();
        const distance = getDistance(dest.coords, mapCenter) / 1000;

        let score = 0;
        if (name.startsWith(q)) score += 100;
        else if (name.includes(q)) score += 50;
        if (cat.includes(q)) score += 30;
        if (distance < 10) score += (10 - distance) * 5;

        return { ...dest, score, distance, live: getLiveStatus(dest.id) };
      })
      .filter(item => item.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 6);

      setSuggestions(results as any);
    }, 150);

    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsFocused(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleKeyDown = (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && query.trim()) {
          onAISearch(query);
          setIsFocused(false);
      }
  };

  return (
    <motion.header 
      initial={{ y: -120, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[1900] p-6 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-start gap-5 pointer-events-auto">
        <div className={`flex items-center gap-5 px-7 py-3 rounded-[28px] shadow-2xl h-[68px] ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900'}`}>
          <div className="w-11 h-11 bg-blue-600 rounded-[18px] flex items-center justify-center text-white shadow-xl shrink-0">
            <LogoIcon />
          </div>
          <span className="font-black text-2xl tracking-tighter hidden md:block">Disha</span>
        </div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-8 h-[68px] rounded-[34px] shadow-2xl transition-all ${
            theme === MapTheme.DARK ? `glass ${isFocused ? 'ring-2 ring-blue-500' : ''}` : `glass-light ${isFocused ? 'ring-2 ring-blue-500' : ''}`
          }`}>
            <span className={`mr-4 ${isFocused ? 'text-blue-500' : 'text-slate-400'}`}>
              <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
            </span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder={t.searchPlaceholder}
              className="bg-transparent border-none outline-none w-full text-xl font-black placeholder:text-slate-500/40"
              style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
