        </div>

        <div className="flex gap-4 shrink-0">
          <button onClick={onOpenLayers} className={`w-[72px] h-[72px] rounded-[32px] flex items-center justify-center shadow-2xl transition-all hover:scale-105 ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600 border-white/60'}`}>
