      >
        <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><circle cx="12" cy="12" r="3"></circle><path d="M19 12a7 7 0 1 1-14 0 7 7 0 0 1 14 0z"></path><line x1="12" y1="2" x2="12" y2="5"></line><line x1="12" y1="19" x2="12" y2="22"></line><line x1="2" y1="12" x2="5" y2="12"></line><line x1="19" y1="12" x2="22" y2="12"></line></svg>
      </motion.button>
    </div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
// Import GoogleGenAI as per the latest guidelines
import { GoogleGenAI } from "@google/genai";

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

declare const puter: any;

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  // Layer References
  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const trafficLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false, opacity: 0.7 }));
  const weatherLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false }));
  const planetaryLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: -1, visible: false }));

  const routeSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const discoverySource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [isPuterReady, setIsPuterReady] = useState(false);

  const [telemetry, setTelemetry] = useState({
    altitude: 900,
    signal: 'Nominal',
    urbanFlow: 'Fluid',
    nodes: 42,
    sync: '98.4%'
  });

  // Puter.js v2 Integration for Persistence
  useEffect(() => {
    const initPuter = async () => {
        try {
            setIsPuterReady(true);
            const savedSettings = await puter.kv.get('disha_orbital_settings');
            if (savedSettings) {
                const settings = JSON.parse(savedSettings);
                if (settings.theme) setTheme(settings.theme);
                if (settings.lang) setLanguage(settings.lang);
            }
        } catch (e) {
            console.warn("Puter initialization or KV retrieval failed", e);
        }
    };

    if (typeof puter !== 'undefined') {
        initPuter();
    }
  }, []);

  // Update body class for light/dark transition
  useEffect(() => {
    if (theme === MapTheme.LIGHT) {
        document.body.classList.add('light-mode');
    } else {
        document.body.classList.remove('light-mode');
    }
  }, [theme]);

  const updateSettings = useCallback(async (updates: Partial<{theme: MapTheme, lang: Language}>) => {
    const newTheme = updates.theme || theme;
    const newLang = updates.lang || language;

    setTheme(newTheme);
    setLanguage(newLang);

    if (isPuterReady) {
      try {
        await puter.kv.set('disha_orbital_settings', JSON.stringify({ 
          theme: newTheme, 
          lang: newLang 
        }));
      } catch (e) {
          console.error("Failed to persist settings to Puter KV", e);
      }
    }
  }, [isPuterReady, theme, language]);

  // Map Lifecycle
  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;

    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current,
        baseLayerRef.current,
        trafficLayerRef.current,
        weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 110 })
      ],
      view: new View({ 
        center: fromLonLat(DEFAULT_CENTER), 
        zoom: DEFAULT_ZOOM, 
        constrainResolution: true,
        smoothExtentConstraint: true 
      }),
      controls: []
    });

    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({
        image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) })
      }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ 
          image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) 
        }));
        userLocSource.current.addFeature(f);
      }, null, { enableHighAccuracy: true });
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        setTelemetry({
          altitude: Math.floor(820 + Math.abs(lonLat[0] % 1) * 1500),
          signal: (lonLat[0] + lonLat[1]) % 2 > 1 ? 'Optimal' : 'Relinking',
          urbanFlow: (lonLat[1] % 0.1) > 0.05 ? 'Heavy' : 'Nominal',
          nodes: Math.floor(30 + Math.random() * 20),
          sync: (97 + Math.random() * 2.9).toFixed(1) + '%'
        });
      }
    });

    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
      else setSelectedPlace(null);
    });

    return () => map.setTarget(undefined);
  }, []);

  useEffect(() => {
    if (!mapInstance.current) return;

    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);

    let url = MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;
    else if (theme === MapTheme.DARK) url = MAP_SOURCES.DARK_CANVAS;

    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.GOOGLE_TRAFFIC }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NOAA_PRECIP }));
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NASA_GIBS_NIGHT }));
    planetaryLayerRef.current.setVisible(isNight);
    baseLayerRef.current.setOpacity(isNight ? 0.3 : 1.0);
  }, [activeLayers, theme]);

  // handleAISearch uses the Gemini API to provide intelligent geospatial context
  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    discoverySource.current.clear();

    try {
        // Initialize Gemini API client as per coding guidelines
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // FIX: Replaced non-existent 'mapCenter' with 'mapViewCenter' to resolve the error
        const prompt = `You are a planetary geospatial assistant. Locate "${query}" near coordinates ${mapViewCenter[1]}, ${mapViewCenter[0]}. Provide high-precision description.`;

        // Use gemini-3-flash-preview for fast and efficient text grounding tasks
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: prompt,
        });

        // Correctly extract text from response property (not a method)
        const responseText = response.text || 'Spatial data link established.';

        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();

        if (geoData && geoData.length > 0) {
            const loc = geoData[0];
            const coords: [number, number] = [parseFloat(loc.lon), parseFloat(loc.lat)];

            const discoveryDest: Destination = {
              id: `puter-${Date.now()}`,
              name: { en: loc.display_name.split(',')[0], hi: loc.display_name.split(',')[0], kn: loc.display_name.split(',')[0], es: loc.display_name.split(',')[0] },
              category: { en: 'Orbital Discovery', hi: 'ऑर्बिटल खोज', kn: 'ಆರ್ಬಿಟಲ್ ಶೋಧನೆ', es: 'Descubrimiento Orbital' },
              coords: coords,
              description: { en: responseText, hi: responseText, kn: responseText, es: responseText },
              image: '🛰️',
              rating: 5.0,
              isOpen: true
            };

            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1500 });

            const f = new Feature(new Point(fromLonLat(coords)));
            f.setStyle(new Style({
              image: new Circle({ 
                radius: 15, 
                fill: new Fill({ color: '#3b82f6' }), 
                stroke: new Stroke({ color: '#fff', width: 5 }) 
              })
            }));
            discoverySource.current.addFeature(f);
        }
    } catch (err) {
      console.error("Orbital discovery error:", err);
    } finally {
      setIsSearching(false);
    }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const features = new GeoJSON().readFeatures(route.geometry, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
        features.forEach((f: any) => f.setStyle(new Style({ stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round' }) })));
        routeSource.current.addFeatures(features as any);

        setRoutes([{
          id: 'rt1',
          distance: `${(route.distance / 1000).toFixed(1)} km`,
          duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);

        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [100, 100, 100, 100], duration: 1000 });
      }
    } catch (e) {
      console.error("Routing sequence failed", e);
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-500`}>
      <div ref={mapRef} className="map-container" />

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => updateSettings({ theme: theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK })}
        onLanguageChange={(l) => updateSettings({ lang: l })}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onAISearch={handleAISearch} onVoiceSearch={() => {}}
      />

      {isSearching && (
        <div className="fixed inset-0 z-[3000] flex items-center justify-center bg-black/60 backdrop-blur-xl">
          <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className={`${theme === MapTheme.DARK ? 'glass' : 'glass-light'} p-14 rounded-[60px] border border-blue-500/30 text-center flex flex-col items-center gap-8`}>
            <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin shadow-[0_0_20px_rgba(59,130,246,0.5)]"></div>
            <div>
                <h4 className={`font-black text-3xl tracking-tight mb-2 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Syncing Planetary Hub...</h4>
                <p className="text-blue-500 font-black uppercase text-[12px] tracking-[0.5em] mono">Spatial Data Propagation</p>
            </div>
          </motion.div>
        </div>
      )}

      {/* Advanced Orbital Telemetry HUD */}
      <div className="fixed top-32 left-8 z-[800] space-y-5 pointer-events-none hidden lg:block">
        <motion.div layout className={`${theme === MapTheme.DARK ? 'glass border-l-4 border-blue-600' : 'glass-light border-l-4 border-blue-600'} p-6 rounded-[34px] w-64 shadow-2xl`}>
          <div className="flex justify-between items-center mb-1">
              <p className={`text-[10px] font-black opacity-40 uppercase tracking-[0.2em] mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Elevation</p>
              <div className="w-2 h-2 rounded-full bg-blue-500"></div>
          </div>
          <p className={`text-3xl font-black ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{telemetry.altitude} m</p>
        </motion.div>

        <motion.div layout className={`${theme === MapTheme.DARK ? 'glass border-l-4 border-emerald-500' : 'glass-light border-l-4 border-emerald-500'} p-6 rounded-[34px] w-64 shadow-2xl`}>
          <div className="flex justify-between items-center mb-1">
              <p className={`text-[10px] font-black opacity-40 uppercase tracking-[0.2em] mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Orbital Link</p>
              <span className="text-[10px] font-black text-emerald-500 mono">{telemetry.sync}</span>
          </div>
          <p className="text-3xl font-black text-emerald-500">{telemetry.signal}</p>
        </motion.div>

        <motion.div layout className={`${theme === MapTheme.DARK ? 'glass border-l-4 border-amber-500' : 'glass-light border-l-4 border-amber-500'} p-6 rounded-[34px] w-64 shadow-2xl`}>
          <p className={`text-[10px] font-black opacity-40 uppercase tracking-[0.2em] mono mb-1 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Active Nodes</p>
          <p className={`text-3xl font-black ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{telemetry.nodes}</p>
        </motion.div>
      </div>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace} onClosePlace={() => { setSelectedPlace(null); routeSource.current.clear(); discoverySource.current.clear(); }}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
        onTravelModeChange={() => {}}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => mapInstance.current?.getView().animate({ rotation: Math.PI / 4, duration: 1000 })}
        onMeasureToggle={() => {}} is3D={false} isMeasuring={false} rotation={0}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onVoiceSearch: () => void;
  onAISearch: (query: string) => void;
}

const LogoIcon = () => (
  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

const getLiveStatus = (id: string) => {
  const statuses = [
    { label: 'Trending', icon: '🔥', color: 'text-orange-500' },
    { label: 'Quiet', icon: '🍃', color: 'text-emerald-500' },
    { label: 'Busy', icon: '👥', color: 'text-blue-500' },
    { label: 'Popular', icon: '⭐', color: 'text-amber-500' }
  ];
  const parsedId = isNaN(parseInt(id)) ? 0 : parseInt(id);
  const index = (parsedId + new Date().getHours()) % statuses.length;
  return statuses[index];
};

const QUICK_CATEGORIES = [
  { label: 'Stations', icon: '🔋', query: 'Charging stations' },
  { label: 'Cafes', icon: '☕', query: 'Coffee shops' },
  { label: 'Parks', icon: '🌳', query: 'Green spaces' },
  { label: 'Hotels', icon: '🏨', query: 'Luxury hotels' },
];

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, mapCenter, onThemeToggle, onOpenLayers, onSuggestionSelect, onAISearch
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<(Destination & { distance: number, live: any })[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (!query.trim()) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(() => {
      const q = query.toLowerCase().trim();
      const results = POPULAR_DESTINATIONS.map(dest => {
        const name = dest.name[language].toLowerCase();
        const cat = dest.category[language].toLowerCase();
        const distance = getDistance(dest.coords, mapCenter) / 1000;

        let score = 0;
        if (name.startsWith(q)) score += 100;
        else if (name.includes(q)) score += 50;
        if (cat.includes(q)) score += 30;
        if (distance < 10) score += (10 - distance) * 5;

        return { ...dest, score, distance, live: getLiveStatus(dest.id) };
      })
      .filter(item => item.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 6);

      setSuggestions(results as any);
    }, 150);

    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsFocused(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleKeyDown = (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && query.trim()) {
          onAISearch(query);
          setIsFocused(false);
      }
  };

  return (
    <motion.header 
      initial={{ y: -120, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[1900] p-8 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-start gap-6 pointer-events-auto">
        {/* Branding Node */}
        <div className={`flex items-center gap-5 px-8 py-3 rounded-[32px] shadow-2xl h-[72px] transition-all duration-500 ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900 border-white/60'}`}>
          <div className="w-12 h-12 bg-blue-600 rounded-[20px] flex items-center justify-center text-white shadow-xl shadow-blue-600/20 shrink-0">
            <LogoIcon />
          </div>
          <span className="font-black text-2xl tracking-tighter hidden lg:block">Disha</span>
        </div>

        {/* Intelligence Search Bar */}
        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-10 h-[72px] rounded-[36px] shadow-2xl transition-all duration-300 ${
            theme === MapTheme.DARK ? `glass ${isFocused ? 'ring-2 ring-blue-500 border-transparent bg-[#0c1326]' : ''}` : `glass-light border-white/60 ${isFocused ? 'ring-2 ring-blue-500 border-transparent bg-white' : ''}`
          }`}>
            <span className={`mr-5 transition-colors ${isFocused ? 'text-blue-500' : 'text-slate-400'}`}>
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
            </span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder={t.searchPlaceholder}
              className={`bg-transparent border-none outline-none w-full text-xl font-bold placeholder:opacity-30 placeholder:font-bold tracking-tight`}
              style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
            />
            <button 
                onClick={() => { onAISearch(query); setIsFocused(false); }}
                className="ml-4 text-[11px] font-black uppercase tracking-[0.2em] text-blue-500 bg-blue-500/10 px-6 py-3 rounded-full hover:bg-blue-600 hover:text-white transition-all shrink-0 mono"
            >
                Ground
            </button>
          </div>

          <AnimatePresence>
            {isFocused && (
              <motion.div
                initial={{ opacity: 0, y: 15, scale: 0.98 }}
                animate={{ opacity: 1, y: 12, scale: 1 }}
                exit={{ opacity: 0, y: 15, scale: 0.98 }}
                transition={{ type: 'spring', damping: 20, stiffness: 150 }}
                className={`absolute top-full left-0 right-0 rounded-[44px] shadow-[0_40px_100px_rgba(0,0,0,0.3)] overflow-hidden border transition-colors duration-300 ${
                  theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-white/60'
                }`}
              >
                <div className="max-h-[65vh] overflow-y-auto py-8 no-scrollbar">
                  {suggestions.length > 0 ? (
                    <div className="space-y-1">
                      <p className={`px-10 mb-4 text-[10px] font-black uppercase tracking-[0.3em] opacity-30 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Orbital Matches</p>
                      {suggestions.map((dest) => (
                        <motion.div 
                          key={dest.id} 
                          initial={{ opacity: 0, x: -10 }}
                          animate={{ opacity: 1, x: 0 }}
                          onClick={() => {
                            onSuggestionSelect(dest);
                            setIsFocused(false);
                            setQuery(dest.name[language]);
                          }} 
                          className={`px-10 py-5 flex items-center gap-7 cursor-pointer transition-all group ${theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-blue-500/5'}`}
                        >
                          <div className={`text-3xl w-16 h-16 flex items-center justify-center rounded-[24px] transition-transform group-hover:scale-110 group-hover:rotate-6 ${theme === MapTheme.DARK ? 'bg-white/5' : 'bg-slate-500/10'}`}>
                            {dest.image}
                          </div>
                          <div className="flex-1">
                            <div className={`font-black text-xl flex items-center gap-3 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
                              {dest.name[language]}
                              <span className={`text-[10px] font-black uppercase tracking-wider ${dest.live.color}`}>{dest.live.icon} {dest.live.label}</span>
                            </div>
                            <div className={`text-[11px] font-bold opacity-40 uppercase tracking-[0.2em] mono`}>{dest.category[language]} • {dest.distance.toFixed(1)} km</div>
                          </div>
                          <div className="opacity-0 group-hover:opacity-100 transition-opacity">
                            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" className="text-blue-500"><polyline points="9 18 15 12 9 6"></polyline></svg>
                          </div>
                        </motion.div>
                      ))}
                    </div>
                  ) : (
                    <div className="px-10">
                        <div className="mb-10">
                            <p className={`mb-6 text-[10px] font-black uppercase tracking-[0.3em] opacity-30 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Quick Recon</p>
                            <div className="grid grid-cols-2 gap-4">
                                {QUICK_CATEGORIES.map(cat => (
                                    <button 
                                        key={cat.label}
                                        onClick={() => { setQuery(cat.query); onAISearch(cat.query); setIsFocused(false); }}
                                        className={`flex items-center gap-4 p-5 rounded-3xl transition-all text-left ${theme === MapTheme.DARK ? 'bg-white/5 hover:bg-white/10' : 'bg-slate-900/5 hover:bg-slate-900/10'}`}
                                    >
                                        <span className="text-2xl">{cat.icon}</span>
                                        <span className="font-black text-sm uppercase tracking-widest">{cat.label}</span>
                                    </button>
                                ))}
                            </div>
                        </div>
                        <div className="text-center py-8">
                            <div className="mb-6 text-6xl animate-pulse">🛰️</div>
                            <p className={`font-black text-2xl tracking-tight mb-2 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Orbital Intel Link</p>
                            <p className={`font-medium opacity-40 text-sm leading-relaxed max-w-sm mx-auto`}>Deploy AI Discovery to identify spatial nodes, quiet zones, or urban vital centers by pressing Enter.</p>
                        </div>
                    </div>
                  )}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        {/* Global Control Deck */}
        <div className="flex gap-4 shrink-0">
          <button onClick={onOpenLayers} className={`w-[72px] h-[72px] rounded-[32px] flex items-center justify-center shadow-2xl transition-all hover:scale-105 hover:-translate-y-1 ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600 border-white/60'}`}>
            <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline></svg>
          </button>
          <button onClick={onThemeToggle} className={`w-[72px] h-[72px] rounded-[32px] flex items-center justify-center shadow-2xl transition-all hover:scale-105 hover:-translate-y-1 ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600 border-white/60'}`}>
            <span className="text-2xl transition-transform hover:rotate-12">{theme === MapTheme.DARK ? '☀️' : '🌙'}</span>
          </button>
        </div>
      </div>
    </motion.header>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
import { GoogleGenAI } from "@google/genai";

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

declare const puter: any;

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  // Layer References
  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const trafficLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false, opacity: 0.7 }));
  const weatherLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false }));
  const planetaryLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: -1, visible: false }));

  const routeSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const discoverySource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [isPuterReady, setIsPuterReady] = useState(false);

  const [telemetry, setTelemetry] = useState({
    altitude: 900,
    signal: 'Nominal',
    urbanFlow: 'Fluid',
    nodes: 42,
    sync: '98.4%'
  });

  useEffect(() => {
    const initPuter = async () => {
        try {
            setIsPuterReady(true);
            const savedSettings = await puter.kv.get('disha_orbital_settings');
            if (savedSettings) {
                const settings = JSON.parse(savedSettings);
                if (settings.theme) setTheme(settings.theme);
                if (settings.lang) setLanguage(settings.lang);
            }
        } catch (e) {
            console.warn("Puter initialization or KV retrieval failed", e);
        }
    };
    if (typeof puter !== 'undefined') initPuter();
  }, []);

  useEffect(() => {
    if (theme === MapTheme.LIGHT) document.body.classList.add('light-mode');
    else document.body.classList.remove('light-mode');
  }, [theme]);

  const updateSettings = useCallback(async (updates: Partial<{theme: MapTheme, lang: Language}>) => {
    const newTheme = updates.theme || theme;
    const newLang = updates.lang || language;
    setTheme(newTheme);
    setLanguage(newLang);
    if (isPuterReady) {
      try {
        await puter.kv.set('disha_orbital_settings', JSON.stringify({ theme: newTheme, lang: newLang }));
      } catch (e) { console.error("KV persist failed", e); }
    }
  }, [isPuterReady, theme, language]);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;
    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current, baseLayerRef.current, trafficLayerRef.current, weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 110 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true, smoothExtentConstraint: true }),
      controls: []
    });
    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({ image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) }) }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      }, null, { enableHighAccuracy: true });
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        setTelemetry({
          altitude: Math.floor(820 + Math.abs(lonLat[0] % 1) * 1500),
          signal: (lonLat[0] + lonLat[1]) % 2 > 1 ? 'Optimal' : 'Relinking',
          urbanFlow: (lonLat[1] % 0.1) > 0.05 ? 'Heavy' : 'Nominal',
          nodes: Math.floor(30 + Math.random() * 20),
          sync: (97 + Math.random() * 2.9).toFixed(1) + '%'
        });
      }
    });

    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
      else setSelectedPlace(null);
    });
    return () => map.setTarget(undefined);
  }, []);

  useEffect(() => {
    if (!mapInstance.current) return;
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);
    let url = MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;
    else if (theme === MapTheme.DARK) url = MAP_SOURCES.DARK_CANVAS;
    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.GOOGLE_TRAFFIC }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NOAA_PRECIP }));
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NASA_GIBS_NIGHT }));
    planetaryLayerRef.current.setVisible(isNight);
    baseLayerRef.current.setOpacity(isNight ? 0.3 : 1.0);
  }, [activeLayers, theme]);

  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    discoverySource.current.clear();
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `You are a planetary geospatial assistant. Locate "${query}" near coordinates ${mapViewCenter[1]}, ${mapViewCenter[0]}. Provide high-precision description.`;
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: prompt,
        });
        const responseText = response.text || 'Spatial data link established.';
        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();
        if (geoData && geoData.length > 0) {
            const loc = geoData[0];
            const coords: [number, number] = [parseFloat(loc.lon), parseFloat(loc.lat)];
            const discoveryDest: Destination = {
              id: `ai-${Date.now()}`,
              name: { en: loc.display_name.split(',')[0], hi: loc.display_name.split(',')[0], kn: loc.display_name.split(',')[0], es: loc.display_name.split(',')[0] },
              category: { en: 'Orbital Discovery', hi: 'ऑर्बिटल खोज', kn: 'ಆರ್ಬಿಟಲ್ ಶೋಧನೆ', es: 'Descubrimiento Orbital' },
              coords: coords,
              description: { en: responseText, hi: responseText, kn: responseText, es: responseText },
              image: '🛰️',
              rating: 5.0,
              isOpen: true
            };
            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1500 });
            const f = new Feature(new Point(fromLonLat(coords)));
            f.setStyle(new Style({ image: new Circle({ radius: 15, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 5 }) }) }));
            discoverySource.current.addFeature(f);
        }
    } catch (err) { console.error("Discovery error:", err); } finally { setIsSearching(false); }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const features = new GeoJSON().readFeatures(route.geometry, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
        features.forEach((f: any) => f.setStyle(new Style({ stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round' }) })));
        routeSource.current.addFeatures(features as any);
        setRoutes([{
          id: 'rt1', distance: `${(route.distance / 1000).toFixed(1)} km`, duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);
        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [100, 100, 100, 100], duration: 1000 });
      }
    } catch (e) { console.error("Routing failed", e); }
  };

  return (
    <div className="relative w-full h-screen overflow-hidden transition-colors duration-500">
      <div ref={mapRef} className="map-container" />
      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => updateSettings({ theme: theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK })}
        onLanguageChange={(l) => updateSettings({ lang: l })}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onAISearch={handleAISearch} onVoiceSearch={() => {}}
      />

      <AnimatePresence>
        {isSearching && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[3000] flex items-center justify-center bg-black/60 backdrop-blur-xl">
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className={`${theme === MapTheme.DARK ? 'glass' : 'glass-light'} p-14 rounded-[60px] border border-blue-500/30 text-center flex flex-col items-center gap-8`}>
              <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin shadow-[0_0_20px_rgba(59,130,246,0.5)]"></div>
              <div>
                  <h4 className={`font-black text-3xl tracking-tight mb-2 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Syncing Planetary Hub...</h4>
                  <p className="text-blue-500 font-black uppercase text-[12px] tracking-[0.5em] mono">Spatial Data Propagation</p>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="fixed top-32 left-8 z-[800] space-y-5 pointer-events-none hidden lg:block">
        {[
          { label: 'Elevation', val: `${telemetry.altitude} m`, color: 'border-blue-600', dot: 'bg-blue-500' },
          { label: 'Orbital Link', val: telemetry.signal, color: 'border-emerald-500', sync: telemetry.sync, text: 'text-emerald-500' },
          { label: 'Active Nodes', val: telemetry.nodes, color: 'border-amber-500' }
        ].map((item, idx) => (
          <motion.div key={idx} layout className={`${theme === MapTheme.DARK ? 'glass' : 'glass-light'} ${item.color} border-l-4 p-6 rounded-[34px] w-64 shadow-2xl`}>
            <div className="flex justify-between items-center mb-1">
                <p className={`text-[10px] font-black opacity-40 uppercase tracking-[0.2em] mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{item.label}</p>
                {item.dot && <div className={`w-2 h-2 rounded-full ${item.dot}`}></div>}
                {item.sync && <span className="text-[10px] font-black text-emerald-500 mono">{item.sync}</span>}
            </div>
            <p className={`text-3xl font-black ${item.text || (theme === MapTheme.DARK ? 'text-white' : 'text-slate-900')}`}>{item.val}</p>
          </motion.div>
        ))}
      </div>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />
      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace} onClosePlace={() => { setSelectedPlace(null); routeSource.current.clear(); discoverySource.current.clear(); }}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
        onTravelModeChange={() => {}}
      />
      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => mapInstance.current?.getView().animate({ rotation: Math.PI / 4, duration: 1000 })}
        onMeasureToggle={() => {}} is3D={false} isMeasuring={false} rotation={0}
      />
    </div>
  );
};
export default App;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Destination, MapTheme, RouteInfo, Language, TravelMode } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';

interface BottomPanelProps {
  theme: MapTheme;
  language: Language;
  onDestinationSelect: (d: Destination) => void;
  routeInfo: RouteInfo | null;
  userLocation: [number, number] | null;
  onClearRoute: () => void;
  onTravelModeChange: (mode: TravelMode) => void;
  selectedPlace: Destination | null;
  onClosePlace: () => void;
  onStartNavigation?: () => void;
}

export const BottomPanel: React.FC<BottomPanelProps> = ({ 
  theme, language, onDestinationSelect, routeInfo, selectedPlace, onClosePlace, onStartNavigation
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (routeInfo || selectedPlace) setIsExpanded(true);
    else setIsExpanded(false);
  }, [routeInfo, selectedPlace]);

  return (
    <motion.div 
      animate={{ height: isExpanded ? (selectedPlace ? '78vh' : '48vh') : '100px' }}
      transition={{ type: 'spring', damping: 28, stiffness: 140 }}
      className={`fixed bottom-0 left-0 right-0 z-[1400] rounded-t-[64px] shadow-2xl flex flex-col transition-colors duration-500 overflow-hidden ${theme === MapTheme.DARK ? 'glass bg-[#080e1c]/95' : 'glass-light bg-white/85 border-white/80'}`}
    >
      {/* Interaction Handle */}
      <div className="h-14 flex items-center justify-center cursor-pointer group" onClick={() => setIsExpanded(!isExpanded)}>
        <motion.div 
          animate={{ width: isExpanded ? 64 : 100 }}
          className={`h-2 rounded-full transition-colors ${theme === MapTheme.DARK ? 'bg-white/10 group-hover:bg-white/30' : 'bg-slate-300/40 group-hover:bg-slate-400/60'}`} 
        />
      </div>

