import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onAISearch: (query: string) => void;
}

const LogoIcon = () => (
  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

const QUICK_ACTIONS = [
  { label: 'Stations', icon: '🔋', query: 'Electric charging' },
  { label: 'Parks', icon: '🌳', query: 'Public parks' },
  { label: 'Transit', icon: '🚆', query: 'Metro stations' },
  { label: 'Work', icon: '💻', query: 'Co-working' },
];

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, mapCenter, onThemeToggle, onOpenLayers, onSuggestionSelect, onAISearch
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language];

  // Real-time Search Logic (Local + Global Geocoding)
  useEffect(() => {
    if (!query.trim() || query.length < 2) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(async () => {
      setIsLoading(true);
      try {
        // 1. Filter local popular destinations
        const localResults = POPULAR_DESTINATIONS.filter(dest => 
          dest.name[language].toLowerCase().includes(query.toLowerCase()) ||
          dest.category[language].toLowerCase().includes(query.toLowerCase())
        ).map(dest => ({
          ...dest,
          type: 'local',
          distance: getDistance(dest.coords, mapCenter) / 1000
        }));

        // 2. Fetch global results via Nominatim for "real-time" feel
        const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=5&addressdetails=1`);
        const globalData = await response.json();

        const globalResults = globalData.map((item: any) => ({
          id: item.place_id,
          name: { en: item.display_name.split(',')[0], hi: item.display_name.split(',')[0], kn: item.display_name.split(',')[0], es: item.display_name.split(',')[0] },
          category: { en: item.type || 'Location', hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Ubicación' },
          coords: [parseFloat(item.lon), parseFloat(item.lat)],
          description: { en: item.display_name, hi: item.display_name, kn: item.display_name, es: item.display_name },
          image: '📍',
          type: 'global',
          distance: getDistance([parseFloat(item.lon), parseFloat(item.lat)], mapCenter) / 1000
        }));

        setSuggestions([...localResults, ...globalResults]);
      } catch (e) {
        console.warn("Real-time search uplink failed", e);
      } finally {
        setIsLoading(false);
      }
    }, 300);

    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsFocused(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <motion.header 
      initial={{ y: -120, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[2000] p-6 lg:p-8 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-start gap-5 lg:gap-8 pointer-events-auto">
        {/* Branding Hub */}
        <div className={`flex items-center gap-5 px-8 py-3 rounded-[32px] shadow-2xl h-[72px] transition-all duration-500 shrink-0 ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900 border-white/60'}`}>
          <div className="w-12 h-12 bg-blue-600 rounded-[20px] flex items-center justify-center text-white shadow-xl shadow-blue-600/30">
            <LogoIcon />
          </div>
          <span className="font-black text-2xl tracking-tighter hidden xl:block">Disha</span>
        </div>

        {/* Global Discovery Bar */}
        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-10 h-[72px] rounded-[36px] shadow-2xl transition-all duration-500 overflow-hidden ${
            theme === MapTheme.DARK ? `glass ${isFocused ? 'ring-2 ring-blue-500/50 bg-[#0c1326]' : ''}` : `glass-light border-white/60 ${isFocused ? 'ring-2 ring-blue-600/20 bg-white' : ''}`
          }`}>
            <div className="flex-1 flex items-center">
              <span className={`mr-5 transition-colors duration-300 ${isFocused ? 'text-blue-500' : 'text-slate-400'}`}>
                {isLoading ? (
                  <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
                ) : (
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
                )}
              </span>
              <input 
                type="text" 
                value={query}
                onFocus={() => setIsFocused(true)}
                onChange={(e) => setQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && (onAISearch(query), setIsFocused(false))}
                placeholder={t.searchPlaceholder}
                className="bg-transparent border-none outline-none w-full text-xl font-bold placeholder:opacity-20 placeholder:font-black tracking-tight"
                style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
              />
            </div>
            <button 
                onClick={() => { onAISearch(query); setIsFocused(false); }}
                className="ml-4 text-[11px] font-black uppercase tracking-[0.2em] text-blue-500 bg-blue-500/10 px-6 py-3 rounded-full hover:bg-blue-600 hover:text-white transition-all shrink-0 mono"
            >
                Ground
            </button>
          </div>

          <AnimatePresence>
            {isFocused && (
              <motion.div
                initial={{ opacity: 0, y: 15, scale: 0.98 }}
                animate={{ opacity: 1, y: 12, scale: 1 }}
                exit={{ opacity: 0, y: 15, scale: 0.98 }}
                transition={{ type: 'spring', damping: 25, stiffness: 150 }}
                className={`absolute top-full left-0 right-0 rounded-[44px] shadow-[0_40px_120px_rgba(0,0,0,0.3)] overflow-hidden border transition-all duration-300 ${
                  theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-white/70'
                }`}
              >
                <div className="max-h-[70vh] overflow-y-auto py-8 no-scrollbar">
                  {suggestions.length > 0 ? (
                    <div className="space-y-1">
                      <p className={`px-12 mb-6 text-[11px] font-black uppercase tracking-[0.4em] opacity-30 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Spatial Matches</p>
                      {suggestions.map((dest, idx) => (
                        <motion.div 
                          key={dest.id || idx} 
                          initial={{ opacity: 0, x: -10 }}
                          animate={{ opacity: 1, x: 0 }}
                          transition={{ delay: idx * 0.05 }}
                          onClick={() => {
                            onSuggestionSelect(dest);
                            setIsFocused(false);
                            setQuery(dest.name[language]);
                          }} 
                          className={`px-12 py-6 flex items-center gap-8 cursor-pointer transition-all group ${theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-blue-500/5'}`}
                        >
                          <div className={`text-4xl w-20 h-20 flex items-center justify-center rounded-[28px] transition-transform duration-500 group-hover:scale-110 group-hover:-rotate-12 ${theme === MapTheme.DARK ? 'bg-white/5 shadow-inner' : 'bg-slate-100 border border-white'}`}>
                            {dest.image}
                          </div>
                          <div className="flex-1">
                            <div className={`font-black text-2xl tracking-tighter mb-1 flex items-center gap-4 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
                              {dest.name[language]}
                              {dest.type === 'local' && <span className="text-[10px] bg-blue-500 text-white px-3 py-1 rounded-full uppercase tracking-widest font-black">Verified</span>}
                            </div>
                            <div className={`text-[12px] font-bold opacity-40 uppercase tracking-[0.2em] mono flex items-center gap-3`}>
                              <span className="text-blue-500">{dest.category[language]}</span>
                              <span>•</span>
                              <span>{dest.distance.toFixed(1)} KM</span>
                            </div>
                          </div>
                          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" className="opacity-0 group-hover:opacity-100 group-hover:translate-x-2 transition-all text-blue-500"><polyline points="9 18 15 12 9 6"></polyline></svg>
                        </motion.div>
                      ))}
                    </div>
                  ) : (
                    <div className="px-12 py-6">
                      <div className="mb-12">
                        <p className={`mb-8 text-[11px] font-black uppercase tracking-[0.4em] opacity-30 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Orbital Shortcuts</p>
                        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                          {QUICK_ACTIONS.map(act => (
                            <motion.button 
                              key={act.label}
                              whileHover={{ y: -5, scale: 1.05 }}
                              onClick={() => { setQuery(act.query); onAISearch(act.query); setIsFocused(false); }}
                              className={`flex flex-col items-center justify-center gap-4 p-8 rounded-[40px] transition-all border ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5 hover:border-blue-500/30' : 'bg-white border-slate-100 hover:border-blue-600/20 shadow-lg shadow-slate-200/50'}`}
                            >
                              <span className="text-4xl drop-shadow-md">{act.icon}</span>
                              <span className={`font-black text-[10px] uppercase tracking-[0.2em] ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{act.label}</span>
                            </motion.button>
                          ))}
                        </div>
                      </div>
                      <div className="text-center py-12 border-t border-white/5">
                        <div className="text-7xl mb-8 animate-bounce">🛰️</div>
                        <h3 className={`font-black text-3xl tracking-tighter mb-4 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Discovery Uplink Active</h3>
                        <p className={`font-medium opacity-40 text-lg leading-relaxed max-w-lg mx-auto`}>Deploy planetary discovery to locate quiet zones, nodes, or urban vitality centers by typing and pressing Enter.</p>
                      </div>
                    </div>
                  )}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        {/* Global Deck Controls */}
        <div className="flex gap-4 lg:gap-6 shrink-0">
          <button onClick={onOpenLayers} className={`w-[72px] h-[72px] rounded-[32px] flex items-center justify-center shadow-2xl transition-all duration-300 hover:scale-110 hover:-translate-y-2 ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600 border-white/60 shadow-blue-900/10'}`}>
            <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline></svg>
          </button>
          <button onClick={onThemeToggle} className={`w-[72px] h-[72px] rounded-[32px] flex items-center justify-center shadow-2xl transition-all duration-300 hover:scale-110 hover:-translate-y-2 ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600 border-white/60 shadow-blue-900/10'}`}>
            <span className="text-3xl transition-transform duration-700 hover:rotate-[360deg]">{theme === MapTheme.DARK ? '☀️' : '🌙'}</span>
          </button>
        </div>
      </div>
    </motion.header>
  );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Destination, MapTheme, RouteInfo, Language, TravelMode } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';

interface BottomPanelProps {
  theme: MapTheme;
  language: Language;
  onDestinationSelect: (d: Destination) => void;
  routeInfo: RouteInfo | null;
  userLocation: [number, number] | null;
  onClearRoute: () => void;
  onTravelModeChange: (mode: TravelMode) => void;
  selectedPlace: Destination | null;
  onClosePlace: () => void;
  onStartNavigation?: () => void;
}

export const BottomPanel: React.FC<BottomPanelProps> = ({ 
  theme, language, onDestinationSelect, routeInfo, selectedPlace, onClosePlace, onStartNavigation
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (routeInfo || selectedPlace) setIsExpanded(true);
    else setIsExpanded(false);
  }, [routeInfo, selectedPlace]);

  return (
    <motion.div 
      animate={{ height: isExpanded ? (selectedPlace ? '82vh' : '52vh') : '110px' }}
      transition={{ type: 'spring', damping: 30, stiffness: 160 }}
      className={`fixed bottom-0 left-0 right-0 z-[1400] rounded-t-[72px] shadow-[0_-20px_100px_rgba(0,0,0,0.1)] flex flex-col transition-colors duration-700 overflow-hidden ${theme === MapTheme.DARK ? 'glass bg-[#080e1c]/98' : 'glass-light bg-white/95 border-white/90'}`}
    >
      {/* Interaction Surface */}
      <div className="h-16 flex items-center justify-center cursor-pointer group" onClick={() => setIsExpanded(!isExpanded)}>
        <motion.div 
          animate={{ width: isExpanded ? 80 : 120 }}
          className={`h-2.5 rounded-full transition-colors duration-500 ${theme === MapTheme.DARK ? 'bg-white/10 group-hover:bg-blue-500/40' : 'bg-slate-300/60 group-hover:bg-blue-600/30'}`} 
        />
      </div>

      <AnimatePresence mode="wait">
        {isExpanded ? (
          <motion.div 
            key={selectedPlace ? selectedPlace.id : (routeInfo ? 'route-active' : 'default-list')}
            initial={{ opacity: 0, scale: 0.98, y: 30 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.98, y: -30 }}
            className="flex-1 overflow-hidden flex flex-col px-12 lg:px-32 pb-20"
          >
            {selectedPlace ? (
              <div className="overflow-y-auto no-scrollbar space-y-16 h-full py-6">
                {/* Visual Identity */}
                <div className="flex flex-col lg:flex-row items-start justify-between gap-12">
                  <div className="max-w-4xl space-y-6">
                    <div className="flex items-center gap-5">
                       <p className="text-blue-500 font-black uppercase text-[12px] tracking-[0.5em] mono">{selectedPlace.category[language]}</p>
                       <span className={`w-2 h-2 rounded-full ${selectedPlace.isOpen ? 'bg-emerald-500 animate-pulse shadow-[0_0_10px_#10b981]' : 'bg-rose-500'}`}></span>
                    </div>
                    <h2 className={`text-7xl lg:text-8xl font-black tracking-tighter leading-[0.9] ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{selectedPlace.name[language]}</h2>
                    <div className="flex flex-wrap items-center gap-8 pt-4">
                      <div className="flex items-center gap-3">
                        <span className="text-amber-500 font-black text-4xl">★ {selectedPlace.rating || 'Verified'}</span>
                        <div className="flex -space-x-4">
                           {[1,2,3].map(i => <div key={i} className="w-10 h-10 rounded-full border-4 border-slate-900 bg-blue-600 flex items-center justify-center text-[10px] font-black">AI</div>)}
                        </div>
                      </div>
                      <div className={`px-8 py-3 rounded-[24px] font-black text-[12px] uppercase tracking-widest border transition-all ${theme === MapTheme.DARK ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' : 'bg-blue-600/5 text-blue-600 border-blue-600/20 shadow-sm'}`}>Planetary Mesh Node</div>
                    </div>
                  </div>
                  <motion.button whileHover={{ rotate: 90, scale: 1.1 }} onClick={onClosePlace} className={`w-24 h-24 rounded-[40px] flex items-center justify-center text-4xl transition-all ${theme === MapTheme.DARK ? 'bg-white/5 text-white hover:bg-rose-500/20' : 'bg-slate-900/5 text-slate-900 hover:bg-rose-500/10'}`}>✕</motion.button>
                </div>

                {/* Tactical Operations */}
                <div className="flex flex-wrap gap-8 py-4">
                  <motion.button 
                    whileHover={{ scale: 1.05, y: -4 }} whileTap={{ scale: 0.95 }}
                    className="px-16 py-8 rounded-[40px] bg-blue-600 text-white font-black text-lg uppercase tracking-[0.4em] flex items-center gap-6 shadow-[0_30px_80px_rgba(37,99,235,0.4)] mono group" 
                    onClick={() => onDestinationSelect(selectedPlace)}
                  >
                    <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" className="group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform"><path d="M3 11l19-9-9 19-2-8-8-2z"></path></svg>
                    Deploy Link
                  </motion.button>

                  {[
                    { label: 'Secure', icon: 'M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z' },
                    { label: 'Broadcast', icon: 'M4 12v8a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2v-8M16 6l-4-4-4 4M12 2v13' }
                  ].map((btn, idx) => (
                    <motion.button 
                      key={idx} whileHover={{ scale: 1.05, y: -4 }} whileTap={{ scale: 0.95 }}
                      className={`px-14 py-8 rounded-[40px] font-black text-lg uppercase tracking-[0.3em] flex items-center gap-6 border transition-all mono ${theme === MapTheme.DARK ? 'bg-white/5 border-white/10 text-white' : 'bg-white border-slate-200 text-slate-900 shadow-xl shadow-slate-200/50'}`}
                    >
                      <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d={btn.icon}></path></svg>
                      {btn.label}
                    </motion.button>
                  ))}
                </div>

                {/* Spatial Grid */}
                <div className={`grid grid-cols-1 lg:grid-cols-2 gap-20 py-20 border-y ${theme === MapTheme.DARK ? 'border-white/5' : 'border-slate-900/5'}`}>
                   <div className="space-y-16">
                      <div className="space-y-8">
                        <h4 className={`text-[13px] font-black uppercase tracking-[0.5em] opacity-30 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Spatial Grounding</h4>
                        <p className={`text-3xl font-bold leading-relaxed tracking-tight ${theme === MapTheme.DARK ? 'text-slate-100' : 'text-slate-800'}`}>{selectedPlace.description[language]}</p>
                      </div>

                      <div className="grid grid-cols-2 gap-10">
                         {[
                           { l: 'Uptime', v: '99.8%', d: 'Real-time Sync' },
                           { l: 'Node Rank', v: 'A-Tier', d: 'Top Priority' }
                         ].map((node, i) => (
                           <div key={i} className={`p-10 rounded-[48px] ${theme === MapTheme.DARK ? 'bg-white/5 border border-white/5' : 'bg-slate-50 border border-slate-100 shadow-sm'}`}>
                             <p className="text-[11px] font-black uppercase tracking-[0.3em] opacity-40 mb-4 mono">{node.l}</p>
                             <p className="text-3xl font-black mb-1">{node.v}</p>
                             <p className="text-[10px] font-bold opacity-30 uppercase tracking-widest">{node.d}</p>
                           </div>
                         ))}
                      </div>
                   </div>

                   <div className={`${theme === MapTheme.DARK ? 'glass bg-white/5' : 'glass-light bg-slate-50/80 border-white'} p-14 rounded-[64px] border shadow-2xl`}>
                      <h4 className="text-[13px] font-black uppercase tracking-[0.5em] text-blue-500 mb-12 mono">Uplink Parameters</h4>
                      <div className="space-y-6">
                        {[
                          { l: 'Processor', v: 'Puter v2.1 Orbital', c: 'text-blue-500' },
                          { l: 'Grounding', v: 'Neural Mesh V9', c: 'text-emerald-500' },
                          { l: 'Index Source', v: 'OSM Global Collective', c: 'text-amber-500' },
                          { l: 'Refresh Mode', v: 'Zero-Latency Feed', c: 'text-rose-500' }
                        ].map((spec, i) => (
                          <div key={i} className={`flex items-center justify-between p-7 rounded-[32px] border transition-all ${theme === MapTheme.DARK ? 'bg-white/5 border-white/10' : 'bg-white/90 border-slate-200 shadow-sm'}`}>
                             <span className={`font-black text-[12px] uppercase tracking-widest opacity-40 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{spec.l}</span>
                             <span className={`font-black text-sm ${spec.c}`}>{spec.v}</span>
                          </div>
                        ))}
                      </div>
                   </div>
                </div>
              </div>
            ) : routeInfo ? (
              <div className="flex flex-col h-full justify-center">
                <div className={`flex flex-col lg:flex-row justify-between items-center p-16 rounded-[64px] border ${theme === MapTheme.DARK ? 'bg-blue-600/5 border-blue-600/20 shadow-[0_0_80px_rgba(37,99,235,0.1)]' : 'bg-blue-50 border-blue-100 shadow-2xl shadow-blue-900/10'}`}>
                  <div className="space-y-6 text-center lg:text-left mb-12 lg:mb-0">
                    <p className={`text-[10vw] lg:text-[140px] font-black text-blue-600 tracking-tighter hud-text leading-none`}>{routeInfo.duration}</p>
                    <div className="flex items-center gap-6 justify-center lg:justify-start">
                        <div className="flex items-center gap-3">
                           <div className="w-3 h-3 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_10px_#10b981]"></div>
                           <p className={`text-[14px] font-black uppercase tracking-[0.5em] mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{routeInfo.distance}</p>
                        </div>
                        <span className="opacity-20">/</span>
                        <p className={`text-[14px] font-black uppercase tracking-[0.5em] mono text-blue-500`}>Velocity Optimized</p>
                    </div>
                  </div>
                  <motion.button 
                    whileHover={{ scale: 1.05, y: -8 }} whileTap={{ scale: 0.95 }}
                    onClick={onStartNavigation} 
                    className="px-28 py-14 rounded-[48px] font-black text-2xl uppercase tracking-[0.4em] bg-blue-600 text-white shadow-[0_40px_100px_rgba(37,99,235,0.5)] mono transition-all"
                  >
                    Initiate
                  </motion.button>
                </div>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-10 pt-16 h-full overflow-y-auto no-scrollbar pb-20">
                {POPULAR_DESTINATIONS.map((dest, idx) => (
                  <motion.div 
                    key={dest.id} 
                    initial={{ opacity: 0, scale: 0.9, y: 20 }}
                    animate={{ opacity: 1, scale: 1, y: 0 }}
                    transition={{ delay: idx * 0.1 }}
                    whileHover={{ y: -15, scale: 1.03 }} 
                    onClick={() => onDestinationSelect(dest)} 
                    className={`p-12 rounded-[56px] border-2 transition-all cursor-pointer group flex flex-col justify-between h-[360px] ${theme === MapTheme.DARK ? 'bg-white/5 border-transparent hover:border-blue-500/40' : 'bg-white border-slate-100 hover:border-blue-600/30 shadow-2xl shadow-slate-300/30'}`}
                  >
                    <div>
                      <span className="text-8xl block mb-12 transition-transform duration-700 group-hover:scale-125 group-hover:-rotate-12 drop-shadow-2xl">{dest.image}</span>
                      <h3 className={`font-black text-4xl tracking-tighter mb-4 leading-tight ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{dest.name[language]}</h3>
                    </div>
                    <div className="flex items-center justify-between border-t border-white/5 pt-8">
                        <p className={`text-[12px] font-black uppercase tracking-[0.4em] opacity-40 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{dest.category[language]}</p>
                        <div className="flex items-center gap-2">
                          <span className="text-amber-500 font-black text-xl">★ {dest.rating}</span>
                        </div>
                    </div>
                  </motion.div>
                ))}
              </div>
            )}
          </motion.div>
        ) : (
            <motion.div 
                initial={{ opacity: 0 }} 
                animate={{ opacity: 1 }} 
                className="flex flex-col items-center justify-center h-full px-12 pb-4"
            >
                <div className="flex items-center gap-6">
                   <div className="w-2 h-2 rounded-full bg-blue-500 animate-ping"></div>
                   <p className={`font-black uppercase tracking-[0.5em] text-[12px] opacity-20 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
                       Standing by for Deployment
                   </p>
                </div>
            </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
import { GoogleGenAI } from "@google/genai";

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

declare const puter: any;

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  // Layer References
  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const trafficLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false, opacity: 0.7 }));
  const weatherLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false }));
  const planetaryLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: -1, visible: false }));

  const routeSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const discoverySource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [isPuterReady, setIsPuterReady] = useState(false);

  const [telemetry, setTelemetry] = useState({
    altitude: 900,
    signal: 'Nominal',
    urbanFlow: 'Fluid',
    nodes: 42,
    sync: '98.4%'
  });

  useEffect(() => {
    const initPuter = async () => {
        try {
            setIsPuterReady(true);
            const savedSettings = await puter.kv.get('disha_orbital_settings');
            if (savedSettings) {
                const settings = JSON.parse(savedSettings);
                if (settings.theme) setTheme(settings.theme);
                if (settings.lang) setLanguage(settings.lang);
            }
        } catch (e) {
            console.warn("Puter uplink offline", e);
        }
    };
    if (typeof puter !== 'undefined') initPuter();
  }, []);

  useEffect(() => {
    if (theme === MapTheme.LIGHT) document.body.classList.add('light-mode');
    else document.body.classList.remove('light-mode');
  }, [theme]);

  const updateSettings = useCallback(async (updates: Partial<{theme: MapTheme, lang: Language}>) => {
    const newTheme = updates.theme || theme;
    const newLang = updates.lang || language;
    setTheme(newTheme);
    setLanguage(newLang);
    if (isPuterReady) {
      try {
        await puter.kv.set('disha_orbital_settings', JSON.stringify({ theme: newTheme, lang: newLang }));
      } catch (e) { console.error("KV sync failed", e); }
    }
  }, [isPuterReady, theme, language]);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;
    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current, baseLayerRef.current, trafficLayerRef.current, weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 110 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true, smoothExtentConstraint: true }),
      controls: []
    });
    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({ image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) }) }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      }, null, { enableHighAccuracy: true });
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        setTelemetry({
          altitude: Math.floor(820 + Math.abs(lonLat[0] % 1) * 1500),
          signal: (lonLat[0] + lonLat[1]) % 2 > 1 ? 'Optimal' : 'Relinking',
          urbanFlow: (lonLat[1] % 0.1) > 0.05 ? 'Heavy' : 'Nominal',
          nodes: Math.floor(30 + Math.random() * 20),
          sync: (97 + Math.random() * 2.9).toFixed(1) + '%'
        });
      }
    });

    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) setSelectedPlace(feature.get('poiData'));
      else { setSelectedPlace(null); routeSource.current.clear(); }
    });
    return () => map.setTarget(undefined);
  }, []);

  useEffect(() => {
    if (!mapInstance.current) return;
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);
    let url = MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;
    else if (theme === MapTheme.DARK) url = MAP_SOURCES.DARK_CANVAS;
    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.GOOGLE_TRAFFIC }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NOAA_PRECIP }));
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NASA_GIBS_NIGHT }));
    planetaryLayerRef.current.setVisible(isNight);
    baseLayerRef.current.setOpacity(isNight ? 0.3 : 1.0);
  }, [activeLayers, theme]);

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const features = new GeoJSON().readFeatures(route.geometry, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
        features.forEach((f: any) => f.setStyle(new Style({ stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round' }) })));
        routeSource.current.addFeatures(features as any);
        setRoutes([{
          id: 'rt1', distance: `${(route.distance / 1000).toFixed(1)} km`, duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);
        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [120, 120, 120, 120], duration: 1200 });
      }
    } catch (e) { console.error("Tactical routing failed", e); }
  };

  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    discoverySource.current.clear();
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Planetary geospatial analysis: Locate "${query}" near coordinates ${mapViewCenter[1]}, ${mapViewCenter[0]}. Return a crisp, expert description for a command center HUD.`;
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: prompt,
        });
        const responseText = response.text || 'Spatial node identified.';
        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();
        if (geoData && geoData.length > 0) {
            const loc = geoData[0];
            const coords: [number, number] = [parseFloat(loc.lon), parseFloat(loc.lat)];
            const discoveryDest: Destination = {
              id: `ai-${Date.now()}`,
              name: { en: loc.display_name.split(',')[0], hi: loc.display_name.split(',')[0], kn: loc.display_name.split(',')[0], es: loc.display_name.split(',')[0] },
              category: { en: 'Orbital Discovery', hi: 'खोज', kn: 'ಶೋಧನೆ', es: 'Descubrimiento' },
              coords: coords,
              description: { en: responseText, hi: responseText, kn: responseText, es: responseText },
              image: '🌌',
              rating: 5.0,
              isOpen: true
            };
            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1500 });
            const f = new Feature(new Point(fromLonLat(coords)));
            f.setStyle(new Style({ image: new Circle({ radius: 18, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 6 }) }) }));
            discoverySource.current.addFeature(f);
        }
    } catch (err) { console.error("AI Uplink failed", err); } finally { setIsSearching(false); }
  };

  return (
    <div className="relative w-full h-screen overflow-hidden transition-colors duration-700">
      <div ref={mapRef} className="map-container" />
      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => updateSettings({ theme: theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK })}
        onLanguageChange={(l) => updateSettings({ lang: l })}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onAISearch={handleAISearch}
      />

      <AnimatePresence>
        {isSearching && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[3000] flex items-center justify-center bg-black/70 backdrop-blur-2xl">
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className={`${theme === MapTheme.DARK ? 'glass' : 'glass-light'} p-16 rounded-[72px] border border-blue-500/40 text-center flex flex-col items-center gap-10 shadow-[0_0_120px_rgba(59,130,246,0.4)]`}>
              <div className="w-24 h-24 border-6 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
              <div className="space-y-4">
                  <h4 className={`font-black text-4xl tracking-tighter ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Synchronizing Planetary Hub...</h4>
                  <p className="text-blue-500 font-black uppercase text-sm tracking-[0.6em] mono animate-pulse">Neural Mesh Propagation</p>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Orbital HUD Elements */}
      <div className="fixed top-32 left-10 z-[800] space-y-6 pointer-events-none hidden xl:block">
        {[
          { label: 'Altitude', val: `${telemetry.altitude} m`, color: 'border-blue-600', dot: 'bg-blue-500' },
          { label: 'Orbital Uplink', val: telemetry.signal, color: 'border-emerald-500', sync: telemetry.sync, text: 'text-emerald-500' },
          { label: 'Neural Nodes', val: telemetry.nodes, color: 'border-amber-500' }
        ].map((item, idx) => (
          <motion.div 
            key={idx} layout 
            initial={{ opacity: 0, x: -30 }} 
            animate={{ opacity: 1, x: 0 }} 
            transition={{ delay: idx * 0.1 }}
            className={`${theme === MapTheme.DARK ? 'glass' : 'glass-light'} ${item.color} border-l-8 p-7 rounded-[40px] w-72 shadow-2xl backdrop-blur-3xl`}
          >
            <div className="flex justify-between items-center mb-2">
                <p className={`text-[11px] font-black uppercase tracking-[0.3em] opacity-40 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{item.label}</p>
                {item.dot && <div className={`w-3 h-3 rounded-full ${item.dot} shadow-[0_0_10px_#3b82f6]`}></div>}
                {item.sync && <span className="text-[11px] font-black text-emerald-500 mono tracking-tighter">{item.sync}</span>}
            </div>
            <p className={`text-4xl font-black tracking-tighter ${item.text || (theme === MapTheme.DARK ? 'text-white' : 'text-slate-900')}`}>{item.val}</p>
          </motion.div>
        ))}
      </div>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />
      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace} onClosePlace={() => { setSelectedPlace(null); routeSource.current.clear(); discoverySource.current.clear(); }}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
        onTravelModeChange={() => {}}
      />
      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => mapInstance.current?.getView().animate({ rotation: Math.PI / 4, duration: 1000 })}
        onMeasureToggle={() => {}} is3D={false} isMeasuring={false} rotation={0}
      />
    </div>
  );
};
export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onAISearch: (query: string) => void;
}

const LogoIcon = () => (
  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

const QUICK_ACTIONS = [
  { label: 'EV Power', icon: '🔋', query: 'EV Charging Station' },
  { label: 'Hubs', icon: '🏢', query: 'Coworking space' },
  { label: 'Vitality', icon: '🌳', query: 'Public park' },
  { label: 'Transit', icon: '🚆', query: 'Railway station' },
];

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, mapCenter, onThemeToggle, onOpenLayers, onSuggestionSelect, onAISearch
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const [isUplinking, setIsUplinking] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (!query.trim() || query.length < 2) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(async () => {
      setIsUplinking(true);
      try {
        // 1. Local Node Sync
        const localNodes = POPULAR_DESTINATIONS.filter(dest => 
          dest.name[language].toLowerCase().includes(query.toLowerCase()) ||
          dest.category[language].toLowerCase().includes(query.toLowerCase())
        ).map(dest => ({
          ...dest,
          isVerified: true,
          distance: getDistance(dest.coords, mapCenter) / 1000
        }));

        // 2. Global Geocoding Uplink (OSM)
        const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=4&addressdetails=1`);
        const globalData = await response.json();

        const globalNodes = globalData.map((item: any) => ({
          id: `osm-${item.place_id}`,
          name: { en: item.display_name.split(',')[0], hi: item.display_name.split(',')[0], kn: item.display_name.split(',')[0], es: item.display_name.split(',')[0] },
          category: { en: item.type || 'Location', hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Ubicación' },
          coords: [parseFloat(item.lon), parseFloat(item.lat)],
          description: { en: item.display_name, hi: item.display_name, kn: item.display_name, es: item.display_name },
          image: '📍',
          isVerified: false,
          distance: getDistance([parseFloat(item.lon), parseFloat(item.lat)], mapCenter) / 1000
        }));

        // Deduplicate and set
        setSuggestions([...localNodes, ...globalNodes]);
      } catch (err) {
        console.warn("Spatial link error", err);
      } finally {
        setIsUplinking(false);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsFocused(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <motion.header 
      initial={{ y: -100, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[2000] p-6 lg:p-8 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-start gap-4 lg:gap-8 pointer-events-auto">
        {/* Command Branding */}
        <div className={`flex items-center gap-5 px-8 py-3 rounded-[32px] h-[72px] transition-all duration-500 shadow-2xl ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900 border-white/60'}`}>
          <div className="w-12 h-12 bg-blue-600 rounded-[20px] flex items-center justify-center text-white shadow-lg shadow-blue-600/30">
            <LogoIcon />
          </div>
          <span className="font-black text-2xl tracking-tighter hidden xl:block">Disha</span>
        </div>

        {/* Intelligence Input Area */}
        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-10 h-[72px] rounded-[36px] transition-all duration-500 shadow-2xl overflow-hidden ${
            theme === MapTheme.DARK ? `glass ${isFocused ? 'ring-2 ring-blue-500/50 bg-[#0c1326]' : ''}` : `glass-light border-white/60 ${isFocused ? 'ring-2 ring-blue-600/20 bg-white' : ''}`
          }`}>
            <span className={`mr-5 transition-colors duration-300 ${isFocused ? 'text-blue-500' : 'text-slate-400'}`}>
              {isUplinking ? (
                <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" />
              ) : (
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
              )}
            </span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && (onAISearch(query), setIsFocused(false))}
              placeholder={t.searchPlaceholder}
              className="bg-transparent border-none outline-none w-full text-xl font-bold placeholder:opacity-20 placeholder:font-black tracking-tight"
              style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
            />
            <button 
                onClick={() => { onAISearch(query); setIsFocused(false); }}
                className="ml-4 text-[11px] font-black uppercase tracking-[0.2em] text-blue-500 bg-blue-500/10 px-6 py-3 rounded-full hover:bg-blue-600 hover:text-white transition-all shrink-0 mono"
            >
                Uplink
            </button>
          </div>

          <AnimatePresence>
            {isFocused && (
              <motion.div
                initial={{ opacity: 0, y: 15, scale: 0.98 }}
                animate={{ opacity: 1, y: 12, scale: 1 }}
                exit={{ opacity: 0, y: 15, scale: 0.98 }}
                transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                className={`absolute top-full left-0 right-0 rounded-[48px] shadow-[0_50px_150px_rgba(0,0,0,0.4)] overflow-hidden border transition-all duration-300 ${
                  theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-white/80'
                }`}
              >
                <div className="max-h-[75vh] overflow-y-auto py-10 no-scrollbar">
                  {suggestions.length > 0 ? (
                    <div className="space-y-2">
                      <p className={`px-12 mb-6 text-[11px] font-black uppercase tracking-[0.4em] opacity-30 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Discovery Feed</p>
                      {suggestions.map((dest, idx) => (
                        <motion.div 
                          key={dest.id || idx} 
                          initial={{ opacity: 0, x: -10 }}
                          animate={{ opacity: 1, x: 0 }}
                          transition={{ delay: idx * 0.04 }}
                          onClick={() => {
                            onSuggestionSelect(dest);
                            setIsFocused(false);
                            setQuery(dest.name[language]);
                          }} 
                          className={`px-12 py-6 flex items-center gap-8 cursor-pointer transition-all group ${theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-blue-600/5'}`}
                        >
                          <div className={`text-4xl w-20 h-20 flex items-center justify-center rounded-[32px] transition-all duration-500 group-hover:scale-110 group-hover:-rotate-12 ${theme === MapTheme.DARK ? 'bg-white/5 shadow-inner' : 'bg-slate-50 border border-slate-100'}`}>
                            {dest.image}
                          </div>
                          <div className="flex-1">
                            <div className={`font-black text-2xl tracking-tighter mb-1 flex items-center gap-4 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
                              {dest.name[language]}
                              {dest.isVerified && <span className="text-[10px] bg-blue-600 text-white px-3 py-1 rounded-full uppercase tracking-widest font-black shadow-lg shadow-blue-600/20">Node</span>}
                            </div>
                            <div className={`text-[12px] font-bold opacity-40 uppercase tracking-[0.2em] mono flex items-center gap-3`}>
                              <span className="text-blue-500">{dest.category[language]}</span>
                              <span className="opacity-20">•</span>
                              <span>{dest.distance.toFixed(1)} KM Range</span>
                            </div>
                          </div>
                          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" className="opacity-0 group-hover:opacity-100 group-hover:translate-x-2 transition-all text-blue-500"><polyline points="9 18 15 12 9 6"></polyline></svg>
                        </motion.div>
                      ))}
                    </div>
                  ) : (
                    <div className="px-12">
                      <div className="mb-14">
                        <p className={`mb-10 text-[11px] font-black uppercase tracking-[0.5em] opacity-30 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Orbital Shortcuts</p>
                        <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
                          {QUICK_ACTIONS.map(act => (
                            <motion.button 
                              key={act.label}
                              whileHover={{ y: -8, scale: 1.05 }}
                              onClick={() => { setQuery(act.query); onAISearch(act.query); setIsFocused(false); }}
                              className={`flex flex-col items-center justify-center gap-5 p-10 rounded-[44px] transition-all border ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5 hover:border-blue-500/30' : 'bg-white border-slate-100 hover:border-blue-600/30 shadow-xl shadow-slate-200/50'}`}
                            >
                              <span className="text-5xl drop-shadow-xl">{act.icon}</span>
                              <span className={`font-black text-[11px] uppercase tracking-[0.3em] ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{act.label}</span>
                            </motion.button>
                          ))}
                        </div>
                      </div>
                      <div className="text-center py-16 border-t border-white/5">
                        <div className="text-8xl mb-10 animate-bounce">🛰️</div>
                        <h3 className={`font-black text-4xl tracking-tighter mb-6 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Discovery Mesh Ready</h3>
                        <p className={`font-medium opacity-30 text-xl leading-relaxed max-w-xl mx-auto`}>Deploy planetary discovery via natural language. Locate specific spatial nodes or urban vitality centers by typing above.</p>
                      </div>
                    </div>
                  )}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        {/* System Controls */}
        <div className="flex gap-4 lg:gap-6 shrink-0">
          <button onClick={onOpenLayers} className={`w-[72px] h-[72px] rounded-[32px] flex items-center justify-center transition-all duration-300 hover:scale-110 hover:-translate-y-2 shadow-2xl ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600 border-white/60 shadow-blue-900/10'}`}>
            <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline></svg>
          </button>
          <button onClick={onThemeToggle} className={`w-[72px] h-[72px] rounded-[32px] flex items-center justify-center transition-all duration-300 hover:scale-110 hover:-translate-y-2 shadow-2xl ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600 border-white/60 shadow-blue-900/10'}`}>
            <span className="text-3xl transition-transform duration-1000 hover:rotate-[360deg]">{theme === MapTheme.DARK ? '☀️' : '🌙'}</span>
          </button>
