                        ))}
                      </div>
                   </div>
                </div>
              </div>
            ) : routeInfo ? (
              <div className="flex flex-col h-full justify-center">
                <div className={`flex flex-col lg:flex-row justify-between items-center p-20 rounded-[80px] border ${theme === MapTheme.DARK ? 'bg-blue-600/5 border-blue-600/20 shadow-[0_0_120px_rgba(37,99,235,0.1)]' : 'bg-blue-50 border-blue-100 shadow-3xl shadow-blue-900/10'}`}>
                  <div className="space-y-8 text-center lg:text-left mb-16 lg:mb-0">
                    <p className={`text-[12vw] lg:text-[160px] font-black text-blue-600 tracking-tighter hud-text leading-none`}>{routeInfo.duration}</p>
                    <div className="flex items-center gap-10 justify-center lg:justify-start">
