                      </div>
                   </div>
                   <div className={`${theme === MapTheme.DARK ? 'glass bg-white/5' : 'glass-light bg-slate-50/80 border-white'} p-12 rounded-[56px] shadow-2xl`}>
                      <h4 className="text-[13px] font-black uppercase tracking-[0.5em] text-blue-500 mb-10 mono">Node Registry</h4>
                      <div className="space-y-6">
                        {[
