                 <div className={`flex flex-col lg:flex-row justify-between items-center p-16 rounded-[64px] border ${theme === MapTheme.DARK ? 'bg-blue-600/5 border-blue-600/20' : 'bg-blue-50 border-blue-100 shadow-2xl'}`}>
                  <div className="space-y-6 text-center lg:text-left mb-12 lg:mb-0">
                    <p className={`text-[120px] lg:text-[140px] font-black text-blue-600 tracking-tighter hud-text leading-none`}>{routeInfo.duration}</p>
                    <div className="flex items-center gap-6 justify-center lg:justify-start">
                        <div className="flex items-center gap-3">
                           <div className="w-3 h-3 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_10px_#10b981]"></div>
                           <p className={`text-[14px] font-black uppercase tracking-[0.5em] mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{routeInfo.distance}</p>
