                        ? 'bg-blue-600 text-white border-transparent shadow-xl shadow-blue-600/30' 
                        : (theme === MapTheme.DARK ? 'bg-white/5 text-white/40 border-white/5 hover:border-blue-500/30' : 'bg-slate-100 text-slate-500 border-slate-200 hover:bg-slate-200')
                      }`}
                    >
                      <span>{cat.icon}</span>
                      {cat.label}
                    </button>
                  ))}
                </div>

                {/* Discovery Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8 overflow-y-auto no-scrollbar pb-12 pr-2">
                  {filteredDiscovery.length > 0 ? (
                    filteredDiscovery.map((dest, idx) => (
                      <motion.div 
                        key={dest.id} 
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: idx * 0.05 }}
                        whileHover={{ y: -8, scale: 1.02 }} 
                        onClick={() => onDestinationSelect(dest)} 
                        className={`p-10 rounded-[48px] border-2 transition-all cursor-pointer group flex flex-col justify-between min-h-[300px] ${theme === MapTheme.DARK ? 'bg-white/5 border-transparent hover:border-blue-500/40' : 'bg-white border-slate-100 hover:border-blue-600/30 shadow-xl shadow-slate-200/50'}`}
                      >
                        <div>
                          <div className="flex justify-between items-start mb-8">
                            <span className="text-6xl block transition-transform duration-700 group-hover:scale-125 group-hover:-rotate-12 drop-shadow-2xl">{dest.image}</span>
                            <span className="text-amber-500 font-black text-xl">★ {dest.rating?.toFixed(1)}</span>
                          </div>
                          <h3 className={`font-black text-3xl tracking-tighter mb-2 leading-tight ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{dest.name[language]}</h3>
                          <p className={`text-[11px] font-black uppercase tracking-[0.3em] opacity-40 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{dest.category[language]}</p>
                        </div>
                        <div className="pt-6 border-t border-white/5 flex items-center justify-between">
                            <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">Deploy Link</span>
                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" className="text-blue-500 opacity-0 group-hover:opacity-100 translate-x-2 transition-all"><polyline points="9 18 15 12 9 6"></polyline></svg>
                        </div>
                      </motion.div>
                    ))
                  ) : (
                    <div className="col-span-full py-20 text-center">
                       <div className="text-6xl mb-6">📡</div>
                       <p className="font-black text-2xl opacity-20 uppercase tracking-widest">Searching urban frequency...</p>
                    </div>
                  )}
                </div>
              </div>
            )}
          </motion.div>
        ) : (
            <motion.div 
                initial={{ opacity: 0 }} 
                animate={{ opacity: 1 }} 
                className="flex flex-col items-center justify-center h-full px-12"
            >
                <div className="flex flex-col items-center gap-6">
                   <div className="flex items-center gap-3">
                      <div className="w-3 h-3 rounded-full bg-blue-500 animate-pulse shadow-[0_0_10px_#3b82f6]"></div>
                      <p className={`font-black uppercase tracking-[0.5em] text-[13px] opacity-20 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
                          Standing by for Discovery Sequence
                      </p>
                   </div>
                   {nearbyDiscovery.length > 0 && (
                     <p className="text-[10px] font-bold text-blue-500 uppercase tracking-widest opacity-40 animate-bounce">Expand for {nearbyDiscovery.length} local hubs</p>
                   )}
                </div>
            </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
import { GoogleGenAI } from "@google/genai";

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

declare const puter: any;

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  // Layer References
  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const trafficLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false, opacity: 0.7 }));
  const weatherLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false }));
  const planetaryLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: -1, visible: false }));

  const routeSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const discoverySource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [nearbyPOIs, setNearbyPOIs] = useState<Destination[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [vayuIntel, setVayuIntel] = useState<string | null>(null);
  const [groundingLinks, setGroundingLinks] = useState<{title: string, uri: string}[]>([]);

  const [telemetry, setTelemetry] = useState({
    altitude: 900,
    signal: 'Nominal',
    urbanFlow: 'Fluid',
    nodes: 42,
    sync: '98.4%'
  });

  // Nearby Discovery Logic (Real-time POI from OSM)
  const fetchNearbyDiscovery = useCallback(async (lon: number, lat: number) => {
    try {
      const query = `[out:json][timeout:25];(node["amenity"~"cafe|restaurant|park|charging_station|hospital|hotel|bank|atm"](around:2500,${lat},${lon}););out 12;`;
      const res = await fetch(`https://overpass-api.de/api/interpreter?data=${encodeURIComponent(query)}`);
      const data = await res.json();

      const results: Destination[] = (data.elements || []).map((el: any) => ({
        id: `osm-${el.id}`,
        name: { en: el.tags.name || 'Urban Node', hi: el.tags.name || 'शहरी नोड', kn: el.tags.name || 'ನಗರ ನೋಡ್', es: el.tags.name || 'Nodo Urbano' },
        category: { 
          en: el.tags.amenity?.replace('_', ' ').toUpperCase() || 'SPATIAL NODE', 
          hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Punto de Interés' 
        },
        coords: [el.lon, el.lat],
        description: { 
          en: `Operational ${el.tags.amenity || 'Public node'} detected in active urban mesh.`, 
          hi: 'शहरी नोड।', kn: 'ನಗರ ನೋಡ್.', es: 'Nodo urbano.' 
        },
        image: el.tags.amenity === 'cafe' ? '☕' : el.tags.amenity === 'park' ? '🌳' : el.tags.amenity === 'charging_station' ? '🔋' : '📍',
        rating: 4.1 + (Math.random() * 0.9),
        isOpen: Math.random() > 0.3
      }));
      setNearbyPOIs(results);
    } catch (err) {
      console.warn("Nearby discovery failed", err);
    }
  }, []);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;
    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current, baseLayerRef.current, trafficLayerRef.current, weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 110 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true, smoothExtentConstraint: true }),
      controls: []
    });
    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({ image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) }) }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        fetchNearbyDiscovery(coords[0], coords[1]);
        map.getView().animate({ center: fromLonLat(coords), zoom: 15, duration: 2000 });
      });
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      }, null, { enableHighAccuracy: true });
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        fetchNearbyDiscovery(lonLat[0], lonLat[1]);
        setTelemetry({
          altitude: Math.floor(820 + Math.abs(lonLat[0] % 1) * 2000),
          signal: (lonLat[0] + lonLat[1]) % 2 > 1 ? 'Optimal' : 'Relinking',
          urbanFlow: (lonLat[1] % 0.1) > 0.05 ? 'High' : 'Fluid',
          nodes: Math.floor(40 + Math.random() * 30),
          sync: (98.5 + Math.random() * 1.4).toFixed(1) + '%'
        });
      }
    });

    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) {
        setSelectedPlace(feature.get('poiData'));
      } else {
        setSelectedPlace(null);
        setVayuIntel(null);
        routeSource.current.clear();
      }
    });
    return () => map.setTarget(undefined);
  }, [fetchNearbyDiscovery]);

  useEffect(() => {
    if (!mapInstance.current) return;
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);
    let url = theme === MapTheme.DARK ? MAP_SOURCES.DARK_CANVAS : MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;

    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.GOOGLE_TRAFFIC }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NOAA_PRECIP }));
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NASA_GIBS_NIGHT }));
    planetaryLayerRef.current.setVisible(isNight);
  }, [activeLayers, theme]);

  const handleVayuUplink = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    setVayuIntel(null);
    setGroundingLinks([]);
    discoverySource.current.clear();

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Vayu Command Task: Strategically analyze "${query}" near coordinates ${mapViewCenter[1]}, ${mapViewCenter[0]}. Provide an expert spatial assessment focusing on Urban Fluidity and Node Accessibility. Include specific reasons why this location is relevant.`,
          config: { tools: [{googleSearch: {}}] }
        });

        const intel = response.text || 'Spatial node verified.';
        setVayuIntel(intel);

        // Extract Grounding
        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            const chunks = response.candidates[0].groundingMetadata.groundingChunks;
            const links = chunks
                .filter((c: any) => c.web)
                .map((c: any) => ({ title: c.web.title || 'Intel Source', uri: c.web.uri }));
            setGroundingLinks(links);
        }

        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();

        if (geoData && geoData.length > 0) {
            const loc = geoData[0];
            const coords: [number, number] = [parseFloat(loc.lon), parseFloat(loc.lat)];
            const discoveryDest: Destination = {
              id: `vayu-${Date.now()}`,
              name: { en: loc.display_name.split(',')[0], hi: loc.display_name.split(',')[0], kn: loc.display_name.split(',')[0], es: loc.display_name.split(',')[0] },
              category: { en: 'VAYU ANALYZED NODE', hi: 'विश्लेषित नोड', kn: 'ವಿಶ್ಲೇಷಿಸಿದ ನೋಡ್', es: 'Nodo Analizado' },
              coords: coords,
              description: { en: intel, hi: intel, kn: intel, es: intel },
              image: '🌌',
              rating: 5.0,
              isOpen: true
            };
            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1800 });
            const f = new Feature(new Point(fromLonLat(coords)));
            f.setStyle(new Style({ image: new Circle({ radius: 22, fill: new Fill({ color: 'rgba(59, 130, 246, 0.2)' }), stroke: new Stroke({ color: '#3b82f6', width: 4 }) }) }));
            discoverySource.current.addFeature(f);
        }
    } catch (err) {
        console.error("Vayu AGI Disconnected", err);
    } finally {
        setIsSearching(false);
    }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const features = new GeoJSON().readFeatures(route.geometry, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
        features.forEach((f: any) => f.setStyle(new Style({ stroke: new Stroke({ color: '#3b82f6', width: 10, lineCap: 'round' }) })));
        routeSource.current.addFeatures(features as any);
        setRoutes([{
          id: 'rt1', distance: `${(route.distance / 1000).toFixed(1)} km`, duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);
        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [150, 150, 150, 150], duration: 1500 });
      }
    } catch (e) {
      console.warn("Routing uplink interrupted", e);
    }
  };

  return (
    <div className="relative w-full h-screen overflow-hidden transition-colors duration-700">
      <div ref={mapRef} className="map-container" />

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onAISearch={handleVayuUplink}
      />

      <AnimatePresence>
        {isSearching && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[3000] flex items-center justify-center bg-slate-950/80 backdrop-blur-3xl">
            <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="flex flex-col items-center gap-12 text-center p-20">
              <div className="relative w-48 h-48">
                 <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 4, ease: "linear" }} className="absolute inset-0 border-4 border-blue-500/20 border-t-blue-500 rounded-full" />
                 <motion.div animate={{ rotate: -360 }} transition={{ repeat: Infinity, duration: 2, ease: "linear" }} className="absolute inset-4 border-4 border-blue-400/20 border-b-blue-400 rounded-full" />
                 <motion.div animate={{ scale: [1, 1.2, 1] }} transition={{ repeat: Infinity, duration: 1.5 }} className="absolute inset-0 flex items-center justify-center text-5xl">🛰️</motion.div>
              </div>
              <div className="space-y-4">
                  <h4 className="text-5xl font-black text-white tracking-tighter">VAYU AGENT UPLINK</h4>
                  <p className="text-blue-500 font-black uppercase text-sm tracking-[0.8em] mono animate-pulse">Neural Mesh Calibration in Progress</p>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="fixed top-40 left-10 z-[800] space-y-6 pointer-events-none hidden xl:block">
        {[
          { label: 'Spatial Altitude', val: `${telemetry.altitude} m`, color: 'border-blue-600' },
          { label: 'AGI Sync Status', val: telemetry.signal, color: 'border-emerald-500', sync: telemetry.sync, text: 'text-emerald-500' },
          { label: 'Urban Fluidity', val: telemetry.urbanFlow, color: 'border-amber-500' }
        ].map((item, idx) => (
          <motion.div key={idx} initial={{ x: -100, opacity: 0 }} animate={{ x: 0, opacity: 1 }} transition={{ delay: idx * 0.1 }}
            className={`glass ${item.color} border-l-8 p-8 rounded-[40px] w-80 shadow-3xl backdrop-blur-3xl`}
          >
            <div className="flex justify-between items-center mb-2">
                <p className="text-[11px] font-black uppercase tracking-[0.4em] opacity-30 text-white mono">{item.label}</p>
                {item.sync && <span className="text-[11px] font-black text-emerald-500 mono">{item.sync}</span>}
            </div>
            <p className={`text-4xl font-black tracking-tighter text-white`}>{item.val}</p>
          </motion.div>
        ))}
      </div>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace}
        nearbyDiscovery={nearbyPOIs} vayuIntel={vayuIntel} groundingLinks={groundingLinks}
        onClosePlace={() => { setSelectedPlace(null); setVayuIntel(null); routeSource.current.clear(); discoverySource.current.clear(); }}
        onDestinationSelect={(dest) => { setSelectedPlace(dest); calculateRoute(dest); }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => mapInstance.current?.getView().animate({ rotation: Math.PI / 4, duration: 1000 })}
        onMeasureToggle={() => {}} is3D={false} isMeasuring={false} rotation={0}
      />
    </div>
  );
};
export default App;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Destination, MapTheme, RouteInfo, Language, TravelMode } from '../types';
import { TRANSLATIONS } from '../constants';

interface BottomPanelProps {
  theme: MapTheme;
  language: Language;
  onDestinationSelect: (d: Destination) => void;
  routeInfo: RouteInfo | null;
  userLocation: [number, number] | null;
  onClearRoute: () => void;
  selectedPlace: Destination | null;
  onClosePlace: () => void;
  nearbyDiscovery: Destination[];
  vayuIntel: string | null;
  groundingLinks: {title: string, uri: string}[];
}

const CATEGORIES = [
  { id: 'all', label: 'All Intel', icon: '🌌' },
  { id: 'cafe', label: 'Energy Hubs', icon: '☕' },
  { id: 'park', label: 'Vital Zones', icon: '🌳' },
  { id: 'charging', label: 'EV Ports', icon: '🔋' },
  { id: 'transit', label: 'Nodes', icon: '🚆' },
];

export const BottomPanel: React.FC<BottomPanelProps> = ({ 
  theme, language, onDestinationSelect, routeInfo, selectedPlace, onClosePlace, nearbyDiscovery, vayuIntel, groundingLinks
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [activeCategory, setActiveCategory] = useState('all');

  useEffect(() => {
    if (routeInfo || selectedPlace || vayuIntel) setIsExpanded(true);
    else setIsExpanded(false);
  }, [routeInfo, selectedPlace, vayuIntel]);

  const filteredDiscovery = activeCategory === 'all' 
    ? nearbyDiscovery 
    : nearbyDiscovery.filter(poi => poi.category.en.toLowerCase().includes(activeCategory.toLowerCase()) || poi.image.includes(activeCategory));

  return (
    <motion.div 
      animate={{ height: isExpanded ? (selectedPlace ? '88vh' : '68vh') : '140px' }}
      transition={{ type: 'spring', damping: 30, stiffness: 180 }}
      className={`fixed bottom-0 left-0 right-0 z-[1400] rounded-t-[80px] shadow-2xl flex flex-col transition-all duration-700 overflow-hidden ${theme === MapTheme.DARK ? 'glass bg-slate-950/98' : 'glass-light bg-white/98 border-white/90'}`}
    >
      <div className="h-20 flex items-center justify-center cursor-pointer group shrink-0" onClick={() => setIsExpanded(!isExpanded)}>
        <motion.div 
          animate={{ width: isExpanded ? 100 : 160 }}
          className={`h-2.5 rounded-full transition-colors duration-500 ${theme === MapTheme.DARK ? 'bg-white/10 group-hover:bg-blue-500' : 'bg-slate-300/60 group-hover:bg-blue-600'}`} 
        />
      </div>

      <AnimatePresence mode="wait">
        {isExpanded ? (
          <motion.div 
            key={selectedPlace ? selectedPlace.id : (routeInfo ? 'route' : 'discovery')}
            initial={{ opacity: 0, y: 40 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -40 }}
            className="flex-1 overflow-hidden flex flex-col px-10 lg:px-40 pb-24"
          >
            {selectedPlace ? (
              <div className="overflow-y-auto no-scrollbar space-y-20 h-full py-6">
                <div className="flex flex-col lg:flex-row items-start justify-between gap-12">
                  <div className="max-w-5xl space-y-8">
                    <div className="flex items-center gap-6">
                       <p className="text-blue-500 font-black uppercase text-[14px] tracking-[0.6em] mono">{selectedPlace.category[language]}</p>
                       <span className={`w-3 h-3 rounded-full ${selectedPlace.isOpen ? 'bg-emerald-500 animate-pulse shadow-[0_0_15px_#10b981]' : 'bg-rose-500'}`}></span>
                    </div>
                    <h2 className={`text-7xl lg:text-9xl font-black tracking-tighter leading-tight ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{selectedPlace.name[language]}</h2>
                    <div className="flex items-center gap-6">
                        <span className="text-amber-500 font-black text-5xl tracking-tighter">★ {selectedPlace.rating?.toFixed(1) || 'PRO'}</span>
                        <div className="px-10 py-4 rounded-[28px] bg-blue-600/10 text-blue-500 font-black text-sm uppercase tracking-widest border border-blue-600/20">VAYU VERIFIED NODE</div>
                    </div>
                  </div>
                  <motion.button whileHover={{ rotate: 90, scale: 1.1 }} onClick={onClosePlace} className={`w-24 h-24 rounded-[40px] flex items-center justify-center text-5xl transition-all ${theme === MapTheme.DARK ? 'bg-white/5 text-white hover:bg-rose-500/20' : 'bg-slate-900/5 text-slate-900 hover:bg-rose-500/10'}`}>✕</motion.button>
                </div>

                <div className="flex gap-8">
                   <motion.button 
                    whileHover={{ scale: 1.05, y: -8 }} whileTap={{ scale: 0.95 }}
                    className="px-24 py-12 rounded-[56px] bg-blue-600 text-white font-black text-2xl uppercase tracking-[0.4em] flex items-center gap-8 shadow-3xl shadow-blue-600/40 mono" 
                    onClick={() => onDestinationSelect(selectedPlace)}
                  >
                    🚀 Initiate Uplink
                  </motion.button>
                </div>

                <div className={`grid grid-cols-1 lg:grid-cols-2 gap-24 py-24 border-y ${theme === MapTheme.DARK ? 'border-white/5' : 'border-slate-900/5'}`}>
                   <div className="space-y-12">
                      <h4 className="text-[14px] font-black uppercase tracking-[0.6em] text-blue-500 mono">Vayu Spatial Assessment</h4>
                      <p className={`text-4xl font-bold leading-relaxed tracking-tight ${theme === MapTheme.DARK ? 'text-slate-200' : 'text-slate-800'}`}>{vayuIntel || selectedPlace.description[language]}</p>

                      {groundingLinks.length > 0 && (
                        <div className="space-y-6">
                           <h5 className="text-[11px] font-black uppercase tracking-[0.4em] opacity-30 mono text-white">Verified Intelligence Sources</h5>
                           <div className="flex flex-wrap gap-4">
                              {groundingLinks.slice(0, 3).map((link, idx) => (
                                <a key={idx} href={link.uri} target="_blank" rel="noopener noreferrer" className="px-6 py-3 rounded-full bg-white/5 border border-white/10 text-xs font-black uppercase text-blue-400 hover:bg-blue-600 hover:text-white transition-all">
                                   {link.title.substring(0, 20)}...
                                </a>
                              ))}
                           </div>
                        </div>
                      )}
                   </div>

                   <div className={`p-16 rounded-[72px] border ${theme === MapTheme.DARK ? 'glass bg-white/5 border-white/10' : 'bg-slate-50 border-slate-200'} shadow-2xl`}>
                      <h4 className="text-[14px] font-black uppercase tracking-[0.6em] text-emerald-500 mb-12 mono">Orbital Parameters</h4>
                      <div className="space-y-8">
                        {[
                          { l: 'Stability Index', v: '98.4%', c: 'text-blue-500' },
                          { l: 'Urban Vitality', v: 'HIGH FREQUENCY', c: 'text-emerald-500' },
                          { l: 'Registry Type', v: 'OSM/VAYU HYBRID', c: 'text-amber-500' }
                        ].map((spec, i) => (
                          <div key={i} className={`flex items-center justify-between p-8 rounded-[36px] border ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5' : 'bg-white border-slate-100'}`}>
                             <span className="font-black text-sm uppercase tracking-widest opacity-40 mono text-white">{spec.l}</span>
                             <span className={`font-black text-lg ${spec.c}`}>{spec.v}</span>
                          </div>
                        ))}
                      </div>
                   </div>
                </div>
              </div>
            ) : routeInfo ? (
              <div className="flex flex-col h-full justify-center">
                 <div className={`flex flex-col lg:flex-row justify-between items-center p-20 rounded-[80px] border ${theme === MapTheme.DARK ? 'bg-blue-600/5 border-blue-600/20' : 'bg-blue-50 border-blue-100 shadow-3xl'}`}>
                  <div className="space-y-8 text-center lg:text-left mb-16 lg:mb-0">
                    <p className={`text-[12vw] lg:text-[180px] font-black text-blue-600 tracking-tighter leading-none`}>{routeInfo.duration}</p>
                    <div className="flex items-center gap-10 justify-center lg:justify-start">
                        <div className="flex items-center gap-4">
                           <div className="w-5 h-5 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_20px_#10b981]"></div>
                           <p className="text-[20px] font-black uppercase tracking-[0.8em] mono text-white">{routeInfo.distance}</p>
                        </div>
                    </div>
                  </div>
                  <motion.button 
                    whileHover={{ scale: 1.05, y: -15 }} whileTap={{ scale: 0.95 }}
                    className="px-36 py-16 rounded-[64px] font-black text-3xl uppercase tracking-[0.6em] bg-blue-600 text-white shadow-3xl shadow-blue-600/40 mono transition-all"
                  >
                    Engage Path
                  </motion.button>
                </div>
              </div>
            ) : (
              <div className="flex-1 flex flex-col h-full overflow-hidden">
                <div className="flex flex-col lg:flex-row items-center justify-between mb-12 gap-8 shrink-0">
                  <div className="space-y-3 text-center lg:text-left">
                    <h3 className={`text-6xl lg:text-7xl font-black tracking-tighter ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>NEARBY MESH</h3>
                    <p className="text-blue-500 font-black uppercase text-sm tracking-[0.7em] mono">Vayu Real-time Active Recon</p>
                  </div>
                  <div className="flex gap-4 overflow-x-auto no-scrollbar w-full lg:w-auto">
                    {CATEGORIES.map(cat => (
                      <button 
                        key={cat.id} onClick={() => setActiveCategory(cat.id)}
                        className={`px-10 py-5 rounded-full font-black text-sm uppercase tracking-widest transition-all border whitespace-nowrap flex items-center gap-4 ${
                          activeCategory === cat.id ? 'bg-blue-600 text-white border-transparent shadow-xl' : 'glass border-white/5 text-white/40 hover:border-blue-500'
                        }`}
                      >
                        <span className="text-2xl">{cat.icon}</span>{cat.label}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-10 overflow-y-auto no-scrollbar pb-20 pr-4">
                  {filteredDiscovery.map((dest, idx) => (
                    <motion.div 
                      key={dest.id} initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: idx * 0.04 }}
                      whileHover={{ y: -15, scale: 1.05 }} 
                      onClick={() => onDestinationSelect(dest)} 
                      className={`p-12 rounded-[64px] border-4 transition-all cursor-pointer group flex flex-col justify-between h-[420px] ${theme === MapTheme.DARK ? 'bg-white/5 border-transparent hover:border-blue-500/50' : 'bg-white border-slate-100 hover:border-blue-600/30 shadow-3xl'}`}
                    >
                      <div>
                        <div className="flex justify-between items-start mb-10">
                          <span className="text-8xl block transition-transform duration-1000 group-hover:scale-125 group-hover:-rotate-12 drop-shadow-3xl">{dest.image}</span>
                          <div className="text-right">
                             <span className="text-amber-500 font-black text-2xl tracking-tighter">★ {dest.rating?.toFixed(1)}</span>
                             <p className="text-[10px] font-black text-emerald-500 uppercase mt-1">Vitality 94%</p>
                          </div>
                        </div>
                        <h3 className={`font-black text-4xl tracking-tighter mb-4 leading-tight ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{dest.name[language]}</h3>
                        <p className={`text-[12px] font-black uppercase tracking-[0.4em] opacity-40 mono text-white`}>{dest.category[language]}</p>
                      </div>
                      <div className="pt-8 border-t border-white/10 flex items-center justify-between">
                          <span className="text-sm font-black text-blue-500 uppercase tracking-widest mono">Deploy Uplink</span>
                          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="5" className="text-blue-500 group-hover:translate-x-3 transition-transform"><polyline points="9 18 15 12 9 6"></polyline></svg>
                      </div>
                    </motion.div>
                  ))}
                </div>
              </div>
            )}
          </motion.div>
        ) : (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex flex-col items-center justify-center h-full gap-4">
                <div className="flex items-center gap-10">
                   <div className="w-4 h-4 rounded-full bg-blue-500 animate-ping"></div>
                   <p className="font-black uppercase tracking-[0.8em] text-[15px] opacity-20 mono text-white">Vayu Standby: Ready for Engagement</p>
                </div>
            </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export enum MapLayerType {
  STREET = 'street',
  SATELLITE = 'satellite',
  TRAFFIC = 'traffic',
  WEATHER = 'weather',
  TRANSIT = 'transit',
  BUILDINGS = 'buildings',
  ROUTE = 'route',
  MINIMALIST = 'minimalist',
  RETRO = 'retro',
  INDUSTRIAL = 'industrial'
}

export enum MapTheme {
  DARK = 'dark',
  LIGHT = 'light'
}

export type Language = 'en' | 'hi' | 'kn' | 'es';
export type TravelMode = 'driving' | 'walking' | 'cycling' | 'transit';

export interface LocalizedString {
  en: string;
  hi: string;
  kn: string;
  es: string;
}

export interface PlaceReview {
  id: string;
  author: string;
  rating: number;
  text: string;
  date: string;
  avatar?: string;
}

export interface WeatherData {
  temp: number;
  condition: string;
  windSpeed: number;
  humidity: number;
  icon: string;
}

export interface Destination {
  id: string;
  name: LocalizedString;
  category: LocalizedString;
  coords: [number, number];
  description: LocalizedString;
  image: string;
  rating?: number;
  liveDistance?: number;
  reviews?: PlaceReview[];
  phone?: string;
  website?: string;
  priceLevel?: number;
  isOpen?: boolean;
  hours?: string;
  weather?: WeatherData;
}

export interface RouteInfo {
  id: string;
  distance: string;
  duration: string;
  trafficDelay: string;
  congestionLevel: 'low' | 'moderate' | 'heavy';
  mode: TravelMode;
  segments: any[];
  label?: string;
  geometry?: any; 
}

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
import { GoogleGenAI } from "@google/genai";

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, WeatherData } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

declare const puter: any;

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const trafficLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false, opacity: 0.7 }));
  const weatherLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false }));
  const planetaryLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: -1, visible: false }));

  const routeSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const discoverySource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [nearbyPOIs, setNearbyPOIs] = useState<Destination[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [vayuIntel, setVayuIntel] = useState<string | null>(null);
  const [groundingLinks, setGroundingLinks] = useState<{title: string, uri: string}[]>([]);

  const [telemetry, setTelemetry] = useState({
    altitude: 900,
    signal: 'Nominal',
    urbanFlow: 'Fluid',
    nodes: 42,
    sync: '98.4%'
  });

  const fetchWeather = async (lon: number, lat: number): Promise<WeatherData | undefined> => {
    try {
      const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true`);
      const data = await res.json();
      if (data.current_weather) {
        return {
          temp: Math.round(data.current_weather.temperature),
          condition: 'Clear Skies',
          windSpeed: data.current_weather.windspeed,
          humidity: 65,
          icon: '☀️'
        };
      }
    } catch (e) {
      console.warn("Atmospheric sync failed", e);
    }
    return undefined;
  };

  const fetchNearbyDiscovery = useCallback(async (lon: number, lat: number) => {
    try {
      const query = `[out:json][timeout:25];(node["amenity"~"cafe|restaurant|park|charging_station|hospital|hotel|bank|atm"](around:2500,${lat},${lon}););out 12;`;
      const res = await fetch(`https://overpass-api.de/api/interpreter?data=${encodeURIComponent(query)}`);
      const data = await res.json();

      const results: Destination[] = (data.elements || []).map((el: any) => ({
        id: `osm-${el.id}`,
        name: { en: el.tags.name || 'Urban Node', hi: el.tags.name || 'शहरी नोड', kn: el.tags.name || 'ನಗರ ನೋಡ್', es: el.tags.name || 'Nodo Urbano' },
        category: { 
          en: el.tags.amenity?.replace('_', ' ').toUpperCase() || 'SPATIAL NODE', 
          hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Punto de Interés' 
        },
        coords: [el.lon, el.lat],
        description: { 
          en: `Operational ${el.tags.amenity || 'Public node'} detected in active urban mesh.`, 
          hi: 'शहरी नोड।', kn: 'ನಗರ ನೋಡ್.', es: 'Nodo urbano.' 
        },
        image: el.tags.amenity === 'cafe' ? '☕' : el.tags.amenity === 'park' ? '🌳' : el.tags.amenity === 'charging_station' ? '🔋' : '📍',
        rating: 4.1 + (Math.random() * 0.9),
        isOpen: Math.random() > 0.3,
        hours: '09:00 - 21:00',
        phone: '+91 80 0000 0000',
        reviews: [
            { id: 'dr1', author: 'Local Guide', rating: 4, text: 'Great discovery in the mesh.', date: 'Just now' }
        ]
      }));
      setNearbyPOIs(results);
    } catch (err) {
      console.warn("Nearby discovery failed", err);
    }
  }, []);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;
    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current, baseLayerRef.current, trafficLayerRef.current, weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 110 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true, smoothExtentConstraint: true }),
      controls: []
    });
    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({ image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) }) }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        fetchNearbyDiscovery(coords[0], coords[1]);
        map.getView().animate({ center: fromLonLat(coords), zoom: 15, duration: 2000 });
      });
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      }, null, { enableHighAccuracy: true });
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        fetchNearbyDiscovery(lonLat[0], lonLat[1]);
        setTelemetry({
          altitude: Math.floor(820 + Math.abs(lonLat[0] % 1) * 2000),
          signal: (lonLat[0] + lonLat[1]) % 2 > 1 ? 'Optimal' : 'Relinking',
          urbanFlow: (lonLat[1] % 0.1) > 0.05 ? 'High' : 'Fluid',
          nodes: Math.floor(40 + Math.random() * 30),
          sync: (98.5 + Math.random() * 1.4).toFixed(1) + '%'
        });
      }
    });

    map.on('click', async (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) {
        const data = feature.get('poiData');
        const weather = await fetchWeather(data.coords[0], data.coords[1]);
        setSelectedPlace({ ...data, weather });
      } else {
        setSelectedPlace(null);
        setVayuIntel(null);
        routeSource.current.clear();
      }
    });
    return () => map.setTarget(undefined);
  }, [fetchNearbyDiscovery]);

  useEffect(() => {
    if (!mapInstance.current) return;
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);
    let url = theme === MapTheme.DARK ? MAP_SOURCES.DARK_CANVAS : MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;

    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.GOOGLE_TRAFFIC }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NOAA_PRECIP }));
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setSource(new XYZ({ url: MAP_SOURCES.NASA_GIBS_NIGHT }));
    planetaryLayerRef.current.setVisible(isNight);
  }, [activeLayers, theme]);

  const handleVayuUplink = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    setVayuIntel(null);
    setGroundingLinks([]);
    discoverySource.current.clear();

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Vayu Command Task: Strategically analyze "${query}" near coordinates ${mapViewCenter[1]}, ${mapViewCenter[0]}. Provide an expert spatial assessment focusing on Urban Fluidity and Node Accessibility. Include specific reasons why this location is relevant.`,
          config: { tools: [{googleSearch: {}}] }
        });

        const intel = response.text || 'Spatial node verified.';
        setVayuIntel(intel);

        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            const chunks = response.candidates[0].groundingMetadata.groundingChunks;
            const links = chunks
                .filter((c: any) => c.web)
                .map((c: any) => ({ title: c.web.title || 'Intel Source', uri: c.web.uri }));
            setGroundingLinks(links);
        }

        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();

        if (geoData && geoData.length > 0) {
            const loc = geoData[0];
            const coords: [number, number] = [parseFloat(loc.lon), parseFloat(loc.lat)];
            const weather = await fetchWeather(coords[0], coords[1]);
            const discoveryDest: Destination = {
              id: `vayu-${Date.now()}`,
              name: { en: loc.display_name.split(',')[0], hi: loc.display_name.split(',')[0], kn: loc.display_name.split(',')[0], es: loc.display_name.split(',')[0] },
              category: { en: 'VAYU ANALYZED NODE', hi: 'विश्लेषित नोड', kn: 'ವಿಶ್ಲೇಷಿಸಿದ ನೋಡ್', es: 'Nodo Analizado' },
              coords: coords,
              description: { en: intel, hi: intel, kn: intel, es: intel },
              image: '🌌',
              rating: 5.0,
              isOpen: true,
              weather
            };
            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1800 });
            const f = new Feature(new Point(fromLonLat(coords)));
            f.setStyle(new Style({ image: new Circle({ radius: 22, fill: new Fill({ color: 'rgba(59, 130, 246, 0.2)' }), stroke: new Stroke({ color: '#3b82f6', width: 4 }) }) }));
            discoverySource.current.addFeature(f);
        }
    } catch (err) {
        console.error("Vayu AGI Disconnected", err);
    } finally {
        setIsSearching(false);
    }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const features = new GeoJSON().readFeatures(route.geometry, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
        features.forEach((f: any) => f.setStyle(new Style({ stroke: new Stroke({ color: '#3b82f6', width: 10, lineCap: 'round' }) })));
        routeSource.current.addFeatures(features as any);
        setRoutes([{
          id: 'rt1', distance: `${(route.distance / 1000).toFixed(1)} km`, duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);
        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [150, 150, 150, 150], duration: 1500 });
      }
    } catch (e) {
      console.warn("Routing uplink interrupted", e);
    }
  };

  return (
    <div className="relative w-full h-screen overflow-hidden transition-colors duration-700">
      <div ref={mapRef} className="map-container" />

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(theme === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onAISearch={handleVayuUplink}
      />

      <AnimatePresence>
        {isSearching && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[3000] flex items-center justify-center bg-slate-950/80 backdrop-blur-3xl">
            <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="flex flex-col items-center gap-12 text-center p-20">
              <div className="relative w-48 h-48">
                 <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 4, ease: "linear" }} className="absolute inset-0 border-4 border-blue-500/20 border-t-blue-500 rounded-full" />
                 <motion.div animate={{ rotate: -360 }} transition={{ repeat: Infinity, duration: 2, ease: "linear" }} className="absolute inset-4 border-4 border-blue-400/20 border-b-blue-400 rounded-full" />
                 <motion.div animate={{ scale: [1, 1.2, 1] }} transition={{ repeat: Infinity, duration: 1.5 }} className="absolute inset-0 flex items-center justify-center text-5xl">🛰️</motion.div>
              </div>
              <div className="space-y-4">
                  <h4 className="text-5xl font-black text-white tracking-tighter">VAYU AGENT UPLINK</h4>
                  <p className="text-blue-500 font-black uppercase text-sm tracking-[0.8em] mono animate-pulse">Neural Mesh Calibration in Progress</p>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="fixed top-40 left-10 z-[800] space-y-6 pointer-events-none hidden xl:block">
        {[
          { label: 'Spatial Altitude', val: `${telemetry.altitude} m`, color: 'border-blue-600' },
          { label: 'AGI Sync Status', val: telemetry.signal, color: 'border-emerald-500', sync: telemetry.sync, text: 'text-emerald-500' },
          { label: 'Urban Fluidity', val: telemetry.urbanFlow, color: 'border-amber-500' }
        ].map((item, idx) => (
          <motion.div key={idx} initial={{ x: -100, opacity: 0 }} animate={{ x: 0, opacity: 1 }} transition={{ delay: idx * 0.1 }}
            className={`glass ${item.color} border-l-8 p-8 rounded-[40px] w-80 shadow-3xl backdrop-blur-3xl`}
          >
            <div className="flex justify-between items-center mb-2">
                <p className="text-[11px] font-black uppercase tracking-[0.4em] opacity-30 text-white mono">{item.label}</p>
                {item.dot && <div className={`w-3 h-3 rounded-full ${item.dot} shadow-[0_0_10px_#3b82f6]`}></div>}
                {item.sync && <span className="text-[11px] font-black text-emerald-500 mono">{item.sync}</span>}
            </div>
            <p className={`text-4xl font-black tracking-tighter text-white`}>{item.val}</p>
          </motion.div>
        ))}
      </div>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace}
        nearbyDiscovery={nearbyPOIs} vayuIntel={vayuIntel} groundingLinks={groundingLinks}
        onClosePlace={() => { setSelectedPlace(null); setVayuIntel(null); routeSource.current.clear(); discoverySource.current.clear(); }}
        onDestinationSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => mapInstance.current?.getView().animate({ rotation: Math.PI / 4, duration: 1000 })}
        onMeasureToggle={() => {}} is3D={false} isMeasuring={false} rotation={0}
      />
    </div>
  );
};
export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onAISearch: (query: string) => void;
}

const LogoIcon = () => (
  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

const QUICK_ACTIONS = [
  { label: 'EV Power', icon: '🔋', query: 'EV Charging Station' },
  { label: 'Hubs', icon: '🏢', query: 'Coworking space' },
  { label: 'Vitality', icon: '🌳', query: 'Public park' },
  { label: 'Transit', icon: '🚆', query: 'Railway station' },
];

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, mapCenter, onThemeToggle, onOpenLayers, onSuggestionSelect, onAISearch
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const [isUplinking, setIsUplinking] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (!query.trim() || query.length < 2) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(async () => {
      setIsUplinking(true);
      try {
        const localNodes = POPULAR_DESTINATIONS.filter(dest => 
          dest.name[language].toLowerCase().includes(query.toLowerCase()) ||
          dest.category[language].toLowerCase().includes(query.toLowerCase())
        ).map(dest => ({
          ...dest,
          isVerified: true,
          distance: getDistance(dest.coords, mapCenter) / 1000
        }));

        const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=4&addressdetails=1`);
        const globalData = await response.json();

        const globalNodes = globalData.map((item: any) => ({
          id: `osm-${item.place_id}`,
          name: { en: item.display_name.split(',')[0], hi: item.display_name.split(',')[0], kn: item.display_name.split(',')[0], es: item.display_name.split(',')[0] },
          category: { en: item.type || 'Location', hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Ubicación' },
          coords: [parseFloat(item.lon), parseFloat(item.lat)],
          description: { en: item.display_name, hi: item.display_name, kn: item.display_name, es: item.display_name },
          image: '📍',
          isVerified: false,
          distance: getDistance([parseFloat(item.lon), parseFloat(item.lat)], mapCenter) / 1000
        }));

        setSuggestions([...localNodes, ...globalNodes]);
      } catch (err) {
        console.warn("Spatial link error", err);
      } finally {
        setIsUplinking(false);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsFocused(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <motion.header 
      initial={{ y: -100, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[2000] p-4 lg:p-8 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-start gap-2 lg:gap-8 pointer-events-auto">
        <div className={`flex items-center gap-4 lg:gap-5 px-4 lg:px-8 py-3 rounded-[24px] lg:rounded-[32px] h-[60px] lg:h-[72px] transition-all duration-500 shadow-2xl ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900 border-white/60'}`}>
          <div className="w-10 h-10 lg:w-12 lg:h-12 bg-blue-600 rounded-[16px] lg:rounded-[20px] flex items-center justify-center text-white shadow-lg shadow-blue-600/30">
            <LogoIcon />
          </div>
          <span className="font-black text-xl lg:text-2xl tracking-tighter hidden sm:block">Disha</span>
        </div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-4 lg:px-10 h-[60px] lg:h-[72px] rounded-[30px] lg:rounded-[36px] transition-all duration-500 shadow-2xl overflow-hidden ${
            theme === MapTheme.DARK ? `glass ${isFocused ? 'ring-2 ring-blue-500/50 bg-[#0c1326]' : ''}` : `glass-light border-white/60 ${isFocused ? 'ring-2 ring-blue-600/20 bg-white' : ''}`
          }`}>
            <span className={`mr-3 lg:mr-5 transition-colors duration-300 ${isFocused ? 'text-blue-500' : 'text-slate-400'}`}>
              {isUplinking ? (
                <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" />
              ) : (
                <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
              )}
            </span>
            <input 
              type="text" 
              value={query}
              onFocus={() => setIsFocused(true)}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && (onAISearch(query), setIsFocused(false))}
              placeholder={t.searchPlaceholder}
              className="bg-transparent border-none outline-none w-full text-base lg:text-xl font-bold placeholder:opacity-20 placeholder:font-black tracking-tight"
              style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
            />
            <button 
                onClick={() => { onAISearch(query); setIsFocused(false); }}
                className="ml-2 lg:ml-4 text-[9px] lg:text-[11px] font-black uppercase tracking-[0.2em] text-blue-500 bg-blue-500/10 px-4 lg:px-6 py-2 lg:py-3 rounded-full hover:bg-blue-600 hover:text-white transition-all shrink-0 mono"
            >
                Uplink
            </button>
          </div>

          <AnimatePresence>
            {isFocused && (
              <motion.div
                initial={{ opacity: 0, y: 15, scale: 0.98 }}
                animate={{ opacity: 1, y: 12, scale: 1 }}
                exit={{ opacity: 0, y: 15, scale: 0.98 }}
                transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                className={`absolute top-full left-0 right-0 rounded-[30px] lg:rounded-[48px] shadow-[0_50px_150px_rgba(0,0,0,0.4)] overflow-hidden border transition-all duration-300 ${
                  theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-white/80'
                }`}
              >
                <div className="max-h-[60vh] lg:max-h-[75vh] overflow-y-auto py-6 lg:py-10 no-scrollbar">
                  {suggestions.length > 0 ? (
                    <div className="space-y-2">
                      <p className={`px-8 lg:px-12 mb-4 lg:mb-6 text-[10px] lg:text-[11px] font-black uppercase tracking-[0.4em] opacity-30 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Discovery Feed</p>
                      {suggestions.map((dest, idx) => (
                        <motion.div 
                          key={dest.id || idx} 
                          initial={{ opacity: 0, x: -10 }}
                          animate={{ opacity: 1, x: 0 }}
                          transition={{ delay: idx * 0.04 }}
                          onClick={() => {
                            onSuggestionSelect(dest);
                            setIsFocused(false);
                            setQuery(dest.name[language]);
                          }} 
                          className={`px-8 lg:px-12 py-4 lg:py-6 flex items-center gap-4 lg:gap-8 cursor-pointer transition-all group ${theme === MapTheme.DARK ? 'hover:bg-white/5' : 'hover:bg-blue-600/5'}`}
                        >
                          <div className={`text-3xl lg:text-4xl w-14 h-14 lg:w-20 lg:h-20 flex items-center justify-center rounded-[20px] lg:rounded-[32px] transition-all duration-500 group-hover:scale-110 ${theme === MapTheme.DARK ? 'bg-white/5 shadow-inner' : 'bg-slate-50 border border-slate-100'}`}>
                            {dest.image}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className={`font-black text-lg lg:text-2xl tracking-tighter mb-1 flex items-center gap-2 lg:gap-4 truncate ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
                              {dest.name[language]}
                              {dest.isVerified && <span className="text-[8px] lg:text-[10px] bg-blue-600 text-white px-2 lg:px-3 py-1 rounded-full uppercase tracking-widest font-black shrink-0">Node</span>}
                            </div>
                            <div className={`text-[10px] lg:text-[12px] font-bold opacity-40 uppercase tracking-[0.2em] mono flex items-center gap-2 lg:gap-3`}>
                              <span className="text-blue-500 truncate">{dest.category[language]}</span>
                              <span className="opacity-20 shrink-0">•</span>
                              <span className="shrink-0">{dest.distance.toFixed(1)} KM</span>
                            </div>
                          </div>
                        </motion.div>
                      ))}
                    </div>
                  ) : (
                    <div className="px-8 lg:px-12">
                      <div className="mb-8 lg:mb-14">
                        <p className={`mb-6 lg:mb-10 text-[10px] lg:text-[11px] font-black uppercase tracking-[0.5em] opacity-30 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Orbital Shortcuts</p>
                        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 lg:gap-6">
                          {QUICK_ACTIONS.map(act => (
                            <motion.button 
                              key={act.label}
                              whileHover={{ y: -5, scale: 1.05 }}
                              onClick={() => { setQuery(act.query); onAISearch(act.query); setIsFocused(false); }}
                              className={`flex flex-col items-center justify-center gap-3 lg:gap-5 p-6 lg:p-10 rounded-[30px] lg:rounded-[44px] transition-all border ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5 hover:border-blue-500/30' : 'bg-white border-slate-100 hover:border-blue-600/30 shadow-xl'}`}
                            >
                              <span className="text-4xl lg:text-5xl drop-shadow-xl">{act.icon}</span>
                              <span className={`font-black text-[9px] lg:text-[11px] uppercase tracking-[0.3em] ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{act.label}</span>
                            </motion.button>
                          ))}
                        </div>
                      </div>
                      <div className="text-center py-8 lg:py-16 border-t border-white/5">
                        <div className="text-6xl lg:text-8xl mb-6 lg:mb-10 animate-bounce">🛰️</div>
                        <h3 className={`font-black text-2xl lg:text-4xl tracking-tighter mb-4 lg:mb-6 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Discovery Mesh Ready</h3>
                        <p className={`font-medium opacity-30 text-sm lg:text-xl leading-relaxed max-w-xl mx-auto`}>Deploy planetary discovery via natural language.</p>
                      </div>
                    </div>
                  )}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex gap-2 lg:gap-6 shrink-0">
          <button onClick={onOpenLayers} className={`w-[60px] lg:w-[72px] h-[60px] lg:h-[72px] rounded-[24px] lg:rounded-[32px] flex items-center justify-center transition-all duration-300 hover:scale-110 shadow-2xl ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600 border-white/60 shadow-blue-900/10'}`}>
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline></svg>
