import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onAISearch: (query: string) => void;
}

const LogoIcon = () => (
  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, mapCenter, onThemeToggle, onOpenLayers, onSuggestionSelect, onAISearch
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const [isUplinking, setIsUplinking] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (!query.trim() || query.length < 2) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(async () => {
      setIsUplinking(true);
      try {
        const local = POPULAR_DESTINATIONS.filter(dest => 
          dest.name[language].toLowerCase().includes(query.toLowerCase())
        ).map(dest => ({ ...dest, isVerified: true, distance: getDistance(dest.coords, mapCenter) / 1000 }));

        const res = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=4`);
        const global = await res.json();
        const globalNodes = global.map((item: any) => ({
          id: `osm-${item.place_id}`,
          name: { en: item.display_name.split(',')[0], hi: item.display_name.split(',')[0], kn: item.display_name.split(',')[0], es: item.display_name.split(',')[0] },
          category: { en: item.type || 'NODE', hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Lugar' },
          coords: [parseFloat(item.lon), parseFloat(item.lat)],
          image: '📍',
          distance: getDistance([parseFloat(item.lon), parseFloat(item.lat)], mapCenter) / 1000
        }));

        setSuggestions([...local, ...globalNodes]);
      } catch (err) {
        console.warn("Search Uplink Error", err);
      } finally {
        setIsUplinking(false);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  return (
    <motion.header 
      initial={{ y: -100, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[2000] p-4 lg:p-8 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-start gap-3 lg:gap-8 pointer-events-auto">
        <div className={`flex items-center gap-3 lg:gap-5 px-4 lg:px-7 h-[60px] lg:h-[72px] rounded-[24px] lg:rounded-[36px] transition-all shadow-2xl ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900 border-white/60'}`}>
          <div className="w-10 h-10 lg:w-12 lg:h-12 bg-blue-600 rounded-[16px] lg:rounded-[20px] flex items-center justify-center text-white shrink-0">
            <LogoIcon />
          </div>
          <span className="font-black text-xl lg:text-2xl tracking-tighter hidden sm:block">Disha</span>
        </div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-5 lg:px-10 h-[60px] lg:h-[72px] rounded-[30px] lg:rounded-[36px] transition-all shadow-2xl overflow-hidden ${
            theme === MapTheme.DARK ? `glass ${isFocused ? 'ring-2 ring-blue-500/50' : ''}` : `glass-light border-white/60 ${isFocused ? 'ring-2 ring-blue-600/20' : ''}`
          }`}>
            <span className={`mr-4 ${isFocused ? 'text-blue-500' : 'text-slate-400'}`}>
              {isUplinking ? <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" /> : <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>}
            </span>
            <input 
              type="text" value={query} onFocus={() => setIsFocused(true)} onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && onAISearch(query)}
              placeholder={t.searchPlaceholder}
              className="bg-transparent border-none outline-none w-full text-base lg:text-xl font-bold placeholder:opacity-20"
              style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
            />
            <button onClick={() => onAISearch(query)} className="ml-3 text-[10px] font-black uppercase tracking-widest text-blue-500 bg-blue-500/10 px-4 py-2 rounded-full hover:bg-blue-600 hover:text-white transition-all">Uplink</button>
          </div>

          <AnimatePresence>
            {isFocused && suggestions.length > 0 && (
              <motion.div initial={{ opacity: 0, y: 15 }} animate={{ opacity: 1, y: 12 }} exit={{ opacity: 0, y: 15 }}
                className={`absolute top-full left-0 right-0 rounded-[28px] lg:rounded-[40px] shadow-2xl overflow-hidden border ${theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-white/80'}`}
              >
                <div className="max-h-[50vh] overflow-y-auto py-5 no-scrollbar">
                  {suggestions.map((dest, idx) => (
                    <div key={idx} onClick={() => { onSuggestionSelect(dest); setIsFocused(false); setQuery(dest.name[language]); }}
                      className="px-8 py-4 flex items-center gap-5 cursor-pointer hover:bg-blue-600/10 transition-colors group"
                    >
                      <div className="text-3xl w-14 h-14 flex items-center justify-center rounded-2xl bg-slate-500/5">{dest.image}</div>
                      <div className="flex-1 min-w-0">
                        <div className="font-black text-lg lg:text-xl flex items-center gap-3 truncate">{dest.name[language]}</div>
                        <div className="text-[10px] font-bold opacity-30 uppercase tracking-widest">{dest.category[language]} • {dest.distance.toFixed(1)} KM</div>
                      </div>
                    </div>
                  ))}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex gap-2 lg:gap-4">
          <button onClick={onOpenLayers} className={`w-[60px] lg:w-[72px] h-[60px] lg:h-[72px] rounded-[24px] lg:rounded-[32px] flex items-center justify-center shadow-2xl ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}>
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline></svg>
          </button>
          <button onClick={onThemeToggle} className={`w-[60px] lg:w-[72px] h-[60px] lg:h-[72px] rounded-[24px] lg:rounded-[32px] flex items-center justify-center shadow-2xl ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600'}`}>
            <span className="text-2xl">{theme === MapTheme.DARK ? '☀️' : '🌙'}</span>
          </button>
        </div>
      </div>
    </motion.header>
  );
};

