                         <p className="text-[10px] font-black uppercase tracking-widest opacity-30">{poi.category[language]}</p>
                      </motion.div>
                    ))}
                 </div>
              </div>
            )}
          </motion.div>
        ) : (
          <div className="h-full flex items-center justify-center">
             <p className="text-[12px] font-black uppercase tracking-[0.6em] opacity-20 text-white mono">Awaiting System Deployment</p>
          </div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { motion } from 'framer-motion';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error?: Error;
}

export class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false
  };

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Vayu System Failure:", error, errorInfo);
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-slate-950 p-10 text-center">
          <motion.div 
            initial={{ scale: 0.9, opacity: 0 }} 
            animate={{ scale: 1, opacity: 1 }}
            className="glass border-rose-500/30 p-16 rounded-[48px] max-w-2xl space-y-8"
          >
            <div className="text-8xl">⚠️</div>
            <h1 className="text-4xl font-black tracking-tighter text-white">SYSTEM DE-SYNC</h1>
            <p className="text-slate-400 font-medium leading-relaxed">
              Vayu AGI encountered a critical spatial anomaly. The neural mesh has been disconnected to prevent telemetry corruption.
            </p>
            <button 
              onClick={() => window.location.reload()}
              className="px-12 py-5 bg-blue-600 rounded-full font-black uppercase tracking-[0.4em] text-sm hover:bg-blue-500 transition-all shadow-2xl shadow-blue-600/30"
            >
              Reboot System
            </button>
            <div className="pt-6 border-t border-white/5">
              <p className="text-[10px] font-black uppercase tracking-widest text-rose-500 mono">
                Error Log: {this.state.error?.message || "Unknown Sector Failure"}
              </p>
            </div>
          </motion.div>
        </div>
      );
    }

    // Fix: Class components access children via this.props.children
    return this.props.children;
  }
}

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
import { GoogleGenAI } from "@google/genai";

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, WeatherData } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

declare const puter: any;

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const trafficLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false, opacity: 0.7 }));
  const weatherLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false }));
  const planetaryLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: -1, visible: false }));

  const routeSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const discoverySource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.STREET]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [nearbyPOIs, setNearbyPOIs] = useState<Destination[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [vayuIntel, setVayuIntel] = useState<string | null>(null);
  const [groundingLinks, setGroundingLinks] = useState<{title: string, uri: string}[]>([]);

  const [telemetry, setTelemetry] = useState({
    altitude: 900,
    signal: 'Nominal',
    urbanFlow: 'Fluid',
    nodes: 42,
    sync: '98.4%'
  });

  const fetchWeather = async (lon: number, lat: number): Promise<WeatherData | undefined> => {
    try {
      const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true`);
      if (!res.ok) return undefined;
      const data = await res.json();
      if (data.current_weather) {
        return {
          temp: Math.round(data.current_weather.temperature),
          condition: 'Stable',
          windSpeed: data.current_weather.windspeed,
          humidity: 62,
          icon: data.current_weather.temperature > 22 ? '☀️' : '⛅'
        };
      }
    } catch (e) {
      console.warn("Weather sync failed:", e);
    }
    return undefined;
  };

  const fetchNearbyDiscovery = useCallback(async (lon: number, lat: number) => {
    try {
      const query = `[out:json][timeout:25];(node["amenity"~"cafe|restaurant|park|charging_station"](around:2500,${lat},${lon}););out 12;`;
      const res = await fetch(`https://overpass-api.de/api/interpreter?data=${encodeURIComponent(query)}`);
      if (!res.ok) return;
      const data = await res.json();

      const results: Destination[] = (data.elements || []).map((el: any) => ({
        id: `osm-${el.id}`,
        name: { en: el.tags.name || 'Urban Node', hi: 'नोड', kn: 'ನೋಡ್', es: 'Nodo' },
        category: { en: el.tags.amenity?.toUpperCase() || 'POINT', hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Lugar' },
        coords: [el.lon, el.lat],
        description: { en: `Detected hub. Utility: ${el.tags.amenity || 'Public'}.`, hi: 'सक्रिय नोड।', kn: 'ಸಕ್ರಿಯ ನೋಡ್.', es: 'Nodo activo.' },
        image: el.tags.amenity === 'cafe' ? '☕' : el.tags.amenity === 'park' ? '🌳' : '📍',
        rating: 4.2 + (Math.random() * 0.7),
        isOpen: true,
        hours: '08:00 - 22:00',
        phone: '+91 80 4444 1111',
        reviews: [{ id: 'rev-1', author: 'Local Scout', rating: 5, text: 'Verified urban asset.', date: 'Today' }]
      }));
      setNearbyPOIs(results);
    } catch (err) {
      console.warn("Nearby nodes fetch failed:", err);
    }
  }, []);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;
    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current, baseLayerRef.current, trafficLayerRef.current, weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 110 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true, smoothExtentConstraint: true }),
      controls: []
    });
    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({ image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) }) }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        fetchNearbyDiscovery(coords[0], coords[1]);
        map.getView().animate({ center: fromLonLat(coords), zoom: 15, duration: 2000 });
      });
      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      });
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        fetchNearbyDiscovery(lonLat[0], lonLat[1]);
      }
    });

    map.on('click', async (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) {
        const data = feature.get('poiData');
        const weather = await fetchWeather(data.coords[0], data.coords[1]);
        setSelectedPlace({ ...data, weather });
      } else {
        setSelectedPlace(null);
        setVayuIntel(null);
        routeSource.current.clear();
      }
    });
  }, [fetchNearbyDiscovery]);

  useEffect(() => {
    if (!mapInstance.current) return;
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);
    let url = theme === MapTheme.DARK ? MAP_SOURCES.DARK_CANVAS : MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;

    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setVisible(isNight);
  }, [activeLayers, theme]);

  const handleVayuUplink = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    setVayuIntel(null);
    setGroundingLinks([]);
    discoverySource.current.clear();

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Vayu Intel Task: Summarize "${query}" near ${mapViewCenter[1]}, ${mapCenter[0]}. Provide spatial utility metrics. No markdown formatting.`,
          config: { tools: [{googleSearch: {}}] }
        });

        const intel = response.text || 'Node verified.';
        setVayuIntel(intel);

        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            const chunks = response.candidates[0].groundingMetadata.groundingChunks;
            const links = chunks.filter((c: any) => c.web).map((c: any) => ({ title: c.web.title || 'Source', uri: c.web.uri }));
            setGroundingLinks(links);
        }

        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();

        if (geoData && geoData.length > 0) {
            const loc = geoData[0];
            const coords: [number, number] = [parseFloat(loc.lon), parseFloat(loc.lat)];
            const weather = await fetchWeather(coords[0], coords[1]);
            const discoveryDest: Destination = {
              id: `vayu-${Date.now()}`,
              name: { en: loc.display_name.split(',')[0], hi: loc.display_name.split(',')[0], kn: loc.display_name.split(',')[0], es: loc.display_name.split(',')[0] },
              category: { en: 'VAYU ANALYZED', hi: 'विश्लेषित', kn: 'ವಿಶ್ಲೇಷಿಸಿದ', es: 'Analizado' },
              coords: coords,
              description: { en: intel, hi: intel, kn: intel, es: intel },
              image: '🌌',
              rating: 5.0,
              isOpen: true,
              weather,
              hours: 'Always Open',
              phone: 'N/A',
              reviews: [{ id: 'v1', author: 'Vayu AGI', rating: 5, text: 'Strategic spatial priority.', date: 'Live' }]
            };
            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1800 });
            const f = new Feature(new Point(fromLonLat(coords)));
            f.setStyle(new Style({ image: new Circle({ radius: 22, fill: new Fill({ color: 'rgba(59, 130, 246, 0.1)' }), stroke: new Stroke({ color: '#3b82f6', width: 4 }) }) }));
            discoverySource.current.addFeature(f);
        }
    } catch (err) {
        console.error("Uplink lost:", err);
    } finally {
        setIsSearching(false);
    }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const features = new GeoJSON().readFeatures(route.geometry, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
        features.forEach((f: any) => f.setStyle(new Style({ stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round' }) })));
        routeSource.current.addFeatures(features as any);
        setRoutes([{
          id: 'rt1', distance: `${(route.distance / 1000).toFixed(1)} km`, duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);
        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [150, 150, 150, 150], duration: 1500 });
      }
    } catch (e) {
      console.warn("Routing uplink interrupted:", e);
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-700 ${theme === MapTheme.LIGHT ? 'light-mode' : ''}`}>
      <div ref={mapRef} className="map-container" />

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(prev => prev === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onAISearch={handleVayuUplink}
      />

      <AnimatePresence>
        {isSearching && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[3000] flex items-center justify-center bg-slate-950/80 backdrop-blur-3xl">
            <motion.div initial={{ scale: 0.95, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="flex flex-col items-center gap-12 text-center p-20">
              <div className="w-24 h-24 border-8 border-blue-600 border-t-transparent rounded-full animate-spin shadow-[0_0_60px_rgba(59,130,246,0.5)]"></div>
              <div className="space-y-4">
                  <h4 className="text-3xl font-black text-white tracking-tighter">VAYU UPLINK ACTIVE</h4>
                  <p className="text-blue-500 font-black uppercase text-[10px] tracking-[0.8em] mono animate-pulse">Scanning Neural Mesh</p>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="fixed top-40 left-8 z-[800] space-y-4 pointer-events-none hidden xl:block">
        {[
          { label: 'Spatial Altitude', val: `${telemetry.altitude} m`, dot: 'bg-blue-500' },
          { label: 'AGI Sync Status', val: telemetry.signal, dot: 'bg-emerald-500', sync: telemetry.sync },
          { label: 'Urban Flow', val: telemetry.urbanFlow, dot: 'bg-amber-500' }
        ].map((item, idx) => (
          <motion.div key={idx} initial={{ x: -80, opacity: 0 }} animate={{ x: 0, opacity: 1 }} transition={{ delay: idx * 0.1 }}
            className={`glass border-l-4 p-5 rounded-[24px] w-64 shadow-2xl border-white/5 backdrop-blur-xl`}
          >
            <div className="flex justify-between items-center mb-1">
                <p className="text-[9px] font-black uppercase tracking-[0.3em] opacity-30 text-white mono">{item.label}</p>
                <div className={`w-2 h-2 rounded-full ${item.dot} shadow-[0_0_8px_rgba(255,255,255,0.4)]`}></div>
            </div>
            <p className="text-2xl font-black tracking-tighter text-white">{item.val}</p>
          </motion.div>
        ))}
      </div>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace}
        nearbyDiscovery={nearbyPOIs} vayuIntel={vayuIntel} groundingLinks={groundingLinks}
        onClosePlace={() => { setSelectedPlace(null); setVayuIntel(null); routeSource.current.clear(); }}
        onDestinationSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => mapInstance.current?.getView().animate({ rotation: Math.PI / 4, duration: 1000 })}
        onMeasureToggle={() => {}} is3D={false} isMeasuring={false} rotation={0}
      />
    </div>
  );
};
export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onAISearch: (query: string) => void;
}

const LogoIcon = () => (
  <svg width="28" height="28" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, mapCenter, onThemeToggle, onOpenLayers, onSuggestionSelect, onAISearch
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const [isUplinking, setIsUplinking] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[language];

  useEffect(() => {
    if (!query.trim() || query.length < 2) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(async () => {
      setIsUplinking(true);
      try {
        const local = POPULAR_DESTINATIONS.filter(dest => 
          dest.name[language].toLowerCase().includes(query.toLowerCase())
        ).map(dest => ({ ...dest, isVerified: true, distance: getDistance(dest.coords, mapCenter) / 1000 }));

        const res = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=4`);
        const global = await res.json();
        const globalNodes = global.map((item: any) => ({
          id: `osm-${item.place_id}`,
          name: { en: item.display_name.split(',')[0], hi: item.display_name.split(',')[0], kn: item.display_name.split(',')[0], es: item.display_name.split(',')[0] },
          category: { en: item.type || 'LOCATION', hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Lugar' },
          coords: [parseFloat(item.lon), parseFloat(item.lat)],
          image: '📍',
          distance: getDistance([parseFloat(item.lon), parseFloat(item.lat)], mapCenter) / 1000
        }));

        setSuggestions([...local, ...globalNodes]);
      } catch (err) {
        console.warn("Search Link Interrupted:", err);
      } finally {
        setIsUplinking(false);
      }
    }, 350);

    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  return (
    <motion.header 
      initial={{ y: -100, opacity: 0 }} animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[2000] p-4 lg:p-6 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-center gap-2 lg:gap-6 pointer-events-auto">
        <div className={`flex items-center gap-3 px-4 lg:px-6 h-[56px] lg:h-[64px] rounded-[20px] lg:rounded-[28px] transition-all shadow-xl ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900 border-white/60'}`}>
          <div className="w-9 h-9 lg:w-10 lg:h-10 bg-blue-600 rounded-[14px] lg:rounded-[18px] flex items-center justify-center text-white shrink-0">
            <LogoIcon />
          </div>
          <span className="font-black text-lg lg:text-xl tracking-tighter hidden sm:block">Disha</span>
        </div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-4 lg:px-8 h-[56px] lg:h-[64px] rounded-[24px] lg:rounded-[32px] transition-all shadow-xl overflow-hidden ${
            theme === MapTheme.DARK ? `glass ${isFocused ? 'ring-2 ring-blue-500/40 bg-[#0c1221]' : ''}` : `glass-light border-white/60 ${isFocused ? 'ring-2 ring-blue-600/10 bg-white' : ''}`
          }`}>
            <span className={`mr-3 ${isFocused ? 'text-blue-500' : 'text-slate-400'}`}>
