  routeInfo: RouteInfo | null;
  userLocation: [number, number] | null;
  selectedPlace: Destination | null;
  onClosePlace: () => void;
  nearbyDiscovery: Destination[];
  vayuIntel: string | null;
  groundingLinks: {title: string, uri: string}[];
  onClearRoute: () => void;
}

