  return (
    <motion.div 
      animate={{ height: isExpanded ? (window.innerWidth < 1024 ? '85vh' : '75vh') : '96px' }}
      transition={{ type: 'spring', damping: 32, stiffness: 220 }}
      className={`fixed bottom-0 left-0 right-0 z-[1400] rounded-t-[32px] lg:rounded-t-[56px] shadow-2xl flex flex-col transition-all duration-700 overflow-hidden ${theme === MapTheme.DARK ? 'glass bg-slate-950/98' : 'glass-light bg-white/98 border-white/90'}`}
