                      <p className="text-blue-500 font-black uppercase text-[10px] tracking-[0.5em] mono">{selectedPlace.category?.[language] || 'LOCATION'}</p>
                      <span className={`w-2 h-2 rounded-full ${selectedPlace.isOpen ? 'bg-emerald-500 animate-pulse' : 'bg-rose-500'}`}></span>
                    </div>
                    <h2 className={`text-3xl lg:text-5xl font-black tracking-tighter leading-tight ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{selectedPlace.name?.[language] || 'Selected Node'}</h2>
                    <div className="flex flex-wrap items-center gap-4">
                        <span className="text-amber-500 font-black text-2xl tracking-tighter">★ {selectedPlace.rating?.toFixed(1) || '4.8'}</span>
                        {selectedPlace.weather && (
                          <div className={`flex items-center gap-2 px-4 py-1.5 rounded-full border ${theme === MapTheme.DARK ? 'bg-emerald-500/5 border-emerald-500/20 text-emerald-400' : 'bg-emerald-50 text-emerald-700'}`}>
                             <span className="text-lg">{selectedPlace.weather.icon}</span>
                             <span className="font-black text-sm">{selectedPlace.weather.temp}°C</span>
                          </div>
                        )}
                        <span className={`text-[9px] font-black uppercase px-3 py-1 rounded-full border ${theme === MapTheme.DARK ? 'bg-white/5 border-white/10' : 'bg-slate-100'}`}>Uplink Active</span>
                    </div>
                  </div>
                  <button onClick={onClosePlace} className="w-12 h-12 rounded-2xl flex items-center justify-center text-xl glass hover:bg-rose-500/20 transition-all">✕</button>
                </div>

                <div className="flex flex-wrap gap-3">
                  <button onClick={() => onDestinationSelect(selectedPlace)} className="px-10 py-4 bg-blue-600 text-white font-black text-sm uppercase tracking-[0.3em] rounded-[24px] shadow-lg hover:scale-105 transition-all">Engage Path</button>
