                              </div>
                              <p className={`text-xs lg:text-sm italic opacity-70 leading-relaxed ${theme === MapTheme.DARK ? 'text-slate-200' : 'text-slate-800'}`}>"{r.text}"</p>
                           </div>
                         ))}
                      </div>
                   </div>
                </div>
              </div>
            ) : routeInfo ? (
              <div className="flex flex-col h-full justify-center space-y-8">
                 <div className={`flex flex-col lg:flex-row items-center justify-between p-8 lg:p-16 rounded-[40px] lg:rounded-[64px] border ${theme === MapTheme.DARK ? 'bg-blue-600/5 border-blue-600/20' : 'bg-blue-50 border-blue-100 shadow-xl'}`}>
                    <div className="text-center lg:text-left space-y-3 mb-8 lg:mb-0">
                       <p className="text-6xl lg:text-9xl font-black text-blue-600 tracking-tighter leading-none">{routeInfo.duration}</p>
                       <div className="flex items-center gap-3 justify-center lg:justify-start">
                          <div className="w-3 h-3 lg:w-4 lg:h-4 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_15px_rgba(16,185,129,0.5)]" />
                          <p className="font-black text-xl lg:text-2xl uppercase tracking-[0.3em] lg:tracking-[0.4em] mono">{routeInfo.distance}</p>
                       </div>
                    </div>
                    <button className="w-full lg:w-auto px-16 py-7 bg-blue-600 rounded-[28px] lg:rounded-[48px] font-black text-xl lg:text-3xl uppercase tracking-[0.4em] shadow-2xl hover:scale-105 transition-all">Engage</button>
                 </div>
              </div>
            ) : (
              <div className="space-y-6 lg:space-y-10 h-full flex flex-col overflow-hidden pt-2">
                 <div className="flex flex-col">
                    <h3 className="text-2xl lg:text-5xl font-black tracking-tighter text-white">SPATIAL DISCOVERY</h3>
                    <p className="text-blue-500 text-[9px] lg:text-[11px] font-black uppercase tracking-[0.5em] mono mt-1">Real-time Node Mesh</p>
                 </div>
                 <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 lg:gap-6 overflow-y-auto no-scrollbar pb-10 pr-1">
                    {nearbyDiscovery.map((poi, idx) => (
                      <motion.div key={poi.id} initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: idx * 0.05 }}
                        onClick={() => onDestinationSelect(poi)}
                        className={`p-6 lg:p-8 glass rounded-[32px] lg:rounded-[48px] cursor-pointer border-white/5 hover:border-blue-600/40 transition-all group shadow-sm`}
                      >
                         <div className="text-4xl lg:text-6xl mb-4 lg:mb-6 group-hover:scale-110 transition-transform">{poi.image}</div>
                         <h4 className="font-black text-lg lg:text-2xl tracking-tight mb-1 truncate leading-tight">{poi.name?.[language] || 'Urban Node'}</h4>
                         <p className="text-[8px] lg:text-[10px] font-black uppercase tracking-[0.3em] opacity-30 mono">{poi.category?.[language] || 'LOCATION'}</p>
                      </motion.div>
                    ))}
                 </div>
              </div>
            )}
          </motion.div>
        ) : (
          <div className="h-full flex items-center justify-center px-6">
             <div className="flex items-center gap-3">
               <div className="w-2 h-2 bg-blue-500 animate-ping rounded-full" />
               <p className="text-[9px] lg:text-[11px] font-black uppercase tracking-[0.6em] opacity-20 text-white mono text-center">Awaiting System Deployment</p>
             </div>
          </div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

