                  <div className="absolute inset-0 pointer-events-none flex items-center overflow-hidden">
                    <span className="text-sm lg:text-xl font-black opacity-20 truncate">
                      "{typedText}"
                      <motion.span animate={{ opacity: [0, 1, 0] }} transition={{ duration: 0.8, repeat: Infinity }} className="inline-block w-0.5 h-4 lg:h-6 bg-blue-500 ml-1" />
                    </span>
                  </div>
                )}
              </div>
            </div>

            <button 
              onClick={() => { onAISearch(query); setIsFocused(false); }} 
              className={`ml-3 shrink-0 p-2 lg:px-8 lg:py-3 rounded-full transition-all group ${
                theme === MapTheme.DARK ? 'bg-blue-600/10 hover:bg-blue-600' : 'bg-blue-600 text-white shadow-lg'
              }`}
            >
              {isUplinking ? (
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <div className="flex items-center gap-2">
                   <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" className="w-3.5 h-3.5 lg:w-5 lg:h-5"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
                   <span className="hidden lg:block text-[11px] font-black uppercase tracking-[0.25em]">Explore</span>
                </div>
              )}
            </button>
          </div>

          <AnimatePresence>
            {isFocused && suggestions.length > 0 && (
              <motion.div initial={{ opacity: 0, y: 12, scale: 0.98 }} animate={{ opacity: 1, y: 12, scale: 1 }} exit={{ opacity: 0, y: 12, scale: 0.98 }}
                className={`absolute top-full left-0 right-0 rounded-[24px] lg:rounded-[48px] shadow-3xl overflow-hidden border ${theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-white/80'}`}
              >
                <div className="max-h-[50vh] lg:max-h-[65vh] overflow-y-auto py-2 lg:py-8 no-scrollbar">
                  {suggestions.map((dest, idx) => (
                    <div key={idx} onClick={() => { onSuggestionSelect(dest); setIsFocused(false); setQuery(dest.name?.[language] || dest.name?.en || 'Node'); }}
                      className="px-6 lg:px-12 py-5 lg:py-7 flex items-center gap-5 lg:gap-8 cursor-pointer hover:bg-blue-600/10 transition-colors group"
                    >
                      <div className="text-2xl lg:text-4xl w-14 h-14 lg:w-20 lg:h-20 flex items-center justify-center rounded-2xl lg:rounded-3xl bg-slate-500/5 group-hover:scale-110 transition-transform">{dest.image}</div>
                      <div className="flex-1 min-w-0">
                        <div className="font-black text-sm lg:text-2xl flex items-center gap-3 truncate leading-tight">
                          {dest.name?.[language] || dest.name?.en || 'Unnamed Node'}
                          {dest.live && (
                            <span className={`text-[8px] lg:text-[11px] font-black uppercase flex items-center gap-1.5 px-3 py-1 rounded-full bg-slate-500/5 ${dest.live.color}`}>
                              {dest.live.icon} {dest.live.label}
                            </span>
                          )}
                        </div>
                        <div className="text-[10px] lg:text-[12px] font-bold opacity-30 uppercase tracking-[0.3em] mt-1 lg:mt-3">
                          {dest.category?.[language] || dest.category?.en || 'Location'} • {dest.distance?.toFixed(1) || '0.0'} KM
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex gap-2 lg:gap-4">
          <button onClick={onOpenLayers} className={`w-[52px] lg:w-[72px] h-[52px] lg:h-[72px] rounded-[16px] lg:rounded-[32px] flex items-center justify-center shadow-xl transition-all ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}>
