      if (typeof puter.ui.onThemeChanged === 'function') {
        puter.ui.onThemeChanged((newTheme: string) => {
          setTheme(newTheme === 'dark' ? MapTheme.DARK : MapTheme.LIGHT);
        });
      } else if (typeof puter.ui.getTheme === 'function') {
        const currentTheme = puter.ui.getTheme();
        setTheme(currentTheme === 'dark' ? MapTheme.DARK : MapTheme.LIGHT);
      }
    }
  }, []);

  const fetchWeather = async (lon: number, lat: number): Promise<WeatherData | undefined> => {
    try {
      const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true`);
      if (!res.ok) return undefined;
      const data = await res.json();
      if (data.current_weather) {
        return {
          temp: Math.round(data.current_weather.temperature),
          condition: data.current_weather.temperature > 15 ? 'Clear Skies' : 'Overcast',
          windSpeed: data.current_weather.windspeed,
          humidity: 62,
          icon: data.current_weather.temperature > 22 ? '☀️' : '⛅'
        };
      }
    } catch (e) {
      console.warn("Weather telemetry interrupted:", e);
    }
    return undefined;
  };

  const fetchNearbyDiscovery = useCallback(async (lon: number, lat: number) => {
    try {
      const query = `[out:json][timeout:25];(node["amenity"~"cafe|restaurant|park|charging_station|hotel"](around:3500,${lat},${lon}););out 15;`;
      const res = await fetch(`https://overpass-api.de/api/interpreter?data=${encodeURIComponent(query)}`);
      if (!res.ok) return;
      const data = await res.json();

      const results: Destination[] = (data.elements || []).map((el: any) => ({
        id: `osm-${el.id}`,
        name: { en: el.tags.name || 'Urban Hub', hi: el.tags.name || 'नोड', kn: el.tags.name || 'ನೋಡ್', es: el.tags.name || 'Nodo' },
        category: { en: (el.tags.amenity || 'POI').toUpperCase(), hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Lugar' },
        coords: [el.lon, el.lat],
        description: { en: `Verified sector utility. Primary: ${el.tags.amenity || 'Public'}.`, hi: 'सक्रिय नोड।', kn: 'ಸಕ್ರಿಯ ನೋಡ್.', es: 'Nodo activo.' },
        image: el.tags.amenity === 'cafe' ? '☕' : el.tags.amenity === 'hotel' ? '🏨' : el.tags.amenity === 'park' ? '🌳' : '📍',
        rating: 4.3 + (Math.random() * 0.6),
        isOpen: true,
        hours: el.tags.opening_hours || '08:00 - 22:00',
        phone: el.tags.phone || '+91 80 4400 1100',
        reviews: [
          { id: `r1-${el.id}`, author: 'Local Scout', rating: 5, text: 'Consistently stable and high-quality.', date: 'Today' }
        ]
      }));
      setNearbyPOIs(results);
    } catch (err) {
      console.warn("Nearby nodes fetch failed:", err);
    }
  }, []);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;
    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current, baseLayerRef.current, trafficLayerRef.current, weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 110 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true, smoothExtentConstraint: true }),
      controls: []
    });
    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({ image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) }) }));
      poiSource.current.addFeature(f);
    });

    // High Accuracy GPS Feature
    if (navigator.geolocation) {
      const options = { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 };

      navigator.geolocation.getCurrentPosition(async (pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        fetchNearbyDiscovery(coords[0], coords[1]);
        map.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1500 });
      }, null, options);

      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      }, null, options);
    }

    map.on('moveend', () => {
      const center = map.getView().getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        fetchNearbyDiscovery(lonLat[0], lonLat[1]);
      }
    });

    map.on('click', async (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) {
        const data = feature.get('poiData');
        const weather = await fetchWeather(data.coords[0], data.coords[1]);
        setSelectedPlace({ ...data, weather });
      } else {
        setSelectedPlace(null);
        setVayuIntel(null);
        routeSource.current.clear();
      }
    });
  }, [fetchNearbyDiscovery]);

  useEffect(() => {
    if (!mapInstance.current) return;
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);

    let url = theme === MapTheme.DARK ? MAP_SOURCES.DARK_CANVAS : MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;

    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setVisible(isNight);
  }, [activeLayers, theme]);

  const handleVayuUplink = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    setVayuIntel(null);
    setGroundingLinks([]);
    discoverySource.current.clear();

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Vayu Intel Task: Summarize "${query}" near coordinates ${mapViewCenter[1]}, ${mapViewCenter[0]}. Provide utility value and status. No markdown.`,
          config: { tools: [{googleSearch: {}}] }
        });

        const intel = response.text || 'Verification complete.';
        setVayuIntel(intel);

        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            const chunks = response.candidates[0].groundingMetadata.groundingChunks;
            const links = chunks.filter((c: any) => c.web).map((c: any) => ({ title: c.web.title || 'Source', uri: c.web.uri }));
            setGroundingLinks(links);
        }

        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();

        if (geoData && geoData.length > 0) {
            const loc = geoData[0];
            const coords: [number, number] = [parseFloat(loc.lon), parseFloat(loc.lat)];
            const weather = await fetchWeather(coords[0], coords[1]);
            const discoveryDest: Destination = {
              id: `vayu-${Date.now()}`,
              name: { en: loc.display_name.split(',')[0], hi: loc.display_name.split(',')[0], kn: loc.display_name.split(',')[0], es: loc.display_name.split(',')[0] },
              category: { en: 'VAYU ANALYZED', hi: 'विश्लेषित', kn: 'ವಿಶ್ಲೇಷಿಸಿದ', es: 'Analizado' },
              coords: coords,
              description: { en: intel, hi: intel, kn: intel, es: intel },
              image: '🌌',
              rating: 5.0,
              isOpen: true,
              weather,
              hours: '09:00 - 21:00',
              phone: 'VAYU-SECURE',
              reviews: [{ id: 'v1', author: 'Vayu Core', rating: 5, text: 'Strategic importance identified.', date: 'Live' }]
            };
            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1500 });
            const f = new Feature(new Point(fromLonLat(coords)));
            f.setStyle(new Style({ image: new Circle({ radius: 24, fill: new Fill({ color: 'rgba(59, 130, 246, 0.15)' }), stroke: new Stroke({ color: '#3b82f6', width: 4 }) }) }));
            discoverySource.current.addFeature(f);
        }
    } catch (err: any) {
        console.error("Vayu Intel Fail:", err);
    } finally {
        setIsSearching(false);
    }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const features = new GeoJSON().readFeatures(route.geometry, { dataProjection: 'EPSG:4326', featureProjection: 'EPSG:3857' });
        features.forEach((f: any) => f.setStyle(new Style({ stroke: new Stroke({ color: '#3b82f6', width: 8, lineCap: 'round' }) })));
        routeSource.current.addFeatures(features as any);
        setRoutes([{
          id: 'rt1', distance: `${(route.distance / 1000).toFixed(1)} km`, duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);
        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [150, 150, 150, 150], duration: 1500 });
      }
    } catch (e) {
      console.warn("Pathing failed:", e);
    }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-700 ${theme === MapTheme.LIGHT ? 'light-mode' : ''}`}>
      <div ref={mapRef} className="map-container" />

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(prev => prev === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onAISearch={handleVayuUplink}
      />

      <AnimatePresence>
        {isSearching && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[3000] flex items-center justify-center bg-slate-950/90 backdrop-blur-3xl">
            <motion.div initial={{ scale: 0.95, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="flex flex-col items-center gap-12 text-center p-20">
              <div className="w-24 h-24 border-8 border-blue-600 border-t-transparent rounded-full animate-spin shadow-[0_0_60px_rgba(59,130,246,0.6)]"></div>
              <div className="space-y-4">
                  <h4 className="text-4xl font-black text-white tracking-tighter uppercase">Vayu Processing</h4>
                  <p className="text-blue-500 font-black uppercase text-[12px] tracking-[1.2em] mono animate-pulse">Neural Mesh Active...</p>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace}
        nearbyDiscovery={nearbyPOIs} vayuIntel={vayuIntel} groundingLinks={groundingLinks}
        onClosePlace={() => { setSelectedPlace(null); setVayuIntel(null); routeSource.current.clear(); }}
        onDestinationSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => mapInstance.current?.getView().animate({ rotation: Math.PI / 4, duration: 1000 })}
        onMeasureToggle={() => {}} is3D={false} isMeasuring={false} rotation={0}
      />
    </div>
  );
};
export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onAISearch: (query: string) => void;
}

const LogoIcon = () => (
  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className="lg:w-8 lg:h-8">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

const TYPING_PHRASES = [
  "search for a hotel near me",
  "search for india",
  "search for london",
  "search for kedarnath"
];

const getLiveStatus = (id: string) => {
  const statuses = [
    { label: 'Trending', icon: '🔥', color: 'text-orange-500' },
    { label: 'Quiet', icon: '🍃', color: 'text-emerald-500' },
    { label: 'Busy', icon: '👥', color: 'text-blue-500' },
    { label: 'Popular', icon: '⭐', color: 'text-amber-500' }
  ];
  const hour = new Date().getHours();
  const idNum = parseInt(id.replace(/\D/g, '') || '0');
  const index = (idNum + hour) % statuses.length;
  return statuses[index];
};

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, mapCenter, onThemeToggle, onOpenLayers, onSuggestionSelect, onAISearch
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const [isUplinking, setIsUplinking] = useState(false);

  // Cinematic Typing State
  const [typedText, setTypedText] = useState("");
  const [phraseIndex, setPhraseIndex] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);
  const [typingDelay, setTypingDelay] = useState(100);

  const dropdownRef = useRef<HTMLDivElement>(null);

  // Typing Effect Loop
  useEffect(() => {
    if (isFocused || query) return;

    const currentPhrase = TYPING_PHRASES[phraseIndex];

    const handleTyping = () => {
      if (!isDeleting) {
        setTypedText(currentPhrase.substring(0, typedText.length + 1));
        setTypingDelay(80);
        if (typedText === currentPhrase) {
          setIsDeleting(true);
          setTypingDelay(2500); // Pause at end
        }
      } else {
        setTypedText(currentPhrase.substring(0, typedText.length - 1));
        setTypingDelay(40);
        if (typedText === "") {
          setIsDeleting(false);
          setPhraseIndex((prev) => (prev + 1) % TYPING_PHRASES.length);
          setTypingDelay(500); 
        }
      }
    };

    const timer = setTimeout(handleTyping, typingDelay);
    return () => clearTimeout(timer);
  }, [typedText, isDeleting, phraseIndex, isFocused, query, typingDelay]);

  // Search Engine & Scoring logic
  useEffect(() => {
    if (!query.trim() || query.length < 2) {
      setSuggestions([]);
      return;
    }

    const timer = setTimeout(async () => {
      setIsUplinking(true);
      try {
        const q = query.toLowerCase().trim();

        // Local Match Scoring
        const local = POPULAR_DESTINATIONS.map(dest => {
          const name = (dest.name[language] || dest.name.en).toLowerCase();
          const distance = getDistance(dest.coords, mapCenter) / 1000;

          let score = 0;
          if (name === q) score += 500;
          else if (name.startsWith(q)) score += 200;
          else if (name.includes(q)) score += 100;

          if (distance < 15) score += Math.max(0, (15 - distance) * 10);
          return { ...dest, score, distance, live: getLiveStatus(dest.id) };
        });

        // Global Node Fetching
        const res = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=5`);
        const global = await res.json();
        const globalNodes = global.map((item: any) => {
          const dist = getDistance([parseFloat(item.lon), parseFloat(item.lat)], mapCenter) / 1000;
          const displayName = item.display_name.split(',')[0];

          let score = 50;
          if (displayName.toLowerCase() === q) score += 300;

          return {
            id: `osm-${item.place_id}`,
            name: { en: displayName, hi: displayName, kn: displayName, es: displayName },
            category: { en: item.type?.toUpperCase() || 'LOCATION', hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Lugar' },
            coords: [parseFloat(item.lon), parseFloat(item.lat)],
            image: item.type === 'hotel' ? '🏨' : '📍',
            distance: dist,
            score: score,
            live: getLiveStatus(`osm-${item.place_id}`)
          };
        });

        const combined = [...local, ...globalNodes]
          .filter(item => (item.score || 0) > 0)
          .sort((a, b) => (b.score || 0) - (a.score || 0))
          .slice(0, 6);

        setSuggestions(combined);
      } catch (err) {
        console.warn("Vayu Uplink Failure:", err);
      } finally {
        setIsUplinking(false);
      }
    }, 300);

    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsFocused(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <motion.header 
      initial={{ y: -100, opacity: 0 }} animate={{ y: 0, opacity: 1 }}
      className="fixed top-0 left-0 right-0 z-[2000] p-3 lg:p-6 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-center gap-2 lg:gap-4 pointer-events-auto">
        <div className={`flex items-center gap-2 lg:gap-4 px-3 lg:px-8 h-[52px] lg:h-[72px] rounded-[18px] lg:rounded-[32px] transition-all shadow-xl ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900 border-white/60'}`}>
          <div className="w-8 h-8 lg:w-11 lg:h-11 bg-blue-600 rounded-[12px] lg:rounded-[20px] flex items-center justify-center text-white shrink-0 shadow-lg">
            <LogoIcon />
          </div>
          <span className="font-black text-lg lg:text-2xl tracking-tighter hidden sm:block">Vayu</span>
        </div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-4 lg:px-10 h-[52px] lg:h-[72px] rounded-[20px] lg:rounded-[36px] transition-all shadow-xl overflow-hidden ${
            theme === MapTheme.DARK ? `glass ${isFocused ? 'ring-2 ring-blue-500/40 bg-[#0c1221]' : ''}` : `glass-light border-white/60 ${isFocused ? 'ring-2 ring-blue-600/10 bg-white' : ''}`
          }`}>
            <div className="flex items-center gap-2 lg:gap-3 flex-1 min-w-0">
              <span className={`text-[10px] lg:text-sm font-black uppercase tracking-widest shrink-0 ${theme === MapTheme.DARK ? 'text-blue-500' : 'text-blue-600'}`}>
                Ask Vayu
              </span>
              <div className="relative flex-1">
                <input 
                  type="text" value={query} onFocus={() => setIsFocused(true)} onChange={(e) => setQuery(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && onAISearch(query)}
                  className="bg-transparent border-none outline-none w-full text-sm lg:text-xl font-black placeholder:opacity-0 tracking-tight"
                  style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
                />
                {!query && !isFocused && (
                  <div className="absolute inset-0 pointer-events-none flex items-center overflow-hidden">
                    <span className="text-sm lg:text-xl font-black opacity-20 truncate">
                      "{typedText}"
                      <motion.span animate={{ opacity: [0, 1, 0] }} transition={{ duration: 0.8, repeat: Infinity }} className="inline-block w-0.5 h-4 lg:h-6 bg-blue-500 ml-1" />
                    </span>
                  </div>
                )}
              </div>
            </div>

            <button 
              onClick={() => { onAISearch(query); setIsFocused(false); }} 
              className={`ml-3 shrink-0 p-2 lg:px-7 lg:py-3 rounded-full transition-all group ${
                theme === MapTheme.DARK ? 'bg-blue-600/10 hover:bg-blue-600' : 'bg-blue-600 text-white shadow-lg'
              }`}
            >
              {isUplinking ? (
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <div className="flex items-center gap-2">
                   <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" className="w-3.5 h-3.5 lg:w-5 lg:h-5"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
                   <span className="hidden lg:block text-[11px] font-black uppercase tracking-[0.25em]">Explore</span>
                </div>
              )}
            </button>
          </div>

          <AnimatePresence>
            {isFocused && suggestions.length > 0 && (
              <motion.div initial={{ opacity: 0, y: 12, scale: 0.98 }} animate={{ opacity: 1, y: 12, scale: 1 }} exit={{ opacity: 0, y: 12, scale: 0.98 }}
                className={`absolute top-full left-0 right-0 rounded-[24px] lg:rounded-[48px] shadow-3xl overflow-hidden border ${theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'}`}
              >
                <div className="max-h-[50vh] lg:max-h-[65vh] overflow-y-auto py-2 lg:py-8 no-scrollbar">
                  {suggestions.map((dest, idx) => (
                    <div key={idx} onClick={() => { onSuggestionSelect(dest); setIsFocused(false); setQuery(dest.name?.[language] || dest.name?.en || 'Node'); }}
