          <button onClick={onThemeToggle} className={`w-[52px] lg:w-[72px] h-[52px] lg:h-[72px] rounded-[16px] lg:rounded-[32px] flex items-center justify-center shadow-xl transition-all ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600'}`}>
