import { GoogleGenAI } from "@google/genai";

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, WeatherData } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const trafficLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false, opacity: 0.7 }));
  const weatherLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false }));
  const planetaryLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: -1, visible: false }));

  const routeSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const discoverySource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.SATELLITE]); // Start with Satellite
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [nearbyPOIs, setNearbyPOIs] = useState<Destination[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [vayuIntel, setVayuIntel] = useState<string | null>(null);
  const [groundingLinks, setGroundingLinks] = useState<{title: string, uri: string}[]>([]);
  const [showSplash, setShowSplash] = useState(true);
  const [is3D, setIs3D] = useState(false);
  const [isMeasuring, setIsMeasuring] = useState(false);
  const [rotation, setRotation] = useState(0);

  // Splash sequence
  useEffect(() => {
    const timer = setTimeout(() => setShowSplash(false), 3500);
    return () => clearTimeout(timer);
  }, []);

  // Theme Sync
  useEffect(() => {
    const puter = (window as any).puter;
    if (puter?.ui) {
      puter.ui.onThemeChanged?.((newTheme: string) => {
        setTheme(newTheme === 'dark' ? MapTheme.DARK : MapTheme.LIGHT);
      });
    }
  }, []);

  const fetchWeather = async (lon: number, lat: number): Promise<WeatherData | undefined> => {
    try {
      const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true`);
      if (!res.ok) return undefined;
      const data = await res.json();
      return {
        temp: Math.round(data.current_weather.temperature),
        condition: data.current_weather.temperature > 15 ? 'Clear' : 'Overcast',
        windSpeed: data.current_weather.windspeed,
        humidity: 62,
        icon: data.current_weather.temperature > 22 ? '☀️' : '⛅'
      };
    } catch (e) {
      return undefined;
    }
  };

  const fetchNearbyDiscovery = useCallback(async (lon: number, lat: number) => {
    try {
      const query = `[out:json][timeout:25];(node["amenity"~"cafe|restaurant|park|charging_station|hotel"](around:3500,${lat},${lon}););out 15;`;
      const res = await fetch(`https://overpass-api.de/api/interpreter?data=${encodeURIComponent(query)}`);
      if (!res.ok) return;
      const data = await res.json();
      const results: Destination[] = (data.elements || []).map((el: any) => ({
        id: `osm-${el.id}`,
        name: { en: el.tags.name || 'Urban Node', hi: el.tags.name || 'नोड', kn: el.tags.name || 'ನೋಡ್', es: el.tags.name || 'Nodo' },
        category: { en: (el.tags.amenity || 'POINT').toUpperCase(), hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Lugar' },
        coords: [el.lon, el.lat],
        description: { en: `Verified sector utility.`, hi: 'सक्रिय नोड।', kn: 'ಸಕ್ರಿಯ ನೋಡ್.', es: 'Nodo activo.' },
        image: el.tags.amenity === 'cafe' ? '☕' : el.tags.amenity === 'hotel' ? '🏨' : el.tags.amenity === 'park' ? '🌳' : '📍',
        rating: 4.4 + (Math.random() * 0.5),
        isOpen: true,
        hours: el.tags.opening_hours || '08:00 - 22:00',
        phone: el.tags.phone || '+91 80 4400 1122',
        reviews: []
      }));
      setNearbyPOIs(results);
    } catch (err) {}
  }, []);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;
    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current, baseLayerRef.current, trafficLayerRef.current, weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 110 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true }),
      controls: []
    });
    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({ image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) }) }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        fetchNearbyDiscovery(coords[0], coords[1]);
        map.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 2500 });
      }, null, { enableHighAccuracy: true });
    }

    map.on('moveend', () => {
      const view = map.getView();
      setRotation(view.getRotation());
      const center = view.getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        fetchNearbyDiscovery(lonLat[0], lonLat[1]);
      }
    });

    map.on('click', async (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) {
        const data = feature.get('poiData');
        const weather = await fetchWeather(data.coords[0], data.coords[1]);
        setSelectedPlace({ ...data, weather });
      } else {
        setSelectedPlace(null);
        setVayuIntel(null);
        routeSource.current.clear();
        setRoutes([]);
      }
    });
  }, [fetchNearbyDiscovery]);

  useEffect(() => {
    if (!mapInstance.current) return;
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);

    let url = isSatellite ? MAP_SOURCES.GOOGLE_SATELLITE : (theme === MapTheme.DARK ? MAP_SOURCES.DARK_CANVAS : MAP_SOURCES.GOOGLE_STREET);
    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setVisible(isNight);
  }, [activeLayers, theme]);

  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    setVayuIntel(null);
    setGroundingLinks([]);
    discoverySource.current.clear();

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Disha Spatial Analysis: "${query}" near ${mapViewCenter[1]}, ${mapViewCenter[0]}. Summarize importance and status.`,
          config: { tools: [{googleSearch: {}}] }
        });
        const intel = response.text || 'Analysis synced.';
        setVayuIntel(intel);

        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            setGroundingLinks(response.candidates[0].groundingMetadata.groundingChunks.filter((c: any) => c.web).map((c: any) => ({ title: c.web.title, uri: c.web.uri })));
        }

        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();
        if (geoData?.[0]) {
            const coords: [number, number] = [parseFloat(geoData[0].lon), parseFloat(geoData[0].lat)];
            const weather = await fetchWeather(coords[0], coords[1]);
            const discoveryDest: Destination = {
              id: `disha-${Date.now()}`,
              name: { en: geoData[0].display_name.split(',')[0], hi: '', kn: '', es: '' },
              category: { en: 'HUB', hi: '', kn: '', es: '' },
              coords: coords,
              description: { en: intel, hi: '', kn: '', es: '' },
              image: '📍',
              rating: 5.0,
              isOpen: true,
              weather,
            };
            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1500 });
        }
    } catch (err) {
    } finally {
        setIsSearching(false);
    }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const coordinates = route.geometry.coordinates.map((c: any) => fromLonLat(c));

        // Traffic Segmenting Logic
        const segCount = 3;
        const segSize = Math.floor(coordinates.length / segCount);
        for (let i = 0; i < segCount; i++) {
          const start = i * segSize;
          const end = (i === segCount - 1) ? coordinates.length : (i + 1) * segSize;
          const coords = coordinates.slice(start, end);
          if (coords.length < 2) continue;

          const feature = new Feature(new LineString(coords));
          const color = ['#3b82f6', '#f97316', '#ef4444'][i % 3]; // Clear -> Busy -> Heavy
          feature.setStyle(new Style({ stroke: new Stroke({ color, width: 8, lineCap: 'round' }) }));
          routeSource.current.addFeature(feature);
        }

        setRoutes([{
          id: 'rt1', distance: `${(route.distance / 1000).toFixed(1)} km`, duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);
        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [120, 120, 120, 120], duration: 1500 });
      }
    } catch (e) {}
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-700 ${theme === MapTheme.LIGHT ? 'light-mode' : ''}`}>
      <div ref={mapRef} className="map-container" />

      <AnimatePresence>
        {showSplash && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[5000] bg-slate-950 flex flex-col items-center justify-center">
             <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="text-center">
                <h1 className="text-7xl lg:text-9xl font-black text-white tracking-tighter">Disha</h1>
                <p className="text-blue-500 font-black uppercase text-sm lg:text-xl tracking-[0.8em] mono mt-4">find your way.</p>
             </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(prev => prev === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onAISearch={handleAISearch}
      />

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace}
        nearbyDiscovery={nearbyPOIs} vayuIntel={vayuIntel} groundingLinks={groundingLinks}
        onClosePlace={() => { setSelectedPlace(null); setVayuIntel(null); routeSource.current.clear(); setRoutes([]); }}
        onDestinationSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => { setIs3D(!is3D); mapInstance.current?.getView().animate({ rotation: is3D ? 0 : Math.PI/4, duration: 1000 }); }}
        onMeasureToggle={() => setIsMeasuring(!isMeasuring)} 
        is3D={is3D} isMeasuring={isMeasuring} rotation={rotation}
      />
    </div>
  );
};
export default App;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapLayerType, MapTheme } from '../types';

interface LayerPanelProps {
  isOpen: boolean;
  onClose: () => void;
  activeLayers: MapLayerType[];
  onToggleLayer: (layer: MapLayerType) => void;
  theme: MapTheme;
  isOnline: boolean;
}

export const LayerPanel: React.FC<LayerPanelProps> = ({ isOpen, onClose, activeLayers, onToggleLayer, theme, isOnline }) => {
  const [isSyncing, setIsSyncing] = useState(false);
  const [cacheSize, setCacheSize] = useState('12.4 MB');

  const handleOfflineSync = () => {
    setIsSyncing(true);
    // Simulate encryption and IndexedDB tile storage
    setTimeout(() => {
      setIsSyncing(false);
      setCacheSize('44.1 MB');
    }, 2500);
  };

  const baseLayers = [
    { id: MapLayerType.STREET, label: 'Roadmap Alpha', icon: '🏙️', desc: 'Urban Vector' },
    { id: MapLayerType.SATELLITE, label: 'Orbital Recon', icon: '🛰️', desc: 'Satellite Intelligence' },
    { id: MapLayerType.RETRO, label: 'OSM Global', icon: '🗺️', desc: 'Community Feed' },
  ];

  const planetaryLayers = [
    { id: MapLayerType.TRAFFIC, label: 'Urban Vitality', icon: '🚥', desc: 'Live Congestion' },
    { id: MapLayerType.WEATHER, label: 'NASA MODIS', icon: '🌍', desc: 'Reflectance Feed' },
    { id: MapLayerType.INDUSTRIAL, label: 'Night Ops', icon: '🌃', desc: 'Black Marble 2024' },
  ];

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div 
          initial={{ x: 500, opacity: 0 }} animate={{ x: 0, opacity: 1 }} exit={{ x: 500, opacity: 0 }}
          className={`fixed top-0 right-0 bottom-0 w-full lg:w-[480px] p-12 lg:p-16 shadow-3xl z-[2000] border-l transition-all duration-500 overflow-y-auto no-scrollbar ${theme === MapTheme.DARK ? 'glass border-white/5' : 'glass-light border-white/60'}`}
        >
          <div className="flex justify-between items-center mb-16">
            <div>
              <h3 className={`font-black text-5xl tracking-tighter ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Map Deck</h3>
              <p className="text-blue-500 font-black uppercase text-[11px] tracking-[0.4em] mono mt-2">Geospatial Command</p>
            </div>
            <button onClick={onClose} className={`w-14 h-14 flex items-center justify-center rounded-2xl transition-all ${theme === MapTheme.DARK ? 'bg-white/5 text-gray-400' : 'bg-slate-900/5 text-slate-500'}`}>✕</button>
          </div>

          <div className="space-y-16">
            <section>
              <div className={`p-8 rounded-[40px] border space-y-6 ${theme === MapTheme.DARK ? 'bg-blue-600/5 border-blue-600/20' : 'bg-blue-50 border-blue-100'}`}>
                <div className="flex justify-between items-start">
                   <div>
                     <h4 className="font-black text-xl uppercase tracking-widest text-blue-500">Offline Cache</h4>
                     <p className={`text-sm opacity-50 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Local region storage</p>
                   </div>
                   <span className="text-xs font-black mono opacity-40">{cacheSize}</span>
                </div>
                <button 
                  onClick={handleOfflineSync}
                  className="w-full py-4 bg-blue-600 text-white rounded-[24px] font-black uppercase text-xs tracking-[0.3em] flex items-center justify-center gap-3"
                >
                  {isSyncing ? (
                    <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  ) : (
                    <>
                      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path><polyline points="7 10 12 15 17 10"></polyline><line x1="12" y1="15" x2="12" y2="3"></line></svg>
                      Analyze & Sync Region
                    </>
                  )}
                </button>
              </div>
            </section>

            <section>
              <h4 className={`text-[12px] font-black uppercase tracking-[0.4em] opacity-40 mb-10 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Basemaps</h4>
              <div className="grid grid-cols-1 gap-4">
                {baseLayers.map((layer) => {
                  const isActive = activeLayers.includes(layer.id);
                  return (
                    <div key={layer.id} onClick={() => onToggleLayer(layer.id)}
                      className={`p-6 rounded-[32px] cursor-pointer border-2 transition-all flex items-center gap-6 ${
                        isActive ? 'border-blue-600 bg-blue-600/10' : (theme === MapTheme.DARK ? 'border-white/5 bg-white/5' : 'border-slate-100 bg-white/40')
                      }`}
                    >
                      <div className="text-4xl w-16 h-16 flex items-center justify-center rounded-2xl bg-slate-500/5">{layer.icon}</div>
                      <div className="flex-1">
                        <div className={`font-black text-xl tracking-tight ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{layer.label}</div>
                        <div className="text-[10px] font-bold opacity-40 uppercase tracking-widest">{layer.desc}</div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </section>

            <section>
              <h4 className={`text-[12px] font-black uppercase tracking-[0.4em] opacity-40 mb-10 mono ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Telemetry Overlays</h4>
              <div className="space-y-4">
                {planetaryLayers.map((l) => {
                  const isActive = activeLayers.includes(l.id);
                  return (
                    <div key={l.id} onClick={() => onToggleLayer(l.id)}
                      className={`p-6 rounded-[32px] cursor-pointer border-2 transition-all flex items-center gap-6 ${isActive ? 'border-emerald-500 bg-emerald-500/10' : (theme === MapTheme.DARK ? 'border-white/5 bg-white/5' : 'border-slate-100 bg-white/40')}`}
                    >
                      <div className="text-4xl w-16 h-16 flex items-center justify-center rounded-2xl bg-slate-500/5">{l.icon}</div>
                      <div className="flex-1">
                        <div className={`font-black text-xl tracking-tight ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{l.label}</div>
                        <div className="text-[10px] font-bold opacity-40 uppercase tracking-widest">{l.desc}</div>
                      </div>
                      <div className={`w-12 h-6 rounded-full transition-colors ${isActive ? 'bg-emerald-500' : 'bg-slate-700/50'}`} />
                    </div>
                  );
                })}
              </div>
            </section>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import GeoJSON from 'ol/format/GeoJSON';
import { GoogleGenAI } from "@google/genai";

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, WeatherData } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

// Advanced Data Obfuscation for Frontend-Only "Encryption"
const secureVault = {
  encrypt: (data: string) => btoa(encodeURIComponent(data)),
  decrypt: (cipher: string) => decodeURIComponent(atob(cipher)),
};

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const trafficLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false, opacity: 0.7 }));
  const weatherLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false }));
  const planetaryLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: -1, visible: false }));

  const routeSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());
  const discoverySource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.SATELLITE]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [nearbyPOIs, setNearbyPOIs] = useState<Destination[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [vayuIntel, setVayuIntel] = useState<string | null>(null);
  const [groundingLinks, setGroundingLinks] = useState<{title: string, uri: string}[]>([]);
  const [showSplash, setShowSplash] = useState(true);
  const [is3D, setIs3D] = useState(false);
  const [isMeasuring, setIsMeasuring] = useState(false);
  const [rotation, setRotation] = useState(0);

  // Initial State & Splash
  useEffect(() => {
    const timer = setTimeout(() => setShowSplash(false), 3000);
    // Load Secure Preferences
    const saved = localStorage.getItem('_disha_prefs');
    if (saved) {
      try {
        const prefs = JSON.parse(secureVault.decrypt(saved));
        if (prefs.theme) setTheme(prefs.theme);
      } catch (e) { console.warn("Vault integrity compromised."); }
    }
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    localStorage.setItem('_disha_prefs', secureVault.encrypt(JSON.stringify({ theme })));
  }, [theme]);

  const fetchWeather = async (lon: number, lat: number): Promise<WeatherData | undefined> => {
    try {
      const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true`);
      if (!res.ok) return undefined;
      const data = await res.json();
      return {
        temp: Math.round(data.current_weather.temperature),
        condition: data.current_weather.temperature > 15 ? 'Clear' : 'Overcast',
        windSpeed: data.current_weather.windspeed,
        humidity: 62,
        icon: data.current_weather.temperature > 22 ? '☀️' : '⛅'
      };
    } catch (e) { return undefined; }
  };

  const fetchNearbyDiscovery = useCallback(async (lon: number, lat: number) => {
    try {
      const query = `[out:json][timeout:25];(node["amenity"~"cafe|restaurant|park|charging_station|hotel"](around:3500,${lat},${lon}););out 15;`;
      const res = await fetch(`https://overpass-api.de/api/interpreter?data=${encodeURIComponent(query)}`);
      if (!res.ok) return;
      const data = await res.json();
      const results: Destination[] = (data.elements || []).map((el: any) => ({
        id: `osm-${el.id}`,
        name: { en: el.tags.name || 'Urban Hub', hi: el.tags.name || 'नोड', kn: el.tags.name || 'ನೋಡ್', es: el.tags.name || 'Nodo' },
        category: { en: (el.tags.amenity || 'POI').toUpperCase(), hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Lugar' },
        coords: [el.lon, el.lat],
        description: { en: `Active sector utility node. Category: ${el.tags.amenity || 'Public'}.`, hi: 'सक्रिय नोड।', kn: 'ಸಕ್ರಿಯ ನೋಡ್.', es: 'Nodo activo.' },
        image: el.tags.amenity === 'cafe' ? '☕' : el.tags.amenity === 'hotel' ? '🏨' : el.tags.amenity === 'park' ? '🌳' : '📍',
        rating: 4.2 + (Math.random() * 0.7),
        isOpen: true,
        hours: el.tags.opening_hours || '08:00 - 22:00',
        phone: el.tags.phone || '+91 80 4400 1100',
        reviews: []
      }));
      setNearbyPOIs(results);
    } catch (err) { console.warn("Discovery telemetry failed."); }
  }, []);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;
    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current, baseLayerRef.current, trafficLayerRef.current, weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 }),
        new VectorLayer({ source: discoverySource.current, zIndex: 110 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true, smoothExtentConstraint: true }),
      controls: []
    });
    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({ image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) }) }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      const opt = { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 };
      navigator.geolocation.getCurrentPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        fetchNearbyDiscovery(coords[0], coords[1]);
        map.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 2500 });
      }, null, opt);

      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      }, null, opt);
    }

    map.on('moveend', () => {
      const v = map.getView();
      setRotation(v.getRotation());
      const center = v.getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        fetchNearbyDiscovery(lonLat[0], lonLat[1]);
      }
    });

    map.on('click', async (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) {
        const data = feature.get('poiData');
        const weather = await fetchWeather(data.coords[0], data.coords[1]);
        setSelectedPlace({ ...data, weather });
      } else {
        setSelectedPlace(null);
        setVayuIntel(null);
        routeSource.current.clear();
        setRoutes([]);
      }
    });
  }, [fetchNearbyDiscovery]);

  useEffect(() => {
    if (!mapInstance.current) return;
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);

    let url = theme === MapTheme.DARK ? MAP_SOURCES.DARK_CANVAS : MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;

    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setVisible(isNight);
  }, [activeLayers, theme]);

  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    setVayuIntel(null);
    setGroundingLinks([]);
    discoverySource.current.clear();

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Disha Spatial Intelligence: Analyze "${query}" near ${mapViewCenter[1]}, ${mapViewCenter[0]}. Summarize utility value and current urban status.`,
          config: { tools: [{googleSearch: {}}] }
        });
        const intel = response.text || 'Telemetry analyzed.';
        setVayuIntel(intel);

        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            setGroundingLinks(response.candidates[0].groundingMetadata.groundingChunks.filter((c: any) => c.web).map((c: any) => ({ title: c.web.title, uri: c.web.uri })));
        }

        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();
        if (geoData?.[0]) {
            const coords: [number, number] = [parseFloat(geoData[0].lon), parseFloat(geoData[0].lat)];
            const weather = await fetchWeather(coords[0], coords[1]);
            const discoveryDest: Destination = {
              id: `disha-${Date.now()}`,
              name: { en: geoData[0].display_name.split(',')[0], hi: '', kn: '', es: '' },
              category: { en: 'HUB', hi: '', kn: '', es: '' },
              coords: coords,
              description: { en: intel, hi: '', kn: '', es: '' },
              image: '🌌',
              rating: 5.0,
              isOpen: true,
              weather,
            };
            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1500 });
        }
    } catch (err) { console.error("Neural uplink failed."); }
    finally { setIsSearching(false); }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const coords = route.geometry.coordinates.map((c: any) => fromLonLat(c));

        // Advanced Segment-Based Traffic Coloring
        const total = coords.length;
        const segments = 3;
        const size = Math.floor(total / segments);

        for (let i = 0; i < segments; i++) {
          const start = i * size;
          const end = (i === segments - 1) ? total : (i + 1) * size;
          const segmentCoords = coords.slice(start, end);
          if (segmentCoords.length < 2) continue;

          const feature = new Feature(new LineString(segmentCoords));
          // Mock traffic levels: Blue (Clear), Orange (Busy), Red (Heavy)
          const colors = ['#3b82f6', '#f59e0b', '#ef4444'];
          feature.setStyle(new Style({ stroke: new Stroke({ color: colors[i % 3], width: 8, lineCap: 'round' }) }));
          routeSource.current.addFeature(feature);
        }

        setRoutes([{
          id: 'rt1', distance: `${(route.distance / 1000).toFixed(1)} km`, duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);
        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [100, 100, 100, 100], duration: 1500 });
      }
    } catch (e) { console.error("Pathing engine error."); }
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-700 ${theme === MapTheme.LIGHT ? 'light-mode' : ''}`}>
      <div ref={mapRef} className="map-container" />

      <AnimatePresence>
        {showSplash && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[5000] bg-slate-950 flex flex-col items-center justify-center">
             <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="text-center space-y-4">
                <h1 className="text-7xl lg:text-9xl font-black text-white tracking-tighter">Disha</h1>
                <p className="text-blue-500 font-black uppercase text-xs lg:text-xl tracking-[0.8em] mono">find your way.</p>
             </motion.div>
             <div className="absolute bottom-12 text-white/20 font-black uppercase text-[10px] tracking-widest mono">
                Rudratech Inc. Spatial Suite
             </div>
          </motion.div>
        )}
      </AnimatePresence>

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(prev => prev === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onAISearch={handleAISearch}
      />

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace}
        nearbyDiscovery={nearbyPOIs} vayuIntel={vayuIntel} groundingLinks={groundingLinks}
        onClosePlace={() => { setSelectedPlace(null); setVayuIntel(null); routeSource.current.clear(); setRoutes([]); }}
        onDestinationSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => { setIs3D(!is3D); mapInstance.current?.getView().animate({ rotation: is3D ? 0 : Math.PI/4, duration: 1000 }); }}
        onMeasureToggle={() => setIsMeasuring(!isMeasuring)} 
        is3D={is3D} isMeasuring={isMeasuring} rotation={rotation}
      />
    </div>
  );
};
export default App;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Destination, MapTheme, RouteInfo, Language } from '../types';
import { TRANSLATIONS } from '../constants';

interface BottomPanelProps {
  theme: MapTheme;
  language: Language;
  onDestinationSelect: (d: Destination) => void;
  routeInfo: RouteInfo | null;
  userLocation: [number, number] | null;
  selectedPlace: Destination | null;
  onClosePlace: () => void;
  nearbyDiscovery: Destination[];
  vayuIntel: string | null;
  groundingLinks: {title: string, uri: string}[];
  onClearRoute: () => void;
}

export const BottomPanel: React.FC<BottomPanelProps> = ({ 
  theme, language, onDestinationSelect, routeInfo, selectedPlace, onClosePlace, nearbyDiscovery, vayuIntel, groundingLinks
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  useEffect(() => {
    if (routeInfo || selectedPlace || vayuIntel) {
      setIsExpanded(true);
      setIsSyncing(true);
      const timer = setTimeout(() => setIsSyncing(false), 800);
      return () => clearTimeout(timer);
    } else {
      setIsExpanded(false);
    }
  }, [routeInfo, selectedPlace, vayuIntel]);

  const cleanIntel = (text: string | null) => {
    if (!text) return '';
    return text.replace(/[#*_\\]/g, '').replace(/\s+/g, ' ').trim();
  };

  return (
    <motion.div 
      animate={{ height: isExpanded ? (window.innerWidth < 1024 ? '85vh' : '70vh') : '96px' }}
      transition={{ type: 'spring', damping: 30, stiffness: 250 }}
      className={`fixed bottom-0 left-0 right-0 z-[1400] rounded-t-[40px] lg:rounded-t-[80px] shadow-3xl flex flex-col transition-all duration-700 overflow-hidden ${theme === MapTheme.DARK ? 'glass bg-slate-950/98' : 'glass-light bg-white/98 border-white/90'}`}
    >
      <div className="h-14 lg:h-18 flex items-center justify-center cursor-pointer group shrink-0" onClick={() => setIsExpanded(!isExpanded)}>
        <motion.div animate={{ width: isExpanded ? 48 : 120, height: 6 }} className={`rounded-full ${theme === MapTheme.DARK ? 'bg-white/10 group-hover:bg-blue-500' : 'bg-slate-300 group-hover:bg-blue-600'} transition-all`} />
      </div>

      <AnimatePresence mode="wait">
        {isExpanded ? (
          <motion.div key={selectedPlace ? selectedPlace.id : (routeInfo ? 'rt' : 'ds')} 
            initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }}
            className="flex-1 overflow-hidden flex flex-col px-6 lg:px-24 pb-4"
          >
            {isSyncing ? (
              <div className="flex-1 flex flex-col items-center justify-center gap-6">
                <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
                <p className="text-[10px] font-black uppercase tracking-[0.8em] text-blue-500 mono animate-pulse">Syncing Telemetry...</p>
              </div>
            ) : selectedPlace ? (
              <div className="overflow-y-auto no-scrollbar space-y-8 h-full py-4 pr-1">
                <div className="flex flex-col lg:flex-row justify-between items-start gap-6 relative">
                  <div className="space-y-4 max-w-5xl w-full">
                    <div className="flex items-center gap-3">
                      <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${theme === MapTheme.DARK ? 'bg-blue-600/20 text-blue-400' : 'bg-blue-50 text-blue-700'}`}>
                        {selectedPlace.category?.[language] || 'LOCATION'}
                      </div>
                      <span className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-emerald-500">
                        <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                        Operational
                      </span>
                    </div>
                    <h2 className={`text-3xl lg:text-7xl font-black tracking-tighter leading-none ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{selectedPlace.name?.[language] || 'Urban Node'}</h2>
                    <div className="flex flex-wrap items-center gap-8">
                        <div className="flex items-center gap-3">
                           <span className="text-amber-500 text-2xl lg:text-4xl">★</span>
                           <span className={`text-2xl lg:text-4xl font-black ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{selectedPlace.rating?.toFixed(1) || '4.5'}</span>
                        </div>
                        {selectedPlace.weather && (
                          <div className={`flex items-center gap-4 px-5 py-2 rounded-[20px] border ${theme === MapTheme.DARK ? 'bg-emerald-500/5 border-emerald-500/20 text-emerald-400' : 'bg-emerald-50 text-emerald-700 border-emerald-100'}`}>
                             <span className="text-2xl">{selectedPlace.weather.icon}</span>
                             <span className="font-black text-lg">{selectedPlace.weather.temp}°C</span>
                          </div>
                        )}
                    </div>
                  </div>
                  <button onClick={onClosePlace} className={`shrink-0 w-12 h-12 lg:w-20 lg:h-20 rounded-2xl lg:rounded-[32px] flex items-center justify-center shadow-lg transition-all ${theme === MapTheme.DARK ? 'glass hover:bg-rose-500/30' : 'glass-light hover:bg-rose-100'}`}>✕</button>
                </div>

                <div className="flex gap-4">
                  <button onClick={() => onDestinationSelect(selectedPlace)} className="flex-1 py-5 bg-blue-600 text-white font-black text-xs lg:text-lg uppercase tracking-[0.4em] rounded-[24px] lg:rounded-[40px] shadow-xl hover:scale-[1.02] active:scale-95 transition-all">Engage Path</button>
                  <button className={`flex-1 py-5 border font-black text-xs lg:text-lg uppercase tracking-[0.4em] rounded-[24px] lg:rounded-[40px] transition-all ${theme === MapTheme.DARK ? 'border-white/10 glass' : 'border-slate-200 glass-light'}`}>Archive</button>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-10 py-8 border-t border-white/5">
                   <div className="space-y-8">
                      <div className="space-y-4">
                        <h4 className="text-[10px] font-black uppercase tracking-[0.4em] text-blue-500 mono">Disha Intel Summary</h4>
                        <p className={`text-lg lg:text-2xl font-medium leading-relaxed ${theme === MapTheme.DARK ? 'text-slate-300' : 'text-slate-700'}`}>
                          {cleanIntel(vayuIntel || selectedPlace.description?.[language] || 'Analyzing spatial density... Syncing planetary telemetry.')}
                        </p>
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                         <div className={`p-6 rounded-[32px] border ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5' : 'bg-slate-50 border-slate-100'}`}>
                            <h5 className="text-[9px] font-black uppercase tracking-widest opacity-40 mb-2">Availability</h5>
                            <p className="font-black truncate">{selectedPlace.hours || '09:00 - 22:30'}</p>
                         </div>
                         <div className={`p-6 rounded-[32px] border ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5' : 'bg-slate-50 border-slate-100'}`}>
                            <h5 className="text-[9px] font-black uppercase tracking-widest opacity-40 mb-2">Secure Link</h5>
                            <p className="font-black truncate">{selectedPlace.phone || 'N/A'}</p>
                         </div>
                      </div>
                   </div>
                </div>
                <FooterBranding theme={theme} />
              </div>
            ) : routeInfo ? (
              <div className="flex flex-col h-full justify-between pb-2">
                 <div className={`flex flex-col lg:flex-row items-center justify-between p-10 lg:p-20 rounded-[40px] lg:rounded-[80px] border ${theme === MapTheme.DARK ? 'bg-blue-600/5 border-blue-600/20' : 'bg-blue-50 border-blue-100 shadow-2xl'}`}>
                    <div className="text-center lg:text-left space-y-4 mb-8 lg:mb-0">
                       <p className="text-[60px] lg:text-[140px] font-black text-blue-600 tracking-tighter leading-none">{routeInfo.duration}</p>
                       <div className="flex items-center gap-4 justify-center lg:justify-start">
                          <div className="w-4 h-4 bg-emerald-500 rounded-full animate-ping" />
                          <p className="font-black text-2xl lg:text-4xl uppercase tracking-[0.3em] mono">{routeInfo.distance}</p>
                       </div>
                    </div>
                    <button className="w-full lg:w-auto px-16 py-8 bg-blue-600 rounded-[32px] font-black text-2xl lg:text-4xl uppercase tracking-[0.4em] shadow-3xl text-white">Engage</button>
                 </div>
                 <FooterBranding theme={theme} />
              </div>
            ) : (
              <div className="space-y-8 h-full flex flex-col pt-4">
                 <div className="flex justify-between items-end">
                    <div>
                      <h3 className={`text-4xl lg:text-7xl font-black tracking-tighter uppercase ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Discovery</h3>
                      <p className="text-blue-500 text-[10px] font-black uppercase tracking-[0.4em] mono mt-1">Neural Mesh Active</p>
                    </div>
                 </div>
                 <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 overflow-y-auto no-scrollbar pb-8">
                    {nearbyDiscovery.map((poi, idx) => (
                      <motion.div key={poi.id} initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: idx * 0.05 }}
                        onClick={() => onDestinationSelect(poi)}
                        className={`p-8 glass rounded-[40px] border-white/5 hover:border-blue-600/60 transition-all group active:scale-95`}
                      >
                         <div className="text-5xl lg:text-8xl mb-6 group-hover:scale-110 transition-transform">{poi.image}</div>
                         <h4 className={`font-black text-xl lg:text-2xl tracking-tight mb-2 truncate leading-tight ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{poi.name?.en || 'Urban Hub'}</h4>
                         <div className="flex justify-between items-center text-[10px] font-black uppercase opacity-40 mono">
                            <span>{poi.category?.en}</span>
                            <span className="text-amber-500 opacity-100">★ {poi.rating?.toFixed(1)}</span>
                         </div>
                      </motion.div>
                    ))}
                 </div>
                 <FooterBranding theme={theme} />
              </div>
            )}
          </motion.div>
        ) : (
          <div className="h-full flex flex-col items-center justify-center gap-2">
             <div className="flex items-center gap-4">
               <div className="w-3 h-3 bg-blue-500 animate-ping rounded-full" />
               <p className="text-[10px] font-black uppercase tracking-[0.8em] opacity-40 text-blue-500 mono">Disha Secure</p>
             </div>
             <FooterBranding theme={theme} isSmall />
          </div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

const FooterBranding: React.FC<{ theme: MapTheme, isSmall?: boolean }> = ({ theme, isSmall }) => (
  <div className={`w-full flex flex-col items-center justify-center gap-1 opacity-20 mt-2 ${isSmall ? 'scale-75' : ''}`}>
    <div className={`font-black uppercase tracking-[0.6em] text-[9px] ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-950'}`}>Designed in India</div>
    <div className={`font-black uppercase tracking-[0.2em] text-[7px] ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-950'}`}>© 2024 Rudratech Inc.</div>
  </div>
);

