  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.SATELLITE]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [nearbyPOIs, setNearbyPOIs] = useState<Destination[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [vayuIntel, setVayuIntel] = useState<string | null>(null);
  const [groundingLinks, setGroundingLinks] = useState<{title: string, uri: string}[]>([]);
  const [showSplash, setShowSplash] = useState(true);
  const [is3D, setIs3D] = useState(false);
  const [isMeasuring, setIsMeasuring] = useState(false);
  const [rotation, setRotation] = useState(0);

  useEffect(() => {
    const timer = setTimeout(() => setShowSplash(false), 2500);
    const saved = localStorage.getItem('_disha_vault');
    if (saved) {
      try {
        const prefs = JSON.parse(secureVault.decrypt(saved));
        if (prefs.theme) setTheme(prefs.theme);
        if (prefs.lang) setLanguage(prefs.lang);
      } catch (e) { console.warn("Vault reset."); }
    }
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    localStorage.setItem('_disha_vault', secureVault.encrypt(JSON.stringify({ theme, lang: language })));
    document.body.className = theme === MapTheme.LIGHT ? 'light-mode' : '';
  }, [theme, language]);

  const fetchWeather = async (lon: number, lat: number): Promise<WeatherData | undefined> => {
    try {
      const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true`);
      if (!res.ok) return undefined;
      const data = await res.json();
      return {
        temp: Math.round(data.current_weather.temperature),
        condition: data.current_weather.temperature > 15 ? 'Clear' : 'Overcast',
        windSpeed: data.current_weather.windspeed,
        humidity: 62,
        icon: data.current_weather.temperature > 22 ? '☀️' : '⛅'
      };
    } catch (e) { return undefined; }
  };

  const fetchNearbyDiscovery = useCallback(async (lon: number, lat: number) => {
    try {
      const query = `[out:json][timeout:25];(node["amenity"~"cafe|restaurant|park|charging_station|hotel"](around:3500,${lat},${lon}););out 15;`;
      const res = await fetch(`https://overpass-api.de/api/interpreter?data=${encodeURIComponent(query)}`);
      if (!res.ok) return;
      const data = await res.json();
      const results: Destination[] = (data.elements || []).map((el: any) => ({
        id: `osm-${el.id}`,
        name: { en: el.tags.name || 'Urban Node', hi: el.tags.name || 'नोड', kn: el.tags.name || 'ನೋಡ್', es: el.tags.name || 'Nodo' },
        category: { en: (el.tags.amenity || 'POINT').toUpperCase(), hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Lugar' },
        coords: [el.lon, el.lat],
        description: { en: `Verified sector utility node. Status: Active.`, hi: 'सक्रिय नोड।', kn: 'ಸಕ್ರಿಯ ನೋಡ್.', es: 'Nodo activo.' },
        image: el.tags.amenity === 'cafe' ? '☕' : el.tags.amenity === 'hotel' ? '🏨' : el.tags.amenity === 'park' ? '🌳' : '📍',
        rating: 4.4 + (Math.random() * 0.5),
        isOpen: true,
        hours: el.tags.opening_hours || '08:00 - 22:00',
        phone: el.tags.phone || '+91 80 4400 1122',
        reviews: []
      }));
      setNearbyPOIs(results);
    } catch (err) {}
  }, []);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;
    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current, baseLayerRef.current, trafficLayerRef.current, weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true, smoothExtentConstraint: true }),
      controls: []
    });
    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({ image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) }) }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      const opt = { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 };
      navigator.geolocation.getCurrentPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        fetchNearbyDiscovery(coords[0], coords[1]);
        map.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 2500 });
      }, null, opt);

      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      }, null, opt);
    }

    map.on('moveend', () => {
      const view = map.getView();
      setRotation(view.getRotation());
      const center = view.getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        fetchNearbyDiscovery(lonLat[0], lonLat[1]);
      }
    });

    map.on('click', async (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) {
        const data = feature.get('poiData');
        const weather = await fetchWeather(data.coords[0], data.coords[1]);
        setSelectedPlace({ ...data, weather });
      } else {
        setSelectedPlace(null);
        setVayuIntel(null);
        routeSource.current.clear();
        setRoutes([]);
      }
    });
  }, [fetchNearbyDiscovery]);

  useEffect(() => {
    if (!mapInstance.current) return;
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);

    let url = theme === MapTheme.DARK ? MAP_SOURCES.DARK_CANVAS : MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;

    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setVisible(isNight);
  }, [activeLayers, theme]);

  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    setVayuIntel(null);
    setGroundingLinks([]);

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Disha Spatial Intel: Analyze "${query}" near ${mapViewCenter[1]}, ${mapViewCenter[0]}. Summarize context. No markdown.`,
          config: { tools: [{googleSearch: {}}] }
        });
        const intel = response.text || 'Analysis synced.';
        setVayuIntel(intel);

        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            setGroundingLinks(response.candidates[0].groundingMetadata.groundingChunks.filter((c: any) => c.web).map((c: any) => ({ title: c.web.title, uri: c.web.uri })));
        }

        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();
        if (geoData?.[0]) {
            const coords: [number, number] = [parseFloat(geoData[0].lon), parseFloat(geoData[0].lat)];
            const weather = await fetchWeather(coords[0], coords[1]);
            const discoveryDest: Destination = {
              id: `disha-${Date.now()}`,
              name: { en: geoData[0].display_name.split(',')[0], hi: '', kn: '', es: '' },
              category: { en: 'HUB', hi: '', kn: '', es: '' },
              coords: coords,
              description: { en: intel, hi: '', kn: '', es: '' },
              image: '📍',
              rating: 5.0,
              isOpen: true,
              weather,
            };
            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1500 });
        }
    } catch (err) { }
    finally { setIsSearching(false); }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const coords = route.geometry.coordinates.map((c: any) => fromLonLat(c));

        // Dynamic Traffic Segmentation Coloring
        const segmentsCount = 4;
        const segmentSize = Math.floor(coords.length / segmentsCount);
        for (let i = 0; i < segmentsCount; i++) {
          const start = i * segmentSize;
          const end = (i === segmentsCount - 1) ? coords.length : (i + 1) * segmentSize;
          const segmentCoords = coords.slice(start, end);
          if (segmentCoords.length < 2) continue;

          const feature = new Feature(new LineString(segmentCoords));
          const color = ['#3b82f6', '#f59e0b', '#ef4444', '#3b82f6'][i % 4];
          feature.setStyle(new Style({ stroke: new Stroke({ color, width: 8, lineCap: 'round' }) }));
          routeSource.current.addFeature(feature);
        }

        setRoutes([{
          id: 'rt1', distance: `${(route.distance / 1000).toFixed(1)} km`, duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);
        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [100, 100, 100, 100], duration: 1500 });
      }
    } catch (e) {}
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-700 ${theme === MapTheme.LIGHT ? 'light-mode' : ''}`}>
      <div ref={mapRef} className="map-container" />

      <AnimatePresence>
        {showSplash && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[5000] bg-slate-950 flex flex-col items-center justify-center">
             <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="text-center space-y-4">
                <h1 className="text-7xl lg:text-9xl font-black text-white tracking-tighter">Disha</h1>
                <p className="text-blue-500 font-black uppercase text-xs lg:text-xl tracking-[0.8em] mono">find your way.</p>
             </motion.div>
             <div className="absolute bottom-12 text-white/20 font-black uppercase text-[10px] tracking-widest mono">Rudratech Planetary Suite</div>
          </motion.div>
        )}
      </AnimatePresence>

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(prev => prev === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onAISearch={handleAISearch}
      />

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace}
        nearbyDiscovery={nearbyPOIs} vayuIntel={vayuIntel} groundingLinks={groundingLinks}
        onClosePlace={() => { setSelectedPlace(null); setVayuIntel(null); routeSource.current.clear(); setRoutes([]); }}
        onDestinationSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => { setIs3D(!is3D); mapInstance.current?.getView().animate({ rotation: is3D ? 0 : Math.PI/4, duration: 1000 }); }}
        onMeasureToggle={() => setIsMeasuring(!isMeasuring)} 
        is3D={is3D} isMeasuring={isMeasuring} rotation={rotation}
      />
    </div>
  );
};
export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onAISearch: (query: string) => void;
}

const LogoIcon = () => (
  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className="lg:w-8 lg:h-8">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

const DISCOVERY_PROMPTS = [
  "Analyze urban density...",
  "Search for coffee nodes...",
  "Navigate to Lalbagh...",
  "Check atmospherics...",
  "Locate EV stations...",
  "Explore green belts..."
];

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, mapCenter, onThemeToggle, onOpenLayers, onSuggestionSelect, onAISearch
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const [placeholderText, setPlaceholderText] = useState('');
  const [promptIndex, setPromptIndex] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);
  const [typingSpeed, setTypingSpeed] = useState(100);

  useEffect(() => {
    const handleTyping = () => {
      const currentPrompt = DISCOVERY_PROMPTS[promptIndex];
      const isFinishing = !isDeleting && placeholderText === currentPrompt;
      const isStartingDeleting = isDeleting && placeholderText === '';

      if (isFinishing) {
        setTypingSpeed(2000);
        setIsDeleting(true);
      } else if (isStartingDeleting) {
        setTypingSpeed(100);
        setIsDeleting(false);
        setPromptIndex((prev) => (prev + 1) % DISCOVERY_PROMPTS.length);
      } else {
        setTypingSpeed(isDeleting ? 50 : 100);
        setPlaceholderText(current => 
          isDeleting 
            ? current.slice(0, -1) 
            : currentPrompt.slice(0, current.length + 1)
        );
      }
    };
    const timer = setTimeout(handleTyping, typingSpeed);
    return () => clearTimeout(timer);
  }, [placeholderText, isDeleting, promptIndex, typingSpeed]);

  useEffect(() => {
    if (!query.trim() || query.length < 2) {
      setSuggestions([]);
      return;
    }
    const timer = setTimeout(async () => {
      const q = query.toLowerCase().trim();
      const results = POPULAR_DESTINATIONS.map(dest => {
        const name = dest.name[language].toLowerCase();
        const distance = getDistance(dest.coords, mapCenter) / 1000;
        let score = name.startsWith(q) ? 100 : (name.includes(q) ? 50 : 0);
        return { ...dest, score, distance };
      })
      .filter(item => item.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 5);
      setSuggestions(results);
    }, 150);
    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) setIsFocused(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <motion.header 
      initial={{ y: -100 }} animate={{ y: 0 }}
      className="fixed top-0 left-0 right-0 z-[2000] p-3 lg:p-6 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-center gap-2 lg:gap-5 pointer-events-auto">
        <div className={`flex items-center gap-2 lg:gap-5 px-3 lg:px-8 h-[50px] lg:h-[72px] rounded-[16px] lg:rounded-[36px] transition-all shadow-xl ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900 border-white/50'}`}>
          <div className="w-8 h-8 lg:w-11 lg:h-11 bg-blue-600 rounded-[10px] lg:rounded-[20px] flex items-center justify-center text-white shrink-0">
            <LogoIcon />
          </div>
          <span className="font-black text-sm lg:text-2xl tracking-tighter hidden sm:block">Disha</span>
        </div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-4 lg:px-10 h-[50px] lg:h-[72px] rounded-[16px] lg:rounded-[36px] transition-all shadow-xl ${
            theme === MapTheme.DARK ? `glass ${isFocused ? 'ring-2 ring-blue-500' : ''}` : `glass-light border-white/50 ${isFocused ? 'ring-2 ring-blue-500' : ''}`
          }`}>
            <div className="relative flex-1 h-full flex items-center">
              <input 
                type="text" value={query} onFocus={() => setIsFocused(true)} 
                onChange={(e) => setQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && onAISearch(query)}
                className="bg-transparent border-none outline-none w-full text-sm lg:text-xl font-black tracking-tight z-10"
                style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
              />
              {!query && (
                <div className="absolute inset-0 flex items-center pointer-events-none">
                  <span className={`text-xs lg:text-xl font-black tracking-tight opacity-30 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
                    Vayu: {placeholderText}
                    <span className="animate-pulse">|</span>
                  </span>
                </div>
              )}
            </div>
            <button onClick={() => onAISearch(query)} className="ml-2 text-slate-500 hover:text-blue-500">
               <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
            </button>
          </div>

          <AnimatePresence>
            {isFocused && suggestions.length > 0 && (
              <motion.div initial={{ opacity: 0, y: 15 }} animate={{ opacity: 1, y: 12 }} exit={{ opacity: 0, y: 15 }}
                className={`absolute top-full left-0 right-0 rounded-[24px] lg:rounded-[48px] shadow-3xl overflow-hidden border ${theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'}`}
              >
                <div className="max-h-[40vh] overflow-y-auto py-2 lg:py-4 no-scrollbar">
                  {suggestions.map((dest, idx) => (
                    <div key={idx} onClick={() => { onSuggestionSelect(dest); setIsFocused(false); setQuery(dest.name[language]); }}
                      className="px-6 lg:px-10 py-3 lg:py-5 flex items-center gap-4 lg:gap-8 cursor-pointer hover:bg-blue-600/10 transition-colors group"
                    >
                      <div className="text-xl lg:text-4xl w-10 h-10 lg:w-14 lg:h-14 rounded-xl bg-slate-500/5 flex items-center justify-center">{dest.image}</div>
                      <div className="flex-1">
                        <div className="font-black text-xs lg:text-xl truncate leading-tight">{dest.name[language]}</div>
                        <div className="text-[8px] lg:text-[12px] font-bold opacity-30 uppercase tracking-widest">{dest.distance.toFixed(1)} km away</div>
                      </div>
                    </div>
                  ))}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex gap-1.5 lg:gap-4 shrink-0">
          <button onClick={onOpenLayers} className={`w-[50px] lg:w-[72px] h-[50px] lg:h-[72px] rounded-[14px] lg:rounded-[32px] flex items-center justify-center shadow-xl transition-all ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline></svg>
          </button>
          <button onClick={onThemeToggle} className={`w-[50px] lg:w-[72px] h-[50px] lg:h-[72px] rounded-[14px] lg:rounded-[32px] flex items-center justify-center shadow-xl transition-all ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600'}`}>
            {theme === MapTheme.DARK ? '☀️' : '🌙'}
          </button>
        </div>
      </div>
    </motion.header>
  );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Destination, MapTheme, RouteInfo, Language } from '../types';

interface BottomPanelProps {
  theme: MapTheme;
  language: Language;
  onDestinationSelect: (d: Destination) => void;
  routeInfo: RouteInfo | null;
  userLocation: [number, number] | null;
  selectedPlace: Destination | null;
  onClosePlace: () => void;
  nearbyDiscovery: Destination[];
  vayuIntel: string | null;
  groundingLinks: {title: string, uri: string}[];
  onClearRoute: () => void;
}

export const BottomPanel: React.FC<BottomPanelProps> = ({ 
  theme, language, onDestinationSelect, routeInfo, selectedPlace, onClosePlace, nearbyDiscovery, vayuIntel
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  useEffect(() => {
    if (routeInfo || selectedPlace || vayuIntel) {
      setIsExpanded(true);
      setIsSyncing(true);
      const timer = setTimeout(() => setIsSyncing(false), 800);
      return () => clearTimeout(timer);
    } else {
      setIsExpanded(false);
    }
  }, [routeInfo, selectedPlace, vayuIntel]);

  const cleanIntel = (text: string | null) => text ? text.replace(/[#*_\\]/g, '').replace(/\s+/g, ' ').trim() : '';

  return (
    <motion.div 
      animate={{ height: isExpanded ? (window.innerWidth < 1024 ? '85vh' : '65vh') : '84px' }}
      transition={{ type: 'spring', damping: 30, stiffness: 250 }}
      className={`fixed bottom-0 left-0 right-0 z-[1400] rounded-t-[32px] lg:rounded-t-[80px] shadow-3xl flex flex-col transition-all duration-700 overflow-hidden ${theme === MapTheme.DARK ? 'glass bg-slate-950/98' : 'glass-light bg-white/98 border-white/90'}`}
    >
      <div className="h-12 lg:h-18 flex items-center justify-center cursor-pointer group shrink-0" onClick={() => setIsExpanded(!isExpanded)}>
        <motion.div animate={{ width: isExpanded ? 40 : 100, height: 6 }} className={`rounded-full ${theme === MapTheme.DARK ? 'bg-white/10 group-hover:bg-blue-500' : 'bg-slate-300 group-hover:bg-blue-600'} transition-all`} />
      </div>

      <AnimatePresence mode="wait">
        {isExpanded ? (
          <motion.div key={selectedPlace ? selectedPlace.id : (routeInfo ? 'rt' : 'ds')} 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="flex-1 overflow-hidden flex flex-col px-4 lg:px-24 pb-4"
          >
            {isSyncing ? (
              <div className="flex-1 flex flex-col items-center justify-center gap-6">
                <div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
                <p className="text-[10px] font-black uppercase tracking-[0.4em] text-blue-500 mono">Syncing Telemetry...</p>
              </div>
            ) : selectedPlace ? (
              <div className="overflow-y-auto no-scrollbar space-y-6 lg:space-y-8 h-full py-2">
                <div className="flex justify-between items-start gap-4">
                  <div className="space-y-2 lg:space-y-4 max-w-5xl">
                    <div className="flex items-center gap-3">
                      <div className={`px-2 py-0.5 rounded-full text-[9px] font-black uppercase tracking-widest ${theme === MapTheme.DARK ? 'bg-blue-600/20 text-blue-400' : 'bg-blue-50 text-blue-700'}`}>
                        {selectedPlace.category?.[language] || 'LOCATION'}
                      </div>
                    </div>
                    <h2 className={`text-2xl lg:text-7xl font-black tracking-tighter leading-none ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{selectedPlace.name?.[language]}</h2>
                    <div className="flex items-center gap-6">
                       <span className="text-amber-500 font-black text-lg lg:text-4xl">★ {selectedPlace.rating?.toFixed(1) || '4.5'}</span>
                       {selectedPlace.weather && (
                         <div className="flex items-center gap-2 font-black text-emerald-500 lg:text-2xl">
                           <span>{selectedPlace.weather.icon}</span>
                           <span>{selectedPlace.weather.temp}°C</span>
                         </div>
                       )}
                    </div>
                  </div>
                  <button onClick={onClosePlace} className={`shrink-0 w-10 h-10 lg:w-20 lg:h-20 rounded-xl lg:rounded-[32px] flex items-center justify-center transition-all ${theme === MapTheme.DARK ? 'glass hover:bg-rose-500/20' : 'glass-light hover:bg-rose-50'}`}>✕</button>
                </div>

                <div className="flex gap-3">
                  <button onClick={() => onDestinationSelect(selectedPlace)} className="flex-1 py-4 lg:py-6 bg-blue-600 text-white font-black text-xs lg:text-xl uppercase tracking-[0.4em] rounded-[16px] lg:rounded-[40px] shadow-xl active:scale-95 transition-all">Engage Path</button>
                  <button className={`flex-1 py-4 lg:py-6 border font-black text-xs lg:text-xl uppercase tracking-[0.4em] rounded-[16px] lg:rounded-[40px] ${theme === MapTheme.DARK ? 'border-white/10 glass' : 'border-slate-200 glass-light'}`}>Archive</button>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 lg:gap-10 py-6 border-t border-white/5">
                   <div className="space-y-4">
                      <h4 className="text-[10px] font-black uppercase tracking-[0.4em] text-blue-500 mono">Disha Spatial Summary</h4>
                      <p className={`text-base lg:text-2xl font-medium leading-relaxed ${theme === MapTheme.DARK ? 'text-slate-300' : 'text-slate-700'}`}>
                        {cleanIntel(vayuIntel || selectedPlace.description?.[language] || 'Analyzing spatial density... Syncing telemetry.')}
                      </p>
                   </div>
                   <div className="grid grid-cols-2 gap-3">
                      <div className={`p-4 rounded-[20px] lg:rounded-[32px] border ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5' : 'bg-slate-50 border-slate-100'}`}>
                         <h5 className="text-[9px] font-black opacity-30 uppercase mb-1">Hours</h5>
                         <p className="font-black text-xs lg:text-base truncate">{selectedPlace.hours || '09:00 - 22:00'}</p>
                      </div>
                      <div className={`p-4 rounded-[20px] lg:rounded-[32px] border ${theme === MapTheme.DARK ? 'bg-white/5 border-white/5' : 'bg-slate-50 border-slate-100'}`}>
                         <h5 className="text-[9px] font-black opacity-30 uppercase mb-1">Status</h5>
                         <p className="font-black text-xs lg:text-base text-emerald-500">Operational</p>
                      </div>
                   </div>
                </div>
                <FooterBranding theme={theme} />
              </div>
            ) : routeInfo ? (
              <div className="flex flex-col h-full justify-between pb-2 pt-2">
                 <div className={`flex flex-col lg:flex-row items-center justify-between p-6 lg:p-20 rounded-[32px] lg:rounded-[80px] border ${theme === MapTheme.DARK ? 'bg-blue-600/5 border-blue-600/20' : 'bg-blue-50 border-blue-100 shadow-2xl'}`}>
                    <div className="text-center lg:text-left space-y-2 mb-6 lg:mb-0">
                       <p className="text-[40px] lg:text-[140px] font-black text-blue-600 tracking-tighter leading-none">{routeInfo.duration}</p>
                       <p className="font-black text-lg lg:text-4xl uppercase tracking-[0.3em] mono opacity-40">{routeInfo.distance}</p>
                    </div>
                    <button className="w-full lg:w-auto px-12 py-5 lg:px-24 lg:py-10 bg-blue-600 rounded-[20px] lg:rounded-[40px] font-black text-sm lg:text-4xl uppercase tracking-[0.4em] shadow-3xl text-white active:scale-95 transition-transform">Engage</button>
                 </div>
                 <FooterBranding theme={theme} />
              </div>
            ) : (
              <div className="space-y-6 lg:space-y-8 h-full flex flex-col pt-2">
                 <div>
                    <h3 className={`text-2xl lg:text-7xl font-black tracking-tighter uppercase ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>Discovery</h3>
                    <p className="text-blue-500 text-[10px] font-black uppercase tracking-[0.4em] mono mt-1">Neural Mesh Active</p>
                 </div>
                 <div className="grid grid-cols-2 sm:grid-cols-2 lg:grid-cols-3 gap-3 lg:gap-6 overflow-y-auto no-scrollbar pb-8">
                    {nearbyDiscovery.map((poi, idx) => (
                      <div key={poi.id} onClick={() => onDestinationSelect(poi)}
                        className={`p-4 lg:p-8 glass rounded-[24px] lg:rounded-[40px] border-white/5 hover:border-blue-600/60 transition-all group active:scale-95`}
                      >
                         <div className="text-3xl lg:text-8xl mb-3 lg:mb-6">{poi.image}</div>
                         <h4 className={`font-black text-xs lg:text-2xl tracking-tight truncate ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>{poi.name?.en}</h4>
                         <div className="flex justify-between items-center text-[8px] lg:text-[10px] font-black uppercase opacity-40 mono mt-1">
                            <span>{poi.category?.en}</span>
                            <span className="text-amber-500">★ {poi.rating?.toFixed(1)}</span>
                         </div>
                      </div>
                    ))}
                 </div>
                 <FooterBranding theme={theme} />
              </div>
            )}
          </motion.div>
        ) : (
          <div className="h-full flex flex-col items-center justify-center gap-2">
             <div className="flex items-center gap-3">
               <div className="w-2 h-2 bg-blue-500 animate-ping rounded-full" />
               <p className="text-[10px] font-black uppercase tracking-[0.8em] opacity-40 text-blue-500 mono">Disha Operational</p>
             </div>
          </div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

const FooterBranding: React.FC<{ theme: MapTheme, isSmall?: boolean }> = ({ theme }) => (
  <div className="w-full flex flex-col items-center justify-center gap-1 opacity-20 mt-4 pb-4">
    <div className={`font-black uppercase tracking-[0.6em] text-[8px] ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-950'}`}>Designed in India</div>
    <div className={`font-black uppercase tracking-[0.2em] text-[6px] ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-950'}`}>© 2024 Rudratech Inc.</div>
  </div>
);

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, WeatherData } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

// Puter.js Global Declaration
declare const puter: any;

const secureVault = {
  encrypt: (data: string) => btoa(encodeURIComponent(data)),
  decrypt: (cipher: string) => {
    try { return decodeURIComponent(atob(cipher)); }
    catch(e) { return "{}"; }
  },
};

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const trafficLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false, opacity: 0.7 }));
  const weatherLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false }));
  const planetaryLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: -1, visible: false }));

  const routeSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.SATELLITE]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [nearbyPOIs, setNearbyPOIs] = useState<Destination[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [vayuIntel, setVayuIntel] = useState<string | null>(null);
  const [showSplash, setShowSplash] = useState(true);
  const [is3D, setIs3D] = useState(false);
  const [isMeasuring, setIsMeasuring] = useState(false);
  const [rotation, setRotation] = useState(0);

  useEffect(() => {
    const timer = setTimeout(() => setShowSplash(false), 2500);
    const saved = localStorage.getItem('_disha_v2_vault');
    if (saved) {
      try {
        const prefs = JSON.parse(secureVault.decrypt(saved));
        if (prefs.theme) setTheme(prefs.theme);
        if (prefs.lang) setLanguage(prefs.lang);
      } catch (e) { console.warn("Vault reset."); }
    }
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    localStorage.setItem('_disha_v2_vault', secureVault.encrypt(JSON.stringify({ theme, lang: language })));
    document.body.className = theme === MapTheme.LIGHT ? 'light-mode' : '';
  }, [theme, language]);

  const fetchWeather = async (lon: number, lat: number): Promise<WeatherData | undefined> => {
    try {
      const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true`);
      if (!res.ok) return undefined;
      const data = await res.json();
      return {
        temp: Math.round(data.current_weather.temperature),
        condition: data.current_weather.temperature > 15 ? 'Clear' : 'Overcast',
        windSpeed: data.current_weather.windspeed,
        humidity: 62,
        icon: data.current_weather.temperature > 22 ? '☀️' : '⛅'
      };
    } catch (e) { return undefined; }
  };

  const fetchNearbyDiscovery = useCallback(async (lon: number, lat: number) => {
    try {
      const query = `[out:json][timeout:25];(node["amenity"~"cafe|restaurant|park|charging_station|hotel"](around:3500,${lat},${lon}););out 15;`;
      const res = await fetch(`https://overpass-api.de/api/interpreter?data=${encodeURIComponent(query)}`);
      if (!res.ok) return;
      const data = await res.json();
      const results: Destination[] = (data.elements || []).map((el: any) => ({
        id: `osm-${el.id}`,
        name: { en: el.tags.name || 'Urban Hub', hi: el.tags.name || 'नोड', kn: el.tags.name || 'ನೋಡ್', es: el.tags.name || 'Nodo' },
        category: { en: (el.tags.amenity || 'POINT').toUpperCase(), hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Lugar' },
        coords: [el.lon, el.lat],
        description: { en: `Verified sector utility node. Status: Active.`, hi: 'सक्रिय नोड।', kn: 'ಸಕ್ರಿಯ ನೋಡ್.', es: 'Nodo activo.' },
        image: el.tags.amenity === 'cafe' ? '☕' : el.tags.amenity === 'hotel' ? '🏨' : el.tags.amenity === 'park' ? '🌳' : '📍',
        rating: 4.4 + (Math.random() * 0.5),
        isOpen: true,
        hours: el.tags.opening_hours || '08:00 - 22:00',
        phone: el.tags.phone || '+91 80 4400 1122',
        reviews: []
      }));
      setNearbyPOIs(results);
    } catch (err) {}
  }, []);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;
    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current, baseLayerRef.current, trafficLayerRef.current, weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 })
      ],
      view: new View({ center: fromLonLat(DEFAULT_CENTER), zoom: DEFAULT_ZOOM, constrainResolution: true, smoothExtentConstraint: true }),
      controls: []
    });
    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({ image: new Circle({ radius: 8, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 3 }) }) }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      const opt = { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 };
      navigator.geolocation.getCurrentPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        fetchNearbyDiscovery(coords[0], coords[1]);
        map.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 2500 });
      }, null, opt);

      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ image: new Circle({ radius: 10, fill: new Fill({ color: '#3b82f6' }), stroke: new Stroke({ color: '#fff', width: 4 }) }) }));
        userLocSource.current.addFeature(f);
      }, null, opt);
    }

    map.on('moveend', () => {
      const view = map.getView();
      setRotation(view.getRotation());
      const center = view.getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        fetchNearbyDiscovery(lonLat[0], lonLat[1]);
      }
    });

    map.on('click', async (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) {
        const data = feature.get('poiData');
        const weather = await fetchWeather(data.coords[0], data.coords[1]);
        setSelectedPlace({ ...data, weather });
      } else {
        setSelectedPlace(null);
        setVayuIntel(null);
        routeSource.current.clear();
        setRoutes([]);
      }
    });
  }, [fetchNearbyDiscovery]);

  useEffect(() => {
    if (!mapInstance.current) return;
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);

    let url = theme === MapTheme.DARK ? MAP_SOURCES.DARK_CANVAS : MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;

    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setVisible(isNight);
  }, [activeLayers, theme]);

  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    setVayuIntel(null);

    try {
        // Using Puter AI for advanced spatial intelligence
        const systemPrompt = `You are Disha Spatial Intelligence. Analyze "${query}" near coordinates ${mapViewCenter[1]}, ${mapViewCenter[0]}. Provide a high-density utility summary. Avoid markdown bolding or hashtags. Keep it sleek and professional.`;
        const response = await puter.ai.chat(systemPrompt);
        const intel = response?.toString() || 'Telemetry analysis complete.';
        setVayuIntel(intel);

        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();
        if (geoData?.[0]) {
            const coords: [number, number] = [parseFloat(geoData[0].lon), parseFloat(geoData[0].lat)];
            const weather = await fetchWeather(coords[0], coords[1]);
            const discoveryDest: Destination = {
              id: `disha-${Date.now()}`,
              name: { en: geoData[0].display_name.split(',')[0], hi: '', kn: '', es: '' },
              category: { en: 'HUB', hi: '', kn: '', es: '' },
              coords: coords,
              description: { en: intel, hi: '', kn: '', es: '' },
              image: '📍',
              rating: 5.0,
              isOpen: true,
              weather,
            };
            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1500 });
        }
    } catch (err) {
      console.error("Spatial uplink interrupted:", err);
    } finally {
      setIsSearching(false);
    }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const coords = route.geometry.coordinates.map((c: any) => fromLonLat(c));

        const segmentsCount = 4;
        const segmentSize = Math.floor(coords.length / segmentsCount);
        for (let i = 0; i < segmentsCount; i++) {
          const start = i * segmentSize;
          const end = (i === segmentsCount - 1) ? coords.length : (i + 1) * segmentSize;
          const segmentCoords = coords.slice(start, end);
          if (segmentCoords.length < 2) continue;

          const feature = new Feature(new LineString(segmentCoords));
          const color = ['#3b82f6', '#f59e0b', '#ef4444', '#3b82f6'][i % 4];
          feature.setStyle(new Style({ stroke: new Stroke({ color, width: 8, lineCap: 'round' }) }));
          routeSource.current.addFeature(feature);
        }

        setRoutes([{
          id: 'rt1', distance: `${(route.distance / 1000).toFixed(1)} km`, duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);
        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [100, 100, 100, 100], duration: 1500 });
      }
    } catch (e) {}
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-700 ${theme === MapTheme.LIGHT ? 'light-mode' : ''}`}>
      <div ref={mapRef} className="map-container" />

      <AnimatePresence>
        {showSplash && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[5000] bg-slate-950 flex flex-col items-center justify-center">
             <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="text-center space-y-4">
                <h1 className="text-7xl lg:text-9xl font-black text-white tracking-tighter">Disha</h1>
                <p className="text-blue-500 font-black uppercase text-xs lg:text-xl tracking-[0.8em] mono">find your way.</p>
             </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(prev => prev === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onAISearch={handleAISearch}
      />

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace}
        nearbyDiscovery={nearbyPOIs} vayuIntel={vayuIntel} groundingLinks={[]}
        onClosePlace={() => { setSelectedPlace(null); setVayuIntel(null); routeSource.current.clear(); setRoutes([]); }}
        onDestinationSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => { setIs3D(!is3D); mapInstance.current?.getView().animate({ rotation: is3D ? 0 : Math.PI/4, duration: 1000 }); }}
        onMeasureToggle={() => setIsMeasuring(!isMeasuring)} 
        is3D={is3D} isMeasuring={isMeasuring} rotation={rotation}
      />

      {isSearching && (
        <div className="fixed inset-x-0 top-32 flex justify-center z-[2500] pointer-events-none">
          <div className="px-6 py-2 glass rounded-full flex items-center gap-3 border border-blue-500/30">
            <div className="w-2 h-2 bg-blue-500 rounded-full animate-ping" />
            <span className="text-[10px] font-black uppercase tracking-widest text-blue-500 mono">Syncing Urban Telemetry...</span>
          </div>
        </div>
      )}
    </div>
  );
};
export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onAISearch: (query: string) => void;
}

const LogoIcon = () => (
  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className="lg:w-8 lg:h-8">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

const DISCOVERY_PROMPTS = [
  "Analyze urban density...",
  "Search for coffee nodes...",
  "Navigate to Lalbagh...",
  "Check atmospherics...",
  "Locate EV stations...",
  "Explore green belts..."
];

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, mapCenter, onThemeToggle, onOpenLayers, onSuggestionSelect, onAISearch
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const [placeholderText, setPlaceholderText] = useState('');
  const [promptIndex, setPromptIndex] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);
  const [typingSpeed, setTypingSpeed] = useState(100);

  useEffect(() => {
    const handleTyping = () => {
      const currentPrompt = DISCOVERY_PROMPTS[promptIndex];
      const isFinishing = !isDeleting && placeholderText === currentPrompt;
      const isStartingDeleting = isDeleting && placeholderText === '';

      if (isFinishing) {
        setTypingSpeed(2000);
        setIsDeleting(true);
      } else if (isStartingDeleting) {
        setTypingSpeed(100);
        setIsDeleting(false);
        setPromptIndex((prev) => (prev + 1) % DISCOVERY_PROMPTS.length);
      } else {
        setTypingSpeed(isDeleting ? 50 : 100);
        setPlaceholderText(current => 
          isDeleting 
            ? current.slice(0, -1) 
            : currentPrompt.slice(0, current.length + 1)
        );
      }
    };
    const timer = setTimeout(handleTyping, typingSpeed);
    return () => clearTimeout(timer);
  }, [placeholderText, isDeleting, promptIndex, typingSpeed]);

  useEffect(() => {
    if (!query.trim() || query.length < 2) {
      setSuggestions([]);
      return;
    }
    const timer = setTimeout(async () => {
      const q = query.toLowerCase().trim();
      const results = POPULAR_DESTINATIONS.map(dest => {
        const name = dest.name[language].toLowerCase();
        const distance = getDistance(dest.coords, mapCenter) / 1000;
        let score = name.startsWith(q) ? 100 : (name.includes(q) ? 50 : 0);
        return { ...dest, score, distance };
      })
      .filter(item => item.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 5);
      setSuggestions(results);
    }, 150);
    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) setIsFocused(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <motion.header 
      initial={{ y: -100 }} animate={{ y: 0 }}
      className="fixed top-0 left-0 right-0 z-[2000] p-3 lg:p-6 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-center gap-2 lg:gap-5 pointer-events-auto">
        <div className={`flex items-center gap-2 lg:gap-5 px-3 lg:px-8 h-[50px] lg:h-[72px] rounded-[16px] lg:rounded-[36px] transition-all shadow-xl ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900 border-white/50'}`}>
          <div className="w-8 h-8 lg:w-11 lg:h-11 bg-blue-600 rounded-[10px] lg:rounded-[20px] flex items-center justify-center text-white shrink-0">
            <LogoIcon />
          </div>
          <span className="font-black text-sm lg:text-2xl tracking-tighter hidden sm:block">Disha</span>
        </div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-4 lg:px-10 h-[50px] lg:h-[72px] rounded-[16px] lg:rounded-[36px] transition-all shadow-xl ${
            theme === MapTheme.DARK ? `glass ${isFocused ? 'ring-2 ring-blue-500' : ''}` : `glass-light border-white/50 ${isFocused ? 'ring-2 ring-blue-500' : ''}`
          }`}>
            <div className="relative flex-1 h-full flex items-center">
              <input 
                type="text" value={query} onFocus={() => setIsFocused(true)} 
                onChange={(e) => setQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && onAISearch(query)}
                className="bg-transparent border-none outline-none w-full text-sm lg:text-xl font-black tracking-tight z-10"
                style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
              />
              {!query && (
                <div className="absolute inset-0 flex items-center pointer-events-none">
                  <span className={`text-xs lg:text-xl font-black tracking-tight opacity-30 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
                    Query: {placeholderText}
                    <span className="animate-pulse">|</span>
                  </span>
                </div>
              )}
            </div>
            <button onClick={() => onAISearch(query)} className="ml-2 text-slate-500 hover:text-blue-500">
               <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
            </button>
          </div>

          <AnimatePresence>
            {isFocused && suggestions.length > 0 && (
              <motion.div initial={{ opacity: 0, y: 15 }} animate={{ opacity: 1, y: 12 }} exit={{ opacity: 0, y: 15 }}
                className={`absolute top-full left-0 right-0 rounded-[24px] lg:rounded-[48px] shadow-3xl overflow-hidden border ${theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'}`}
              >
                <div className="max-h-[40vh] overflow-y-auto py-2 lg:py-4 no-scrollbar">
                  {suggestions.map((dest, idx) => (
                    <div key={idx} onClick={() => { onSuggestionSelect(dest); setIsFocused(false); setQuery(dest.name[language]); }}
                      className="px-6 lg:px-10 py-3 lg:py-5 flex items-center gap-4 lg:gap-8 cursor-pointer hover:bg-blue-600/10 transition-colors group"
                    >
                      <div className="text-xl lg:text-4xl w-10 h-10 lg:w-14 lg:h-14 rounded-xl bg-slate-500/5 flex items-center justify-center">{dest.image}</div>
                      <div className="flex-1">
                        <div className="font-black text-xs lg:text-xl truncate leading-tight">{dest.name[language]}</div>
                        <div className="text-[8px] lg:text-[12px] font-bold opacity-30 uppercase tracking-widest">{dest.distance.toFixed(1)} km away</div>
                      </div>
                    </div>
                  ))}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex gap-1.5 lg:gap-4 shrink-0">
          <button onClick={onOpenLayers} className={`w-[50px] lg:w-[72px] h-[50px] lg:h-[72px] rounded-[14px] lg:rounded-[32px] flex items-center justify-center shadow-xl transition-all ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline></svg>
          </button>
          <button onClick={onThemeToggle} className={`w-[50px] lg:w-[72px] h-[50px] lg:h-[72px] rounded-[14px] lg:rounded-[32px] flex items-center justify-center shadow-xl transition-all ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600'}`}>
            {theme === MapTheme.DARK ? '☀️' : '🌙'}
          </button>
        </div>
      </div>
    </motion.header>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import XYZ from 'ol/source/XYZ';
import VectorSource from 'ol/source/Vector';
import { fromLonLat, toLonLat } from 'ol/proj';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import LineString from 'ol/geom/LineString';
import { Style, Circle, Fill, Stroke } from 'ol/style';

import { Header } from './components/Header';
import { BottomPanel } from './components/BottomPanel';
import { LayerPanel } from './components/LayerPanel';
import { FloatingControls } from './components/FloatingControls';
import { MapTheme, MapLayerType, Destination, RouteInfo, Language, WeatherData } from './types';
import { DEFAULT_CENTER, DEFAULT_ZOOM, MAP_SOURCES, POPULAR_DESTINATIONS } from './constants';

// Puter.js Global Declaration
declare const puter: any;

const secureVault = {
  encrypt: (data: string) => btoa(encodeURIComponent(data)),
  decrypt: (cipher: string) => {
    try { return decodeURIComponent(atob(cipher)); }
    catch(e) { return "{}"; }
  },
};

const App: React.FC = () => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<Map | null>(null);

  const baseLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 0 }));
  const trafficLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 1, visible: false, opacity: 0.7 }));
  const weatherLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: 2, visible: false }));
  const planetaryLayerRef = useRef<TileLayer<XYZ>>(new TileLayer({ zIndex: -1, visible: false }));

  const routeSource = useRef<VectorSource>(new VectorSource());
  const userLocSource = useRef<VectorSource>(new VectorSource());
  const poiSource = useRef<VectorSource>(new VectorSource());

  const [theme, setTheme] = useState<MapTheme>(MapTheme.DARK);
  const [language, setLanguage] = useState<Language>('en');
  const [isLayerPanelOpen, setIsLayerPanelOpen] = useState(false);
  const [activeLayers, setActiveLayers] = useState<MapLayerType[]>([MapLayerType.SATELLITE]);
  const [userLiveCoords, setUserLiveCoords] = useState<[number, number] | null>(null);
  const [mapViewCenter, setMapViewCenter] = useState<[number, number]>(DEFAULT_CENTER);
  const [routes, setRoutes] = useState<RouteInfo[]>([]);
  const [selectedPlace, setSelectedPlace] = useState<Destination | null>(null);
  const [nearbyPOIs, setNearbyPOIs] = useState<Destination[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [vayuIntel, setVayuIntel] = useState<string | null>(null);
  const [showSplash, setShowSplash] = useState(true);
  const [is3D, setIs3D] = useState(false);
  const [isMeasuring, setIsMeasuring] = useState(false);
  const [rotation, setRotation] = useState(0);

  // Initialization & Vault Sync
  useEffect(() => {
    const timer = setTimeout(() => setShowSplash(false), 2800);
    const saved = localStorage.getItem('_disha_v3_vault');
    if (saved) {
      try {
        const prefs = JSON.parse(secureVault.decrypt(saved));
        if (prefs.theme) setTheme(prefs.theme);
        if (prefs.lang) setLanguage(prefs.lang);
      } catch (e) { console.warn("Vault reset."); }
    }
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    localStorage.setItem('_disha_v3_vault', secureVault.encrypt(JSON.stringify({ theme, lang: language })));
    document.body.className = theme === MapTheme.LIGHT ? 'light-mode' : '';
  }, [theme, language]);

  const fetchWeather = async (lon: number, lat: number): Promise<WeatherData | undefined> => {
    try {
      const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true`);
      if (!res.ok) return undefined;
      const data = await res.json();
      return {
        temp: Math.round(data.current_weather.temperature),
        condition: data.current_weather.temperature > 15 ? 'Clear' : 'Overcast',
        windSpeed: data.current_weather.windspeed,
        humidity: 62,
        icon: data.current_weather.temperature > 22 ? '☀️' : '⛅'
      };
    } catch (e) { return undefined; }
  };

  const fetchNearbyDiscovery = useCallback(async (lon: number, lat: number) => {
    try {
      const query = `[out:json][timeout:25];(node["amenity"~"cafe|restaurant|park|charging_station|hotel"](around:4000,${lat},${lon}););out 15;`;
      const res = await fetch(`https://overpass-api.de/api/interpreter?data=${encodeURIComponent(query)}`);
      if (!res.ok) return;
      const data = await res.json();
      const results: Destination[] = (data.elements || []).map((el: any) => ({
        id: `osm-${el.id}`,
        name: { en: el.tags.name || 'Urban Hub', hi: el.tags.name || 'नोड', kn: el.tags.name || 'ನೋಡ್', es: el.tags.name || 'Nodo' },
        category: { en: (el.tags.amenity || 'POINT').toUpperCase(), hi: 'स्थान', kn: 'ಸ್ಥಳ', es: 'Lugar' },
        coords: [el.lon, el.lat],
        description: { en: `Verified sector utility node. Status: Active.`, hi: 'सक्रिय नोड।', kn: 'ಸಕ್ರಿಯ ನೋಡ್.', es: 'Nodo activo.' },
        image: el.tags.amenity === 'cafe' ? '☕' : el.tags.amenity === 'hotel' ? '🏨' : el.tags.amenity === 'park' ? '🌳' : '📍',
        rating: 4.4 + (Math.random() * 0.5),
        isOpen: true,
        hours: el.tags.opening_hours || '08:00 - 22:00',
        phone: el.tags.phone || '+91 80 4400 1122',
        reviews: []
      }));
      setNearbyPOIs(results);
    } catch (err) {}
  }, []);

  useEffect(() => {
    if (!mapRef.current || mapInstance.current) return;
    const map = new Map({
      target: mapRef.current,
      layers: [
        planetaryLayerRef.current, baseLayerRef.current, trafficLayerRef.current, weatherLayerRef.current,
        new VectorLayer({ source: routeSource.current, zIndex: 10 }),
        new VectorLayer({ source: poiSource.current, zIndex: 40 }),
        new VectorLayer({ source: userLocSource.current, zIndex: 100 })
      ],
      view: new View({ 
        center: fromLonLat(DEFAULT_CENTER), 
        zoom: DEFAULT_ZOOM, 
        constrainResolution: true, 
        smoothExtentConstraint: true,
        multiWorld: true 
      }),
      controls: []
    });
    mapInstance.current = map;

    POPULAR_DESTINATIONS.forEach(dest => {
      const f = new Feature(new Point(fromLonLat(dest.coords)));
      f.set('poiData', dest);
      f.setStyle(new Style({ 
        image: new Circle({ 
          radius: 8, 
          fill: new Fill({ color: '#3b82f6' }), 
          stroke: new Stroke({ color: '#fff', width: 3 }) 
        }) 
      }));
      poiSource.current.addFeature(f);
    });

    if (navigator.geolocation) {
      const opt = { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 };
      navigator.geolocation.getCurrentPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        fetchNearbyDiscovery(coords[0], coords[1]);
        map.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 2500 });
      }, null, opt);

      navigator.geolocation.watchPosition((pos) => {
        const coords: [number, number] = [pos.coords.longitude, pos.coords.latitude];
        setUserLiveCoords(coords);
        userLocSource.current.clear();
        const f = new Feature(new Point(fromLonLat(coords)));
        f.setStyle(new Style({ 
          image: new Circle({ 
            radius: 10, 
            fill: new Fill({ color: '#3b82f6' }), 
            stroke: new Stroke({ color: '#fff', width: 4 }) 
          }) 
        }));
        userLocSource.current.addFeature(f);
      }, null, opt);
    }

    map.on('moveend', () => {
      const view = map.getView();
      setRotation(view.getRotation());
      const center = view.getCenter();
      if (center) {
        const lonLat = toLonLat(center) as [number, number];
        setMapViewCenter(lonLat);
        fetchNearbyDiscovery(lonLat[0], lonLat[1]);
      }
    });

    map.on('click', async (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f);
      if (feature?.get('poiData')) {
        const data = feature.get('poiData');
        const weather = await fetchWeather(data.coords[0], data.coords[1]);
        setSelectedPlace({ ...data, weather });
      } else {
        setSelectedPlace(null);
        setVayuIntel(null);
        routeSource.current.clear();
        setRoutes([]);
      }
    });
  }, [fetchNearbyDiscovery]);

  useEffect(() => {
    if (!mapInstance.current) return;
    const isSatellite = activeLayers.includes(MapLayerType.SATELLITE);
    const isTraffic = activeLayers.includes(MapLayerType.TRAFFIC);
    const isWeather = activeLayers.includes(MapLayerType.WEATHER);
    const isNight = activeLayers.includes(MapLayerType.INDUSTRIAL);

    let url = theme === MapTheme.DARK ? MAP_SOURCES.DARK_CANVAS : MAP_SOURCES.GOOGLE_STREET;
    if (isSatellite) url = MAP_SOURCES.GOOGLE_SATELLITE;

    baseLayerRef.current.setSource(new XYZ({ url, crossOrigin: 'anonymous' }));
    trafficLayerRef.current.setVisible(isTraffic);
    weatherLayerRef.current.setVisible(isWeather);
    planetaryLayerRef.current.setVisible(isNight);
  }, [activeLayers, theme]);

  const handleAISearch = async (query: string) => {
    if (!query.trim()) return;
    setIsSearching(true);
    setVayuIntel(null);

    try {
        // High-precision Urban Analytics via Puter.ai
        const systemPrompt = `Analyze spatial data for "${query}" near ${mapViewCenter[1]}, ${mapViewCenter[0]}. Provide urban density assessment, vibe summary, and utility level. Professional, data-driven tone. No markdown bolding.`;
        const response = await puter.ai.chat(systemPrompt);
        const intel = response?.toString() || 'Telemetry analysis complete.';
        setVayuIntel(intel);

        const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=1`);
        const geoData = await geoRes.json();
        if (geoData?.[0]) {
            const coords: [number, number] = [parseFloat(geoData[0].lon), parseFloat(geoData[0].lat)];
            const weather = await fetchWeather(coords[0], coords[1]);
            const discoveryDest: Destination = {
              id: `disha-${Date.now()}`,
              name: { en: geoData[0].display_name.split(',')[0], hi: '', kn: '', es: '' },
              category: { en: 'SPATIAL HUB', hi: '', kn: '', es: '' },
              coords: coords,
              description: { en: intel, hi: '', kn: '', es: '' },
              image: '📍',
              rating: 4.8,
              isOpen: true,
              weather,
            };
            setSelectedPlace(discoveryDest);
            mapInstance.current?.getView().animate({ center: fromLonLat(coords), zoom: 16, duration: 1500 });
        }
    } catch (err) {
      console.error("System De-sync:", err);
    } finally {
      setIsSearching(false);
    }
  };

  const calculateRoute = async (dest: Destination) => {
    if (!userLiveCoords) return;
    try {
      const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${userLiveCoords[0]},${userLiveCoords[1]};${dest.coords[0]},${dest.coords[1]}?overview=full&geometries=geojson`);
      const data = await res.json();
      if (data.code === 'Ok' && data.routes.length > 0) {
        const route = data.routes[0];
        routeSource.current.clear();
        const coords = route.geometry.coordinates.map((c: any) => fromLonLat(c));

        // Dynamic Segment Rendering
        const segCount = 4;
        const segSize = Math.floor(coords.length / segCount);
        for (let i = 0; i < segCount; i++) {
          const start = i * segSize;
          const end = (i === segCount - 1) ? coords.length : (i + 1) * segSize;
          const segmentCoords = coords.slice(start, end);
          if (segmentCoords.length < 2) continue;

          const feature = new Feature(new LineString(segmentCoords));
          const color = ['#3b82f6', '#f59e0b', '#ef4444', '#3b82f6'][i % 4];
          feature.setStyle(new Style({ stroke: new Stroke({ color, width: 8, lineCap: 'round' }) }));
          routeSource.current.addFeature(feature);
        }

        setRoutes([{
          id: 'rt1', distance: `${(route.distance / 1000).toFixed(1)} km`, duration: `${Math.round(route.duration / 60)} min`,
          trafficDelay: '0', congestionLevel: 'low', mode: 'driving', segments: []
        }]);
        mapInstance.current?.getView().fit(routeSource.current.getExtent(), { padding: [120, 120, 120, 120], duration: 1500 });
      }
    } catch (e) {}
  };

  return (
    <div className={`relative w-full h-screen overflow-hidden transition-colors duration-700 ${theme === MapTheme.LIGHT ? 'light-mode' : ''}`}>
      <div ref={mapRef} className="map-container" />

      <AnimatePresence>
        {showSplash && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[5000] bg-slate-950 flex flex-col items-center justify-center">
             <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="text-center space-y-4">
                <h1 className="text-7xl lg:text-9xl font-black text-white tracking-tighter">Disha</h1>
                <p className="text-blue-500 font-black uppercase text-xs lg:text-xl tracking-[0.8em] mono">find your way.</p>
             </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <Header 
        theme={theme} language={language} mapCenter={mapViewCenter}
        onThemeToggle={() => setTheme(prev => prev === MapTheme.DARK ? MapTheme.LIGHT : MapTheme.DARK)}
        onLanguageChange={setLanguage}
        onLocate={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        onOpenLayers={() => setIsLayerPanelOpen(true)}
        onSuggestionSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onAISearch={handleAISearch}
      />

      <LayerPanel 
        isOpen={isLayerPanelOpen} onClose={() => setIsLayerPanelOpen(false)}
        activeLayers={activeLayers} theme={theme} isOnline={true}
        onToggleLayer={(l) => setActiveLayers(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])}
      />

      <BottomPanel 
        theme={theme} language={language} userLocation={userLiveCoords}
        routeInfo={routes[0] || null} selectedPlace={selectedPlace}
        nearbyDiscovery={nearbyPOIs} vayuIntel={vayuIntel} groundingLinks={[]}
        onClosePlace={() => { setSelectedPlace(null); setVayuIntel(null); routeSource.current.clear(); setRoutes([]); }}
        onDestinationSelect={async (dest) => { 
            const weather = await fetchWeather(dest.coords[0], dest.coords[1]);
            setSelectedPlace({ ...dest, weather }); 
            calculateRoute(dest); 
        }}
        onClearRoute={() => { setRoutes([]); routeSource.current.clear(); }}
      />

      <FloatingControls 
        onRecenter={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 800 })}
        onGPS={() => userLiveCoords && mapInstance.current?.getView().animate({ center: fromLonLat(userLiveCoords), zoom: 17, duration: 1000 })}
        on3D={() => { setIs3D(!is3D); mapInstance.current?.getView().animate({ rotation: is3D ? 0 : Math.PI/4, duration: 1000 }); }}
        onMeasureToggle={() => setIsMeasuring(!isMeasuring)} 
        is3D={is3D} isMeasuring={isMeasuring} rotation={rotation}
      />

      {isSearching && (
        <div className="fixed inset-x-0 top-32 flex justify-center z-[2500] pointer-events-none">
          <div className="px-6 py-2 glass rounded-full flex items-center gap-3 border border-blue-500/30">
            <div className="w-2 h-2 bg-blue-500 rounded-full animate-ping" />
            <span className="text-[10px] font-black uppercase tracking-widest text-blue-500 mono">Syncing Urban Telemetry...</span>
          </div>
        </div>
      )}
    </div>
  );
};
export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MapTheme, Destination, Language } from '../types';
import { POPULAR_DESTINATIONS, TRANSLATIONS } from '../constants';
import { getDistance } from 'ol/sphere';

interface HeaderProps {
  theme: MapTheme;
  language: Language;
  mapCenter: [number, number];
  onThemeToggle: () => void;
  onLanguageChange: (l: Language) => void;
  onLocate: () => void;
  onOpenLayers: () => void;
  onSuggestionSelect: (dest: Destination) => void;
  onAISearch: (query: string) => void;
}

const LogoIcon = () => (
  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className="lg:w-8 lg:h-8">
    <path d="M12 2L4 7V17L12 22L20 17V7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
    <circle cx="12" cy="12" r="4" fill="currentColor"/>
  </svg>
);

const DISCOVERY_PROMPTS = [
  "Analyze urban density...",
  "Search for coffee nodes...",
  "Navigate to Lalbagh Core...",
  "Check atmospherics...",
  "Locate EV stations...",
  "Explore green belts..."
];

export const Header: React.FC<HeaderProps> = ({ 
  theme, language, mapCenter, onThemeToggle, onOpenLayers, onSuggestionSelect, onAISearch
}) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [isFocused, setIsFocused] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const [placeholderText, setPlaceholderText] = useState('');
  const [promptIndex, setPromptIndex] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);
  const [typingSpeed, setTypingSpeed] = useState(100);

  useEffect(() => {
    const handleTyping = () => {
      const currentPrompt = DISCOVERY_PROMPTS[promptIndex];
      const isFinishing = !isDeleting && placeholderText === currentPrompt;
      const isStartingDeleting = isDeleting && placeholderText === '';

      if (isFinishing) {
        setTypingSpeed(2000);
        setIsDeleting(true);
      } else if (isStartingDeleting) {
        setTypingSpeed(100);
        setIsDeleting(false);
        setPromptIndex((prev) => (prev + 1) % DISCOVERY_PROMPTS.length);
      } else {
        setTypingSpeed(isDeleting ? 50 : 100);
        setPlaceholderText(current => 
          isDeleting 
            ? current.slice(0, -1) 
            : currentPrompt.slice(0, current.length + 1)
        );
      }
    };
    const timer = setTimeout(handleTyping, typingSpeed);
    return () => clearTimeout(timer);
  }, [placeholderText, isDeleting, promptIndex, typingSpeed]);

  useEffect(() => {
    if (!query.trim() || query.length < 2) {
      setSuggestions([]);
      return;
    }
    const timer = setTimeout(async () => {
      const q = query.toLowerCase().trim();
      const results = POPULAR_DESTINATIONS.map(dest => {
        const name = dest.name[language].toLowerCase();
        const distance = getDistance(dest.coords, mapCenter) / 1000;
        let score = name.startsWith(q) ? 100 : (name.includes(q) ? 50 : 0);
        return { ...dest, score, distance };
      })
      .filter(item => item.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 5);
      setSuggestions(results);
    }, 150);
    return () => clearTimeout(timer);
  }, [query, language, mapCenter]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) setIsFocused(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <motion.header 
      initial={{ y: -100 }} animate={{ y: 0 }}
      className="fixed top-0 left-0 right-0 z-[2000] p-3 lg:p-6 flex justify-center pointer-events-none"
    >
      <div className="max-w-7xl w-full flex items-center gap-2 lg:gap-5 pointer-events-auto">
        <div className={`flex items-center gap-2 lg:gap-5 px-3 lg:px-8 h-[50px] lg:h-[72px] rounded-[16px] lg:rounded-[36px] transition-all shadow-xl ${theme === MapTheme.DARK ? 'glass text-white' : 'glass-light text-slate-900 border-white/50'}`}>
          <div className="w-8 h-8 lg:w-11 lg:h-11 bg-blue-600 rounded-[10px] lg:rounded-[20px] flex items-center justify-center text-white shrink-0 shadow-lg">
            <LogoIcon />
          </div>
          <span className="font-black text-sm lg:text-2xl tracking-tighter hidden sm:block">Disha</span>
        </div>

        <div className="flex-1 relative" ref={dropdownRef}>
          <div className={`flex items-center px-4 lg:px-10 h-[50px] lg:h-[72px] rounded-[16px] lg:rounded-[36px] transition-all shadow-xl ${
            theme === MapTheme.DARK ? `glass ${isFocused ? 'ring-2 ring-blue-500' : ''}` : `glass-light border-white/50 ${isFocused ? 'ring-2 ring-blue-500' : ''}`
          }`}>
            <div className="relative flex-1 h-full flex items-center">
              <input 
                type="text" value={query} onFocus={() => setIsFocused(true)} 
                onChange={(e) => setQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && onAISearch(query)}
                className="bg-transparent border-none outline-none w-full text-sm lg:text-xl font-black tracking-tight z-10"
                style={{ color: theme === MapTheme.DARK ? 'white' : '#0f172a' }}
              />
              {!query && (
                <div className="absolute inset-0 flex items-center pointer-events-none">
                  <span className={`text-xs lg:text-xl font-black tracking-tight opacity-30 ${theme === MapTheme.DARK ? 'text-white' : 'text-slate-900'}`}>
                    Vayu: {placeholderText}
                    <span className="animate-pulse">|</span>
                  </span>
                </div>
              )}
            </div>
            <button onClick={() => onAISearch(query)} className="ml-2 text-slate-500 hover:text-blue-500 transition-colors">
               <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
            </button>
          </div>

          <AnimatePresence>
            {isFocused && suggestions.length > 0 && (
              <motion.div initial={{ opacity: 0, y: 15 }} animate={{ opacity: 1, y: 12 }} exit={{ opacity: 0, y: 15 }}
                className={`absolute top-full left-0 right-0 rounded-[24px] lg:rounded-[48px] shadow-3xl overflow-hidden border ${theme === MapTheme.DARK ? 'glass border-white/10' : 'glass-light border-black/5'}`}
              >
                <div className="max-h-[40vh] overflow-y-auto py-2 lg:py-4 no-scrollbar">
                  {suggestions.map((dest, idx) => (
                    <div key={idx} onClick={() => { onSuggestionSelect(dest); setIsFocused(false); setQuery(dest.name[language]); }}
                      className="px-6 lg:px-10 py-3 lg:py-5 flex items-center gap-4 lg:gap-8 cursor-pointer hover:bg-blue-600/10 transition-colors group"
                    >
                      <div className="text-xl lg:text-4xl w-10 h-10 lg:w-14 lg:h-14 rounded-xl bg-slate-500/5 flex items-center justify-center group-hover:scale-110 transition-transform">{dest.image}</div>
                      <div className="flex-1">
                        <div className="font-black text-xs lg:text-xl truncate leading-tight">{dest.name[language]}</div>
                        <div className="text-[8px] lg:text-[12px] font-bold opacity-30 uppercase tracking-widest">{dest.distance.toFixed(1)} km away</div>
                      </div>
                    </div>
                  ))}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex gap-1.5 lg:gap-4 shrink-0">
          <button onClick={onOpenLayers} className={`w-[50px] lg:w-[72px] h-[50px] lg:h-[72px] rounded-[14px] lg:rounded-[32px] flex items-center justify-center shadow-xl transition-all ${theme === MapTheme.DARK ? 'glass text-blue-400' : 'glass-light text-blue-600'}`}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><polygon points="12 2 2 7 12 12 22 7 12 2"></polygon><polyline points="2 17 12 22 22 17"></polyline></svg>
          </button>
          <button onClick={onThemeToggle} className={`w-[50px] lg:w-[72px] h-[50px] lg:h-[72px] rounded-[14px] lg:rounded-[32px] flex items-center justify-center shadow-xl transition-all ${theme === MapTheme.DARK ? 'glass text-yellow-400' : 'glass-light text-blue-600'}`}>
            {theme === MapTheme.DARK ? '☀️' : '🌙'}
          </button>
        </div>
      </div>
    </motion.header>
  );
};
